window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-051.json"] = [{"name":"特立尼达歌雀","english_name":"Trinidad Euphonia","scientific_name":"Euphonia trinitatis","overview":"特立尼达歌雀（英文名：Trinidad Euphonia，学名：Euphonia trinitatis），是雀形目燕雀科歌雀属的小型鸟类。常见于南美洲北部，包括哥伦比亚东部、委内瑞拉、圭亚那和巴西北部，以及特立尼达岛。雄鸟具有独特的蓝黑色头部、背部、喉咙和上胸部，额头和头顶鲜黄，下体同样鲜黄。雌鸟橄榄绿上体，下体黄橄榄色，胸部和腹部中央有灰色斑块，尾巴下方有明显的白色。","appearance":"特立尼达歌雀体型丰满，体长约9.7-11厘米，重约8.8-14克。雄鸟头部、背部、下巴和喉咙呈蓝黑色，前额和头顶亮黄色，下体亦为亮黄色。雌鸟上体橄榄绿，下体黄橄榄色，胸腹部中央有一灰白色区域。两者尾巴下方均有显著白色，雄鸟的翼下覆羽也有白色条纹。","call":"特立尼达歌雀的叫声高亢而哀婉，通常由雄鸟在树顶或半暴露的枝条上发出。最常听到的是两声清脆的哨音，类似“tee dee”。还有上升的双音调叫声，如“puwee”、“cooleee”或“duu dee”。其歌曲为混杂的音乐性和非音乐性音符的短暂组合。","habits":"特立尼达歌雀主要栖息于干燥到湿润的林地，包括干林、湿润森林边缘、轻木林、灌丛和耕作区，海拔可达1,100米。它们以果实为主食，尤其是槲寄生浆果，偶尔也吃昆虫和其他无脊椎动物。飞行时会在翼下形成白色条纹。","breeding":"繁殖期在特立尼达为1月至4月，在大陆地区主要为4月。雄鸟和雌鸟通过翅膀抖动、侧向抽搐和低鞠躬来求偶。巢为圆形，由干草和茎构成，有侧面入口，内部铺有细软材料，高度从1.4至12米不等。雌鸟单独孵卵，双方共同喂养幼鸟。","identification":"雄性特立尼达歌雀的暗喉部可将其与厚嘴歌雀和紫喉歌雀相区分，雌鸟则可通过较小的体型、细小的喙和胸腹部的灰白色区域来识别。与橙腹歌雀相比，雄鸟的前额为黄色而非红棕色，雌鸟颈后部呈灰白色。雌鸟与紫喉歌雀的雌鸟几乎无法区分。","protection":"IUCN：LC（无危）。然而在特立尼达岛上，由于捕捉作为笼鸟贸易导致数量稀少。","distribution":"分布于南美洲的哥伦比亚东部和委内瑞拉中部至圭亚那和巴西北部，以及特立尼达岛。在特立尼达岛上的分布较为局部。","other":"特立尼达歌雀的命名源自1851年英国鸟类学家Hugh Edwin Strickland，以纪念它在特立尼达岛的发现地。"},{"name":"绒额歌雀","english_name":"Velvet-fronted Euphonia","scientific_name":"Euphonia concinna","overview":"绒额歌雀（英文名：Velvet-fronted Euphonia，学名：Euphonia concinna），是雀形目燕雀科歌雀属的鸟类。分布于南美洲哥伦比亚的马格达莱纳河谷地区，主要栖息于海拔200至1,000米的开放林地。","appearance":"雄鸟个体上部呈深钢蓝色，下部为鲜艳黄色，前额黄色明显；喉部和尾巴下侧全黑。雌鸟为暗灰色橄榄色上部，下部黄色，同样具有黄色前额。雄性橙腹歌雀有白色尾巴下侧，雌鸟则颜色更灰，与本种有明显区别。","habits":"偏好栖息在开放的林地环境中，活动范围限制在哥伦比亚中部的特定区域内。","identification":"与橙腹歌雀区分，雄性橙腹歌雀尾巴下侧为白色，而雌鸟颜色更偏向灰色。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚的上马格达莱纳河谷，从托利马北部（Honda）和相邻的昆迪纳马卡省南部到胡伊拉省西南部（La Plata）；最近的记录显示在中间考卡河谷也有分布。"},{"name":"橙冠歌雀","english_name":"Orange-crowned Euphonia","scientific_name":"Euphonia saturata","overview":"橙冠歌雀（英文名：Orange-crowned Euphonia，学名：Euphonia saturata），是雀形目燕雀科歌雀属的小型鸣禽。该物种以独特的橙色羽冠和色彩鲜明的体羽著称，常见于南美洲的哥伦比亚中西部至秘鲁远西北部的低地和山麓地带。","appearance":"橙冠歌雀体型紧凑，尾巴短小，喙部粗壮。雄鸟个体拥有橙色调的下体和带有紫色光泽的深色上体，其橙黄色的冠羽十分显眼，几乎覆盖整个头顶，与仅限于前额的其他歌雀种类形成鲜明对比。尾部下方全为暗色。雌鸟个体整体呈淡黄橄榄色，与其他歌雀种类较难区分，尤其是在无雄鸟伴随时。","habits":"栖息于干燥地区的森林边缘、林地和开阔地带。常出现在混合觅食群中，与多种鸟类如莺和唐纳雀一同活动。","identification":"雄鸟的显著橙黄色冠羽和暗色尾下覆羽是与其他歌雀种类区分的关键特征。雌鸟个体虽与同类较难区分，但在混群中通常与雄鸟相伴，有助于识别。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚中西部至秘鲁远西北部，包括哥伦比亚西安第斯山脉两侧、厄瓜多尔西部和秘鲁极西北部（Tumbes地区）。栖息于亚热带或热带的干燥森林、湿润低地森林及严重退化的旧森林。"},{"name":"芬氏歌雀","english_name":"Finsch's Euphonia","scientific_name":"Euphonia finschi","overview":"芬氏歌雀（英文名：Finsch's Euphonia，学名：Euphonia finschi），是雀形目燕雀科歌雀属的鸟类。以德国自然学家Friedrich Hermann Otto Finsch的名字命名。主要特征是雄鸟具有黄色的前冠和腹部，与深色喉咙形成鲜明对比，而雌鸟则主要呈现淡黄色和绿色。常在森林树冠层活动，有时会静止不动许久。分布于南美洲北部，包括委内瑞拉东部、巴西东北部、圭亚那、苏里南西部和北部、法属圭亚那北部。","appearance":"雄性芬氏歌雀拥有醒目的黄色前冠和腹部，与暗色喉咙形成鲜明对比，雌鸟则主要是淡黄绿色，不如雄鸟色彩鲜艳。体型较小，常见于森林树冠，喜欢在裸露的树枝上栖息。","call":"它们的叫声通常是一声哀婉的双音哨声，易于辨识。","habits":"芬氏歌雀偏好生活在各种类型的森林中，包括沿海和草原森林，通常在树冠层活动，靠近结果的树木。它们通常成对或小群体出现，有时会长时间保持静止，然后飞向远方。","identification":"雄性芬氏歌雀与紫喉歌雀非常相似，但下方色彩更为丰富；雌鸟则与紫褐色歌雀相似，通过伴随的雄鸟可以较好地区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲北部，包括委内瑞拉近圣埃琳娜德乌艾伦和罗赖马山附近地区，巴西东北部罗赖马州，以及跨越圭亚那中部、苏里南西部和北部、法属圭亚那北部。","other":"芬氏歌雀是纪念德国自然学家Friedrich Hermann Otto Finsch的重要物种之一，其生平与贡献在科学界备受尊敬。"},{"name":"紫歌雀","english_name":"Violaceous Euphonia","scientific_name":"Euphonia violacea","overview":"紫歌雀（英文名：Violaceous Euphonia，学名：Euphonia violacea），是雀形目燕雀科歌雀属的鸟类。以其悦耳的歌声闻名。雄鸟拥有闪亮的蓝黑色上体和亮丽的黄色下体，雌鸟及幼鸟则呈现较为暗淡的橄榄绿色。广泛分布于南美洲东北部至东部地区。","appearance":"雄性紫歌雀上体光泽蓝黑，前额及下体金黄，雌鸟和幼鸟橄榄绿上体，绿黄色下体。雄鸟的上体有强烈的紫蓝色光泽，下体深金色；雌鸟和幼鸟上体橄榄色，下体橄榄黄色。","call":"紫歌雀的鸣唱融合了其他物种的歌曲片段，间以短促的颤音和咔嗒声。","habits":"紫歌雀栖息于森林边缘、次生林、果园及城市公园。它们主要以果实为食，偶尔也吃昆虫，常单独或小群体活动。","breeding":"紫歌雀在树洞、河岸或树桩上筑巢，每次产卵3至4枚，由雌鸟孵化。","identification":"雄性紫歌雀与厚嘴歌雀相似，但后者有更大的黄色头冠斑块和更纯净的黄色喉咙。雌性紫歌雀与厚嘴歌雀雌鸟非常相似，但在腹部颜色上有所不同。","protection":"IUCN：LC（无危）","distribution":"紫歌雀广泛分布于南美洲东北部和东部，包括委内瑞拉、特立尼达、巴拉圭、阿根廷东北部和巴西东南部。","other":"紫歌雀因其悦耳的歌声而受到人们的喜爱，但其相对偏远的栖息地使其免受过度捕猎的影响。"},{"name":"厚嘴歌雀","english_name":"Thick-billed Euphonia","scientific_name":"Euphonia laniirostris","overview":"厚嘴歌雀（英文名：Thick-billed Euphonia，学名：Euphonia laniirostris），是雀形目燕雀科歌雀属的鸟类。小型的燕雀科鸟类，主要分布在中美洲的哥斯达黎加西南部至南美洲的亚马逊雨林西部地区。雄鸟拥有独特的黄色喉部至腹部，上半身呈现深蓝黑色，头部带有黄色冠羽，而雌鸟则呈橄榄绿色背部和黄绿色腹部。","appearance":"厚嘴歌雀体长约10厘米，体重介于13到16.5克之间。雄鸟具有一张相对厚实的喙，额头至头顶中部为黄色，侧面头部、后部头顶、颈背及上体为光泽的蓝黑色，上尾覆羽深蓝色，上翼覆羽和飞羽暗淡带深蓝色调，喉咙至整个下体亮黄色，下尾羽暗灰色，外侧2-3对羽毛内缘主要为白色形成两个大的白色椭圆。雌鸟上体黄绿橄榄色，下体绿色带黄，腹部颜色较浅。未成年个体类似雌鸟，次成年雄鸟（第二全年）背部橄榄色，前额黄色带橄榄斑点，头部侧面常形成面罩，喉咙和胸部黄色，两侧、胁部和下体大部分为橄榄色。","habits":"厚嘴歌雀偏好开放的森林生境、边缘和花园地带。它们经常成对或小群体活动，偶尔会与其他物种如莺类和唐纳雀形成混合觅食群。以小果实和浆果为主食，包括槲寄生（Loranthaceae）、梅拉斯托姆属、无花果（Ficus）等植物的果实。","breeding":"繁殖期在巴拿马为3月至9月，哥伦比亚的繁殖季可能相似，而在哥伦比亚12月和1月有记录，4月至7月有处于繁殖状态的个体。一年内可有两至三窝。巢由两性共同建造，通常建于离地面3米以内，偶尔可达15米高，藏匿于树干洞穴、附生植物覆盖或藤蔓缠绕的枝条或枝叉中。每窝产2至5枚蛋，蛋壳白色或粉白，带棕色斑点，尤其在大端明显。孵化期14至16天，双亲喂养雏鸟，雏鸟期18至21天。次成年雄鸟在第二全年可能以亚成年羽毛繁殖。","identification":"雄性厚嘴歌雀通过其完全黄色的冠部和喉部来识别，而雌鸟与其他歌雀区分较为困难，尤其是与黄冠歌雀的区别。雄鸟头部黄色冠羽延伸程度是辨识的关键。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加西南部至南美洲的亚马逊雨林西部，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、巴拿马、秘鲁和委内瑞拉。"},{"name":"黄喉歌雀","english_name":"Yellow-throated Euphonia","scientific_name":"Euphonia hirundinacea","overview":"黄喉歌雀（英文名：Yellow-throated Euphonia，学名：Euphonia hirundinacea），是雀形目燕雀科歌雀属的鸟类。小型热带鸟类，分布于墨西哥东部至巴拿马西部的热带低地和山麓地带，栖息于森林冠层、相邻林间空地、花园等地。雄鸟上部蓝黑色，下部及前额黄色，与同域分布的薮歌雀不同，其黄色下部延伸至喙基。雌鸟上部橄榄绿色，下部淡灰色，两侧黄色，营造小球形巢，巢入口侧向。","appearance":"黄喉歌雀是一种小型雀形目鸟类，体长约10-12厘米，翼展5.8-6.1厘米，体重11.6-17.8克。雄鸟前额黄色，其余头部、上体蓝黑色，下体黄色。雌鸟上体橄榄绿色，下体淡灰，两侧亮黄。幼鸟类似雌鸟，但羽毛质地松散，上体橄榄色无光泽。成熟雄鸟具黑喉面具，上体蓝绿，下体黄色。","call":"雄鸟鸣声包含高音尖锐和中音调交替，有时模仿其他鸟类叫声，但曲目不如近缘物种丰富。叫声包括快速‘pidgel-eece’、对话式‘chi-bib-bib-bib-bib’、急促‘tuck-a-tuck’或‘chuck-a-chuck’、清脆‘weet’及饱满‘queer’或‘gleer’。","habits":"黄喉歌雀偏好干湿兼备的生境，常出现在森林边缘、次生林、阴凉种植园及河谷树林。主要以果实和浆果为食，尤其是槲寄生浆果，偶尔食昆虫。全年成对活动，不守卫领地。","breeding":"繁殖期从3月至8月，随地理位置而异。营建圆顶巢，侧向开口，由草、细叶、根须、苔藓和地衣构成，置于树干、枝条或棕榈叶上，或在树洞、路边土堤内。平均产卵五枚，孵化期约15天，雏鸟主要以吐出的果实和种子喂养。","identification":"雄鸟黄色喉部是主要识别特征，与厚嘴歌雀相似，但后者冠部黄色更广泛。雌鸟区别于其他同域Euphonia种类，具有白色或淡灰色喉部和腹部，两侧黄色。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥东部至巴拿马西部，包括贝里斯、洪都拉斯、萨尔瓦多、尼加拉瓜、哥斯达黎加和巴拿马。在墨西哥南至塔毛利帕斯南部，东部圣路易斯波托西，普埃布拉东北部，维拉克鲁斯北部至图斯潘和特拉帕科扬。","other":"黄喉歌雀适应人类干扰环境，常见于种植园、次生林和森林边缘。"},{"name":"绿喉歌雀","english_name":"Green-chinned Euphonia","scientific_name":"Euphonia chalybea","overview":"绿喉歌雀（英文名：Green-chinned Euphonia，学名：Euphonia chalybea），是雀形目燕雀科歌雀属的鸟类。小型鸟类，以光泽鲜明的绿色羽毛和厚实的喙著称。分布于南美的巴拉圭东部、阿根廷东北部和巴西东南部，栖息于热带湿润森林。","appearance":"绿喉歌雀体型微小，喙部结实且厚，尾羽较短。雄鸟个体通体呈深绿色，带有金属光泽，头部有一条黄色带纹，腹部完全为黄色。雌鸟则为橄榄绿色，头部两侧和胸部中央为灰色，腹部和两胁为黄色。","call":"其鸣声为一系列快速的吱吱声，音调尖锐。","habits":"绿喉歌雀偏好栖息在热带湿润森林的树冠层，常见于混合物种的鸟群中。它们的活动范围广泛，从海平面至较高海拔均有发现。","identification":"与其他歌雀属鸟类相比，绿喉歌雀的显著特征在于雄鸟的绿色金属光泽羽毛和黄色腹部，以及雌鸟的橄榄绿色与黄色的对比。","protection":"IUCN：LC（无危）。在巴西东南部大西洋森林中相对常见，但由于栖息地的大量砍伐，其数量被认为正在减少。在多个国家公园和保护区中可见，如阿根廷的伊瓜苏国家公园和巴西的伊瓜苏、伊塔蒂亚亚及塞拉达博卡伊纳国家公园。","distribution":"绿喉歌雀主要分布在南美洲的巴西东南部，从里约热内卢向南至里奥格兰德杜苏尔，以及相邻的巴拉圭东部和阿根廷东北部。"},{"name":"褐臀歌雀","english_name":"Fulvous-vented Euphonia","scientific_name":"Euphonia fulvicrissa","overview":"褐臀歌雀（英文名：Fulvous-vented Euphonia，学名：Euphonia fulvicrissa），是雀形目燕雀科歌雀属的鸟类。主要分布在中美洲和南美洲，从巴拿马中部到厄瓜多尔西北部的低地森林中。","appearance":"雄性褐臀歌雀下体呈黄色，上体为深蓝色，背部带有黑色条纹，喙粗壮而短，头部有醒目的黄色冠羽。其下尾覆羽为暗橙色，逐渐淡入下腹部。雌鸟的下尾覆羽带锈色，前额也有锈色斑点。","call":"鸣叫时发出刺耳的两音节叫声。","habits":"常在低地森林及边缘的中层活动，以群居形式出现，常与其他物种如莺鸟和唐纳雀混群觅食。","identification":"与其他歌雀属鸟类相比，褐臀歌雀的下尾覆羽颜色更为显著，雄鸟特有的黄色冠羽也是辨识要点。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，具体为巴拿马中部至厄瓜多尔西北部，偏好栖息在亚热带或热带湿润低地森林及重度退化的旧森林中。"},{"name":"斑冠歌雀","english_name":"Spot-crowned Euphonia","scientific_name":"Euphonia imitans","overview":"斑冠歌雀（英文名：Spot-crowned Euphonia，学名：Euphonia imitans），是雀形目燕雀科歌雀属的鸟类。小型的燕雀科鸟类，主要分布在中美洲的哥斯达黎加和巴拿马，栖息于低地森林和边缘地带，最高可达海拔1,300米。其特征性的斑点仅在特定光照条件下可见于雄鸟的冠部后端。","appearance":"雄性斑冠歌雀拥有典型的歌雀羽毛色彩：上半身呈深蓝钢色，腹部和头部顶部为黄色，喉部较暗。冠部后端的命名斑点在野外观察时难以察觉。黄色主要局限于冠部前半部分，这与黄冠歌雀的广泛黄色冠部形成对比。雌性斑冠歌雀比雄鸟更为独特，具有红褐色的腹部和前额冠部，这是其分布范围内其他歌雀所不具备的特征。","habits":"斑冠歌雀通常以成对或小群体的形式活动，生活在低地森林和边缘地带，从地面至树冠层均有它们的身影。它们的活动范围广泛，从哥斯达黎加的卡腊拉和圣何塞至少到巴拿马的奇里基西部。","identification":"雄性斑冠歌雀与黄冠歌雀的区别在于黄色主要限于冠部前半部分，而雌性斑冠歌雀的红褐色腹部和前额冠部是识别的关键特征。与灌丛歌雀相似，但二者的分布区域并不重叠。","protection":"IUCN：LC（无危）","distribution":"斑冠歌雀分布于中美洲的哥斯达黎加太平洋沿岸（至少从卡腊拉和圣何塞开始）至巴拿马西部（奇里基）。"},{"name":"绿背歌雀","english_name":"Olive-backed Euphonia","scientific_name":"Euphonia gouldi","overview":"绿背歌雀（英文名：Olive-backed Euphonia，学名：Euphonia gouldi），是雀形目燕雀科歌雀属的鸟类。主要分布在中美洲，从墨西哥东南部到巴拿马的热带低地森林中。其最显著的外部特征是全身呈现青铜绿色，腹部有深锈色斑块，雄鸟的黄色前额和雌鸟的深锈色前额形成鲜明对比。","appearance":"绿背歌雀体型小巧，全长约9.5厘米，体重约为12克。雄鸟拥有光泽的橄榄色背部，黄色前额，以及被黄色环绕的锈色腹部。雌鸟上部不如雄鸟光泽，前额呈栗色，下部黄色，腹部带有小片锈色斑。幼鸟颜色较暗，较为暗淡，且下部橄榄色。","call":"绿背歌雀的叫声为金属质感的连串‘chrrr-chrrr’声，其歌声则是叫声与清晰或鼻音哨声的混合。","habits":"绿背歌雀常以小群体出现，或作为混合物种觅食群的一部分。它们主要栖息于湿润的森林、高大的次生林及邻近的灌木空地，活动高度通常从海平面至海拔750米，有时可达1000米。主要食物来源为小果实。","breeding":"繁殖期间，绿背歌雀会在树上的苔藓或寄生植物中建造球形侧入口的杯状巢，高度介于2至11米之间。每窝通常产三枚带有褐色斑点的白色蛋。","identification":"绿背歌雀与其它歌雀属鸟类的区别在于其独特的青铜绿色外观，以及雄鸟与雌鸟前额颜色的不同。雄鸟黄色前额和雌鸟栗色前额是辨识关键。","protection":"IUCN：LC（无危）","distribution":"绿背歌雀主要分布于中美洲，覆盖从墨西哥东南部至巴拿马的热带低地和丘陵地带。"},{"name":"金腹歌雀","english_name":"White-lored Euphonia","scientific_name":"Euphonia chrysopasta","overview":"金腹歌雀（英文名：White-lored Euphonia，学名：Euphonia chrysopasta），是雀形目燕雀科歌雀属的鸟类。生活在南美洲低地雨林中的小型鸣禽，属于燕雀科。雄鸟拥有亮丽的金黄色羽毛，颈部轻灰，两侧耳羽处有显著的白色斑点；雌鸟相似，但腹部呈灰色。此物种偏好开放的森林环境，如年轻雨林和森林空地，偶尔也见于成熟的雨林中。","appearance":"雄性金腹歌雀呈现富丽的金色调，头部后方有浅灰色的领圈，最显眼的是其耳羽位置的白色斑纹。雌鸟的下体颜色为灰色，上体保留了雄鸟的金黄色调。两性均具有黄色的下尾覆羽。成年个体大小适中，与同类相比，其喙周有一片淡色区域，而不会像其他种类那样呈现出橙色色调。","call":"金腹歌雀发出一系列多样的叫声，包括短暂的高音哨声和啾啾声，以及一种平滑的‘dwick’声。","habits":"金腹歌雀栖息于南美低地的雨林中，它们偏爱开放的森林生境，如年轻雨林和森林边缘地带，有时也会在成熟的雨林中发现它们的身影。它们的活动范围广泛，包括森林地面到树冠层。","breeding":"关于金腹歌雀的繁殖行为信息有限，但一般而言，它们会在适宜的季节内营巢、产卵，进行繁殖活动。","identification":"与相似的雌鸟歌雀相比，金腹歌雀的特征在于喙部周围的淡色区域和黄色的下尾覆羽，而不具橙色色调。","protection":"IUCN：LC（无危）","distribution":"金腹歌雀的分布范围涵盖南美洲的圭亚那高地和亚马逊地区，具体国家包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。"},{"name":"铜绿歌雀","english_name":"Bronze-green Euphonia","scientific_name":"Euphonia mesochrysa","overview":"铜绿歌雀（英文名：Bronze-green Euphonia，学名：Euphonia mesochrysa），是雀形目燕雀科歌雀属的鸟类。小型森林鸟类，分布于南美洲安第斯山脉东坡的云雾森林，从哥伦比亚中部至玻利维亚中部。其最显著的特征是雄鸟拥有亮丽的黄色前额、橙色腹部，头部和翅膀带蓝灰色调。","appearance":"雄性铜绿歌雀拥有鲜明的外观，其头部、翅膀边缘呈蓝灰色，前额亮黄，腹部橙色。雌鸟则与其它雌鸟歌雀相似，但其喉部黄色，腹部白色，通常在颈背和翅膀上显现出灰蓝色的痕迹。雌雄两性的幼鸟特征随成长而变化。","call":"鸣叫声独特，发出一系列引人注目的哨音和响亮的颤音，这在歌雀中较为罕见，具有较高的辨识度。","habits":"栖息于亚热带或热带湿润的山地森林中，常在果实丰富的树木上觅食，活动高度较高，有时会加入混合鸟群中。","breeding":"具体繁殖细节尚需进一步研究，但一般在春季进行繁殖，筑巢于树上，以果实和昆虫喂养雏鸟。","identification":"雄性铜绿歌雀的黄色前额和橙色腹部是识别的关键，而雌鸟的黄色喉部和白色腹部以及灰蓝色的翼部痕迹帮助与同类区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，沿着安第斯山脉东坡，自哥伦比亚中部至玻利维亚中部的云雾森林。"},{"name":"白臀歌雀","english_name":"White-vented Euphonia","scientific_name":"Euphonia minuta","overview":"白臀歌雀（英文名：White-vented Euphonia，学名：Euphonia minuta），是雀形目燕雀科歌雀属的小型鸟类。常见于中美洲和南美洲热带低地的常绿森林及其边缘地带。","appearance":"体长约9.5厘米。雄鸟上体蓝黑色，额部黄色，喉部紫黑色，腹部鲜黄；雌鸟上体橄榄绿，喉部灰白色，腹部淡黄，雌雄均具白色中腹。雌鸟较雄鸟色彩暗淡。","call":"叫声由单一音节组成，如‘beem’或‘seeu’。","habits":"栖息于湿润林地的树冠层及边缘，偏好热带低地的环境。通常成对出现，易于与其他歌雀属鸟类混群活动。","identification":"雄鸟白色臀部明显，与同域分布的Scrub Euphonias相比，胸部颜色更金黄；雌鸟喉部淡灰色，与黄色胸部形成对比，臀部亦为白色。","protection":"IUCN状态未知。","distribution":"分布于中美洲至南美洲，具体包括墨西哥东南部至厄瓜多尔，以及圭亚那至玻利维亚中部。","other":"系统学历史未详。"},{"name":"黄顶歌雀","english_name":"Tawny-capped Euphonia","scientific_name":"Euphonia anneae","overview":"黄顶歌雀（英文名：Tawny-capped Euphonia，学名：Euphonia anneae），是雀形目燕雀科歌雀属的小型鸣禽，分布于中美洲至南美洲，具体见于哥斯达黎加至哥伦比亚一带。其自然栖息地主要包括亚热带或热带湿润低地森林、亚热带或热带湿润山地森林以及严重退化的前森林。","appearance":"黄顶歌雀体型紧凑，尾部短小，外观类似小型雀类。通体黄色腹部与深蓝黑色背部形成鲜明对比，喙部粗壮且短。雄性黄顶歌雀的识别特征在于其整个头顶部呈红褐色，喉部颜色较暗。雌鸟个体的橙色前额区域较为有限，有助于缩小鉴别范围。此外，其腹部呈灰色，而非橄榄色或棕色。","habits":"黄顶歌雀常以成对或小群出现，尤其在混合觅食群中，常见于森林环境及其边缘地带，与其它物种如莺类和唐纳雀共同活动。","identification":"雄性黄顶歌雀的红褐色冠羽和暗色喉部是关键识别点，而雌鸟头部橙色区域的局限性也是区分的重要依据。与其他歌雀属物种相比，黄顶歌雀的灰色腹部是显著特征。","protection":"IUCN：LC（无危）","distribution":"黄顶歌雀主要分布于中美洲至南美洲，具体涵盖哥斯达黎加至哥伦比亚的区域，栖息于多种森林环境中。"},{"name":"橙腹歌雀","english_name":"Orange-bellied Euphonia","scientific_name":"Euphonia xanthogaster","overview":"橙腹歌雀（英文名：Orange-bellied Euphonia，学名：Euphonia xanthogaster），是雀形目燕雀科歌雀属的小型鸟类，主要分布在中美洲，自巴拿马东部至秘鲁西北部的跨安第斯山脉地区，委内瑞拉顺安第斯山脉至玻利维亚中部和巴西西部，以及巴西东南部的零散分布。","appearance":"体长约9-11厘米，体重9-16克。雄鸟具深黄色前额至头顶中部，其余头部及颈为光泽黑，喉部紫黑色；上体及翅膀覆盖羽蓝黑光泽，尾上覆羽蓝黑；胸部和下体黄色，腹部略带赭色；翼下覆羽白色；尾下灰色，外侧几对尾羽内缘白色，形成大块白色区域；虹膜棕色；喙大多黑色，下颚基部蓝灰，尖端暗色；腿深灰。雌鸟前额橄榄黄，头顶橄榄，后头及颈灰，上体橄榄，翼覆羽橄榄至暗淡，边缘橄榄；初级覆羽暗淡，飞羽和尾暗淡，边缘橄榄；侧面头部橄榄，喉、胸及中下体灰色，与橄榄到橄榄黄的两侧和胁部形成对比；腹部和尾下覆羽微带淡褐色。亚成年雄鸟似雌鸟，但在首年结束时获得黑色面罩，有时头部有不同程度的黑色；在第二年末似乎获得成年羽毛。各亚种在羽毛颜色和图案上有所不同，尤其是雄鸟。","call":"在哥伦比亚和委内瑞拉，叫声为鼻音粗糙的'nay nay'或鼻音抱怨的'chee dee'（2-4音符）；歌声为断续的' deeu deeu...deet deet deet... jew jew... chu chu chu...jew, ju-du-du-du...'等。西亚马逊低地的鸟儿似乎有一套几乎完全不同的叫声和歌声库，缺乏安第斯山脉鸟类的鼻音'nay nay'和其他鼻音音符；在秘鲁东南部山脚下的鸟儿又有所不同。这些区域性的鸣叫差异的意义尚未研究，但可能值得探究，因为它们的显著差异暗示着某种形式的声学隔离可能正在发生。","habits":"广泛出现在湿润和潮湿的森林、森林边界、林间空地、倒木处以及潮湿空地上的散生树木中。在安第斯山脉，也见于前山和高山雨林（云雾林），以及沿林木边缘和荫蔽的种植园。在亚马逊地区，既可见于泛滥平原森林，也可见于内陆高地森林，至少在某些地区（如秘鲁的洛雷托）主要生活在森林或较老的次生林中，较少在开阔地带，河岛和年轻河岸植被中稀少或不存在。海拔分布范围在委内瑞拉限制在丘陵和山区，主要在沿海山脉900-1500米之间，其他地方350-2250米；在哥伦比亚，海拔范围从太平洋沿岸的海平面到超过30米的山脉（东北哥伦比亚主要是1300-2100米），在厄瓜多尔，位于安第斯山脉两侧的低地和局部至少达到1500米；在秘鲁，出现在亚马逊低地，以及安第斯山脉东坡至约2000米；在西亚马逊巴西低地广泛分布；巴西东部海岸和山脉局部从巴伊亚南至里约热内卢。主要以水果和浆果为食，也会摄取一些昆虫和蜘蛛。通常成对出现，几乎所有地区的成对个体都是森林树冠或上层混合物种群的常规成员，偶尔会低至地面；在低地森林中主要在树冠活动，但沿森林边界会定期降至较低位置；在安第斯山脉常在较低水平觅食。","breeding":"在哥伦比亚，11月至4月期间观察到七个巢穴，5月至7月在佩里哈山脉发现处于繁殖状态的鸟；在秘鲁中部（帕斯科），11月观察到成鸟喂养幼鸟，而在厄瓜多尔西南部（埃尔奥罗；洛哈）两个地点，2月中旬至3月初观察到离巢的幼鸟。巢为带有侧入口的草和苔藓搭建的穹顶状结构，通常距离地面几米。雄鸟可能在亚成年（主要是绿色）的羽毛状态下繁殖。没有更多繁殖信息。","identification":"雄性橙腹歌雀与其他歌雀属物种的区别在于其黄色的帽和深色的喉，以及略带橙黄色的腹部。雌鸟与其他歌雀属物种极难区分，但通常成对或小群体出现，伴随雄鸟，这有助于识别。","protection":"IUCN：LC（无危）。橙腹歌雀在安第斯山脉以西和亚马逊低地广泛分布且普遍常见。它存在于许多保护区中，也在许多看似短期内不受威胁的未受保护地点被发现。巴西东南部分布的孤立指名亚种所在的区域现已被严重砍伐；这一种群应受到密切监控。","distribution":"分布于远东巴拿马至秘鲁西北部的跨安第斯山脉区域；委内瑞拉顺安第斯山脉至玻利维亚中部和巴西西部；巴西东南部的零散分布。","other":"黑喉歌雀（Euphonia vittata）现在被认为是由橙腹歌雀和栗腹歌雀杂交产生的。"},{"name":"棕腹歌雀","english_name":"Rufous-bellied Euphonia","scientific_name":"Euphonia rufiventris","overview":"棕腹歌雀（英文名：Rufous-bellied Euphonia，学名：Euphonia rufiventris），是雀形目燕雀科歌雀属的小型鸟类。分布于南美洲的低地雨林，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉。其自然栖息地位于亚热带或热带湿润的低地森林。","appearance":"雄性棕腹歌雀呈现光泽的深蓝色外观，腹部为醒目的红橙色，这一特征在其分布范围内相当独特。雌鸟则呈金色，头部、背部和腹部带有灰色调，尾下覆羽橙红色。雌鸟的尾下覆羽颜色通常比橙腹歌雀更深，不呈黄色。","call":"常能听到它们快速而深沉的连续鸣叫，声音类似“chree-chree-chree-chree”。","habits":"生活在湿润的森林环境中，是当地最常见的歌雀之一。它们的活动范围主要集中在亚热带或热带湿润的低地森林。","identification":"与橙腹歌雀雌鸟相似，但棕腹歌雀的尾下覆羽颜色更深，通常是橙色或红色，而非黄色。","distribution":"分布于南美洲的奥里诺科河流域南部，以及西部和中部亚马逊地区。"},{"name":"栗腹歌雀","english_name":"Chestnut-bellied Euphonia","scientific_name":"Euphonia pectoralis","overview":"栗腹歌雀（英文名：Chestnut-bellied Euphonia，学名：Euphonia pectoralis），是雀形目燕雀科歌雀属的小型鸟类。雄鸟具有独特的金属蓝头部至胸部和全身上部，下腹部呈深栗色，肩部金黄色；雌鸟则主要是橄榄绿色，冠部灰色，喉部和腹部中央也是灰色，两胁和侧腹部黄橄榄色，下腹部和尾下覆羽暗赤褐色。分布于南美东部，包括巴拉圭东部、巴西中部和东南部以及阿根廷东北部。","appearance":"体长约11厘米，体重15至16.5克。雄鸟拥有光泽金属蓝色的头至胸及整个上体，包括翼上覆羽，飞羽和尾部暗淡，边缘和金属蓝色调（初级飞羽较少）。下腹部和下部呈深栗色，除金属蓝色大腿外，常有突出的金色胸部羽毛簇。雌鸟前额冠暗黄，其余冠部至颈背中央灰色，上体橄榄色；下体大部分灰色，两侧和侧腹黄橄榄色，臀部和尾下覆羽深赤褐色。","call":"发出一系列低沉的粗哑颤音，‘j’a’a’a’a, j’a’a’a’a, j’a’a’a’a...’，节奏较慢，类似棕腹歌雀的叫声。","habits":"生活在湿润森林的树冠层，沿森林边界和树散的开阔地带。觅食小果实，包括梅拉斯特姆、寄生植物、寄生仙人掌、Cecropia、棕榈和茄属植物的果实，也观察到其捕食树皮表面的小节肢动物。通常单独、成对或以小群体出现，常与混合物种群一起活动。觅食高度从中层到树冠，经常在开阔处停歇，如Cecropia树，活跃且容易被看到。","breeding":"繁殖报告在1月于巴西东南部（里约热内卢）和8月在巴拉圭。筑造类似同类的圆顶形巢，有小侧入口，由苔藓和蕨类植物制成，距地面约2米或略高，隐蔽在树干侧面，悬根中的附生蕨类植物中，或大枝上的附生植物中，或灌木的树枝中；两个巢穴位于陡峭河岸的壁龛中。一巢含3枚卵。无其他信息。","identification":"雄鸟与棕腹歌雀主要通过颜色更深，尤其是下腹部来区分。雌鸟前额暗黄，其余冠部至颈背中央灰色，上体橄榄色，下体大部分灰色，两侧和侧腹黄橄榄色，臀部和尾下覆羽深赤褐色。","protection":"IUCN：LC（无危）。在巴西东南部、阿根廷东北极端和巴拉圭东部相对常见和广泛分布。虽然在其分布范围内森林砍伐严重，但在剩余森林中数量众多。出现在多个保护区，如伊瓜苏国家公园（阿根廷）和相邻的伊瓜苏国家公园（巴西），以及Itatiaia、Serra dos Órgãos和Tijuca国家公园，Augusto Ruschi（Nova Lombardia）生物保护区和其他沿海大西洋山脉的保护区。","distribution":"分布于南美东部，包括巴拉圭东部，巴西中部和东南部和阿根廷东北部。","other":"黑喉歌雀（\"Euphonia vittata\"）现被认为是由栗腹歌雀和橙腹歌雀杂交产生。"},{"name":"金胁歌雀","english_name":"Golden-sided Euphonia","scientific_name":"Euphonia cayennensis","overview":"金胁歌雀（英文名：Golden-sided Euphonia，学名：Euphonia cayennensis），是雀形目燕雀科歌雀属的鸟类。体型较小的森林冠层鸟类，主要分布在南美洲亚马逊雨林北部区域，包括委内瑞拉东南部、圭亚那地区和巴西东北部。","appearance":"雄鸟通常全身呈现黑色，两侧胸部有金色羽簇，这一特征虽诊断性强，但观察起来较为困难。雌鸟背部为绿色，腹部广泛覆盖灰色。雌鸟与白眉歌雀相似，但外观更整洁，下体覆羽为灰色而非黄色，雄鸟的存在有助于雌鸟的识别。","call":"最常见的是其响亮、刺耳的喋喋不休叫声，一旦熟悉，这种叫声便极具辨识度。","habits":"金胁歌雀以果实为食，常跟随混合物种群落移动，可能会从隐蔽的栖木上反复鸣叫，然后飞向远处的另一棵树。","breeding":"具体繁殖细节未详述。","identification":"雄性金胁歌雀独特的金色胸侧羽簇和雌鸟的清洁外观及灰色下体覆羽，使其易于与类似物种区分。","protection":"IUCN状态未知。","distribution":"分布于南美洲北部亚马逊地区，包括委内瑞拉东南部、圭亚那、苏里南、法属圭亚那和巴西东北部。","other":"该物种分类学上归于Euphonia属，由Desmarest于1806年引入，目前认为无亚种分化。"},{"name":"墨西哥歌雀","english_name":"West Mexican Euphonia","scientific_name":"Euphonia godmani","overview":"墨西哥歌雀（英文名：West Mexican Euphonia，学名：Euphonia godmani），是雀形目燕雀科歌雀属的鸟类。为墨西哥西部特有种。雄鸟具有蓝黑色头部、上体和胸部，前额黄色，其余下体鲜黄，雌鸟颜色较为暗淡，下体呈淡黄色，上体灰绿。分布于从墨西哥南部索诺拉至瓜纳华托的低地和山脚地带，常见于开阔林地、森林边缘和有树的空旷地。","appearance":"雄鸟特征明显，头部、上体和胸部蓝黑发亮，前额至眼睛处有鲜黄色斑块，其余头部和前颈处呈光泽蓝黑色，带紫晕；上体蓝黑色，中翼覆羽、大覆羽、飞羽及三级飞羽黑色，略带深蓝色光泽；胸部和腹部鲜黄，尾下覆羽白色，翅膀下方覆羽白色；尾巴黑色，最外侧两根尾羽内侧有白色斑点。雌鸟头部橄榄黄色，逐渐变为冠部和颈背的灰色，背部橄榄色带灰色调，侧面头部和大部分下体橄榄黄色，腹中部和尾下覆羽白色，两侧黄色，尾部暗色。幼鸟似雌鸟，但头部橄榄色，可能展示蓝黑色飞羽。","call":"发出一至三个纯薄哨声，‘dee-dee-dee’，有时在同一音高或稍低音高后跟两个或三个哨声；还发出较短的‘whit-it-it-it’和较长的‘whee’。其歌声较少听到，为弱小的叽叽喳喳混合声，例如‘wheetidy-titity-witity-titity’。","habits":"墨西哥歌雀栖息于墨西哥西部干旱热带环境中的半开放、干燥或轻度林木区域，全年经历显著的干湿季节变化。它们主要以水果为食，如槲寄生（Loranthaceae）浆果和其他小果实，偶尔吃昆虫。加入混合群的果食鸟类中。","breeding":"巢穴足球状，侧入口，由草茎、叶柄、叶子碎片、树皮和细根构成，内部铺有菌丝纤维，建于3.5到8米高的水平枝条上，位于树苗分叉处或夹在大型死叶下的分叉中。已知在五月于墨西哥发现带有蛋的巢。","identification":"雄鸟与薮歌雀相似，但薮歌雀尾下覆羽黄色而非白色。雌鸟相比墨西哥歌雀更苍白，腹部中心和尾下覆羽白色，两侧黄色，尾部有更多白色。与紫喉歌雀、黄冠歌雀和特立尼达歌雀有相似的色彩模式，但这些物种都是异域分布。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥西部，从南部索诺拉至中部瓜纳华托，主要栖息于低地和山脚地带，海拔从海平面至约1000米。","other":"曾被认为是薮歌雀的一个亚种，但基于遗传和形态差异，现已被确认为独立物种。"},{"name":"亮丽歌雀","english_name":"Elegant Euphonia","scientific_name":"Chlorophonia elegantissima","overview":"亮丽歌雀（英文名：Elegant Euphonia，学名：Chlorophonia elegantissima），是雀形目燕雀科绿雀属的鸟类。小型而优雅的雀科鸟类，分布于中美洲的墨西哥至巴拿马西部，包括中美洲各国。其别称蓝帽歌雀，来源于其独特的蓝色头部特征。","appearance":"亮丽歌雀体型小巧，约10厘米长，体重13至17克。雄鸟具有深锈色的下体，黑色喉咙，以及醒目的天蓝色头冠和额部；雌鸟整体呈绿色，同样拥有天蓝色头冠和锈色前额。幼鸟类似雌鸟，雄鸟幼鸟有肉桂色的下巴和对比明显的蓝黑色飞羽。不同亚种间存在色彩上的细微差异。","call":"鸣唱为一连串快速的颤音、泡泡般的音符、口哨声和叽叽喳喳的声音，以游荡的方式发出。叫声包括多种芦苇般的和清脆的音调，有些尖锐，有些柔和。","habits":"生活在从湿润的松栎林到农田中的灌木篱笆等各种环境中，常见于寄生植物的栖息地。在繁殖季节，通常成对或小群活动，非繁殖季节会下降到更低海拔。主要食物是小软果，尤其是寄生植物的果实。栖息地包括开放的松栎林、橡树灌丛、常绿阔叶林边缘和种植园。","breeding":"关于繁殖季节的数据不足。巢呈圆形或球形，侧面入口，由细根和干草茎精心编织而成，内衬更细的草。巢高可达18米，位于陡峭河岸的凹龛、苔藓、空气凤梨或寄生植物上。每窝产3枚蛋，乳白色，带有棕色或紫色斑点。","identification":"雄性亮丽歌雀的深锈色下体和天蓝色头冠是辨识的关键特征，雌鸟则以其绿色体羽和蓝色头冠区分。幼鸟和雌鸟的相似性使得区分较为困难。","protection":"IUCN：LC（无危）。在大部分分布区内数量相当普遍，能在各种半开阔或受干扰的山地栖息地中生存，且出现在多个保护区中。","distribution":"分布于中美洲，从墨西哥南部至巴拿马西部，包括中美洲各国。主要栖息于1000至2500米的海拔，但在特定时期会下降至更低高度。"},{"name":"金腰歌雀","english_name":"Golden-rumped Euphonia","scientific_name":"Chlorophonia cyanocephala","overview":"金腰歌雀（英文名：Golden-rumped Euphonia，学名：Chlorophonia cyanocephala），是雀形目燕雀科绿雀属的小型鸟类。原分类在Euphonia属下，现基于系统发育证据归入Chlorophonia属。其分布广泛，包括南美洲多个国家和地区，如阿根廷、玻利维亚、巴西东南部、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、巴拉圭、秘鲁、苏里南、特立尼达和多巴哥、委内瑞拉。","appearance":"体长约11厘米，体重15-16克。雄鸟具有天蓝色的冠羽和颈背，深色喉咙，橙黄色腹部。雌鸟整体较暗，橄榄黄色，但保留了标志性的蓝色冠羽和颈背。两性皆有金色臀部。幼鸟外观与雌鸟相似，但更为暗淡。","call":"歌声快速而复杂，由一系列叽叽喳喳和尖细音符组成，夹杂低沉的‘chup’声。叫声为柔和的吹口哨声‘cheeer’，略有下降趋势，有时连续重复数次。","habits":"栖息于开阔森林、边缘地带和花园，可能进行局部游荡和季节性迁移到较低海拔。主要以果实为食，偶尔捕食昆虫。常在大丛的寄生植物上觅食，保持相对安静，偶尔加入混合物种群。","breeding":"繁殖期在1月至2月的委内瑞拉，哥伦比亚则在4月至5月，以及12月至5月间发现处于繁殖状态的个体。巢呈球状，有侧面入口，藏于路边或树干上，高度4-8米。每窝产2枚蛋，颜色为奶油色，带有浅红棕色和黑色斑点。","identification":"雄性金腰歌雀的天蓝色冠羽和明亮的金色臀部是显著特征。雌鸟和幼鸟较暗，但仍可见到蓝色冠羽，金色臀部帮助识别。","protection":"IUCN：LC（无危）。在一些地区，如巴西东南部和阿根廷东北部，由于严重森林砍伐，依赖现有保护区生存。","distribution":"分布于南美洲北部，从哥伦比亚到特立尼达和圭亚那，以及安第斯山脉至玻利维亚和阿根廷西北部，巴西东南部，巴拉圭东部和阿根廷东北部。","other":"在多个受保护区域内被发现，适应多种栖息环境，包括森林边缘和人类改造的环境。"},{"name":"蓝头歌雀","english_name":"Hispaniolan Euphonia","scientific_name":"Chlorophonia musica","overview":"蓝头歌雀（英文名：Hispaniolan Euphonia，学名：Chlorophonia musica），是雀形目燕雀科绿雀属的鸟类。仅分布在加勒比海的Hispaniola岛上，包括多米尼加共和国和海地。这种小鸟以其明亮的色彩和活泼的特性著称，雄鸟拥有蓝色的头盔、亮丽的橙色腹部、深色的脸颊和喉咙，以及深紫色闪亮的上半身。雌鸟整体呈橄榄绿色，头部和颈后部有淡蓝色，额头有独特的蓝色头盔和小块橙色。蓝头歌雀主要栖息于茂密的林地，以中上层的植物果实为食，尤其是槲寄生浆果。","appearance":"蓝头歌雀是一种小型鸟类，体型娇小，喙短而厚实，两性异形明显。雄鸟的脸侧、耳羽、下巴和喉咙为黑紫，额部有一小片淡黄色，头顶和颈后部为闪亮的天蓝色，背部黑色带有深蓝色光泽，臀部和尾羽覆羽为丰富的橙黄色。雌鸟头部和颈后部为淡蓝色，整体橄榄绿色，喉部黄色逐渐过渡至橄榄黄色胸腹。喙和脚为黑色。","call":"蓝头歌雀的叫声包括单个或连续的活泼‘哔’声，快速的‘whip-ip’声，粗糙的‘djip’声，以及哀怨的‘wheee’声。其歌声是一连串急促的叮当声、尖叫声和口哨音的混合。","habits":"蓝头歌雀居住于密集的林地中，活跃于中上层树冠，以槲寄生浆果为主食。它们有时会加入混合鸟群。尽管颜色鲜艳，但因其小巧的身形和快速的移动，容易被忽视。","breeding":"蓝头歌雀的繁殖行为细节尚需更多研究，但可能与同属的其他物种相似，涉及营巢、交配和育雏等活动。","identification":"蓝头歌雀与亮丽歌雀（E. elegantissima）和金腰歌雀（E. cyanocephala）非常相似，但后两者仅限于中美洲和南美洲大陆。与波多黎各歌雀相比，蓝头歌雀具有橙黄色下体和臀部（而非黄色），黑色喉咙（而非鲜黄色），皇家蓝色头顶和颈后部（而非粉末蓝），以及深紫色的背翼光泽（而非钢蓝色）。","protection":"IUCN：LC（无危）","distribution":"蓝头歌雀仅分布于加勒比海的Hispaniola岛，覆盖多米尼加共和国和海地，栖息于亚热带或热带的干燥森林、湿润低地森林以及重度退化的前森林区域。","other":"历史上，蓝头歌雀曾被认为与波多黎各歌雀和小蓝头歌雀同种，但现在被视为独立物种。"},{"name":"黄领绿雀","english_name":"Yellow-collared Chlorophonia","scientific_name":"Chlorophonia flavirostris","overview":"黄领绿雀（英文名：Yellow-collared Chlorophonia，学名：Chlorophonia flavirostris），是雀形目燕雀科绿雀属的小型鸟类。分布于南美的巴拿马远南部、哥伦比亚西部和厄瓜多尔西北部，栖息于湿润的山脚和亚热带森林地带。","appearance":"雄性黄领绿雀全身以鲜艳的酸橙绿色为主，腹部和颈部环绕着明亮的黄色环带，具有鲑鱼色的喙和腿，眼色淡，颈部两侧有栗色标记。雌鸟颜色较暗淡，全身大致呈草绿色，腹部黄色，胸部逐渐变为黄色，喙和眼圈颜色较雄鸟暗淡。幼鸟类似雌鸟，但裸露部分更暗淡。","call":"在觅食时发出柔和的“pek”声，飞行中或偶尔站立时会发出连续重复的哀婉‘peeeeeeeee’叫声，还有一种可能作为歌唱的弱小喋喋不休的声音。","habits":"主要以小浆果和果实为食，如无花果和Miconia浆果，偶尔捕食昆虫。常成对或小群体（3-7只）活动，有时加入混种群鸟群，偏好高大树木树冠，觅食高度约14米，动作敏捷而从容，跳跃寻找小浆果。","identification":"雄鸟以其独特的黄绿色搭配和黄色颈环易于识别，雌鸟和幼鸟颜色较为单一，但通过其特有的绿色和黄色组合仍能区分。","protection":"IUCN状态未知，未列入华盛顿公约CITES或中国国家重点保护野生动物名录。","distribution":"分布于南美洲，包括巴拿马的极东南部，哥伦比亚的西部以及厄瓜多尔的西北部。","other":"该物种具有季节性的迁徙行为，可能在某个地区常见，然后消失数月。"},{"name":"蓝枕绿雀","english_name":"Blue-naped Chlorophonia","scientific_name":"Chlorophonia cyanea","overview":"蓝枕绿雀（英文名：Blue-naped Chlorophonia，学名：Chlorophonia cyanea），是雀形目燕雀科绿雀属的色彩鲜艳的鸟类。雄鸟上体展现更多的蓝色，而雌鸟的下体则呈现出更多的黄绿色。其分布区域广泛，覆盖了南美洲的多个重要生态区域。","appearance":"蓝枕绿雀是一种体型小巧、体态丰满的鸟，拥有粗壮的喙。雄鸟以鲜亮的翠绿色为主调，腹部为鲜明的黄色，颈部有细窄的钴蓝色颈环，臀部呈蓝色；某些群体的雄鸟上体几乎全蓝。雌鸟颜色较为暗淡，以绿色为主，腹部略带绿黄色，颈环蓝色较淡。幼鸟与雌鸟相似，可能缺少蓝色颈环。成年雄鸟的额头基部为黄色，背部绿色，颈后和臀部蓝色；雌鸟下体为金色橄榄色。","call":"蓝枕绿雀的叫声包括柔和的鼻音“ek”或“enk”声，主要用于栖息或觅食时的联系。还有一种哀怨的‘pleeeeee’声，尤其是在觅食时或起飞前发出，类似Euphonia cyanocephala的叫声。其他叫声包括鼻音的‘peent’和短促的沙哑咔哒声。歌声在所有地区都是一系列急促而不甚悦耳的叫声，液态的哨声，柔和的音符和尖锐或啪嗒啪嗒的音符。","habits":"蓝枕绿雀通常成对或小群出现，最常见的是家庭群体或约十只左右的小群体。它们主要在中间层到树冠高处觅食，大部分时间相对静止，偶尔发出柔和的叫声。它们会花费长时间在槲寄生丛中，活动范围不大；有时也会跟随混合物种的鸟群，如Tangara和其他唐纳鸟。它们主要以各种小浆果为食，尤其是Miconia的果实，在Paraguay则以Allophyllus edulis的果实为主食。","breeding":"在哥伦比亚，观察到蓝枕绿雀在五月筑巢，一月和六月观察到巢建活动，五月和七月发现四只正在乞食的幼鸟，四月和五月有十二只处于繁殖状态的鸟。在秘鲁中部十一月也有巢建记录。它们的巢是草质球形，侧面入口，位于垂直岩壁或悬崖的裂缝中。每窝产3枚蛋，白色，散布着栗色斑点，大端较多。雏鸟通过反刍喂养。","identification":"蓝枕绿雀与其他绿雀属物种的区别在于雄鸟的蓝色颈环和臀部，以及雌鸟的金色橄榄色下体。不同亚种之间可以通过额头基部的颜色、背部颜色以及下体颜色的差异来辨识。","protection":"IUCN：LC（无危）。蓝枕绿雀在南美的山地地区分布广泛，虽然分布有些零散，数量变化不定。它出现在各国众多的保护区中。物种的分布范围内有大量的完好栖息地，尽管不受保护，但在可预见的未来风险相对较小。安第斯山脉和大西洋沿海地区的森林砍伐是对该物种的最大威胁。在巴西东南部，该物种存在于多个保护区，如Augusto Ruschi（Nova Lombardia）生物保护区和Itatiaia、Tijuca和Iguaçu国家公园，但该地区保护区外可供该物种利用的栖息地相对较少。","distribution":"蓝枕绿雀的分布区高度分散，与大西洋森林在巴西东南部、巴拉圭东部和阿根廷东北部有关联，以及从玻利维亚南部到委内瑞拉北部的安第斯山脉，特普伊山脉，委内瑞拉南部，圭亚那远西部和巴西远北部。所有种群都与湿润森林相关联，但在大西洋森林地区，它也会出现在附近的花园和公园中。","other":"蓝枕绿雀曾被归类于裸鼻雀科，但现在被归类于Fringillidae科。"},{"name":"栗胸绿雀","english_name":"Chestnut-breasted Chlorophonia","scientific_name":"Chlorophonia pyrrhophrys","overview":"栗胸绿雀（英文名：Chestnut-breasted Chlorophonia，学名：Chlorophonia pyrrhophrys），是雀形目燕雀科绿雀属的鸟类。以及蓝色的冠羽为显著特征。分布于南美洲安第斯山脉，从委内瑞拉中部至秘鲁中部。","appearance":"雄性栗胸绿雀具有引人注目的外观，其腹部为栗色，两侧呈黄色，胸部和面部覆盖着绿色羽毛，而头顶则为亮丽的蓝色。雌鸟则主要为绿色，带有蓝色的冠羽和锈红色的眉纹。它们的喙粗壮，体态丰盈，是这一物种的显著特征。","habits":"栗胸绿雀通常在安第斯云雾森林中成对出现，它们偏好在树冠层活动，偶尔会下降到较低的位置，尤其是在果实丰富的树木上觅食。它们的叫声独特，类似于喷溅声，与大多数其他绿雀不同。","identification":"与同属其他物种相比，栗胸绿雀的蓝色冠羽和栗色腹部是最明显的辨识特征。雌雄两性的色彩差异也帮助区分不同性别。","distribution":"栗胸绿雀分布于南美洲的安第斯山脉，具体范围从委内瑞拉的Sierra de Perijá，向南延伸至哥伦比亚、厄瓜多尔，直至秘鲁中部的东坡。在委内瑞拉西部、哥伦比亚西部和中部山脉、厄瓜多尔西部坡地至皮钦查省，以及东部坡地局部至洛哈省，以及秘鲁北部至华努科省都有其踪迹。"},{"name":"蓝冠绿雀","english_name":"Blue-crowned Chlorophonia","scientific_name":"Chlorophonia occipitalis","overview":"蓝冠绿雀（英文名：Blue-crowned Chlorophonia，学名：Chlorophonia occipitalis），是雀形目燕雀科绿雀属的小型鸟类。分布于中美洲，从墨西哥至尼加拉瓜，常见于高海拔的常绿森林。","appearance":"蓝冠绿雀体型紧凑，全身呈现鲜艳的翡翠绿色。其腹部为明亮的黄色，喙部短小。最显著的特征是头顶的蓝色冠羽，但在观察时往往难以察觉，尤其是当它们位于树冠层活动时。","habits":"通常成对或小群体活动，偏好在果实丰富的树木和灌木丛中觅食，主要栖息于热带湿润山地森林的树冠层。","identification":"与相似的绿雀相比，蓝冠绿雀的蓝冠斑块更加明显，尽管在观察时可能不易看到。绿雀在同一地区的出现增加了辨识难度。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，具体包括墨西哥至尼加拉瓜的繁殖区域。主要栖息地为墨西哥至尼加拉瓜的热带湿润山地森林。"},{"name":"金眉绿雀","english_name":"Golden-browed Chlorophonia","scientific_name":"Chlorophonia callophrys","overview":"金眉绿雀（英文名：Golden-browed Chlorophonia，学名：Chlorophonia callophrys），是雀形目燕雀科绿雀属的鸟类。小型、体态丰满且紧凑的鸟类，在中美洲的山林间，如哥斯达黎加和巴拿马的高海拔森林中，可以发现它们的身影。通常以绿色为主调，雄鸟具有醒目的黄色眉毛和蓝色帽状羽冠。","appearance":"金眉绿雀的雄鸟和雌鸟都呈现出明亮的绿色上体，黄色腹部，以及蓝紫色的头部顶冠。雄鸟的显著特征是其宽阔的金色眉毛条纹，而雌鸟则在眉毛和胸部的绿色替代了雄鸟的金色和黄色。平均长度约为13厘米（5.1英寸），体型小巧玲珑。","call":"它们拥有柔和的哨声鸣叫，常被描述为'wheeeeuuu'，这是识别它们的一个关键特征。","habits":"金眉绿雀偏好生活在海拔750米（2460英尺）以上的亚热带或热带湿润山地森林中，常见于成对或小群体活动，特别是在果实丰富的树木附近。它们在森林的各个层次中觅食，尤其偏爱树冠层。","breeding":"关于金眉绿雀的繁殖细节资料有限，但它们通常在适宜的季节内进行繁殖活动，包括筑巢、产卵和育雏。","identification":"金眉绿雀在其分布范围内是独特的，主要通过其鲜明的色彩和雄鸟特有的金色眉毛来与其他鸟类区分开来。","protection":"IUCN：LC（无危）","distribution":"主要分布在中美洲的哥斯达黎加和巴拿马的山区。","other":"在哥斯达黎加，金眉绿雀有一个民间传说，讲述它曾为了阻止一位年轻女子的牺牲，将自己美妙的歌声献给了波阿斯火山，从而平息了火山的爆发，保护了当地居民的安全。"},{"name":"波多黎各歌雀","english_name":"Puerto Rican Euphonia","scientific_name":"Chlorophonia sclateri","overview":"波多黎各歌雀（英文名：Puerto Rican Euphonia，学名：Chlorophonia sclateri），是雀形目燕雀科绿雀属的独特鸟类，主要分布于波多黎各的多种生境中，包括低地干燥森林、灌木丛及遮荫咖啡种植园。其鲜艳的色彩与活跃的行为使其在密集的林地中显得格外醒目。","appearance":"雄性波多黎各歌雀拥有蓝色的头盔，黄色的下体，包括喉咙部分，以及一张独特的黑色面罩。雌鸟整体呈橄榄绿色，头部两侧有蓝色头盔，前额有一小块黄色斑点。雄鸟具有橙黄的前额，蓝色的冠羽覆盖头顶至颈背，侧面头部暗蓝近黑，上体黑色带蓝光，臀部与尾羽上覆羽鲜黄。雌鸟整体橄榄绿，下体黄橄榄色渐深，前额红黄或黄橄榄绿。","call":"波多黎各歌雀的叫声包括一系列生动的‘beep’声，快速的‘whip-ip’声，粗糙的‘djip’声，以及哀婉的‘wheee’声。其歌声是一串快速混合的叮当声、尖叫声和哨音。","habits":"波多黎各歌雀栖息于包括Tabonuco森林、Palo Colorado森林、棕榈森林和Elfin Woodland在内的多种生境。它们通常在树冠层活动，但在森林边缘和干扰区域也会下降到较低层次。它们广泛分布于各种海拔高度，偏好有槲寄生（Loranthaceae）的地方。","identification":"在有限的分布范围内，波多黎各歌雀的识别不会与其它物种混淆。它与其它蓝帽绿雀属（Chlorophonia）物种相似，尤其是最近被认为同种的两个西印度群岛物种。与海地歌雀相比，它的下体和臀部更亮黄，喉部黄色而非黑色，冠羽和颈背天蓝而非宝蓝，背部和翅膀的光泽蓝钢而非深紫。","protection":"IUCN状态未提及。","distribution":"波多黎各歌雀的分布主要集中在波多黎各，包括低地干燥森林、灌木丛、遮荫咖啡种植园以及多个特有森林类型。"},{"name":"小蓝头歌雀","english_name":"Lesser Antillean Euphonia","scientific_name":"Chlorophonia flavifrons","overview":"小蓝头歌雀（英文名：Lesser Antillean Euphonia，学名：Chlorophonia flavifrons），是雀形目燕雀科绿雀属的鸟类。头顶、颈侧和颈背呈天蓝色，额头有一小块黄色斑点，与雄鸟相比更统一。其鸣叫声包括活泼的‘哔’声、快速的‘鞭-伊普’声、粗糙的‘吉普’声和哀怨的‘呼’声。","appearance":"小蓝头歌雀体型小巧，喙短而厚。雄鸟特征明显，头部蓝色，背部橄榄绿，腹部橄榄黄色，喉咙更为明亮黄色，面罩深色，额头至颈背天蓝色。雌鸟整体橄榄绿色，头顶、颈侧和颈背天蓝色，额头有黄色斑点，与雄鸟相似但颜色更加统一。喙黑色，脚灰色。","call":"鸣叫声多样，包括活泼的单个或连续‘哔’声、快速的‘鞭-伊普’声、粗糙的‘吉普’声以及哀怨的‘呼’声。其歌曲是一系列叮当、尖锐和口哨音符的快速组合。","habits":"栖息于密集的森林地带，主要在中上层活动，以槲寄生浆果为主食。偶尔加入混合鸟群。尽管色彩鲜艳，但因其活跃的动作容易被忽视。","breeding":"具体繁殖信息未提供。","identification":"与同属的‘蓝头’绿雀相似，但具有绿色下部（而非黄色）、淡黄色或黄色喉部（而非黑色）、明亮的黄色前额（而非橙色）、瓶绿色肩部、背部和翅膀（而非闪亮的钢蓝色）、小而暗淡的黄绿色臀部斑点（而非鲜亮的黄橙色）。尾巴比波多黎各绿雀长，喙比海地绿雀长。","protection":"IUCN：LC（无危）","distribution":"分布于小安的列斯群岛的多个岛屿，包括巴布达、安提瓜、瓜德罗普、拉迪塞拉德、多米尼加、马提尼克、圣卢西亚、圣文森特和格林纳达。在北美，仅限于上述群岛。","other":"历史上曾被报道在巴布达存在，但直接证据缺失，可能已从某些岛屿消失。"},{"name":"麦氏铁爪鹀","english_name":"Thick-billed Longspur","scientific_name":"Rhynchophanes mccownii","overview":"麦氏铁爪鹀（英文名：Thick-billed Longspur，学名：Rhynchophanes mccownii），是雀形目铁爪鹀科麦氏铁爪鹀属的鸟类。仅存于北美大陆，以平原地带为生。其最显著的特征是厚实的喙和肩部的锈色斑块。繁殖季节雄鸟呈灰黑相间的头部图案，黑色胸甲和白色喉部，雌鸟及非繁殖期个体则更为朴素，整体淡黄褐色，头顶和背部略带灰色，喙粉红。分布于加拿大中南部至美国中北部的短草草原。","appearance":"麦氏铁爪鹀是一种体型类似麻雀的地面栖息者，蹲伏低矮，行走时脚步轻快。雄鸟繁殖季节羽毛呈现灰色，头部有鲜明的图案，黑色胸部和肩部带有锈色斑块。雌鸟和非繁殖期个体颜色较为低调，全身呈淡黄色调，颈部偏灰色，喙厚且呈粉色，腹部无条纹。飞行时，尾巴几乎全白，比栗领铁爪鹀更加明显。","call":"麦氏铁爪鹀的鸣叫特征包括了干涩的颤音，不同于其他长趾鹀的‘tew’声，也不似栗领铁爪鹀独特的‘queedle’叫声。","habits":"麦氏铁爪鹀偏好开阔的风扫平原和稀疏植被，栖息于北美的短草草原或过度放牧的牧场。它们在四月抵达繁殖地，即大平原西北边缘和加拿大草原省份的南部边界，通过空中展示建立领地。冬季，它们会迁移到美国西南部、德克萨斯州和墨西哥北部的相似短草环境。","breeding":"麦氏铁爪鹀在繁殖季节，雌鸟会在地面的浅坑中筑巢，靠近仙人掌垫、草丛或灌木下。每次产卵2到5枚，孵化期约12天，双亲共同喂养和照顾雏鸟。幼鸟在约10天后离巢，尚未完全学会飞行。","identification":"麦氏铁爪鹀与栗领铁爪鹀最为相似，但可通过更淡的喙色、较短的翼展和尾羽的‘T’形黑白图案加以区分。此外，麦氏铁爪鹀的雄鸟在繁殖季节下的胸部和腹部仍保留一些暗色斑点。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北美中部，包括加拿大中南部和美国中北部。非繁殖期分布至墨西哥北部。","other":"人类活动的干扰，如耕作、农药使用和控制草原火灾，已导致麦氏铁爪鹀数量和分布区域的减少。"},{"name":"铁爪鹀","english_name":"Lapland Longspur","scientific_name":"Calcarius lapponicus","overview":"铁爪鹀（英文名：Lapland Longspur，学名：Calcarius lapponicus），是雀形目铁爪鹀科铁爪鹀属的鸟类。俗名: 铁爪子、铁雀、雪眉子，分布于新旧大陆极北地区的鸟类，模式产地位于欧洲的拉普兰德。以厚实的黄色喙和长后爪著称，夏季雄鸟具黑色头部与喉部、白色的眉纹、栗色颈背以及重叠条纹的黑灰色背部。雌鸟和非繁殖季雄鸟则呈现较平淡的橙棕色头部、棕色背部、栗色颈背和翼板。繁殖于北美、欧亚北部，冬季迁至欧亚中部、美国南部。偏好开阔地带，冬季可见于草地、沼泽地、平原田野及丘陵的稀疏山林。","appearance":"铁爪鹀是一种结实的鸟，喙厚而呈黄色，适于啄食种子。夏季雄鸟拥有黑色头部与喉部，鲜明的白色眉纹，栗色颈背，以及重叠条纹的黑灰色背部。下体白色，背部有密集的黑色条纹。雌鸟和非繁殖季雄鸟则外观较为朴素，头部为橙棕色，背部棕色，颈背和翼板呈现栗色，缺乏雄鸟的黑色头部特征。幼鸟类似非繁殖羽成鸟，但色彩更深沉，条纹更明显，颈背无栗色，胸腹部黄绿色至淡褐色，具有显著的深色条纹，腹部对比明显为白色。","call":"发出尖锐的‘prrrrt’声，通常由更为鼻音的‘teeww’声引导。繁殖季节中，会发出柔和的‘duyyeee’声，随后是一段停顿和‘triiiuuu’声，交替发声。","habits":"栖息于湿润地带的灌木丛或裸露的山地，冬季则迁往农田或海岸地带。常结成大群，游荡不定，被惊扰时飞得较高且远离原位置。以昆虫喂养幼鸟，冬季主要食用草籽、狐尾草籽、栽培小米、马唐草和小麦籽，夏季则以昆虫为主食，偶尔在空中捕捉昆虫，或在恶劣天气下于植被中寻找食物。","breeding":"繁殖于湿地带有桦树或柳树的环境，或裸露的山脉。筑巢于地面，每窝产2-4枚卵。繁殖期为6月至7月，此时食物转为以昆虫为主，以满足幼鸟成长所需的高蛋白需求。","identification":"与其他长脚雀科鸟类相比，铁爪鹀在繁殖羽雄鸟上最为独特，拥有明显的黑色面部、栗色颈背和白色的眉纹。雌鸟和非繁殖羽雄鸟头部为橙棕色，背部棕色，颈背和翼板呈现栗色，与雄鸟形成对比。冬季羽衣中，铁爪鹀保留了脸部图案的痕迹，但失去了色彩块，整体变为浅棕色并带条纹。尾部暗色，外侧尾羽白色。","protection":"IUCN：LC（无危）","distribution":"繁殖区遍布北美、欧亚北部，冬季迁徙至欧亚中部、美国南部，包括俄罗斯的草原、北欧的北极地区，南至瑞典南部沿海、丹麦和英国。","other":"铁爪鹀是唯一一种亚洲的长脚雀科鸟类，尽管可能并非起源于亚洲，但在东欧至少已有约3万年的历史。"},{"name":"黄腹铁爪鹀","english_name":"Smith's Longspur","scientific_name":"Calcarius pictus","overview":"黄腹铁爪鹀（英文名：Smith's Longspur，学名：Calcarius pictus），是雀形目铁爪鹀科铁爪鹀属的独特鸟类。其最显著的特征是雄鸟在繁殖季节呈现出深黄色至橙色的腹部和颈部，头部则以黑白相间的图案装饰。分布于北美地区的北极苔原地带，冬季则迁徙至美国中南部的开阔草地。此物种展现出不寻常的多配偶制社会繁殖系统，每只雌鸟与两到三只雄鸟配对，同时每只雄鸟也与多只雌鸟形成关系。","appearance":"中等体型，长度约15-17厘米，体重20-32克。雄鸟在繁殖季节具有鲜艳的外观，胸腹部、颈背呈现丰富的淡黄色，头部黑白分明，形成小而醒目的白色耳斑；肩部有由中间覆羽构成的小白色肩饰。雌鸟和非繁殖季节的鸟儿颜色较为暗淡，呈淡黄色，胸部和两侧有条纹，头部缺少雄鸟的黑白色图案。所有个体的外侧两根尾羽几乎全白。喙短而锥形，但比其他铁爪鹀种类的喙更窄。","call":"发出干燥的咔嗒声，类似于缩短版的雌鸟棕头牛鹂叫声，但比铁爪鹀的叫声更加干涩。","habits":"栖息于北极树线附近的开阔草地，冬季聚集于美国中南部的开阔田野，包括机场。迁徙路线呈椭圆形，春季北迁时会在伊利诺伊州停留，秋季南迁时飞越大平原。它们主要以种子为食，夏季会补充昆虫。","breeding":"以小型群落形式筑巢，雄鸟不守卫领地。雌鸟在地面的草丛中产下3至5枚蛋。此物种实行多配偶制，一雌一雄或多雄均可参与抚养后代。","identification":"与其他铁爪鹀相比，黄腹铁爪鹀拥有更大的翅膀，相对较长的尾巴，淡黄色的羽毛，以及外侧两根几乎全白的尾羽。成年雄鸟的白色翼盾，位于上翼的中间覆羽，是其独有的特征。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于美国阿拉斯加州北部和加拿大，以及美国阿拉斯加州东南部和加拿大西部。非繁殖区域则在美国中南部。","other":"黄腹铁爪鹀展现了极为特殊的繁殖系统，雌鸟与多只雄鸟交配，每只雄鸟也与多只雌鸟形成关系，这种行为在鸟类中极为罕见。"},{"name":"栗领铁爪鹀","english_name":"Chestnut-collared Longspur","scientific_name":"Calcarius ornatus","overview":"栗领铁爪鹀（英文名：Chestnut-collared Longspur，学名：Calcarius ornatus），是雀形目铁爪鹀科铁爪鹀属的鸟类。拥有黑色腹部、黄色喉部和独特的栗色颈背。主要分布于北美的加拿大中南部和美国中北部的草原地带，冬季迁至美国南部和墨西哥。","appearance":"繁殖季节的雄鸟展现黑腹、黄喉及深栗色颈背，雌鸟和非繁殖季节的个体则以灰褐色为主，背部有模糊条纹，腹部灰白，胸部模糊条纹，耳周有淡色斑点。喙小而灰色，尾部白色为主，中央形成黑色三角形图案。","call":"雄鸟在春季和夏季从显眼的栖木上，如高草、小灌木或围栏线上，发出下降的悦耳鸣唱，类似西方草地鹨的声音。","habits":"它们生活在短草草原，偏好受牧草影响而非修剪或燃烧的草地。冬季，它们出现在沙漠短草丛中，形成多达百只的大群。","breeding":"在浅凹的地面草窝中，雌鸟产下4至5枚卵。雄鸟通过空中鸣唱表演保卫领地。双亲共同喂养雏鸟。","identification":"与麦氏铁爪鹀相比，本种雄鸟的冠羽和胸部为黑色，翼上有锈色条纹。冬季时，与其他铁爪鹀相比，外观更为朴素，尾部的白色和黑色三角形是识别关键。","protection":"IUCN：VU（易危）","distribution":"繁殖区位于加拿大中南部和美国中北部的短草和混合草原；非繁殖区向南延伸至美国南部和墨西哥的沙漠草原。","other":"自1960年代以来，种群数量估计减少了87%以上，部分原因是原生草原的消失。"},{"name":"雪鹀","english_name":"Snow Bunting","scientific_name":"Plectrophenax nivalis","overview":"雪鹀（英文名：Snow Bunting，学名：Plectrophenax nivalis），是雀形目铁爪鹀科雪鹀属的鸟类。俗名: 雪雀、路边雀，亦被称为雪雀或路边雀。广泛分布于欧亚、北美等地极北地区，以及中国黑龙江、吉林、内蒙古、新疆、河北等地。偏好低山区和丘陵地带的开阔区，偶尔可见于平原地区，常见于未完全被雪覆盖的草丛或公路旁。是\"中日候鸟协定\"保护候鸟种类。","appearance":"雪鹀是一种体型较大（17厘米）而矮圆的黑白色鸟类。其嘴形较小，颜色为黑色。繁殖季节，雄鸟整体白色，背部黑色，翼尖黑色，雌鸟背部有黑色翼尖，带有锈色。非繁殖季节，两性背部均呈锈色。春季，雪鹀通过羽毛磨损而非换羽达到繁殖色彩。","call":"雪鹀的叫声为独特的颤音哨声，以及典型的Plectrophenax颤鸣hudidi feet feet feew hudidi。","habits":"雪鹀多栖息于低山丘陵和山脚平原地带，常见于河边岩石、荒山小树林中活动。冬季群栖，但通常不与其他种类混群。步态快速，有时并足跳跃前行。未在取食群中的鸟作蛙跳式前行。群鸟升空作波状起伏的炫耀舞姿飞行然后突然降至地面。以杂草种子、昆虫为食。","breeding":"雪鹀为卵生，营巢于乔木、岩石裂缝和灌丛中，每窝产卵约5枚。卵是蓝绿色的，有棕色的斑点，在12到13天内孵化。幼鸟在12到14天后即可飞行。","identification":"雪鹀与麦氏鹀极为相似，主要区别在于麦氏鹀羽毛更白，翼上白色更多，翼尖对比度较低。雄性麦氏鹀背部较白，第一年略暗，但始终比最淡的雪鹀更亮。","protection":"IUCN：LC（无危）","distribution":"繁殖区：北美、欧亚北部；非繁殖区：地中海、美国南部。","other":"气候变化可能对雪鹀的繁殖时间和食物资源匹配产生负面影响，进而影响幼鸟的成功率。"},{"name":"麦氏鹀","english_name":"McKay's Bunting","scientific_name":"Plectrophenax hyperboreus","overview":"麦氏鹀（英文名：McKay's Bunting，学名：Plectrophenax hyperboreus），是雀形目铁爪鹀科雪鹀属的鸟类。是北美极为罕见且迷人的鸟类之一，仅在白令海中的圣马修岛和霍尔岛繁殖，以其几乎全白的羽毛和黑色翼尖而著称，与近亲雪鹀相似，但更为洁白。由于地理隔离，麦氏鹀被视为独立物种。","appearance":"麦氏鹀是一种中等体型的白色鸣禽，体长18厘米，平均重54.5克。雄鸟繁殖羽几乎纯白，仅翼尖和尾部中央有小面积黑色。雌鸟繁殖羽背部有条纹，冬季两性均呈淡褐色。雄鸟有白色的内侧次级飞羽和初级覆羽，与黑色翼尖形成鲜明对比。雌鸟的内侧次级飞羽为白色，但初级覆羽较暗，尤其是第一年生的，形成较小的白色翼斑。幼鸟整体灰褐色，通过广泛的预成形换羽，在夏末秋初获得成鸟样的羽毛。","habits":"麦氏鹀在砾石海滩的空心漂流木和岩石裂缝中筑巢。冬季栖息于沿海沼泽、砾石海滩和农田。其觅食习性可能与雪鹀类似，冬季以杂草和禾本科植物种子为食，夏季则以种子、芽和昆虫为主食。","identification":"麦氏鹀与雪鹀非常相似，但整体更白，翅膀上有更大的白色斑块和较为有限的对比黑色翼尖。雄性麦氏鹀背部为白色，而雌性麦氏鹀头部顶部和颈背均为白色，背部颜色较浅。在秋季和冬季，雌性麦氏鹀和雄性雪鹀都带有棕色缓冲色，但即使是最暗的麦氏鹀，背部通常也比大多数雪鹀更白，且多数具有全白色的臀部。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美：美国阿拉斯加州西部的圣马修岛和霍尔岛，冬季迁徙至美国阿拉斯加州西部海岸。"},{"name":"鸫唐纳雀","english_name":"Rosy Thrush-tanager","scientific_name":"Rhodinocichla rosea","overview":"鸫唐纳雀（英文名：Rosy Thrush-tanager，学名：Rhodinocichla rosea），是雀形目鸫唐纳雀科鸫唐纳雀属的鸟类。生活在热带低地和较低山脚下的迷人鸟类。拥有简单而美丽的羽毛，丰富的歌唱声，以及独特的分布模式，分布于西墨西哥、哥斯达黎加、巴拿马、哥伦比亚和委内瑞拉等地。雄鸟呈现深灰色上部和鲜艳的玫瑰粉色胸部，雌鸟则具有锈橙色的胸部，两性均具有一条明显的白色眉纹。","appearance":"雄性鸫唐纳雀上部为暗灰色，具有玫瑰红色的喉部、胸部和腹部侧面，以及一条长的粉白色眉纹。雌鸟的相似，但玫瑰红色被替换为温暖的肉桂色。成年雄鸟和雌鸟均长约20厘米，嘴长且略向下弯曲，尾巴宽而圆，腿较长，适合地面活动。幼鸟喉部和胸部带有烟灰色斑点，面部为烟灰色。","call":"鸫唐纳雀发出响亮、丰富且液状的叫声，通常以一对鸟相互呼应的方式鸣叫，其歌曲清脆悦耳，有时会以二重唱的形式呈现。","habits":"这种鸟主要栖息于茂密的灌木林下层，落叶森林和咖啡种植园的阴凉地带，靠近海岸的低密度森林或高灌木丛。它通常单独或成对出现，常在地面上或附近用长喙翻动树叶。尽管体型大且声音响亮，但在密集的低矮植被中观察到它们可能非常困难。","breeding":"关于鸫唐纳雀的繁殖信息有限，但在墨西哥的繁殖期报告在7月，而在哥斯达黎加则在1月至9月之间。具体繁殖行为尚待进一步研究。","identification":"雄性鸫唐纳雀的玫瑰粉色胸部和白色的眉纹使其在同类中独特而醒目。雌鸟的锈橙色胸部也是辨识关键。它们的声音清晰且富有变化，也是区分的重要特征。","protection":"IUCN：LC（无危）","distribution":"鸫唐纳雀分布于中美洲的西墨西哥至南美洲的委内瑞拉，包括哥伦比亚、哥斯达黎加和巴拿马等地。","other":"鸫唐纳雀属于目前单型的Rhodinocichla属，曾归类于裸鼻雀科，后经分子研究表明其与Calcariidae科关系最近。"},{"name":"凤头鹀","english_name":"Crested Bunting","scientific_name":"Emberiza lathami","overview":"凤头鹀（英文名：Crested Bunting，学名：Emberiza lathami），是雀形目鹀科鹀属的鸟类。俗名: 凤头雀，是雀形目鹀科的一种独特鸟类。其最显著的特征是头部的竖立刺状凤冠，体型较大，主要分布于亚洲南部至中国东部的山区草丛和灌木地带。","appearance":"雄性凤头鹀羽毛光泽黑亮，翼部呈鲜艳的栗色，雌鸟则为斑驳的污褐色，翅膀略显暗淡。雄鸟拥有延长的前冠羽毛，可竖立成显著的凤冠；雌鸟的凤冠较短，整体体色为淡橄榄色，胸部条纹明显。幼鸟与雌鸟相似，但凤冠极短且不明显。","call":"凤头鹀的鸣唱简单，由显眼的栖息处开始，先是一连串2-3对音符，起始音低沉嘶哑，随后音调降低，旋律柔和，结尾音节变化多端，可反复吟唱。典型叫声为轻微的“tip”或“tlip”，飞行中更有力。","habits":"凤头鹀栖息于丘陵开阔地和矮草地，活动与觅食主要在地面进行，好动且容易观察。冬季会前往稻田觅食，一般单独或成对活动，偶尔形成小型群体。偏好在道路边缘和烧过的草地中觅食，受惊时会飞向高草或灌木。","breeding":"繁殖季节为5月至8月，雄鸟在岩石或高树上展示凤冠并高声鸣叫后，与雌鸟配对。雌鸟独立筑巢，巢址选择广泛，包括草丛、堤坝洞穴或灌木下，巢呈深杯状，由细草和苔藓编织。每窝产卵4-5枚，卵呈灰白色带褐色斑点。","identification":"凤头鹀的特征性凤冠和深色羽毛使其易于与其他鹀科鸟类区分。雄鸟与雌鸟的颜色差异明显，而幼鸟则与雌鸟相似，但凤冠不发达。","protection":"IUCN：LC（无危）","distribution":"繁殖于亚洲南部至中国东部的山区，包括巴基斯坦东北部、印度中部与中国中部和东南部，以及东南亚北部。非繁殖期可能向较低海拔移动。","other":"凤头鹀的食物以植物性为主，包括谷粒、薯类、杂草种子和少量昆虫。"},{"name":"蓝鹀","english_name":"Slaty Bunting","scientific_name":"Emberiza siemsseni","overview":"蓝鹀（英文名：Slaty Bunting，学名：Emberiza siemsseni），是雀形目鹀科鹀属的小型鸟类。中国特有种。体长约13厘米，重约20克，喙呈圆锥形。雄鸟体羽石蓝灰色，雌鸟棕色。分布于中国中部及东南部山区，偏好海拔1500至2100米的竹林地带。","appearance":"雄鸟全身石板灰蓝色，雌鸟整体呈深棕色至橄榄褐色，两性均有独特的尾羽，尾端较宽，基部渐窄，喙小巧精致。雌雄差异明显，雄鸟腹部白色，雌鸟腹部偏淡，头部脏橙色。幼鸟羽色更显橄榄棕色，边缘略带橄榄褐色，翼上覆羽尖端白色形成细纹。成年个体与幼鸟在羽色上有细微差别。","call":"鸣唱高亢且内容多变，包含类似雀类的乐章和树鹨的片段，常见叫声为尖锐的“zick”或双重音“zick-zick”。","habits":"栖息于亚热带山谷森林中的山地和丘陵，繁殖季节主要位于1500至2100米的竹林附近，冬季会降至500至1700米的低地，接近人类居住区觅食，包括村落和城市公园。以小昆虫和少量植物种子为食，非繁殖季节时小群体活动，取食厨房残渣。","breeding":"繁殖资料有限，已知6月初在四川开始筑巢，可能最早5月就开始。据观察，巢位于河边灌木丛中，距地面约1.5米。每窝产卵大约5枚。","identification":"与灰鹀相似但雄鸟全身石板灰蓝色，雌鸟深棕至橄榄褐色，尾羽仅最外侧一对有白斑，与他种鹀类有别。","protection":"IUCN：LC（无危）。国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）。","distribution":"繁殖区：中国中部，包括甘肃东南部、四川中部及东南部、陕西南部，可能还包括湖北和安徽。非繁殖区：迁徙至中国中部、东南部和东北部较低海拔和受干扰的生境。","other":"蓝鹀为中国特有鸟类，其种群稳定，偏好退化次生林，冬季数量未见显著减少。"},{"name":"黍鹀","english_name":"Corn Bunting","scientific_name":"Emberiza calandra","overview":"黍鹀（英文名：Corn Bunting，学名：Emberiza calandra），是雀形目鹀科鹀属的鸟类。体长约19厘米的大型鹀科鸟类。具有暗灰褐色的羽毛，上面布满了细腻的纵纹。雄雌外观相似，雄鸟体型略大于雌鸟。这种鸟常见于开阔的草地、高山草原、有稀疏灌木的旷野以及耕地上，尤其喜欢停歇在高枝、电线、墙或篱笆上。其分布范围广阔，自西欧、北非至中亚的温带至亚热带草原地带。","appearance":"黍鹀体长17-19厘米，体重约32-67克。整体呈暗灰褐色，羽衣上带有细密的条纹，无明显白色尾部边缘，这与多数其他鹀科鸟类形成对比。头部灰色至橄榄褐色，耳羽较暖色，喉部及胸前有深色斑点，有时形成黑色斑块。雄雌相似，但雄鸟比雌鸟大。幼鸟羽色偏暖，腿部颜色从粉红到黄粉色不等。","call":"黍鹀的鸣唱独特，被形容为类似钥匙串碰撞的声音，先发两三个音符，随后快速连续地发出其余部分。叫声包括各种嗡嗡声和一个清脆的‘tsi’声。","habits":"黍鹀栖息于开放的草甸，包括自然草原和农业地带，偶尔出现在荒地或废置的污水厂附近。它们偏好低地，但在中亚部分地区可达到海拔2600米的高度。以植物种子为主食，也吃昆虫和其他小型无脊椎动物。迁徙模式复杂，北欧和西欧的鸟群部分迁往南欧和北非过冬。","breeding":"繁殖季节通常较晚，始于5月底或6月初，一窝产1-7枚蛋，通常4-6枚，孵化期12-14天，由雌鸟独自孵化。雄鸟可能拥有多个配偶，每只雄鸟最多可拥有18个配偶。雌鸟独立筑巢，以草和细根编织，置于地面或作物中。","identification":"黍鹀与其他鹀科鸟类的区别在于缺乏明显的白色尾羽，以及上下体均有深色条纹。雄鸟的体型比雌鸟大，这是辨识性别的重要依据。","protection":"IUCN：LC（无危）。尽管普遍分布且数量众多，黍鹀在一些欧洲国家自1930年代以来数量下降，尤其是在农业集约化和土地利用变化的区域。在英国、爱尔兰等地，种群已大幅减少。","distribution":"繁殖区分布于西帕拉里克地区，从不列颠群岛至斯堪的纳维亚南部，东至俄罗斯西南部，南至北非加那利群岛，地中海地区，土耳其，以色列，约旦西部，阿拉伯半岛东北部，经伊朗南部、阿富汗北部至中国新疆西北部。非繁殖季节可见于田野和芦苇丛中。","other":"黍鹀的食物中71.5%为植物种子，28.5%为动物性食物，如甲虫等。"},{"name":"黄鹀","english_name":"Yellowhammer","scientific_name":"Emberiza citrinella","overview":"黄鹀（英文名：Yellowhammer，学名：Emberiza citrinella），是雀形目鹀科鹀属的鸟类。雀形目的一种小型鸣禽，以其明亮的黄色头部和棕红色臀部著称。广泛分布于欧亚大陆，从英国至西伯利亚中部，南至地中海北部山脉和北非部分地区。在中国极为少见，仅见于华北平原、北京、昌黎、新疆天山山地等地。","appearance":"雄性黄鹀具有醒目的黄色头部，黄色下体，胸腹部分有黑色条纹，背部呈暖棕色且有黑色条纹，臀部红褐色。雌鸟和幼鸟颜色较为暗淡，头部和胸部有较淡的黄色调，背部有橄榄色条纹。成年雄鸟体长约16.5厘米，体重20-36.5克。","call":"其歌声以一系列短促音符开始，逐渐增强，最后以两三个拉长音结束，常被形容为“一点面包，没有奶酪”。","habits":"偏好开阔地带，如灌木丛、石楠地、耕地和果园，冬季可见于农田和牧场。飞行时尾巴轻弹，飞行迅速。通常在地面觅食，主要以种子为食，繁殖季节会加入昆虫。","breeding":"繁殖期从四月开始，雄鸟在树上或灌木上建立领地并唱歌吸引雌鸟。雌鸟在隐蔽地点筑巢，每次产卵3-5枚，由雌鸟单独孵化，孵化期12-14天。雏鸟出生后由双亲共同喂养，11-13天后离巢。","identification":"与松鹀有相似之处，但黄鹀头部更黄，臀部更红，且鸣声不同。雌鸟和幼鸟可通过黄色色调和较淡的红褐色臀部与松鹀相区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区：从北极圈至南温带山地的西、中欧，北至斯堪的纳维亚半岛，南至伊比利亚半岛北部，东至西伯利亚中部、高加索、伊朗、哈萨克斯坦、蒙古北部。在中国的分布极为有限，仅见于华北平原、北京、昌黎、新疆天山山地等地。","other":"在新西兰和澳大利亚成功引入，成为当地常见鸟类。"},{"name":"白头鹀","english_name":"Pine Bunting","scientific_name":"Emberiza leucocephalos","overview":"白头鹀（英文名：Pine Bunting，学名：Emberiza leucocephalos），是雀形目鹀科鹀属的鸟类。别名: 白发鹀、白冠雀、松树巫，体长约17厘米的大型鹀科鸟类。具有独特的头部图纹和小型羽冠，分布于欧亚大陆东部，自乌拉尔山脉以东至俄罗斯远东地区、中国东北及西北等地。偏好栖息于林缘、林间空地及被砍伐或火烧过的森林。","appearance":"雄鸟头部有醒目的白冠和颊部，胸腹部为砖红色，背部有深棕色条纹。雌鸟色调较淡，具白色下体和灰色背部。冬季成鸟头部特征依旧，但整体颜色更深，纵纹更明显。亚成鸟缺乏明显的白色颊斑，与田鹀相似，但具较弱的羽冠和灰色耳羽上的小白点。","call":"鸣叫声和歌曲结构与黄鹀类似，但歌曲稍短、节奏稍慢，音符数量较少且间隔更均匀。初始音符频率较低，构成的歌曲较为柔和。","habits":"栖息于多种开放环境，包括林缘、林间空地、火烧过或砍伐后的森林，冬季则出现在农田、荒地及果园。主要以昆虫为食，如蚱蜢、甲虫等，非繁殖季节则以谷物种子为主食。","breeding":"繁殖期为4月底至7月末，通常产两窝。雌鸟筑巢，巢为紧密编织的草杯，内衬柔软草料，置于地面小凹陷处，由草丛、灌木或倒伏植被遮蔽。每窝产4-5枚蛋，孵化期13天，幼鸟喂养期9天，离巢后1-3天完全独立。","identification":"雌鸟与黄鹀雌鸟区别在于嘴具双色，体色较淡且略沾粉色而非黄色，髭下纹较白。亚成鸟与田鹀区分在于较弱的羽冠、淡色腹部纵纹及灰色耳羽后方的白斑。","protection":"IUCN：LC（无危）","distribution":"繁殖于俄罗斯乌拉尔山脉以东至西伯利亚、中国东北、西北地区；非繁殖期迁徙至中亚、印度北部、中国南部等地。","other":"与黄鹀杂交现象普遍，导致某些地区的白头鹀数量锐减。"},{"name":"淡灰眉岩鹀","english_name":"Rock Bunting","scientific_name":"Emberiza cia","appearance":"雄鸟头部有鲜明的黑色条纹，胸腹部呈栗色，上体为深褐色，下体为淡色；雌鸟和幼鸟外观相似，但颜色更为柔和，头部条纹不那么明显。雄鸟成鸟头部和胸部为灰白色，与黑色侧冠纹、眼纹和髭纹形成鲜明对比；背部和翅膀上覆羽为深棕色，翼上有两道明显的白色翼带；尾巴黑色，外侧尾羽边缘白色。雌鸟与雄鸟类似，但色彩较为暗淡。幼鸟头部有棕色条纹，胸部和两胁有暗色斑纹。","call":"鸣唱为清脆、高音调的歌曲，带有突然的音阶变化，有时为短促的高音节，最后一音上升并重复。叫声通常为弱而尖锐的‘tzi’及其变体，受惊时发出‘trrr’的声音。","habits":"栖息于裸露的低山丘陵、高山和高原的岩石荒坡、草地和灌丛中，偏好朝南的斜坡，常出现在有零星树木的灌丛、草丛和岩石地面。主要以草籽、果实、种子和农作物为食，繁殖期间以昆虫和幼虫为主。常成对或单独活动，非繁殖季节会形成小群。白天在地面上觅食，发出‘jier、jier’的叫声。","breeding":"繁殖期从3月底到8月，产卵高峰期在5月，有时会有两窝甚至三窝。巢建在地面上的浅坑内，由干草、苔藓和毛发构成，雌鸟负责筑巢。每窝产3-6枚卵，孵化期13-15天，由雌鸟独自孵化。雏鸟由双亲共同喂养，留巢期9-13天。","identification":"与灰眉岩鹀相比，淡灰眉岩鹀分布限于新疆西北部、西藏等地，侧冠纹为黑色而非栗色。此外，淡灰眉岩鹀的翼上有白色翼带。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括西北非洲、南欧东至中亚、喜马拉雅山脉，以及中欧部分地区。非繁殖季节，一些个体迁移到较低海拔的耕作区。","other":"主要为留鸟，部分个体可能迁徙或游荡。"},{"name":"灰眉岩鹀","english_name":"Godlewski's Bunting","scientific_name":"Emberiza godlewskii","overview":"灰眉岩鹀（英文名：Godlewski's Bunting，学名：Emberiza godlewskii），是雀形目鹀科鹀属的鸟类。俗名: 灰眉子、灰眉雀，雀形目鹀科的鸟类。分布广泛，见于俄罗斯、蒙古、伊朗、阿富汗、巴基斯坦、印度以及中国多个地区，包括东北、河北、内蒙古、青海、山西、陕西、宁夏、甘肃、湖北、四川、贵州、云南和西藏。偏好干燥且多岩石的丘陵山坡，以及靠近森林、多灌木丛的沟壑深谷，亦常见于农耕地。","appearance":"大型鹀类，体长约17厘米，体重14至23克。雄鸟头部、颈部和胸部呈灰色，具有显著的黑色眼纹、颊纹和冠纹，背部橙黑相间，臀部和下体呈橙黄色。雌鸟外观相似但色彩略淡。幼鸟头部有暗色条纹，上体有突出的棕色条纹，下体淡色，胸部有暗色条纹。喙部上黑下浅，腿脚呈淡粉色。","call":"鸣声独特，通常从岩石顶端或树梢开始，由一系列高音“tziit”音节开启，随后是一连串颤音，不如其他种类音乐性丰富，重复数次。叫声包括‘tzii’和更硬的‘pett pett’。","habits":"非繁殖季节以种子为主食，尤其偏好禾本科植物的种子；繁殖期间则增加昆虫等无脊椎动物的比例。通常在地面觅食。非繁殖季节常形成小群，有时多达35只，偶尔与灰头鹀和朱雀（Carpodacus）混群。","breeding":"关于繁殖习性的具体信息未详述。","identification":"与淡灰眉岩鹀的区别在于侧冠纹颜色（灰眉岩鹀为栗色，淡灰眉岩鹀为黑色），以及分布区域的不同（灰眉岩鹀分布更广，淡灰眉岩鹀限于新疆、西藏）。与三道眉草鹀的区别在于顶冠纹的颜色（灰眉岩鹀为灰色，三道眉草鹀耳斑更大）。","protection":"IUCN状态未提供。","distribution":"分布于中国、巴基斯坦、印度、哈萨克斯坦、蒙古、缅甸和俄罗斯。在中国，分布于东北、河北、内蒙古、青海、山西、陕西、宁夏、甘肃、湖北、四川、贵州、云南和西藏。","other":"灰眉岩鹀在中国分布较广，种群数量较丰富。"},{"name":"三道眉草鹀","english_name":"Meadow Bunting","scientific_name":"Emberiza cioides","overview":"三道眉草鹀（英文名：Meadow Bunting，学名：Emberiza cioides），是雀形目鹀科鹀属的鸟类。别名: 大白眉、三道眉、犁雀儿、韩鹀、山带子、山麻雀、小栗鹀，又称大白眉、三道眉、犁雀儿等，是鹀科的典型代表。这种英俊的大型鹀类，以其独特的脸部花纹著称：耳羽深褐色，眉部和喉部淡色，眼先及眼下有黑色条纹。雄鸟颈环灰色，上体和两胁呈锈色。雌鸟头部纹路更淡，颈环不完整，下体黄褐色。常见于亚洲东部开阔地带，包括森林边缘、农田和草地。其分布范围内唯一能发出多音符叫声的鹀类。","appearance":"三道眉草鹀体长约17厘米，体重17-26克。雄鸟繁殖期羽毛颜色鲜明，头顶部红褐色，有较宽的白色眉纹，耳羽深褐色，对比鲜明的白色颊纹和黑色亚颊纹；颈后粉棕色，颈部两侧灰色，上体红褐色，有暗褐色条纹，臀部和尾上覆羽无条纹，呈红褐色；翅膀羽毛红棕色或暗棕色，中覆羽和大覆羽窄端白色；尾巴深色，最外侧一对尾羽有大量白色。雌鸟色彩较淡，头部图案较弱，颈环不完整，下体粉棕色。幼鸟整体色淡，有精细的条纹，胸部有斑点而非条纹。成鸟有五个亚种，其中tarbagataica最为淡色，weigoldi较为明亮，castaneiceps最小且最暗，ciopsis具有独特的细长喙和黑色耳羽。","call":"三道眉草鹀的鸣唱是从小灌木或高树顶发出的简短而急促的乐句，类似于的鸣声，被转录为“chi-hu chee-tsweet-tsweet-tuee”。ciopsis亚种的鸣唱有所不同，具有颤音节奏，可以转录为“ziu-chuhu tsitsirri tsetziz”。典型的叫声是一系列短促、尖锐的“zit zit zit”。","habits":"三道眉草鹀主要栖息在干燥开阔的生境中，如灌木丛、农田、草地和开阔的林地。它们以草籽和杂草种子为主要食物，夏季会增加昆虫的摄入量。冬季时，它们会在小型到中型群体中觅食，通常由30-40个个体组成，偶尔可达数百只，与雀科和其它鹀类混群，尤其是在早晨和傍晚前往偏爱的饮水地点。它们在地面上觅食，姿态蜷缩。","breeding":"三道眉草鹀在4月开始繁殖，雄鸟占地并配对。4月底至5月初，雌鸟在林间灌木或山坡草丛地面筑巢，巢呈碗状，由草茎编织，内垫马鬃兽毛，平均直径约11厘米，高10厘米，深6厘米。每巢产卵3-5枚，卵呈白色或浅天蓝色，带有褐色细纹和斑点，孵化期为11天。雏鸟在另11天后离巢，由亲鸟带领活动直至8月末形成小群。它们每年繁殖两次。","identification":"三道眉草鹀与栗斑腹鹀相似，但三道眉草鹀的喉与胸对比更强烈，耳羽褐色而非灰色，白色翼纹不明显，上背纵纹较少，腹部无栗色斑块。幼鸟色淡且多细纵纹，与灰眉岩鹀及淡灰眉岩鹀的幼鸟相似，但中央尾羽的棕色羽缘较宽，外侧尾羽羽缘白色。","protection":"IUCN：LC（无危）","distribution":"三道眉草鹀的繁殖区域包括中亚的东部哈萨克斯坦和吉尔吉斯斯坦，通过俄罗斯南部、蒙古、中国东北部至日本的萨哈林和库页岛。在中国，它们分布于新疆北部、云南和浙江西北、东南部，韩国半岛和日本北海道至屋久岛。冬季时，一些鸟会向较低海拔移动。","other":"三道眉草鹀在冬季会迁移到较低的海拔或平原地区，它们的食谱随季节变化，冬季以野生草籽为主，夏季以昆虫为主。"},{"name":"白顶鹀","english_name":"White-capped Bunting","scientific_name":"Emberiza stewarti","overview":"白顶鹀（英文名：White-capped Bunting，学名：Emberiza stewarti），是雀形目鹀科鹀属的鸟类。分布于亚洲中部的山区，自哈萨克斯坦南部至印度北部，包括阿富汗、巴基斯坦等地。其独特标志是雄鸟头部的黑白相间图案，雌鸟则全身呈褐色，带有淡色眼环。繁殖于中高海拔的岩石沟壑、山丘，冬季迁往较低海拔的开阔地带。","appearance":"雄性白顶鹀拥有优雅的黑白色面部花纹，头部和颈背为浅灰褐色，逐渐变为白色，与黑色的喉部和脸颊形成鲜明对比。雌鸟整体为暗褐色，头部有较淡的眼纹。繁殖季节雄鸟的胸部两侧和腹部下方为淡粉色，背部为栗色。非繁殖季节雄鸟色彩较暗淡。雌鸟和幼鸟相似，但整体颜色更淡，胸部有斑点而非条纹。","call":"鸣唱是一系列颤音的嗡嗡声，以单一高音结尾，类似“TZI-TZI-TZI-TZI-TZI”。叫声包括尖锐的“tit”声和急促的“tchirit”声。","habits":"栖息于干燥的轻木林山地，偏好杜松和奇戈扎松树丛。夏季在1200米至2500米之间活动，冬季下降到低地的灌木丛、贫瘠农田和平原边缘。以植物种子为主食，偶尔捕食昆虫。","breeding":"营巢于地面或低矮灌木中，具体繁殖细节未知。","identification":"与同属物种相比，白顶鹀的头部特征明显，雄鸟独特的黑白配色易于识别。雌鸟与幼鸟需通过胸部的斑点而非条纹以及头部较淡的眼纹来辨别。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖从哈萨克斯坦南部至印度北部的山脉，包括乌兹别克斯坦东部、土库曼斯坦东南部、吉尔吉斯斯坦、塔吉克斯坦、阿富汗、巴基斯坦北部、克什米尔和印度北部直至喜马偕尔邦中部。非繁殖季节分布至印度西部和中部的开阔地带。","other":"2013年，白顶鹀在中国新疆首次被记录，成为该地区的鸟类新发现。"},{"name":"栗斑腹鹀","english_name":"Jankowski's Bunting","scientific_name":"Emberiza jankowskii","overview":"栗斑腹鹀（英文名：Jankowski's Bunting，学名：Emberiza jankowskii），是雀形目鹀科鹀属的鸟类。罕见的中型雀形目鸟类。其分布区域狭窄，仅限于中国东北部的沙丘灌丛地带，如内蒙古东部和吉林西部，以及蒙古东部和北京部分地区。雄鸟上体红褐色，腹部有独特的深色斑块；雌鸟偏冷褐色，胸前有黑斑组成的项链。面临严重的生存威胁。","appearance":"成年雄鸟头部具红褐色冠羽，与白色眉纹形成鲜明对比，脸颊有黑色条纹延伸至眼睛，耳羽非常浅灰，边界有黑色次须纹，上体主要为红栗色，背部有宽大的黑色条纹。两对最外侧尾羽尖端有白色，其余尾羽暗色，边缘淡色，外侧羽片基部呈淡红色。喉部及下体白色，胸中央灰，侧面及胁部淡红，中央腹部有深红褐色斑。雌鸟整体颜色较冷，胸部有斑点状项链而非腹部斑块。喙灰色，顶端较暗，下颌较浅，腿呈灰粉色。幼鸟上体颜色较暗，顶部为深灰色，两侧有弱条纹。","call":"鸣唱通常简单，被描述为“chu-chu cha-cha cheee”，类似于Accentor属鸟鸣的开头，但以升调“eeee”结尾，如同黄鹀或白头鹀的歌曲尾声。有时记录到更长、更多变的歌曲，尤其是在吉林。叫声包括单个或双重的“tsit”，可能用于联系；更响亮、几乎爆炸性的“sstillit”叫声可能作为警报信号，细长穿透的“hsiu”声也可能如此。","habits":"偏好开阔的草地生境，主要为草原或低矮山丘，植被以Filifolium sibiricum、Stipa baicalensis和Spodiopogon sibiricus为主，间杂有高达3米的Siberian apricot树。在中国东北的分布点，包括内蒙古东部、吉林西部，曾存在于黑龙江和远东俄罗斯，但现被认为在这些地区已灭绝。主要栖息于沙丘灌木草丛和干旱草原，季节性迁移有限，冬季偶尔出现在北京和辽宁等地。","breeding":"繁殖季节在吉林西部从4月底持续至7月底，已灭绝的东部种群繁殖时间更晚，自5月中旬至6月中旬。巢由双亲共同建造，位于地面稀疏草丛中或小灌木下，由干草制成，内部铺有马毛。每窝产卵4-7枚（平均5.26枚），卵色为象牙白，带有淡褐色标记、深棕色斑点和线条。孵化仅由雌鸟承担，周期为11-14天；雏鸟由双亲共同喂养，育雏期为10-13天。巢穴常受杜鹃寄生，繁殖成功率低。","identification":"与三道眉草鹀相似，但色彩更为淡雅，颊斑灰色而非深色，雄鸟腹部有独特深色斑块。雌鸟与非繁殖期雄鸟类似，但胸部有斑点项链而非腹部斑块。幼鸟颜色暗淡，上体偏冷褐色。","protection":"IUCN：EN（濒危）。中国法律给予最高级别保护，被列入《野生动物保护法》2021年修订版的保护名单。在中国，分布范围急剧缩小，种群数量极度稀少，仅存于中国东北部几个零星地点，总成熟个体数估计不足100只。","distribution":"繁殖区：分布于远东蒙古、中国东北部的内蒙古东部和吉林西部，曾存在但现已灭绝于黑龙江和远东俄罗斯。非繁殖区：在北京和辽宁有记录，至少历史记录显示曾在朝鲜北部出现。","other":"历史上，栗斑腹鹀在20世纪上半叶于黑龙江地区局部常见，但如今在其原有栖息地已不再存在。栖息地破坏、过度放牧和农业变化导致其数量急剧下降，成为亚洲最濒危的鸟类之一。"},{"name":"灰颈鹀","english_name":"Grey-necked Bunting","scientific_name":"Emberiza buchanani","overview":"灰颈鹀（英文名：Grey-necked Bunting，学名：Emberiza buchanani），是雀形目鹀科鹀属的鸟类。以其独特的灰头、白眼圈、黄色颊纹和暖色下体而著称。分布于中亚地区，包括帕米尔高原至阿尔泰山脉，冬季迁往南亚部分地区。其生境偏好干燥、岩石较多的环境，如山侧和平原。","appearance":"灰颈鹀体长约15-17厘米，体重17.2-26克。雄鸟繁殖季节头部至颈灰色，眼圈明显，脸颊黄色，胸部至腹部颜色从浅黄至红褐色。上体灰褐色，肩羽边缘红棕色，翅膀和尾羽灰暗，尾端外侧白色。雌鸟较暗淡，头顶和颈侧有细条纹，肩羽色较淡。幼鸟似雌鸟，但头顶几乎无条纹，下体有更多红褐和棕色条纹。","call":"鸣唱是一系列短暂上升的音符，通常以连续的颤音结束，类似‘tsee-tsee-tsee-tsee-dew-dedew’。","habits":"偏好干旱地区的开阔地带，如多石的山丘和覆盖着低矮荆棘的环境。秋季迁徙前会结成小群，与其他鹀类混合。食物包括多种种子、植物嫩芽，以及昆虫如象鼻虫、甲虫、蚱蜢、蝽、蚂蚁和蜗牛。","breeding":"繁殖季节，雏鸟几乎全靠昆虫喂养。筑巢于地面，利用一些悬垂的植被遮蔽，巢材包括草和毛发。","identification":"与圃鹀相比，灰颈鹀胸腹间无明显分界，头部为蓝灰色而非绿灰色。此外，灰颈鹀的下体偏粉色，眼圈白色。","protection":"IUCN：LC（无危）","distribution":"繁殖于东土耳其、伊拉克东北部、亚美尼亚、阿塞拜疆、伊朗、土库曼斯坦南部、乌兹别克斯坦东部、哈萨克斯坦中部和东部、俄罗斯南部和西部、蒙古国。冬季迁徙至巴基斯坦东南部、印度北部、中部和南部。在中国，分布于新疆部分地区。","other":"灰颈鹀的迁徙研究显示，自1940年代以来，通过哈萨克斯坦天山西部Chokpak Pass的数量显著减少，可能与半干旱栖息地的过度放牧有关。"},{"name":"苍头鹀","english_name":"Cinereous Bunting","scientific_name":"Emberiza cineracea","overview":"苍头鹀（英文名：Cinereous Bunting，学名：Emberiza cineracea），是雀形目鹀科鹀属的鸟类。越冬于红海沿岸东北非与也门。欧洲边缘岛屿上亦有零星分布。","appearance":"体长16.5-18厘米，体重21-29.7克，身材较长，嘴较细长。雄鸟头冠、耳羽及颈项呈黄灰色，形成不明显的帽状；喉部淡黄色，眼圈淡黄；上体灰，翼羽具黑褐色中心和浅色边框，形成模糊的翼带；尾羽黑褐，外侧尾羽内缘白色；胸腹部灰或黄绿。雌鸟及幼鸟较暗淡，喉部淡黄，颊纹明显。","call":"发出尖锐的‘Tzip’声，叫声弱而略刺耳，有似快速简短的‘drip-drip-drip-drieeh-drieeh’的歌声，音调比其他类似种更为尖锐。","habits":"栖息于干燥的岩石山坡，迁徙时可见于各种开阔地带。以种子为主食，繁殖季节增加昆虫摄入。飞行时尾端白色显眼。","breeding":"繁殖期不详，通常一窝产三枚蛋。在繁殖季节，雄鸟会占据高地如岩石、树顶或灌木丛唱歌。","identification":"与Ortolan和Cretzschmar's Buntings相比，苍头鹀上体灰，下体灰或黄绿色，腹部白而非橙或黄褐色。叫声与蓝头圃鹀相似，但音调更尖。","protection":"IUCN：NT（近危）。全球估计3300-5800对，约6600-11,600成熟个体。土耳其的繁殖种群自1990至2013年可能下降了19%。","distribution":"繁殖区：希腊爱琴海的莱斯沃斯岛和希俄斯岛，土耳其西南部、中部、东南部，伊拉克北部和伊朗西北部。非繁殖区：红海南部沿海，从苏丹东北部至厄立特里亚，阿拉伯半岛西南部的干旱开阔地区。","other":"迁徙路线和冬季分布范围因亚种而异，部分混群现象发生在迁徙途中。"},{"name":"圃鹀","english_name":"Ortolan Bunting","scientific_name":"Emberiza hortulana","overview":"圃鹀（英文名：Ortolan Bunting，学名：Emberiza hortulana），是雀形目鹀科鹀属的鸟类。体型较小。头部橄榄绿至灰橄榄色，与黄色喉部和胡须纹形成鲜明对比，胸部栗色，上体杂有黑色条纹。广泛分布于欧洲及亚洲西部的开阔农业地带、山地及部分森林边缘，秋季迁往北非和中东。在中国新疆西北部偶有记录。","appearance":"雄鸟成鸟春季时，头部橄榄绿或灰橄榄色，喉部亮黄色，胡须纹明显，下体淡栗色，上体暗棕色，条纹深黑；尾羽黑褐色，末端三对外侧有白色区域。雌鸟和幼鸟类似，但颜色较暗淡，头部图案模糊，身体较少呈现栗色。秋季雄鸟与雌鸟相似，但下体色彩更鲜艳。幼鸟非常暗淡，下体底色红棕，胸部条纹粗大，侧面条纹细小，喙最初灰色，后变为粉色。","call":"鸣唱为一系列5-6个音符组成的短语，起始2-3个音符响亮，随后音调下降，可描述为“swee-swee-swee, dee-dee”。叫声包括清脆的双音节“tsleeu”（主要飞行叫声）、短促尖锐的“quip”或“pwit”（受惊时发出）和短促的“chu”。","habits":"繁殖季节主要以昆虫为食，如蚂蚁、甲虫和蚱蜢；其他时间以种子为主食。栖息于开阔地带，如农田、山地斜坡和林缘，有时在树冠层觅食。夏季单独或小群体活动，秋季形成数百只的大群，冬季保持群居。迁徙时在以色列曾观察到高达800只的群落，春季在中途停歇点可能聚集数千只。","breeding":"繁殖期从4月中旬开始，持续到6月初。一夫一妻制，偶尔一雄多雌。巢由雌鸟单独构建，位于地面的凹陷处，由根须和草构成，内部铺垫精细材料。每窝产4-5枚蛋，孵化期11-12天，仅雌鸟孵化。雏鸟由双亲共同喂养，育雏期12-13天。","identification":"与灰颈鹀相比，圃鹀胸部偏灰，与腹部栗色形成明显对比，头部偏绿，翼斑常为白色。","protection":"IUCN：LC（无危）。尽管在欧洲数量众多，但自1960年代中期以来，西欧和中欧的种群数量急剧下降，监测数据显示自1980年以来减少了89%，2004-2013年间继续减少35%。种群数量减少被认为与农业集约化有关，包括土地利用变化、作物多样性减少、篱笆消失和农药广泛使用。","distribution":"繁殖区覆盖从斯堪的纳维亚半岛到伊比利亚半岛、东至俄罗斯、哈萨克斯坦北部、中国新疆西北部及蒙古的部分地区。非繁殖期迁徙至撒哈拉沙漠南部边缘、厄立特里亚、吉布提、埃塞俄比亚和阿拉伯半岛南部沿海的半干旱高地。","other":"在法国，圃鹀作为美食，导致其种群数量严重下降，促使1999年立法保护。"},{"name":"蓝头圃鹀","english_name":"Cretzschmar's Bunting","scientific_name":"Emberiza caesia","overview":"蓝头圃鹀（英文名：Cretzschmar's Bunting，学名：Emberiza caesia），是雀形目鹀科鹀属的鸟类。主要分布在希腊、土耳其、塞浦路斯及黎凡特地区，繁殖于阳光充足的开放丘陵地带，冬季迁至苏丹和厄立特里亚北部。偶尔会漂泊到西欧，极为罕见。","appearance":"成年雄性蓝头圃鹀具有灰蓝色的头部，橙红色的颊部、喉部和髭纹，上身呈现温暖的棕红色至土黄色，黑色的羽毛中心形成条纹外观，最亮的棕红色位于未标记的臀部和上尾覆羽较弱的部位。雌鸟和幼鸟的头部图案较弱，更接近于同属的物种，但可通过暖棕色的臀部和白色的眼环加以区分。成年雄鸟的体型比雌鸟和幼鸟更为鲜艳和深色。喙粗壮，呈粉色。","call":"鸣唱为三到四个音节的短语，类似“dziree-dziree-dzireee”，声音较低沉，略显粗糙且带有一种嗡嗡声，与同属的物种相似但音调更低。主要的叫声为尖锐的“tchipp”，比同属物种更硬朗、更尖锐，音质不那么金属。","habits":"蓝头圃鹀主要栖息在地中海气候下的开阔岩石坡地。它们的饮食主要包括各种小型种子，尤其是禾本科的种子，也会在特定时期捕食蚂蚁。几乎完全在地面觅食，不会像同属的物种那样在树叶中觅食或空中捕食。秋季和冬季，小群体可合并形成相当大的聚会，可达数百只，与同属的物种混群。","breeding":"蓝头圃鹀在繁殖季节会在地面筑巢，通常产四到六个蛋。它们的繁殖区域主要在地中海半干旱沿海平原和岛屿上，往往在较低海拔处繁殖，特别是在与同属的物种共存的地方。","identification":"与同属的物种相比，蓝头圃鹀的头部颜色为灰色而非绿色，喉部为橙色而非黄色。雄鸟成鸟比雌鸟和幼鸟更加鲜艳和色彩更深。可以通过暖棕色的臀部和白色的眼环来识别雌鸟和幼鸟。","protection":"IUCN：LC（无危）","distribution":"繁殖于南阿尔巴尼亚、希腊大部分地区、克里特岛、土耳其西部和南部、塞浦路斯、叙利亚西部、黎巴嫩、约旦西部、以色列北部和巴勒斯坦；可能还包括伊拉克西北部。越冬于苏丹沿海和尼罗河谷，以及（至少曾经）厄立特里亚东部；一些报道在埃及南部和沙特阿拉伯西北部和西南部有记录。","other":"尽管繁殖范围有限，蓝头圃鹀却异常容易迷途，被报告出现在英国群岛、法国、荷兰、德国、瑞典、芬兰、波兰、奥地利、保加利亚、马耳他、阿尔及利亚、利比亚、乍得、科威特、阿联酋、伊朗、阿曼、格鲁吉亚、加那利群岛，甚至肯尼亚和俄罗斯南部（黑海沿岸的高加索地区）。"},{"name":"黄道眉鹀","english_name":"Cirl Bunting","scientific_name":"Emberiza cirlus","overview":"黄道眉鹀（英文名：Cirl Bunting，学名：Emberiza cirlus），是雀形目鹀科鹀属的鸟类。小型鸣禽，以其独特的头部和胸部图案著称，尤其是雄鸟的黑色喉部。分布于南部欧洲、地中海岛屿、北非，以及土耳其的温带至亚热带灌木林地。在英国南部和威尔士曾广泛分布，现仅限于德文郡南部小范围区域。","appearance":"雄鸟繁殖期个体具有醒目的头型和胸部花纹，灰绿色的冠至颈背，细黑条纹，黑色眼纹被黄色眉纹和长黄色颊纹环绕，黑色颏和喉部；上体栗色，黑色羽干中心，淡橄榄色边缘，臀部灰橄榄色或浅棕灰色；翼上覆羽颜色较浅，三级飞羽黑色，宽红褐色边缘；尾棕色，内外侧有白色边缘；上胸黄色，下方有一宽阔的橄榄绿带，胸侧栗色，下胸和腹部淡黄色，尾下覆羽变白，两胁有棕色条纹。雌鸟和非繁殖期雄鸟外观相似，但头部和胸部的花纹不明显，上体颜色更浅，下体淡橄榄灰色，胸侧淡锈色，下体淡黄色，除腹部外皆有深色条纹。雏鸟似雌鸟，但更苍白，背部灰色，有发达的暗色眼纹和髭纹，肩部有红褐色痕迹，尾羽棕色，三级飞羽边缘淡色（成年雌鸟为栗色）。","call":"雄鸟的单调歌曲为类似极北柳莺的响亮颤音，叫声包括清脆的金属声“tsiu”和较长的高音“tseeu”。","habits":"栖息于阳光充足的灌木丛、小片林地和被田野环绕的开放地带，以及果园、葡萄园等各类农田边缘。偏好南向的地形和有树荫的地方。冬季倾向于选择休耕地或茬地。在繁殖季节以昆虫为食，其余时间主要以草籽和谷物种子为食。","breeding":"繁殖季长，从四月中旬开始至八月，有时至九月初。通常育两窝，偶尔三窝。雌鸟独建巢，巢由茎秆、草、干根和苔藓构成，内衬细草和毛发，置于低处，通常低于2米，藏于密集的灌木、针叶树或类似植被中。每窝产2-5枚卵，多为3-4枚，灰色带许多赤褐色斑点和条纹。雌鸟孵化，周期12-13天。双亲共同喂养雏鸟，育雏期11-13天。","identification":"雄鸟与雌鸟在繁殖期的差异显著，雄鸟具有鲜明的头部和胸部花纹。与黄鹀的区别在于更细腻的暗色条纹、头部条纹更醒目、臀部灰橄榄色（而非明亮的锈色）。","protection":"IUCN：LC（无危）","distribution":"繁殖区：远至英格兰南部、法国南部、德国南部直至罗马尼亚南部；南至伊比利亚半岛、摩洛哥沿海至突尼斯（西北和东北非洲）、地中海岛屿（巴利阿里群岛、科西嘉岛、撒丁岛、西西里岛、克里特岛）和土耳其西部、北部沿海。非繁殖区：邻近的田野。","other":"自19世纪引入新西兰后，该物种在南岛成功建立种群。"},{"name":"黑纹鹀","english_name":"Striolated Bunting","scientific_name":"Emberiza striolata","overview":"黑纹鹀（英文名：Striolated Bunting，学名：Emberiza striolata），是雀形目鹀科鹀属的鸟类。拥有灰色头部，栗褐色翅膀，以及鲜明的双色喙。雄鸟的脸部条纹复杂，带有三道亮白色条纹和深色胸纹，而雌鸟则具有类似但更淡的条纹，缺乏深色线条。非洲亚种的胸部更呈栗色，头部颜色更深，与亚洲个体有所区别。这种鸟在岩石灌丛中繁殖，通常靠近村庄和农田，偶尔会在亚洲的废弃建筑中筑巢。","appearance":"黑纹鹀体型纤细，长度约12至13厘米，体重介于12至16克之间。雄鸟头部、颈部、喉咙和上胸呈灰色，带有黑色条纹，超眉线和颊纹白色。雌鸟比雄鸟更暗淡，头部呈沙棕色，顶部有较深的条纹。幼鸟外观比雌鸟更暗淡，喙部颜色一致。非洲亚种（saturatior和jebelmarrae）比指名亚种稍大，头部颜色更深，条纹更重，下体颜色更丰富。","call":"雄鸟的鸣唱是从低矮的灌木或岩石上发出的一系列快速滚动的嗡嗡声和甜美的哨音，持续大约1.5至2秒。飞行叫声类似于麻雀的‘chielp’声。","habits":"黑纹鹀栖息于干燥地区的岩石地带，通常靠近水源，但在索马里和阿曼的城镇和村庄中也能见到。冬季时，它们的栖息地更加广泛，可能出现在耕作区附近。食物主要是种子，喂养幼鸟时会以昆虫为主。","breeding":"在印度，已观察到黑纹鹀的繁殖范围向南扩展至近普纳的Saswad附近。一窝产卵量为两到四枚，孵化期约为14天。","identification":"与北非的家鹀相比，黑纹鹀具有更强的面部条纹和更苍白的腹部。东部乍得的黑纹鹀（亚种jebelmarrae）显示出与家鹀的混交迹象。","protection":"IUCN状态未提供。","distribution":"繁殖区位于东北非至西南亚洲的岩石灌木地带，分布零散，从东北乍得和埃及东部至东北索马里和肯尼亚西北部；西奈半岛、以色列、约旦西部、阿拉伯半岛、伊朗南部、阿富汗东北部、喜马拉雅山脉下的巴基斯坦和印度西部。非繁殖期则扩展至印度西部的田野。"},{"name":"家鹀","english_name":"House Bunting","scientific_name":"Emberiza sahari","overview":"家鹀（英文名：House Bunting，学名：Emberiza sahari），是雀形目鹀科鹀属的鸟类。主要分布在北非干旱地带，从摩洛哥南至马里，东至乍得。在摩洛哥，自1960年代起，其分布范围向北扩展，近期已抵达直布罗陀海峡南岸的丹吉尔和特陶安。家鹀常在人类居住区筑巢繁殖，巢穴通常位于墙壁或建筑的洞穴中，每窝产2到4枚蛋。以种子为主食，育雏时也会摄取昆虫。","appearance":"体长约14厘米，体型略小于淡灰眉岩鹀，羽色较为朴素。雄鸟头部和上胸灰色，腹部沙橙褐色，头部细密黑纹，无白色眉纹，与黑纹鹀明显不同。雌鸟头部灰棕色，有淡色眉纹。幼鸟色泽比雌鸟更暗淡，喙色一致。","call":"鸣唱由一系列简单的音符组成，较黑纹鹀更为多变，带有2-3个重复元素，音调稍低。叫声为\"dzwii\"。","habits":"偏好岩石地带，通常靠近水源，广泛分布于人类居住区，亦可见于自然岩石露头和干河床。最高可达摩洛哥阿特拉斯山脉的2300米。饮食以种子为主，辅以花、浆果、昆虫和蜘蛛。常在人类聚居地和市场附近觅食，也与牲畜相关联，从其饲料中觅食。","breeding":"全年均可听到鸣唱，但在繁殖前最为频繁。筑巢于人类住所附近，通常在墙洞或建筑物中，每窝产3枚蛋，孵化期12-14天。","identification":"与黑纹鹀相比，家鹀面部条纹不明显，腹部颜色更深。黑纹鹀有更强烈的面部条纹和更浅的腹部颜色。","protection":"IUCN：LC（无危）","distribution":"主要分布于非洲西北部干旱区的人类居住地和岩石地带，从摩洛哥和毛里塔尼亚向东延伸至利比亚西北部和乍得北部。","other":"在摩洛哥，传统上被视为神圣的鸟类，因此变得非常温顺，自由出入房屋、商店和清真寺。"},{"name":"淡岩鹀","english_name":"Lark-like Bunting","scientific_name":"Emberiza impetuani","overview":"淡岩鹀（英文名：Lark-like Bunting，学名：Emberiza impetuani），是雀形目鹀科鹀属的鸟类。分布于非洲西南部，包括安哥拉、纳米比亚、博茨瓦纳、津巴布韦、南非和莱索托的干燥草原和灌木丛地带。其最显著的外部特征是淡褐色的头部，有较暗的棕色条纹，宽阔的米色眉线，以及带有锈色翼斑的小巧银灰色喙。","appearance":"淡岩鹀体长12至14厘米，体重13至19克，整体外观朴素。成鸟头部呈沙棕色，顶部有深棕色条纹，明显的宽米色眉线延伸至颈背；下颊亦为浅沙色；背部灰棕色，有深棕色条纹；上翼覆羽深棕色，边缘宽阔的肉桂色；飞羽深棕色，边缘狭窄的肉桂色；喉咙奶油色，胸部和腹部呈沙色，胸部有稀疏且极细的棕色条纹。两性相似，幼鸟比成鸟稍暗淡，胸部更棕色。sloggetti亚种比指名亚种更浅色，上体边缘更宽的浅色。","call":"雄鸟的歌声是一系列持续2到4秒的啾啾和嗡嗡声。联系叫声为柔和的‘chip’声；警报叫声为更深沉的‘chut’声。","habits":"淡岩鹀偏好半干旱的草地和灌木地，尤其在岩石和沙质地带。它们通常与卡拉哈里系统相关联，包括西多汁卡拉哈里和东草本纳马卡拉哈里，但在干旱期间会侵入更湿润的生境。偶尔会在卡拉哈里村庄的花园中出现。","identification":"淡岩鹀与其他种子食鸟群聚，但与类似雌性云雀雀鹀相比，缺乏黑色的腹部斑块。","protection":"IUCN：LC（无危）","distribution":"分布于非洲南部的多汁和草本卡拉哈里地区，从安哥拉沿海至纳米比亚，穿过博茨瓦纳、津巴布韦，到达南非西部和中部。"},{"name":"朱胸鹀","english_name":"Cinnamon-breasted Bunting","scientific_name":"Emberiza tahapisi","overview":"朱胸鹀（英文名：Cinnamon-breasted Bunting，学名：Emberiza tahapisi），是雀形目鹀科鹀属的鸟类。常见于从加蓬向东至索马里东北部和索科特拉岛，向南贯穿南非，以及西南阿拉伯半岛。","appearance":"朱胸鹀体型小，长度约13-15厘米，体重介于11.6-22克之间。成年雄鸟的头部具有醒目的黑白条纹，下体为肉桂色，雌鸟头部的条纹颜色较淡，为灰褐色，腹部颜色亦较为柔和。幼鸟外观类似雌鸟，但整体更为暗淡，头纹更淡，喉咙颜色偏黄棕色。朱胸鹀的喉咙至胸部上方为黑色，其余下体呈丰富的肉桂色，虹膜深棕色，喙上部暗棕色或灰黑色，下部浅粉色或黄色，腿色偏黄或粉棕色。","call":"朱胸鹀的鸣唱是一系列快速上升音调的短促音符，如“chip-chip-ip-ereee”或“cha-cha-cha chip”，有时结尾带有嗡嗡颤音“chip-chip-ipereeezzzzz”。叫声为鼻音的“dwe-wer-errr”或“fair-air”，飞行中发出轻柔的“twee”声。","habits":"朱胸鹀栖息于岩石山坡、石质区域和侵蚀沟壑，从干旱到湿润的灌木丛和半沙漠地带，包括阿拉伯的杜松森林，只要存在足够的开阔地面。它们在砂质地带也有发现，但需有适当的裸露地面。在干旱区，它们通常靠近水源。在肯尼亚和西南阿拉伯半岛记录到高达3000米的海拔高度，在埃塞俄比亚记录到1990米，在索马里达到1800米，在赞比亚南部和马拉维分别达到2200米和2450米的高度。","breeding":"朱胸鹀在东非的繁殖季节为1月至6月，在马拉维为4月至7月，在赞比亚为4月至8月，在津巴布韦为11月至6月（主要集中在1月至2月），在南非为10月至4月（主要在12月至1月），在索科特拉岛为11月至3月，而在南阿拉伯半岛主要为3月至5月（偶尔延伸至6月）。它们倾向于单配偶制，雌鸟单独筑巢，巢位于地面，靠岩石或小灌木基部，或在岩壁或土坡上，高可达6米。每窝产卵2-4枚（罕见5枚），平均孵化率为66%，但只有31%的雏鸟成功离巢，主要因獴等天敌捕食导致损失。","identification":"与朱胸鹀相似的灰喉鹀可通过其灰色而非黑色的喉咙来区分。家鹀的喉咙和胸部有条纹而非实色。朱胸鹀的亚种间辨识点主要在于颜色深浅和条纹差异。","protection":"IUCN：LC（无危）","distribution":"朱胸鹀广泛分布在非洲南部撒哈拉以南地区，从加蓬向东至索马里东北部和索科特拉岛，向南贯穿南非，以及西南阿拉伯半岛。","other":"朱胸鹀的分布范围自1985年以来有所扩大，可能是由于气候变化和生境片段化的影响。"},{"name":"灰喉鹀","english_name":"Gosling's Bunting","scientific_name":"Emberiza goslingi","overview":"灰喉鹀（英文名：Gosling's Bunting，学名：Emberiza goslingi），是雀形目鹀科鹀属的鸟类。又被称为灰喉田鹀。其最显著的外部特征是雄鸟的黑白条纹头部和淡灰色喉咙，雌鸟则拥有灰色和棕色条纹的头部及黑褐色条纹的喉咙。分布于非洲的毛里塔尼亚、塞内加尔至西南苏丹和东北刚果民主共和国。","appearance":"成年灰喉鹀体长13-15厘米，体重11.1-15.6克。雄鸟具有鲜明的黑白条纹头部，雌鸟则颜色较为暗淡，头部和喉咙呈灰棕色，带有黑色条纹。幼鸟比成鸟更暗淡，下体颜色较浅。两性皆有灰色喉咙，区别于其他物种。","call":"灰喉鹀的叫声为断续的歌曲，由短促的（平均1.2秒）、相对宽带（2.5-9.2 kHz）的片段组成，重复率变化大，通常表现为“jajaja-titi”或“ti-jaa”等声音。","habits":"偏好岩石露头、采石场和峡谷的干旱和湿润草原环境，常在开阔地带活动，有时在岩石旁或灌木基部筑巢。在尼日利亚，倾向于在新耕土地上丰富的谷物区域栖息，通常靠近水源。","breeding":"繁殖季节在西非为7月至次年1月，主要集中在9月至12月。一夫一妻制。巢由雌鸟单独建造，放置于地面或小灌木底部，平均产卵2-3枚，孵化期12天，幼鸟在12-16.5克时离巢，由双亲共同喂养。","identification":"与朱胸鹀的区别在于后者具有纯黑色而非灰或黑褐色条纹的喉咙，翅膀颜色也更锈色。与家鹀的区别在于后者喉咙和胸部有条纹而非单一颜色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的萨赫勒地带岩石山坡，自毛里塔尼亚和塞内加尔向东至西南苏丹和东北刚果民主共和国；南部延伸至喀麦隆北部、中非共和国北部和南苏丹北部。","other":"灰喉鹀曾被认为与朱胸鹀是同一种，但现已确认为独立物种。"},{"name":"索岛鹀","english_name":"Socotra Bunting","scientific_name":"Emberiza socotrana","overview":"索岛鹀（英文名：Socotra Bunting，学名：Emberiza socotrana），是雀形目鹀科鹀属的鸟类。仅见于索科特拉岛。其显著特征为头部黑白条纹鲜明，胸羽呈亮丽的栗色，胸部至腹部有淡色的斑纹。该鸟种分布于岛上的灌木丛和草地，偏好岩石地带。","appearance":"成年雄鸟长约13-14厘米，重约13-16克，头部黑白条纹对比强烈，背部灰褐色，翅膀上覆羽呈栗褐色，喉部白色，胸部为丰富的肉桂色渐变为腹部的白色。雌鸟色彩略显暗淡，幼鸟则更为灰暗，头纹为深灰色，腹部带奶油色。","call":"鸣唱通常为一系列三到四个短促而尖锐的音符，'tseet-tee-too'或'steet-tsoo-steet-tsoo'。","habits":"索岛鹀常在地面跳跃觅食，主要以草籽为食，也会直接从草穗上取食。非繁殖季节会形成小群。","breeding":"繁殖习性了解不多，巢穴未被描述。冬季雨季期间繁殖，雄鸟自11月底至2月唱歌，2月观察到带有育雏斑的雌鸟，新离巢的小鸟在2月和4月初被发现。繁殖期间，雄鸟聚集，成对靠近，暗示半群居繁殖模式。","identification":"与朱胸鹀的区别在于更丰富的栗色翅膀覆羽、白色的喉部、较淡的腹部和灰色臀部带，以及更窄的黑色头部条纹和细长的黑色颊纹。雌鸟与雄鸟相似，但头部条纹呈棕色，野外难以区分。幼鸟比成鸟更暗淡。","protection":"IUCN：NT（近危）","distribution":"繁殖区域限于索科特拉岛的密集植被覆盖的山岩斜坡。非繁殖季节移至低海拔区域。","other":"全球范围内数量稀少且分布零散，全球范围估计为310平方公里，总人口约为3770只，相当于大约2500只成熟个体。数量被认为稳定，但可能面临来自过度放牧和外来掠食者的威胁，如野猫、黑鼠和小印度猫鼬。"},{"name":"南非岩鹀","english_name":"Cape Bunting","scientific_name":"Emberiza capensis","overview":"南非岩鹀（英文名：Cape Bunting，学名：Emberiza capensis），是雀形目鹀科鹀属的鸟类。常见于岩石地带的灌木丛生环境。其特征鲜明，头部有条纹，翅膀呈鲜艳的栗色。雄鸟和雌鸟的外观相似，但雌鸟可能略显暗淡，头纹带有浅褐色调。","appearance":"南非岩鹀长约16厘米，成鸟具有一顶黑色的冠羽，眼上有一条白色的眉纹，耳羽边缘为黑色，耳羽中央白色。背部灰色带深褐色条纹，翼部栗色显著，尾羽深栗色。下体灰白，喉部偏白。雌鸟与雄鸟相似，但白色头部标记可能带有微黄调。幼鸟翼部颜色较淡，头部图案不明显，胸部和侧腹有更重的条纹。","call":"鸣叫为上升的zzoo-zeh-zee-zee声，歌曲是一系列响亮的chup chup chup chup chee chhep chu音节。","habits":"南非岩鹀偏好岩石地带的灌木丛生环境，常在山地北部的干旱杂草丛中活动。它们通常单独或成对出现，偶尔形成家庭群。以种子、昆虫和蜘蛛为食，主要在地面觅食。","breeding":"筑巢低矮，位于灌木或草丛中，巢呈杯状，内部铺垫细软材料。每窝产卵2至4枚，卵壳颜色为奶油色，带有红棕色和淡紫色斑点。孵化期大约13至15天，雏鸟由双亲共同喂养。","identification":"与维氏岩鹀区分，后者上方较暗，下方呈板岩色，翼覆羽上的栗色减少。","protection":"IUCN：LC（无危）","distribution":"分布于南部非洲，自西南安哥拉向东至莫桑比克西部，向南延伸至南非南部。在南非西部、纳米比亚西部和中部、博茨瓦纳、莱索托、斯威士兰以及南非大部分地区均有记录。","other":"该物种对栖息地碎片化有一定的耐受性，能够在被入侵的Acacia cyclops fynbos区域生存。"},{"name":"维氏岩鹀","english_name":"Vincent's Bunting","scientific_name":"Emberiza vincenti","overview":"维氏岩鹀（英文名：Vincent's Bunting，学名：Emberiza vincenti），是雀形目鹀科鹀属的小型鸟类，以独特的条纹脸、淡色无斑点喉部和红褐色翅膀著称，分布于非洲中部和南部的特定山区。","appearance":"维氏岩鹀头顶呈暗灰棕色，从中央冠至颈背有略深的条纹，前额侧至颈背侧有宽黑带。上体其余部分为深灰棕色，具不明显的暗色条纹。尾羽黑色，飞羽深灰棕色，翼盖和腋羽灰白色。下体从喉咙到腹部为灰色至棕灰色，腹部中央较淡，下腹部和臀部尖端为灰白色。","call":"其鸣唱被描述为尖锐、欢快、节奏感强、类似金丝雀的口哨声，'tree-re-reet, tree-re-reet'，第二音节最高。叫声则是一种小而类似麻雀的叽叽声。","habits":"栖息于裸露的岩石山峰，树百合、少量仙人掌、矮灌木、芦荟和干草丛中，以及花岗岩悬崖和其林木基部，海拔高度主要在915至2000米之间。通常单独或成对出现，地面觅食。","breeding":"繁殖季节未知，但在马拉维和赞比亚的记录显示，繁殖状态的个体出现在3月至6月。巢穴未被详细描述，一窝蛋数为三枚，也未具体描述。","identification":"维氏岩鹀最明显区别于重叠地理分布内的肉桂胸岩鹀（Emberiza tahipisi）在于其淡色喉部、均匀的暗灰下体和较长的尾巴。","protection":"IUCN：尚未评估（作为更广泛分布的南非岩鹀的亚种处理）。在莫桑比克局部数量较多，在马拉维不罕见也不受威胁，但在赞比亚较为稀少且容易被忽视。","distribution":"分布在马拉维（从南部Mzimba区向南至Ntchisi、Dedza、Cape Maclear半岛、Mangochi山脉和Mulanje）、邻近的北部莫桑比克（Zobué、Mangochi山脉、Mirrote）和赞比亚东部（从Nyanje至Chadiza，如Mbewa山）。","other":"有时被分类学家视为独立物种，但也有观点认为它是南非岩鹀复杂群体中的一种终端形式，具有逐渐变暗的下体颜色。"},{"name":"白眉鹀","english_name":"Tristram's Bunting","scientific_name":"Emberiza tristrami","overview":"白眉鹀（英文名：Tristram's Bunting，学名：Emberiza tristrami），是雀形目鹀科鹀属的鸟类。俗名: 白三道儿、小白眉、五道眉，小型鸣禽，特征为头部的黑色与白色条纹形成鲜明对比。繁殖于东北亚的针叶林地带，越冬于中国南方及东南亚部分地区。该物种在1870年由罗伯特·斯温霍首次描述。","appearance":"体型小巧紧凑，全长约14-15厘米，体重14-21克。头部有条纹，雄鸟头部和喉咙黑色，中央具白色顶冠纹，眼上方有宽白眉纹，耳羽后角有白色斑点，颈部和背部淡锈褐色，腹部白色，胸部及两侧有栗色斑纹。雌鸟色彩较暗，头部灰褐色，具相似的条纹图案，下颌和喉咙呈淡黄色。幼鸟与雌鸟相似，但色泽更暗淡。","call":"鸣声为高音节后跟拉长音节，常以\"chit\"结尾，如\"hsiee swee-swee swee-tsirririri\"，与黄眉鹀的歌声类似。叫声为爆炸性的\"tzick\"，重复不规律。","habits":"栖息于海拔700-1100米的针叶林、阔叶林和混交林，偏好林下植被丰富的环境。繁殖期间独行或成对，迁徙时结成家族群或小群。胆小且善于隐蔽，主要在地面或林下觅食，以种子和昆虫为食。","breeding":"繁殖期为5-7月，雄鸟在枝间鸣唱吸引雌鸟。巢建于灌丛或草丛中，呈碗状，主要由干草和细软植物构成。每窝产卵4-6枚，卵色灰色或浅蓝绿色，孵化期13-14天。","identification":"与黄眉鹀相比，白眉鹀缺乏黄色眉纹，喉部颜色更深，胸部和两侧的纵纹较少。与田鹀的区别在于头部图案和白色顶冠纹的存在，以及下颊纹的粗黑。","protection":"IUCN：LC（无危）。在适宜的繁殖地局部常见，近年来没有明显数量下降的证据。","distribution":"繁殖于中国东北、外蒙古北部、俄罗斯远东地区和朝鲜半岛北部，越冬于中国南部、中南半岛北部。偶尔出现在日本、韩国、印度东北部等地。","other":"迁徙期间，白眉鹀可能在沿海地区集结成群。"},{"name":"栗耳鹀","english_name":"Chestnut-eared Bunting","scientific_name":"Emberiza fucata","overview":"栗耳鹀（英文名：Chestnut-eared Bunting，学名：Emberiza fucata），是雀形目鹀科鹀属的鸟类。俗名: 高粱颏儿、赤脸雀，特征为栗色耳羽和独特黑色颊纹，以及棕色胸带。分布广泛，见于西伯利亚、日本、朝鲜半岛、印度、中国大陆及台湾岛等多个地区，尤其在低山区或半山区的河谷沿岸草甸和森林边缘的湿草甸中活动频繁。","appearance":"成年雄鸟头冠和颈背呈灰色，具暗色纵纹；耳羽亮栗色；眼圈显著白色，胡须状条纹黑色，下颌和喉部白色，颊纹黑色并扩展至胸部形成斑点和条纹。上体灰褐色，翼羽和尾羽深棕色，尾羽尖端有白色标记。下体白色，胸侧有栗色带，腹部橙褐色渐淡，两胁细纵纹。雌鸟色彩较暗淡，幼鸟上体褐色，下体淡黄色，胸部和两侧有细纵纹。","call":"鸣唱起始于几声急促的‘zwee’或‘zip’音，随后加速成连续的颤音，以三段式结尾，如“chip chip chil-ri-wit chi chi tsiririri”。叫声为爆炸性的‘pzick’。","habits":"栖息于低山和半山区的河谷沿岸草甸，偏好湿润的草地和灌木丛。迁徙性鸟类，北方种群南迁至日本南部、中国南部、台湾、印度东北部、东南亚等地过冬。","breeding":"杯状巢建于地面或矮灌木中，通常产卵3至6枚，以四枚居多，卵呈白色带红褐色斑点，孵化期约为12天，繁殖季节在不同地区有所差异。","identification":"与同属其他物种相比，栗耳鹀的栗色耳羽和黑色颊纹是其明显标识。不同亚种间，如E. f. arcuata和E. f. kuatunensis，在色调和胸带宽度上有细微差别。","protection":"IUCN：LC（无危）","distribution":"繁殖于西喜马拉雅山脉、中国中部、西伯利亚东北部、蒙古北部、韩国半岛、日本北部至南部、中国东部的浙江和福建。冬季迁徙至印度、孟加拉国、东南亚（除马来半岛）、中国中部和东部、韩国半岛、日本南部。","other":"三种亚种存在，其中E. f. arcuata在喜马拉雅山脉和中国西南部发现，色调更深，胸带更宽；E. f. kuatunensis分布于中国东南部，上体颜色更深，更偏红褐色，胸带较窄。"},{"name":"小鹀","english_name":"Little Bunting","scientific_name":"Emberiza pusilla","overview":"小鹀（英文名：Little Bunting，学名：Emberiza pusilla），是雀形目鹀科鹀属的鸟类。俗名: 麦寂寂、花椒子儿、高粱头、铁脸儿、虎头儿，小型鹀，具有独特的头部花纹，包括黑色顶纹和红褐色侧顶纹，以及白色的浅色眼圈。繁殖于远北欧和北方欧亚大陆的针叶林地带，冬季迁徙至印度东北部、中国南部及东南亚。适应性强，常见于农田和山地环境。","appearance":"小鹀长约12至14厘米，拥有白色的下体，胸部和两侧带有深色条纹。头部呈粟色，有明显的白眼圈，脸颊红褐色，边缘由黑线勾勒。繁殖羽和非繁殖羽差异不大，但非繁殖羽更为暗淡，翼斑更为显眼。喙小，直，腿粉色，眼睛深红棕色。","call":"鸣唱由两到三个部分组成，每个部分包含数个相似的音节，最后一部分变化较大，如'zree zree zree tsütsütsü tzriiitu'或'tzrü tzrü tzrü zee zee zee zee zriiiiru'。叫声为尖锐的'zik'声，类似灰头鹀。","habits":"栖息于北方的针叶林、灌木丛和开阔的苔原地带，冬季迁徙至亚洲的亚热带地区。在繁殖季节成对或单独活动，其余时间成小群，活动于地面和低灌木。食物以种子为主，辅以昆虫。","breeding":"繁殖期为6月至7月，巢建于地面的草丛或灌木中，通常产卵4至6枚，卵色多样，从淡紫色到粉红棕色不等，孵化期11至12天，由双亲共同承担。","identification":"与灰头鹀雌鸟的区别在于小鹀有白色眼圈，黑色脸圈在耳后有上扬小尖，且脸圈内部的栗色明显，与脖颈部位颜色对比鲜明。","protection":"IUCN：LC（无危）","distribution":"繁殖于远北欧至西伯利亚东部，非繁殖期分布于印度东北部、中国南部、东南亚部分地区。在中国，分布于东北、华北、长江流域及以南地区。","other":"小鹀的迁徙路径和时间较为固定，春季迁徙始于3月，秋季迁徙始于7月底，迁徙时常见于西北欧、以色列、日本等地。"},{"name":"黄眉鹀","english_name":"Yellow-browed Bunting","scientific_name":"Emberiza chrysophrys","overview":"黄眉鹀（英文名：Yellow-browed Bunting，学名：Emberiza chrysophrys），是雀形目鹀科鹀属的小型鸟类。俗名: 金眉子、黄三道、五道眉儿、大眉子，分布于俄罗斯东部西伯利亚地区，越冬于中国中南部及东部。其显著特征为鲜黄色眉纹，雄鸟头部黑色具条纹。","appearance":"体型介于13至15厘米，体重约15至24克。雄鸟繁殖期头部具鲜明的黑白色图案，黄色眉纹始于眼前方，向后转白，黑色冠顶有窄白中线，黑色面颊、眼纹和耳羽，耳羽后方有小白点。雌鸟头部以褐色为主，眉纹颜色从白色到淡黄色不等，黑色面颊纹不如雄鸟明显。上体灰色带黑色条纹，翼部有明显翼斑，下体白色带黑色条纹，胸侧及胁部淡红褐色。喙部上颚暗灰色，边缘粉红，下颚粉红带暗线，腿粉色。","call":"鸣唱起始于清晰拉长音，通常接两个高音，快速结束，似‘chueee swii-swii chew chew chew’或‘chueee tsriii tzriii wee-wee-wee tzitzi-tueei’。叫声为尖锐‘zick!’或‘ziit’。","habits":"栖息于灌木丛和开阔森林地带，繁殖季节在泰加林区，冬季至中国中部和南部。迁徙时会与其他鹀类混合成群。以昆虫和蜘蛛喂养雏鸟，非繁殖季以草籽和草本植物种子为主食。","breeding":"筑巢于树上，每窝产四枚蛋。春季迁徙通过东北中国，秋季迁徙至中国南部过冬。","identification":"与白眉鹀区别在于黄眉鹀的黑色下颊纹更明显，与胸部纵纹融合。与冬季灰头鹀区别在腰部棕色，头部条纹对比明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于俄罗斯伊尔库茨克州至雅库特地区，南至贝加尔湖以南。越冬于中国中部和南部，东部地区。"},{"name":"田鹀","english_name":"Rustic Bunting","scientific_name":"Emberiza rustica","overview":"田鹀（英文名：Rustic Bunting，学名：Emberiza rustica），是雀形目鹀科鹀属的鸟类。俗名: 花九儿、花嗉儿、田雀、花眉子、白眉儿，东北俗称花椒嗉。繁殖季雄鸟头部及羽冠黑色，具粗大的白色眉纹和髭纹，脸颊黑色，雌鸟脸颊红褐色，头顶后端颜色较浅。分布于北亚地区，包括欧亚大陆北部的湿冷森林地带。","appearance":"繁殖季雄鸟头部黑色，具明显的白色眉纹和髭纹，脸颊黑色，具白色喉部和上胸环，体背栗红色，具黑色纵纹。雌鸟颜色较淡，脸颊红褐色，头顶后端颜色较浅，腰背部棕色，具鱼鳞状斑纹。嘴端部灰色，基部角质色，眼圈不明显或不完整。","call":"鸣叫声为短暂的‘zit’，歌曲柔和旋律，常在夜晚听见。","habits":"繁殖于湿冷森林，冬季迁徙至东亚地区。食物以种子和昆虫为主，冬季常见于农田和城市绿化地带。耐寒，即使在大雪中也十分活跃。","breeding":"在灌木丛或地面筑巢，每窝产4至6枚卵，孵化期间以昆虫喂养雏鸟。","identification":"与白眉鹀的区别在于：白眉鹀有白色顶冠纹，田鹀无；白眉鹀雄鸟下颊纹粗黑，田鹀雄鸟颏、喉白色；白眉鹀腰棕色，田鹀腰棕色具鱼鳞状斑纹。与小鹀的区别在于嘴部颜色、眼圈、耳羽、腰部及胸胁纵纹的不同。","protection":"IUCN：VU（易危）","distribution":"繁殖于北亚，包括斯堪的纳维亚至俄罗斯远东地区，南至阿尔泰山和萨哈林岛。非繁殖季节分布于中国东部、朝鲜半岛、日本中部至南部。","other":"已列入国家三有保护鸟类。"},{"name":"黄喉鹀","english_name":"Yellow-throated Bunting","scientific_name":"Emberiza elegans","overview":"黄喉鹀（英文名：Yellow-throated Bunting，学名：Emberiza elegans），是雀形目鹀科鹀属的鸟类。又称: 黄蓬头、黄眉子、虎头凤，小型鸣禽，体长约15-16厘米。其显著特征为头顶一束高翘的羽毛，雄鸟拥有黑色羽冠、黄白眉纹及胸前半月形黑斑，雌鸟羽色较淡，黑色特征不明显。","appearance":"黄喉鹀拥有金字塔状的羽冠，雄鸟头部黑色，眉纹及喉部黄色，胸部有黑色斑块，颊部黑色，雌鸟体色较淡，缺乏明显的黑色斑块，雌雄两性皆有褐色背部，腹部白色，两胁有少量纵纹。","call":"黄喉鹀的鸣唱为长而单调的啾啾声，如‘tswit tsu ri tu tswee witt tsuri weee dee tswit tsuri tu’，常在短暂间隔后重复，有时几乎连续，叫声为尖锐的‘tzik’。","habits":"黄喉鹀栖息于低山丘陵地带的次生林、阔叶林、针阔叶混交林的林缘灌丛中，偏好河谷与溪流沿岸的疏林灌丛。繁殖期单独或成对活动，非繁殖期成小群，活跃于灌丛与草丛中，食性以昆虫和种子为主。","breeding":"繁殖期为每年5-7月，营巢于地面或灌木丛中，巢呈杯状，由雌雄共同筑巢。每窝产卵4-6枚，孵化期约12-14天，雏鸟晚成性，雌雄亲鸟共同育雏。","identification":"黄喉鹀与田鹀的主要区别在于脸颊颜色和黑色边缘的存在与否，黄喉鹀脸颊清褐色，无黑色边缘，且脸颊后无浅色块斑。","protection":"IUCN：LC（无危）。在中国，黄喉鹀被列为有益的、有重要经济、科学研究价值的陆生野生动物。","distribution":"繁殖区位于东北亚，包括俄罗斯远东、中国东北至朝鲜半岛，以及日本的部分地区。非繁殖区覆盖中国东南部和台湾，以及日本中部和南部。","other":"黄喉鹀除西南亚种在中国为留鸟外，其他亚种均迁徙。"},{"name":"黄胸鹀","english_name":"Yellow-breasted Bunting","scientific_name":"Emberiza aureola","overview":"黄胸鹀（英文名：Yellow-breasted Bunting，学名：Emberiza aureola），是雀形目鹀科鹀属的鸟类。又名: 黄胆、禾花雀、黄肚囊、黄豆瓣、麦黄雀、老铁背、金鹀、白肩鹀。非繁殖期集群活动，繁殖期在地面或灌丛内筑碗状巢。分布广泛，从北欧至西伯利亚，日本北部至中国，冬季迁至印度等地。曾经数量丰富，现因过度捕捉而面临灭绝威胁。","appearance":"小型雀形目，体长14至16厘米，体重17至26克，体型较大且健壮。繁殖期雄鸟具有亮白色下体，黑色侧翼条纹，棕色上体，黑色脸面与喉部横带，粉色下颚。雌鸟背部重条纹灰褐色，下体颜色较淡，脸部白色，具暗冠、眼纹与颊纹。幼鸟相似于雌鸟，但下体与脸部底色为浅黄色。","call":"鸣叫特征明显，叫声为清脆的“zick”，歌声为连续的“tru-tru，tri-tri”。","habits":"栖息于开阔的灌木丛、芦苇丛与农田等低矮植被环境，通常形成大群，群大小不固定，有时可达500只以上，迁徙季节可看到上万只的大群。冬季在南亚、东南亚的稻田、草地和农田中集群过冬。","breeding":"繁殖期为每年5月至7月，巢建于草原或近草原的林缘地带的草丛中，巢呈碗状，由马尾、草根和纤维等软材料编织而成。每巢产卵4至5枚，孵化期12至13天。","identification":"与黄眉鹀相比，黄胸鹀体型更大，下体黄色更为鲜艳，且有明显的栗色胸带。与同属物种区分主要依靠体型大小、色彩亮度及下体的颜色差异。","protection":"IUCN：CR（极危）","distribution":"繁殖于北极圈至北温带的帕拉耳区灌木区，从俄罗斯远西北至西伯利亚、堪察加半岛、千岛群岛、库页岛至中国东北、蒙古北部和日本北海道北部。非繁殖期分布于喜马拉雅山南部至东南亚（除马来半岛南部）和中国东南部。","other":"曾被视为数量丰富的无危物种，但近年来因在中国南方和东南亚的大量捕捉，保育等级急剧恶化。目前在中国被列为国家一级保护动物。"},{"name":"索马里鹀","english_name":"Somali Bunting","scientific_name":"Emberiza poliopleura","overview":"索马里鹀（英文名：Somali Bunting，学名：Emberiza poliopleura），是雀形目鹀科鹀属的美丽雀鸟。其最显著的外部特征是黑白相间的面部图案、灰背带有锈色条纹、灰色臀部以及黄色胸部配以淡色侧面。主要分布于埃塞俄比亚、肯尼亚、索马里、南苏丹、坦桑尼亚和乌干达的干旱灌木草原。","appearance":"体长14至15厘米，体重14至18克。雄鸟头部黑白条纹分明，包括一条显眼的白色中冠纹；颈后灰色，肩羽为栗色边缘带浅灰色，形成强烈的条纹感，覆羽具宽黑心，边缘浅灰色，下背和臀部灰色，背部有模糊的黑色斑点；尾巴黑褐色，外侧羽毛尖端白色；翼上覆羽灰色，中央覆羽白色，大覆羽末端亦白，构成双白色翼带；喉部、胸部和腹部中央黄色，胸中部略橙；两胁、下腹和肛周白色；虹膜棕色；上喙大部分暗色，切割缘粉红，下喙粉红；腿淡灰褐色。雌鸟较雄鸟暗淡，头部有棕色调。幼鸟似雌鸟。","call":"雄鸟的歌声是一系列4至6个清脆的哨音，‘tswit, tsuwee tsuwee tsuwee’，比金胸鹀的歌声更短且变化少。","habits":"常在干燥的荆棘稀树草原成对出现，偏好干旱环境。","identification":"与金胸鹀相比，索马里鹀的整体色调更淡，脸部的黑色条纹更窄，背部和臀部更灰，两侧颜色更浅。","distribution":"分布于东非半干旱灌木丛地带，具体包括埃塞俄比亚中部和索马里（东北部除外）、南苏丹远东南部至坦桑尼亚北部。"},{"name":"金胸鹀","english_name":"Golden-breasted Bunting","scientific_name":"Emberiza flaviventris","overview":"金胸鹀（英文名：Golden-breasted Bunting，学名：Emberiza flaviventris），是雀形目鹀科鹀属的鸟类。以其鲜艳的金色胸部和黑色条纹头部而闻名。这种鸟主要分布在非洲南部萨哈拉以南的干燥开放林地和湿润草原，但在赤道森林地带较为罕见。在非洲，是具黄色胸部的鹀中最常见的种类。","appearance":"金胸鹀体长约15-16厘米，重约15-28.3克。成年雄鸟头部黑白相间，具醒目的白色冠纹、黑色侧冠纹、白色眉线和白色耳羽。其橙黄色腹部向下渐变为黄色喉咙和白色下腹。背部呈栗色，臀部灰色。翅膀棕色，有两道明显的白色翼带。雌鸟与雄鸟相似，但颜色较淡，头纹可能带有赭色调，背部可能有深色条纹。幼鸟比雌鸟更暗淡，腹部呈淡白色。","call":"金胸鹀的叫声包括一种鼻音上升的“zzhrr”，以及一首悦耳的、清晰的口哨声，重复着“weechee weechee weechee”。","habits":"这种鸟偏好阿卡西亚树林和开阔的林地，有时也会出现在花园中。它会在地面寻找食物，如草籽、昆虫和蜘蛛，特别是在有幼鸟时会更多地捕食动物。金胸鹀通常单独或成对出现，偶尔形成小群。它倾向于当地性移动，但具体模式受干旱影响。在旱季，它们会频繁地访问水源。","breeding":"繁殖季节在西非和萨赫勒地区为6月至9月，在南非为9月至4月（主要集中在10月至12月）。繁殖期与雨季相关，在东非地区变化较大。每季最多繁殖三窝。筑巢由雌鸟完成，巢为松散的杯状，由草和植物茎构成，内衬细软材料，常含动物毛发，位于灌木或小树的分叉处，高0.5至2米。每窝产2至4枚蛋，仅在萨赫勒地区产1至2枚。蛋壳为白色至浅蓝绿色，大端有黑色和赭色线条及暗点。仅雌鸟孵卵，期间由雄鸟喂食，孵化期为12至13天。雏鸟由双方共同喂养，初期会移除粪便袋，随着雏鸟长大，粪便袋会在巢边积累。成鸟会激烈保卫雏鸟，雄鸟偶尔会展示引诱动作以吸引掠食者远离巢穴。","identification":"金胸鹀与褐腰鹀和索马里鹀的区别在于后者具有灰色而非栗色的肩部和颈部。与索马里鹀的区别在于金胸鹀的背部条纹较少，肩胛骨颜色与背部一致，脸部白色较少，下体颜色更富金色。与褐腰鹀的区别在于体型更大，有明显的白色翼带，面部黑色条纹更宽，臀部灰色而非棕色。与白眉黄腹鹀的区别在于体型略小，脸颊有明显的白色条纹，腹部和胁部白色，胸部有橙色色调。","protection":"IUCN：LC（无危）","distribution":"分布于非洲南部萨哈拉以南的干燥林地和湿润草原，从塞内加尔南部到厄立特里亚北部和埃塞俄比亚远北；刚果民主共和国南部和南苏丹远南穿过东非，向南延伸至南非（除西南部）。","other":"金胸鹀在某些国家被捕捉用于笼鸟贸易。"},{"name":"褐腰鹀","english_name":"Brown-rumped Bunting","scientific_name":"Emberiza affinis","overview":"褐腰鹀（英文名：Brown-rumped Bunting，学名：Emberiza affinis），是雀形目鹀科鹀属的鸟类。其显著特征为黑白相间的面部图案、棕色背部和臀部，以及黄色的腹部。广泛分布于非洲，从塞内加尔至苏丹和乌干达，最近在纳米比亚、奥万博兰、乌库瓦卢迪也有频繁记录，这可能与气候变化有关。","appearance":"褐腰鹀体型小，约13-15厘米长，体重14.5-18克。具有较为细长的喙，脸部大面积白色，腹部呈黄色，缺乏其他非洲黄胸鹀所具有的白色翼带。雄鸟成鸟头部为白色，带有黑色侧冠纹，眼后至耳羽覆盖处有黑条纹，向下与黑色髭纹相连；颈后灰褐色，逐渐过渡至栗色的背和肩部，臀部略淡，上覆羽灰色；下体黄色，胸处略染红褐色，腹部白色；虹膜深棕色，上喙暗灰色，下喙较淡蓝灰色，腿浅灰褐色。雌鸟较雄鸟稍显暗淡，头部条纹带有淡色冲洗，暗纹为黑褐色。幼鸟比雌鸟更暗淡，头部侧冠纹为褐色并杂有黑色条纹，脸部淡色区域沙褐色，下体淡黄褐色。","call":"雄鸟的歌声为短促、嘈杂的颤音，持续约1-1.5秒。在栖息时发出类似鹎（Pycnonotidae）的清脆接触叫声；飞行时会发出短促的‘chip’声。","habits":"褐腰鹀栖息于阔叶林、湿润草原和耕作区，以昆虫为主食，包括白蚁（Isoptera），在圈养条件下也会食用草籽、野花种子以及甲虫幼虫（Coleoptera）、蟋蟀（Gryllidae）和蜘蛛（Araneae）。通常单独或成对觅食于地面。","identification":"与金胸鹀相似，但可通过较窄的面部黑色条纹、黄色腹部和缺乏白色翼带加以区分。与卡巴尼斯鹀相比，背部为棕色，脸颊斑块主要是白色而非黑色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的萨赫勒地带和东北部湿润森林区域，从塞内加尔、毛里塔尼亚南部至几内亚北部，东至埃塞俄比亚南部、乌干达北部和肯尼亚西部。"},{"name":"白眉黄腹鹀","english_name":"Cabanis's Bunting","scientific_name":"Emberiza cabanisi","overview":"白眉黄腹鹀（英文名：Cabanis's Bunting，学名：Emberiza cabanisi），是雀形目鹀科鹀属的色彩鲜明的鸟类，以德国鸟类学家Jean Louis Cabanis的名字命名。其最显著的外部特征是白色的眼眉和黑色的面部面罩，背部暗色带有两道白色翼带，腹部黄色。分布于非洲热带雨林和草原地带，包括几内亚至南苏丹和乌干达西北部，南部至安哥拉中部、津巴布韦南部和莫桑比克中部。","appearance":"体长16-17厘米，体重18-27克。头部大部分为暗色，雄鸟指名亚种具有深色冠羽，几乎没有较浅的中线纹，白色眼眉，黑色耳羽和脸颊与白色喉部形成对比。上身暗灰褐色，背部有模糊的黑色条纹；尾巴黑褐色，外侧羽毛尖端白色；小覆羽暗灰褐色，中覆羽和大覆羽尖端白色（形成两个白色翼带），其余部分黑褐色带淡色边缘；下身黄色，有时略带橄榄色，下尾覆羽白色；虹膜深棕色；上喙黑褐色，下喙角质色；腿角灰色。雌鸟较雄鸟暗淡，头上有棕色晕染，胸部有赤褐色晕染，翼带不明显。幼鸟似淡化的雌鸟，头部呈棕色，眼眉泛黄，下身淡黄白色。","call":"雄鸟的鸣唱多样化，通常是一系列甜美、清晰的哨声，经常让人联想到金胸鹀的鸣唱，但也可能包含缓慢的颤音。叫声包括上升的“burreee”和下降的“tseeoo”；飞行叫声“tsip”。","habits":"生活在茂密的森林、稀树草原和森林边缘地带，偏好亚热带或热带干燥森林环境。分布广泛，常见于非洲次撒哈拉地区的广阔地带。","breeding":"具体繁殖细节未详述，但一般遵循鹀科鸟类的繁殖模式，涉及筑巢、产卵和育雏。","identification":"与其他三种非洲黄胸鹀相比，白眉黄腹鹀头部暗侧缺乏白色颊纹，背部灰色而非栗褐色或棕色，胸部没有橙色晕染。雄鸟与雌鸟外观相似，但雌鸟颜色更暗淡。","protection":"IUCN状态未明确提及。","distribution":"分布于非洲的热带阔叶林地带，范围从几内亚和马里南部延伸至南苏丹和乌干达西北部，向南至安哥拉中部、津巴布韦南部和莫桑比克中部。"},{"name":"栗鹀","english_name":"Chestnut Bunting","scientific_name":"Emberiza rutila","overview":"栗鹀（英文名：Chestnut Bunting，学名：Emberiza rutila），是雀形目鹀科鹀属的鸟类。俗名: 大红袍。繁殖季节雄鸟上体鲜亮的栗红色，腹部黄色，雌鸟及未成年雄鸟整体偏暗，下体淡黄色，与黄胸鹀雌鸟相似但体型更小。广泛分布于东帕拉尔地区，包括俄罗斯东部、蒙古北部与中国东北部，越冬于中国南部、东南亚及印度东北部。","appearance":"栗鹀长度约14-15厘米，尾短，喙较长。雄鸟在繁殖季节拥有鲜明的栗色上体和头部，黄色腹部，侧身有条纹。非繁殖期雄鸟相似但色泽较淡，部分栗色被淡色羽缘遮盖。雌鸟整体呈暗褐色，上体有深色条纹，下体主要为淡黄色。两性皆有淡栗色臀部，喉部为淡黄色。","call":"栗鹀的鸣唱从树上的隐蔽处发出，通常由三个缓慢纯净的音符开始，随后是独特的颤音“tvia tvia tvia sre-sre-sre sisicha”，类似黄腰柳莺或树鹨的歌声，也有点像灰头鹀的歌声，但更为均匀且音调更低。常用叫声为短促的“zick”，与小鹀的叫声相似，还有尖锐的高音“teseep”。","habits":"栗鹀栖息于有低矮灌丛的开阔森林，包括针叶林、混交林及落叶林，高度可达2500米。在非繁殖季节，它们出现在农田、灌木丛和林地边缘。迁徙时和越冬期间，它们通常以小群出现。","breeding":"栗鹀在西伯利亚、蒙古北部和中国东北部繁殖。它们是长途迁徙者，冬季在中国南部、东南亚和印度东北部越冬。繁殖季节偏好于开放森林中带有丰富地面覆盖物和灌木的环境。","identification":"雌性栗鹀与黄胸鹀雌鸟的区别在于栗鹀的腰为棕色，而黄胸鹀雌鸟具有白色翼斑和明显的皮黄色眉纹。与雌性灰头鹀的区别在于栗鹀腰为棕色，无灰头鹀的白色翼斑和尾部白色边缘，灰头鹀雌鸟在耳羽下方具有清晰的月牙形斑纹。注意区分灰头鹀的不同亚种，因为它们的羽色差异较大。","protection":"IUCN：LC（无危）。被列入中国国家保护的有益的或有重要经济、科学研究价值的陆生野生动物名录。","distribution":"繁殖区域包括西伯利亚南部、蒙古北部、俄罗斯远东乌苏里兰及中国东北内蒙古和黑龙江。非繁殖区域扩展到印度东北部的那加兰到米佐拉姆、东南亚北部、中国南部。"},{"name":"藏鹀","english_name":"Tibetan Bunting","scientific_name":"Emberiza koslowi","overview":"藏鹀（英文名：Tibetan Bunting，学名：Emberiza koslowi），是雀形目鹀科鹀属的鸟类。是中国青藏高原东部特有的一种珍稀鸟类。拥有鲜明的黑白色头部图案，雄鸟特征尤为显著，背部呈砖橙色，腹部为灰色。藏鹀的分布局限于青藏高原东侧的小部分区域，主要栖息于海拔3500至4700米的山柳灌丛地带。","appearance":"雄性藏鹀在繁殖季节具有独特的黑冠，两侧宽阔的白眉纹几乎在颈背处相接，耳羽黑色，颊部至下颚呈红棕色。背部明亮的红栗色，上覆橄榄色的灰斑，翅膀和尾巴的颜色较暗。雌鸟头部橄榄灰至红灰，具细密的暗褐色条纹，下体颜色较浅，喉部和胸部呈淡白色，下腹转为灰色，尾下覆羽可能带有粉色调。喙蓝黑色，腿橙黄色。","call":"藏鹀的鸣唱为一系列高音、尖锐的“pi-pi-pipipew”音符，简单而不悦耳。其叫声包括拉长的‘seee’声，可能作为警报或联系信号，以及飞行时的‘tsip tsip’声。","habits":"藏鹀主要栖息于高山草甸、草原和灌丛地带，偏好林线以上、较为贫瘠的高山环境，如矮桧树丛、杜鹃林及裸露地面。冬季常结成小群体活动。食物以鳞翅目幼虫为主，夏季也会捕食蝴蝶、蚱蜢和甲虫。","breeding":"繁殖期间，藏鹀的巢呈圆顶状，与同类中常见的开放式巢结构不同，这一特性似乎独一无二。雌鸟每次产卵3至4枚。","identification":"藏鹀在分布范围内无混淆物种，其独特的体型、色彩和鸣声使其易于辨识。","protection":"IUCN：LC（无危），保护级别：Ⅱ级（2021.02.05）","distribution":"藏鹀主要分布于青藏高原东部，具体在中国的青海省玉树、果洛以及四川省阿坝一带，位于海拔3500至4700米的高度。","other":"自1900年首次被发现以来，藏鹀因目击记录稀少，被认为是世界上最神秘的鸟类之一。"},{"name":"黑头鹀","english_name":"Black-headed Bunting","scientific_name":"Emberiza melanocephala","overview":"黑头鹀（英文名：Black-headed Bunting，学名：Emberiza melanocephala），是雀形目鹀科鹀属的鸟类。外观独特。分布于东南欧至伊朗，冬季迁徙至印度，偶有记录延伸至东南亚。雌鸟整体呈淡褐色，腹部略带黄色，与雄鸟非繁殖季节的特征相似。","appearance":"黑头鹀长约15.5至17.5厘米，体重23至33克。繁殖季雄鸟头部全黑，颈部两侧和喉部鲜黄，背部和翅膀上覆羽红棕至亮栗色，尾羽黑褐，边缘微带浅色。雌鸟及非繁殖期雄鸟整体偏褐色，腹部和臀部带淡黄色，喉部至胸侧可能带有粉褐色调。幼鸟类似雌鸟，但额部、冠部、颈背及背部羽毛边缘明显浅色。","call":"黑头鹀的鸣唱较为平淡，由一系列嗡嗡声组成。叫声多样，包括类似麻雀的叽叽声和高音的‘tseep’。","habits":"繁殖于开阔森林、边缘和果园、花园等零星种植区，冬季栖息于农田。迁徙时直接向东南飞，速度较快。以昆虫、种子和其他植物材料为食，地面或低矮灌木中觅食。常单独或成对出现，迁徙和越冬时形成小到大群。","breeding":"繁殖季始于5月中旬，6月达到高峰。单窝产卵4至5枚，偶见6或7枚，孵化期10至16天，通常13至14天。雌鸟负责孵卵，雄鸟参与育雏程度不明。雏鸟离巢后3至4天内留在巢附近。","identification":"与褐头鹀极相似，区分要点包括：黑头鹀雌鸟脸颊比喉部暗，嘴较大但不尖。亚成鸟与褐头鹀野外难区分。两者在伊朗北部有自然杂交。","protection":"IUCN：LC（无危）。全球数量稳定，但在某些地区因农业实践改变而下降。","distribution":"繁殖于东南欧至伊朗，冬季迁徙至印度西部和北部，偶尔记录于东南亚。在中国大陆偶见于新疆及东南部。","other":"黑头鹀与褐头鹀是姐妹种，存在遗传差异，但有自然杂交现象。"},{"name":"褐头鹀","english_name":"Red-headed Bunting","scientific_name":"Emberiza bruniceps","overview":"褐头鹀（英文名：Red-headed Bunting，学名：Emberiza bruniceps），是雀形目鹀科鹀属的鸟类。俗名: 红头雀。成年雄鸟头部至胸部呈现鲜明的红褐色，与黄色的颈部和腹部形成强烈对比。繁殖于中亚至阿富汗、伊朗、中国西北部等地，冬季迁徙至印度和孟加拉国。在欧洲西部可能成为迷鸟，但因逃脱个体的存在而难以确定其真实状态。","appearance":"体长15-16.5厘米，体重18-34克，体形较大，尾长，无白色外羽。雄鸟繁殖期头部至胸部红褐色，颈后和上体黄橄榄色，背部有暗色纵纹，肩羽具棕色边缘，臀部黄色。非繁殖期雄鸟头部红色减少，背部有条纹。雌鸟和幼鸟淡棕色，背部和翅膀有条纹。喙蓝灰色，腿粉棕色。","call":"鸣声单调重复，加速节奏，伴有清晰的‘r’音，最后音调稍降，类似于黑头鹀。","habits":"栖息于开阔干燥地带，如纯草原上的灌木丛、半沙漠和沙漠绿洲，以及靠近水源的耕作区。春季迁徙始于3月，主要在4-5月进行，秋季迁徙开始得非常早，7月下半月开始离开北方区域。食谱全年以种子为主，繁殖季节多食昆虫。","breeding":"繁殖季节为5-8月，单窝产卵2-5枚，罕有6枚，由雌鸟独自孵化，孵化期10-14天，雏鸟由双亲喂养，育雏期12-13天。可能繁殖成功率低，初期巢穴损失率高。","identification":"与黑头鹀相比，红头鹀的冠纹更少，外观更细长（嘴和尾巴更长），下体颜色较淡，背部色彩较冷。雌鸟和幼鸟与黑头鹀相似，但在野外很难区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于伏尔加河乌乌拉尔河间流域至中国新疆、蒙古西南部、伊朗东北部、阿富汗、巴基斯坦北部、乌兹别克斯坦、塔吉克斯坦和吉尔吉斯斯坦。冬季迁至印度大部分地区。","other":"在非繁殖季节，常见于中等大小的群落中，有时可达数百只，常与黑头鹀混群。"},{"name":"硫黄鹀","english_name":"Yellow Bunting","scientific_name":"Emberiza sulphurata","overview":"硫黄鹀（英文名：Yellow Bunting，学名：Emberiza sulphurata），是雀形目鹀科鹀属的鸟类。成鸟头部及胸部呈黄绿色，具白色狭窄翼斑及眼圈，翼褐色，腹部黄色，雄鸟眼先黑色，雌雄羽色有异。分布于日本本州山地，迁徙途经东南亚地区。","appearance":"体长约13-14厘米，雄鸟平均体重15.2克，雌鸟平均体重14.6克。头部绿灰色，眼圈白色，雄鸟眼先、鼻须及下巴黑色，雌鸟较淡。上体灰绿至褐色，下体黄色，两胁有暗色条纹，尾下覆羽浅黄色。亚成鸟及冬季羽色较淡，喉部黄色。雌鸟上体更多褐色，下体偏黄。","call":"鸣唱通常从树梢隐蔽处发出，由数个颤音短句交替组成，随后是一串变化的颤音，以单个高音结尾，类似但短于田鹀的鸣唱。叫声为金属质感的‘tsip’声，比田鹀的叫声更柔和。","habits":"栖息于山脚森林，迁徙季节出现在灌木丛生的草地、田野及公园。繁殖于日本本州山地，迁徙至菲律宾北部、台湾及中国东南部过冬。偏好海拔600至1500米的森林边缘。","breeding":"繁殖季从五月中期持续至七月早期。巢筑于灌木低处，每窝产卵3至5枚。","identification":"与灰头鹀相比，硫黄鹀头部颜色更为绿灰色，雄鸟眼先黑色，鸣唱较短，叫声更柔和。","protection":"IUCN：LC（无危）","distribution":"繁殖于日本本州岛北部和中部山区。非繁殖期分布于中国东南部、台湾和菲律宾北部。"},{"name":"灰头鹀","english_name":"Black-faced Bunting","scientific_name":"Emberiza spodocephala","overview":"灰头鹀（英文名：Black-faced Bunting，学名：Emberiza spodocephala），是雀形目鹀科鹀属的小型鸟类。又名: 青头雀、蓬鹀、黑脸鹀、青头鬼儿、青头愣，雄鸟头部呈灰色，腹部黄，背部和翅膀栗色；雌鸟则整体为褐色，具大量纵纹。分布于南部西伯利亚至中国北部，迁徙至东北印度、中国南部和东南亚北部过冬。","appearance":"雄鸟成鸟头部、颈部及前胸为灰色，腹部呈黄色，背部和翅膀为饱满的栗色。雌鸟整体为黯淡的褐色，具大量纵纹。两者长约16厘米，喙粗壮呈粉红色。雌雄均具有明显的头纹，雌鸟脸颊橄榄灰，眉纹浅奶油色。","call":"鸣叫为尖锐的‘吱’声，金属质感，短促，不构成歌曲。","habits":"栖息于河流和溪流旁的灌木丛中，偏好湿地、农业和开阔的灌木环境，冬季接近水源。以种子为主食，喂养幼鸟时会捕食昆虫。不断弹尾以显露外侧尾羽的白色边缘。","breeding":"繁殖期在5月中旬开始求偶，5月下旬至6月中旬筑巢，巢为碗状，由草茎、草根和树叶编织，内垫柔软材料。巢址位于低矮灌丛的地面或近地面的树枝上，每巢产卵5枚左右，卵呈天蓝色带褐色斑点，孵化期12-13天。","identification":"雄鸟与其他鹀类的区别在于灰头和黄色腹部；雌鸟与灰鹀、面纹鹀相比，具有更淡的基部纵纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于南部西伯利亚至中国东北部，越冬于北东印度、中国南部和东南亚北部。偶见于欧洲西部。","other":"未列入中国保护动物目录，种群数量大，但面临非法捕猎威胁，种群呈下降趋势。"},{"name":"灰鹀","english_name":"Grey Bunting","scientific_name":"Emberiza variabilis","overview":"灰鹀（英文名：Grey Bunting，学名：Emberiza variabilis），是雀形目鹀科鹀属的鸟类。俗名: 黑蒿鸟，繁殖于日本北部及堪察加南部，冬季迁徙至日本南部及琉球群岛。国内在台湾、江苏、宁夏等地有零星记录。夏季栖息于中海拔的针叶或阔叶林，冬季则偏好阴凉的树林和公园。","appearance":"灰鹀体长14至17厘米，体重20.9至30克。雄鸟繁殖季节全身呈独特的暗钢灰色，头部、背部和下体皆为深灰色，翼覆羽暗灰色，尾羽边缘蓝灰色，上体有黑色条纹。雌鸟体色较为复杂，头部无灰色调，两颊灰，下体白色带暗色条纹。幼鸟上体橄榄褐色，具黑色条纹，胸腹橄榄色，有明显黑纹。","call":"鸣声通常始于柔和拉长的音符，缓慢展开，包含3到5个独特音节，如'swee swee chi-chi-chi'或'hsuuu twis-twis-twis'，也有较快版本。叫声为尖锐的'tzii'。","habits":"灰鹀习性隐秘，偏好山区森林中的竹林及多荫的林下环境。主要在地面觅食，以小昆虫、种子和小果实为食。常见于单只或成对活动，迁徙时有时会形成小群。","breeding":"繁殖生态信息不详，但已知在夏季于日本北部和俄罗斯远东地区繁殖。","identification":"雄性灰鹀与蓝彩鹀的区别在于灰鹀全身羽色为蓝色，而蓝彩鹀腹部、臀部、尾羽外侧为白色。雌性灰鹀与灰头鹀的区别在于灰鹀外侧尾羽无白色标记。","protection":"IUCN：LC（无危）。全球数量稳定，但在其分布区内并不普遍，局部地区常见。","distribution":"繁殖于东亚远北区，包括南堪察加、库页岛、千岛群岛和日本北部。冬季迁徙至日本南部，包括本州、四国、九州和琉球群岛。"},{"name":"苇鹀","english_name":"Pallas's Reed Bunting","scientific_name":"Emberiza pallasi","overview":"苇鹀（英文名：Pallas's Reed Bunting，学名：Emberiza pallasi），是雀形目鹀科鹀属的小型鸟类。俗名: 山家雀儿、山苇容、春雀（qiǎo）儿（北京）。体型和羽色与红颈苇鹀相近，雄鸟具有独特的白领。繁殖于北极圈至温带亚洲的苔原地带，冬季迁徙至东亚南部。活跃于湿地、河谷及近水的灌木丛中。","appearance":"小型鹀鸟，长12-13.5厘米，重10-20克。喙较短窄，直。繁殖季雄鸟头部及喉部黑色，具显著的白色领圈。雌鸟及非繁殖季雄鸟呈沙色，具苍白髭纹。上体灰褐色，下体淡黄色，具暗色纵纹。翼覆羽边缘淡黄，形成两道明显翼带。尾羽棕色，中央一对较深，外侧有白色边缘。","call":"鸣唱为单调重复的“chi chi chi chi chi chi”或“srri srri srri srri srri srri”。鸣叫为类似麻雀的‘chlip’声。","habits":"繁殖于高纬度苔原及森林苔原，偏好湿润草地和灌木丛。迁徙期间栖息于灌溉地带，近水的芦苇丛、稻田及其它耕作区。以昆虫为主食，全年食用种子和植物材料。春季至平原沼泽地和沿溪的柳丛及芦苇中活动，秋冬季节转至丘陵和平原的灌丛及荒地。","breeding":"繁殖期为6月至7月，北方地区可能提前。巢由草和莎草构成，衬以细草和毛发，置于地面或灌木低处。每窝产3-5枚蛋，孵化期11天，雏鸟由双亲共同喂养，留巢期约10天。","identification":"与芦鹀相比，体型更小，喙更细直，尾较长，上体颜色更冷淡，翼覆羽灰色，具两道清晰的翼带，无红褐色调。","protection":"IUCN：LC（无危）","distribution":"繁殖于北亚的低北极到温带地区，从俄罗斯北部的亚马利亚到楚科奇，南至鄂霍次克海和堪察加半岛。非繁殖季节分布于远东亚洲，包括俄罗斯远东、朝鲜半岛和中国中部、东部。","other":"全球数量稳定，但在冬季分布区内面临因捕食而致的潜在威胁。"},{"name":"红颈苇鹀","english_name":"Ochre-rumped Bunting","scientific_name":"Emberiza yessoensis","overview":"红颈苇鹀（英文名：Ochre-rumped Bunting，学名：Emberiza yessoensis），是雀形目鹀科鹀属的鸟类。又称日本苇鹀，繁殖羽雄鸟以全黑的头部和栗红色颈部独特，雌鸟及非繁殖羽雄鸟头部黑色隐约可见，具黄褐色腰部。分布于远东地区，包括日本、韩国、中国东北及蒙古东部。栖息于芦苇地、沼泽及湿润草甸。","appearance":"体长14-15厘米，体重约13-14克，尾羽尖锐。繁殖羽雄鸟头部至下颈及上胸黑色，肩部粉红调的栗棕色，背部灰褐混合锈色并有粗重的黑色条纹，尾羽灰褐色，翼覆羽和飞羽灰褐至蓝灰，下体乳白色，胸部略暗。雌鸟及非繁殖羽雄鸟头部主要为暗棕色，具淡色条纹，腹部黄白，虹膜暗栗色，嘴黑色，腿粉色。幼鸟冠部黑色，有明显淡色中线。","call":"鸣唱通常自高草或芦苇发出，为短暂的短音节组成，'tsui tsui chrin'。叫声为短促的'tick'，飞行叫声'bziu'，类似芦鹀。","habits":"栖息于芦苇地及有矮丛的沼泽地，以及高地的湿润草甸和靠近水源的开阔田野。迁徙性物种，冬季在沿海沼泽地带越冬。","breeding":"繁殖期5月至7月，可能两次繁殖。巢为干草制成的小杯状，位于草地接近地面处，每窝产3-5枚蛋，赭色带棕斑和黑线。雌鸟孵卵，孵化期12-14天；双亲喂养雏鸟，育雏期10-13天，同时开始第二次筑巢。","identification":"与苇鹀区别在于头和喉部黑色，颈和翕呈栗红色，且腿部和喙在冬季更为粉红。幼鸟具淡灰色中线，腰部黄褐色。","protection":"IUCN：NT（近危）","distribution":"繁殖于远东地区，包括蒙古东部、中国东北、乌苏里兰（俄罗斯东南部）和日本本州至九州。越冬于日本中部至南部、朝鲜半岛和中国沿海中东部。","other":"两个亚种被确认，E. y. continentalis和E. y. yessoensis。"},{"name":"芦鹀","english_name":"Common Reed Bunting","scientific_name":"Emberiza schoeniclus","overview":"芦鹀（英文名：Common Reed Bunting，学名：Emberiza schoeniclus），是雀形目鹀科鹀属的鸟类。俗名: 大山家雀儿、大苇容，广泛分布于欧洲、勘察加半岛、日本、中亚、印度以及中国东北、甘肃、新疆、青海、河北、陕西、江苏、福建、广东等地。主要栖息于平原沼泽地和湖沼沿岸低地的草丛和灌丛，偶尔出现在丘陵和山区。该物种的模式产地在瑞典。","appearance":"中等体型的鸟类，体长13.5-15.5厘米，具有小型但结实的喙，适于食籽。雄鸟头部和喉部黑色，颈圈白色，下体白色，背部有重叠的棕色条纹。雌鸟整体较暗淡，头部具条纹，下体条纹较多。幼鸟类似雌鸟，但冠部呈栗色，带有大量深色条纹，下体有斑点。","call":"雄鸟的叫声为重复的'srip'声，从灌木或芦苇顶部发出。","habits":"栖息于高芦苇地，冬季扩展至林地、田野和开阔原野。秋季迁徙期间，常与苇鹀共同觅食。主要食物为植物性的杂草种子，也摄食部分昆虫。繁殖季节，主要以无脊椎动物为食。","breeding":"在东北地区繁殖，巢建于灌丛或芦苇丛中，每窝产卵4-7枚，由雌雄鸟轮流孵卵，孵卵期大约13-14天。","identification":"与苇鹀相比，芦鹀的小覆羽呈棕色，而苇鹀的小覆羽为灰色。","protection":"IUCN：LC（无危）","distribution":"繁殖区包括欧洲、俄罗斯西北部至远东地区、日本北部、中国西北部新疆、蒙古西部、日本北海道至本州北部。非繁殖期分布更广泛，包括英国、斯堪的纳维亚半岛、俄罗斯西北部、伊比利亚半岛、北非西北部、地中海地区、土耳其、高加索、伊朗北部、土库曼斯坦、塔吉克斯坦至中国新疆北部、蒙古西部、中国东北、日本北部。","other":"在欧洲，芦鹀是紫色灯心草和芦苇牧场生态系统的重要组成部分，该生态系统是英国生物多样性行动计划中的重点保护类型。"},{"name":"日本灰头鹀","english_name":"Masked Bunting","scientific_name":"Emberiza personata","overview":"日本灰头鹀（英文名：Masked Bunting，学名：Emberiza personata），是雀形目鹀科鹀属的鸟类。属于雀形目。这种鸟在低至中海拔的湿润混合林中繁殖，冬季则迁移到林地和灌丛中过冬，偏好茂密的下层植被，尤其是矮竹丛。曾被认为是灰头鹀的亚种，但基于形态学和遗传学差异，现已独立为一个物种。","appearance":"日本灰头鹀的上体为棕色，有条纹，头部呈灰白色，下体为浅黄色，带有细密的暗色条纹。雄鸟色彩更深，条纹更明显，脸部和下巴为黑色。雌鸟羽毛较暗淡，呈褐色，全身布满纵纹。与硫黄鹀相似，但其下体条纹更多。","call":"在冬季，其存在往往因发出高音的“吱！”叫声而暴露。歌曲是一段短暂而缓慢的旋律，以颤音结尾，听起来像“chip chew chiriririii”。","habits":"这种鸟喜欢在隐蔽处活动，但在觅食时会出现在较为开阔的区域。它主要栖息于温带至亚热带的亚洲林缘地带和受干扰的地区。","breeding":"日本灰头鹀在萨哈林岛南部、千岛群岛和日本北部、中部的本州岛繁殖。非繁殖季节，它们分布于日本中部和南部的本州岛，伊豆群岛和琉球群岛。","identification":"与黑脸鹀相比，日本灰头鹀的特征在于更丰富的下体条纹，雄鸟的黑色面部和下巴，以及其独特的鸣叫声。","protection":"IUCN状态未知，未被列入华盛顿公约(CITES)或中国国家重点保护野生动物名录。","distribution":"繁殖区域位于帕拉里克远东北部，包括萨哈林岛南部和千岛群岛（俄罗斯东南部），北海道和日本北部、中部的本州岛。非繁殖区域覆盖日本中部和南部的本州岛至伊豆群岛和琉球群岛。","other":"该物种目前被视为单型种，即没有识别出任何亚种。"},{"name":"白斑黑鹀","english_name":"Lark Bunting","scientific_name":"Calamospiza melanocorys","overview":"白斑黑鹀（英文名：Lark Bunting，学名：Calamospiza melanocorys），是雀形目雀鹀科白斑黑鹀属的鸟类。广泛分布于北美中部和西部的草原地带。此鸟体型中等，被指定为科罗拉多州的州鸟。繁殖季节雄鸟通体黑色，翼上有一显著白色斑块，非繁殖季节及雌鸟则呈灰褐色，带有白色条纹。","appearance":"白斑黑鹀是一种小型鸣禽，体长14-18厘米，体重30-51克，拥有短而厚实的蓝灰色喙。繁殖季雄鸟全身黑色，翼上具大片白色斑块；雌鸟及非繁殖季雄鸟灰褐色，胸前有深色纵纹，翼上有较小的白色斑块，下体白色，两胁带暗色斑点。雌鸟在繁殖季时，羽色更偏棕灰色，上体有深色条纹，翼斑较小且边缘呈淡黄褐色。幼鸟外观似雌鸟，但整体更显淡黄色，背部有更大胆的斑点，下体条纹明显。","call":"雄鸟在领地上空飞行时发出混合哨音和颤音的歌曲，叫声为柔和的‘hoo’声。","habits":"主要栖息于开阔的草地环境，如短草草原。迁徙期间和冬季，可在各种开阔地带，从草地到沙漠再到农田找到它们，有时会形成数千只的大群。觅食时，通常在地上跳跃或行走，也会采取独特的奔跑方式追逐快速移动的昆虫。在迁徙和冬季，它们会组成数百只的大群。","breeding":"在开放的草原上繁殖，通常与鼠尾草灌丛共生，但也会在一些农业区域如干草田中筑巢和觅食。雄鸟通过空中展示飞行并鸣唱来宣告领地。巢为地面开放的杯状巢，位于草地中。社会上表现为一夫一妻制，但存在广泛的额外配偶繁殖现象。雌雄双方为争夺配偶表现出强烈攻击性。","identification":"与相似的雀鹀相比，最显著的识别特征是其厚实的蓝灰色喙和大型白色翼斑。雄鸟的全黑体色与白色翼斑形成鲜明对比，易于识别。雌鸟和非繁殖季雄鸟的白色翼斑和棕色条纹有助于与其它类似雀类区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大中南部至美国中南部的草原地带，冬季迁徙至墨西哥中北部。","other":"尽管社会上表现为一夫一妻制，但存在广泛的额外配偶繁殖现象，显示了复杂的繁殖策略。"},{"name":"狐色雀鹀","english_name":"Red Fox Sparrow","scientific_name":"Passerella iliaca","overview":"狐色雀鹀（英文名：Fox Sparrow，学名：Passerella iliaca），是雀形目雀鹀科狐色雀鹀属的鸟类。是北美地理变异性最大的雀鹀之一，拥有18个亚种，分为4大形态群：红狐色群、乌色群、石板色群和大嘴群。体长15–18.5厘米，体重25–49克，羽色从棕红到深褐、灰褐不等，胸侧具粗大的红褐色或黑褐色三角形纵纹。繁殖于北美北部和西部山地，越冬区自加拿大南部至美国中南部和墨西哥北部。因羽色、体型、鸣唱及迁徙策略差异显著，成为进化与生态研究的模式种，IUCN评为LC（无危）。","appearance":"雄雌同形，体型大。头顶至枕灰色或灰褐色，具红褐色羽缘；背、肩及腰红褐至暗褐色，具黑色纵纹；翼和尾羽红褐色；喉至上胸橙红或红褐色，胸侧及胁部具粗大的三角形深色斑点；腹部中央及尾下覆羽白色或淡黄。嘴粗短，上嘴黑褐，下嘴橙黄色先端暗色；脚粉红至红褐色。幼鸟羽色较成鸟暗淡，纵纹更模糊。四大形态群可通过羽色、尾长及嘴型区分：红狐色群整体红褐，尾短；乌色群羽色深褐近黑，尾短；石板色群背灰翼红，尾较长；大嘴群羽色似石板色群但嘴极大。","call":"鸣唱因地而异。红狐色群雄鸟通常仅1种清脆哨音歌曲，持续2.5秒左右，由7–22个音符组成；西部群体（乌色、石板色、大嘴群）则拥有3–4种甚至7种歌曲，音色更粗哑，带嗡鸣及模仿其他鸟种（如绿胁绿霸鹟、黑喉漠鹀）。警戒声为短促的“check”或“tik”，西部大嘴群发出金属声“chink”。迁徙与越冬时发出微弱“tsip”联络声。雌鸟偶发微弱歌声。","habits":"繁殖期栖息于北部针叶林缘、灌丛、溪边柳灌及火烧迹地灌丛，海拔自海平面至3000米。越冬期迁至南部灌丛、河岸林、灌丛草原及郊区灌丛。迁徙性显著，东部红狐色群迁徙距离超1000公里；阿拉斯加繁殖的乌色群可跨海迁徙至加州；西部山地群体多为短距离海拔迁徙。觅食时于林下落叶层“双抓”翻动枯叶，主食昆虫、蜘蛛及浆果种子，冬季以植物性食物为主。","breeding":"繁殖期4–7月，雄鸟先抵达并占区，雌鸟随后到达配对。巢筑于地面或低灌木中，隐蔽于植被下；雌鸟单独筑巢，2–3天完成。每窝2–5枚卵，卵淡青绿带红褐斑，孵化期12–14天，仅雌鸟孵卵。雏鸟9–10.5天离巢，尚不能飞行，由双亲继续喂养约3周。通常每年1窝，少数可能育第二窝。偶被褐头牛鹂寄生，但发生率不高。","identification":"与歌带鹀相比体型更大，嘴短而厚，上体纵纹少或无，胸斑粗大呈三角形。四大形态群内辨识：红狐色群尾明显短于翼，羽色亮红褐；乌色群全身深褐近黑，尾短；石板色群背灰色翼尾红褐，尾较长；大嘴群嘴最大，尾亦长。亚种间差异体现在羽色深浅、嘴大小及尾长梯度变化，如红狐色群中zaboria比iliaca更灰暗，乌色群中insularis较unalaschcensis更红润。","protection":"IUCN: LC（无危）。","distribution":"繁殖区：红狐色群自阿拉斯加北坡、育空、西北领地至拉布拉多和纽芬兰；乌色群繁殖于阿留申群岛、阿拉斯加半岛、海岸山系至华盛顿州西北；石板色群繁殖于不列颠哥伦比亚内陆、落基山至科罗拉多；大嘴群繁殖于俄勒冈至加州山系和下加利福尼亚北部。越冬区：红狐色群在美国中部和东南部；其余三群主要越冬于加州及下加利福尼亚北部，偶至亚利桑那。迷鸟记录至格陵兰、欧洲、俄罗斯和日本。","other":"历史上曾被认为与歌带鹀近缘，分子研究显示其与美洲树雀鹀关系更近，再与灯草鹀（Junco）-带鹀（Zonotrichia）支系相邻。化石记录见于更新世晚期宾夕法尼亚和弗吉尼亚洞穴，以及加州拉布雷亚沥青坑。"},{"name":"黑狐色雀鹀","english_name":"Sooty Fox Sparrow","scientific_name":"Passerella unalaschcensis","overview":"黑狐色雀鹀（英文名：Sooty Fox Sparrow，学名：Passerella unalaschcensis），是雀形目雀鹀科狐色雀鹀属的鸟类。其被认为是独立的进化分支，这一观点得到了mtDNA序列和单倍型数据分析的支持（Zink 1994, Zink & Kessen 1999, Zink & Weckstein 2003）。该亚种群与厚嘴狐色雀鹀和/或灰狐色雀鹀关系最为密切（Zink 1996, Zink & Weckstein 2003）。繁殖于北美阿留申群岛至阿拉斯加州西南部及不列颠哥伦比亚省西北部。","appearance":"黑狐色雀鹀的颜色强度沿地理梯度变化。上体和头部为可变的棕色，下体有相同颜色的条纹。北部个体呈沙褐色，而南部个体则为深咖啡色。体羽随纬度而变化，北方个体色彩较淡，南方个体则更为深沉。","call":"其叫声被描述为尖锐的‘zitt’或‘thik’，也有说法认为其叫声如同响亮的‘smack’，类似于狐色雀鹀。","habits":"偏好在湿润环境边缘的柳树和桤木中繁殖。","breeding":"具体繁殖行为信息未详述。","identification":"与同属其他种类相比，黑狐色雀鹀在形态、叫声和分布上存在明显差异。","protection":"IUCN状态未提及。","distribution":"繁殖区位于北美阿留申群岛和美国阿拉斯加州西南部至不列颠哥伦比亚省西北部；非繁殖区从不列颠哥伦比亚省南部延伸至美国加利福尼亚州南部。","other":"六种亚种通常被识别，从阿留申群岛的unalaschensis到华盛顿西北部的fuliginosa。现为狐色雀鹀亚种。"},{"name":"灰狐色雀鹀","english_name":"Slate-colored Fox Sparrow","scientific_name":"Passerella schistacea","overview":"灰狐色雀鹀（英文名：Slate-colored Fox Sparrow，学名：Passerella schistacea），是雀形目雀鹀科狐色雀鹀属的鸟类。北美特有的一种小型鸟类。在分类上，被归入Passerella属内的岩山族群，因其独特的形态特征而长期被认为是独立的进化分支。目前，基于遗传学分析，该物种被视为‘亚种群’，与厚喙狐色雀鹀有着显著的遗传差异。","appearance":"灰狐色雀鹀是一种体型小巧的雀类，其最明显的特征是灰色的头部和披肩，搭配着褐色的翅膀和胸部条纹，以及醒目的红褐色尾巴。喙部细小，适应其特定的生态位。","call":"灰狐色雀鹀的叫声被描述为尖锐的‘klink’声，类似拍打的声音，这在识别同类时起到关键作用。","habits":"它们偏好在高山区域的矮柳丛生环境中繁殖，从加拿大西北部的内陆延伸至美国的内华达和加州东部。冬季，它们会迁移到较低海拔的地区，如美国加州至墨西哥的下加利福尼亞州北部以及亚利桑那州南部。","breeding":"灰狐色雀鹀倾向于在湿地边缘筑巢，但对具体植物种类的要求不高，显示了它们对环境的适应性和灵活性。","identification":"灰狐色雀鹀与厚喙狐色雀鹀在形态上相似，但通过mtDNA序列和单倍型数据可以明确区分。相较于狐色雀鹀，它们的关系更为密切，尽管在地理分布和生态习性上存在差异。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要集中在北美，从加拿大西南部至美国中西部；非繁殖期间，则广泛分布于美国加州至墨西哥下加利福尼亞州北部和亚利桑那州南部。","other":"尽管灰狐色雀鹀的亚种在形态上差异不大，但遗传学研究表明，它们的分化可能较新，反映出近期的进化过程。现为狐色雀鹀亚种。"},{"name":"厚嘴狐色雀鹀","english_name":"Thick-billed Fox Sparrow","scientific_name":"Passerella megarhyncha","overview":"厚嘴狐色雀鹀（英文名：Thick-billed Fox Sparrow，学名：Passerella megarhyncha），是雀形目雀鹀科狐色雀鹀属的大型鸣禽。主要分布于北美，包括美国俄勒冈州西南部至加利福尼亚州，其独特的大型喙部是显著的外部特征。","appearance":"厚嘴狐色雀鹀的羽毛与普通的狐色雀鹀相似，但拥有更广阔的蓝灰色头罩和较为暗淡的锈色尾巴。最引人注目的是它们异常巨大的喙，相较于同属的小喙种类，显得尤为突出。喙的颜色也有所区别，钢蓝色而非黄色下颌。","call":"它们具有独特的叫声，是一种高音调的平直吱吱声，类似于加州灌丛鸟的叫声。","habits":"厚嘴狐色雀鹀主要栖息于山地环境，繁殖于美国俄勒冈州南部至加利福尼亚州东部的山区。冬季，它们会迁移到美国加利福尼亚州中部、南部以及墨西哥下加利福尼亞州的西北部。","breeding":"关于厚嘴狐色雀鹀的繁殖行为具体细节尚需进一步研究，但已知它们在特定的山地环境中繁殖。","identification":"与普通狐色雀鹀相比，厚嘴狐色雀鹀的喙更大，颜色为钢蓝色，而非黄色。此外，它们的头部覆盖着更多的蓝灰色羽毛，尾巴颜色较为暗淡。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于美国俄勒冈州西南部和加利福尼亚州，非繁殖区域则在美国加利福尼亚州中部、南部以及墨西哥下加利福尼亞州的西北部。","other":"尽管厚嘴狐色雀鹀与普通狐色雀鹀在接触带存在杂交现象，但基因流动极为有限。现为狐色雀鹀亚种。"},{"name":"歌带鹀","english_name":"Song Sparrow","scientific_name":"Melospiza melodia","appearance":"歌带鹀的上体呈棕色，背部有黑色条纹，下体白色，胸前有一深棕色的斑点。头部为棕色，面部灰色，贯眼纹明显。尾部圆润，棕色。体型随亚种不同而变化显著，从与加州唧鹀相当的大型个体到与稀树草鹀大小相近的小型个体都有。喙短而壮，适合啄食种子。","call":"歌带鹀的鸣唱通常由几个响亮、间隔开的“chip”音符开始，随后是颤音或嗡嗡声。其鸣唱清晰、精确，富有变化，包含多种音调和即兴变奏。","habits":"歌带鹀偏好栖息于灌木丛生的沼泽和盐沼环境，也常见于人类活动频繁的地区，如郊区、农田和路旁。它们在地面或低矮植被中觅食，以昆虫和种子为主食。夏季主要吃昆虫，冬季转向以种子和果实为主。在有足够灌木覆盖的领地内的鸟儿冬季存活率更高，繁殖成功率也更高。","breeding":"歌带鹀在春季进行繁殖，通常在地面或灌木中筑巢。雌鸟负责筑巢和孵卵，每次产卵3到5枚，平均孵化期为13至15天。繁殖期间，雄鸟通过复杂的鸣唱来宣示领地和吸引雌鸟。","identification":"歌带鹀与林氏带鹀相比，后者尾部更短且呈灰色，头上的图案不同，棕色面部形成明显的角状斑块。与稀树草鹀区别在于，后者眉纹黄色，且尾部分叉。","protection":"IUCN：LC（无危）","distribution":"歌带鹀在北美广泛分布，包括加拿大大部分地区、美国全境以及墨西哥中部。它们在繁殖季节遍布加拿大和美国，冬季时北方种群南迁至美国南部和墨西哥，与当地不迁徙的种群混合。","other":"歌带鹀的24个可诊断亚种使其成为北美最具地区变异性的鸟类之一。"},{"name":"林氏带鹀","english_name":"Lincoln's Sparrow","scientific_name":"Melospiza lincolnii","overview":"林氏带鹀（英文名：Lincoln's Sparrow，学名：Melospiza lincolnii），是雀形目雀鹀科歌带鹀属的鸟类。小型的北美原生雀鸟。以隐蔽的特性著称，偏好茂密的灌木覆盖地，特别是在苔藓丰富的环境筑巢。由于其独特的繁殖习性及隐秘的生活方式，林氏带鹀的许多生态习性仍待进一步研究。其名称源于John James Audubon在1833年拉布拉多探险中将其命名，以纪念他的旅伴Thomas Lincoln。","appearance":"林氏带鹀体型略小于歌带鹀，具有精细的条纹特征，如同精致的钢笔画而非油画般粗犷。头部呈灰褐色，带有细黑条纹和鲜明的灰色中线，两颊和颈侧均匀灰白，眼圈淡黄色。胸部呈现明亮的浅黄褐色，与白色的喉部和腹部形成对比。背部橄榄褐色，翅膀和尾巴边缘锈色，翼展公式P9 > P4。幼鸟外观类似沼泽带鹀，但可通过翼展公式区分。","call":"林氏带鹀以其丰富、宛若鹪鹩的鸣唱而最易识别，歌声甜美，咕噜声中夹杂着变化的音调，先由急促的高音开始，随后转为低沉的颤音。","habits":"林氏带鹀栖息于亚高山和山地地带，偏爱湿润的灌木丛、沼泽和苔藓为主的环境。它们在繁殖季节通常独居，活动于地面和柳树基部觅食，而在较高处的树木和柳树枝上歌唱。迁徙期间，它们会出现在灌木丛和河岸地带，利用大平原和城市郊区作为迁徙路径。","breeding":"繁殖期在春季，雄鸟首先抵达繁殖地，通过歌唱吸引配偶。雌鸟会在低矮的柳树或山毛榉下，通常在泥炭苔藓的凹陷处建造巢穴，巢为草或莎草制成的浅开杯状。一窝通常产卵3-5枚，卵色为淡绿色至绿白色，带有红褐色斑点。雌鸟负责孵卵，孵化期约12-14天，雄鸟不参与孵化。雏鸟出生时无助，约9-12天后离巢，但仍需父母照顾2-3周。","identification":"与歌带鹀相比，林氏带鹀胸部颜色更亮，条纹更细，翼展公式不同（P9 > P4）。与沼泽带鹀的区别在于成鸟胸部无条纹，而幼鸟的翼展公式和冠部色彩可作区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要分布在加拿大、阿拉斯加、美国东北部和西部。冬季迁移至中美洲，包括墨西哥和北中美洲的部分地区。在多米尼加共和国和海地的山区也有记录。","other":"林氏带鹀因其偏好高海拔和亚北极生态系统，是研究温带鸣禽生命史中生物与非生物压力相互作用的良好模型。"},{"name":"沼泽带鹀","english_name":"Swamp Sparrow","scientific_name":"Melospiza georgiana","overview":"沼泽带鹀（英文名：Swamp Sparrow，学名：Melospiza georgiana），是雀形目雀鹀科歌带鹀属的鸟类。一种中等体型的新世界雀科鸟类，与歌带鹀关系密切。分布于北美中北部至东北部，冬季南迁至墨西哥东北部。沼泽带鹀以其清晰、缓慢的液滴状颤音闻名，通常在难以接近的湿地环境中发现。","appearance":"成年沼泽带鹀上体呈锈色条纹，混合有缓冲色和黑色，下体灰色无斑纹，腹部较浅，喉部白色。翅膀显眼的锈色是其特征之一，多数雄鸟和少数雌鸟拥有锈红色的顶冠。脸部灰暗，眼睛周围有深色线条。喙短而圆锥形，腿较长。幼鸟和冬季成鸟通常具有两条棕色顶冠条纹，大部分灰色被缓冲色替代。","call":"沼泽带鹀的鸣唱是一种缓慢的单调颤音，比奇普雀的颤音更慢。雄鸟能够发出多种不同的颤音。常见的叫声是一声响亮的'chip'，类似于鹟的叫声。","habits":"沼泽带鹀主要栖息在北美东部和加拿大中部的湿地，包括咸水沼泽。它们的巢穴建在靠近地面或水面的植被中，通常由雌鸟每年建造新的巢穴。它们在冬季主要以果实和种子为食，而在繁殖季节则主要捕食节肢动物。","breeding":"繁殖期，雌鸟会建造一个新的巢，平均每次产卵四枚。在离开巢穴时，雌鸟会发出一系列'chip'声，可能是为了抵御配偶或邻近雄鸟的攻击。","identification":"沼泽带鹀与林氏带鹀最为相似，但林氏带鹀胸部和侧翼有明显的条纹，缺乏锈色顶冠，脸颊和脸灰色，翅膀覆羽边缘为丰富的锈红色。林氏带鹀略大，翼展较长，尾巴较短，翼式不同。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美中北部和东北部，冬季迁徙至墨西哥东北部。","other":"沼泽带鹀的数量因部分繁殖区的栖息地丧失而有所下降。"},{"name":"红领带鹀","english_name":"Rufous-collared Sparrow","scientific_name":"Zonotrichia capensis","overview":"红领带鹀（英文名：Rufous-collared Sparrow，学名：Zonotrichia capensis），是雀形目雀鹀科带鹀属的鸟类。分布广泛的美国雀科鸟类，从墨西哥东南部到阿根廷南部，以及多米尼加和海地的Hispaniola岛都有其踪迹。此鸟拥有独特的红棕色领圈，头部呈现黑白相间的条纹，幼鸟下体则带有纵向的条纹。适应性强，常见于人类居住区附近的各种开放生境。","appearance":"红领带鹀体长约13.5至15厘米，体重约20至25克。成鸟具有灰色的喙，头部为灰色，两侧有宽黑条纹，眼周和脸颊下方有细黑条纹。颈后和胸部侧面呈红棕色，形成明显的红领圈。上体呈棕褐色，散布黑色条纹。两翼上有两个白色翼斑。喉部白色，下体颜色从灰白过渡至棕色，侧腹至尾下覆羽处颜色加深，胸前有黑色斑块。幼鸟外观较暗淡，头纹不明显，呈棕色底色，缺乏红领圈，下体有条纹。","call":"红领带鹀的鸣唱简单，由一系列哨音和结尾的颤音组成。叫声甜美而哀婉，例如“see-seeur tee-te-e-e-e, seeeeur tse-e-e-e-e”。在一些地方，颤音可能减少至几个音符。雄鸟的叫声在不同地区和季节中变化多样，热带地区的雄鸟通常仅有单一的刻板歌曲，而在厄瓜多尔和哥斯达黎加的雄鸟可能有多达七种不同的歌曲。","habits":"红领带鹀广泛分布于各种开放和半开放生境，如村庄、城镇、农田、灌木丛和荆棘篱笆。它们在地面和灌木丛中觅食，有时会以小群的形式活动。它们能适应城市和郊区环境，但在亚马逊盆地的密林中较少见。在南美，它们在海拔600至4000米之间最为常见，而在南美南部和东部地区，则常出现在近海平面的地带。","breeding":"繁殖季节受食物供应和降雨量影响，一般在雨季开始时，雌鸟开始筑巢。巢为开放式的杯状，由植物材料构成，内部铺有细草。巢通常建在地面上的植被中，低矮的树木或灌木中，或墙上的凹陷处。雌鸟产下2至3枚浅绿蓝底、带红褐色斑点的蛋，蛋长约为19至21毫米，宽15至16毫米，重2.6至2.8克。孵化期为12至14天，期间雌鸟会花费三分之二的白天时间在巢中孵卵或照顾巢穴。雄鸟参与喂养雏鸟，雏鸟在巢中停留约两周。","identification":"红领带鹀与同属的其他物种的区别在于其红棕色的领圈和头部的黑白条纹。不同亚种在体型、色彩深度、头部图案等方面有所差异，如costaricensis亚种条纹更明显，rufous领圈更清晰；septentrionalis亚种条纹较少，rufous领圈不那么明显；antillarum亚种黑胸带更宽，rufous领圈较小，翼弯处黄色；macconnelli亚种是最暗的亚种，冠部几乎全黑；inaccessibilis亚种rufous领圈更深，灰色胸部更深，侧腹颜色更深。","protection":"IUCN：LC（无危）","distribution":"红领带鹀广泛分布于中美洲和南美洲，从墨西哥南部至阿根廷南部，以及多米尼加共和国和海地的Hispaniola岛。在北美洲的最北端，它们主要分布在高海拔地区，而在南美洲的南端，它们可以下至近海平面。在Guiana Shield地区较为稀少，主要出现在一些特普伊山和圭亚那的Pakaraima山脉。","other":"红领带鹀在历史上可能曾广泛分布于加勒比地区，但随着气候变暖，它们现在主要局限于Hispaniolan山脉的最高处。此外，它们也被发现在阿鲁巴和其他一些加勒比岛屿上。"},{"name":"赫氏带鹀","english_name":"Harris's Sparrow","scientific_name":"Zonotrichia querula","overview":"赫氏带鹀（英文名：Harris's Sparrow，学名：Zonotrichia querula），是雀形目雀鹀科带鹀属的鸟类。以加拿大中北部的北方森林和灌木丛为繁殖地，是加拿大唯一的本土繁殖鸟类。冬季迁徙至美国大平原州，从南达科他州南部到德克萨斯州中部。物种命名纪念了美国业余鸟类学家Edward Harris（1799–1863）。","appearance":"赫氏带鹀是最大家族Passerellidae中的雀科成员之一，全长约17至20厘米，翼展27厘米，体重介于26至49克之间。标准测量显示，翼弦长度7.7至9.2厘米，尾长7.6至8.8厘米，喙长1.1至1.4厘米，跗跖长度2.2至2.5厘米。成鸟在繁殖季节具有明显的粉红色喙和黑色头部、面部、喉部及上胸，与灰色侧面形成鲜明对比。背部棕色，有厚重的黑色条纹。有两道白色翼斑。非繁殖季节的成鸟更偏褐色，黑色标记减少或消失，头和喉部常有白色的鳞片状斑点。幼鸟的黑色比所有成鸟羽毛都少，通常有白色的下巴和喉咙，一条黑色的颊纹和宽大的模糊黑胸带。","call":"赫氏带鹀的鸣唱通常从高枝发出，由一系列清晰的高音颤音组成，随后是一系列更高或更低音调的颤音。它们还会发出响亮、金属质感的‘chink’声，以及一些变化的音乐般的叽叽喳喳声。","habits":"赫氏带鹀在春季迁徙大约开始于二月底，五月份抵达繁殖地。它们在矮小的针叶林和邻近的灌木丛中繁殖，尤其在大北方森林中，云杉林与苔藓沼泽相邻的地带。冬季迁徙至开阔的林地、林缘和空地、树篱、密集的河岸灌木丛和刷堆周围。它们在城市和乡村花园的喂食器中常见。它们主要在地面觅食，刮擦落叶和土壤寻找食物。饮食以种子为主，包括莎草、禾本科植物和香蒲的种子，以及果实、松针、花蕾和花朵。昆虫幼虫是其饮食的重要组成部分，尤其是甲虫、苍蝇、蜜蜂、蚂蚁、蛾子、蝴蝶、蜘蛛、蝉、蚜虫和叶蝉。","breeding":"繁殖对建立约2公顷的领地。巢通常在6月初至中旬建造。卵通常在6月底至7月产下，取决于雪融化的时间。巢置于地面隐蔽处，下方是浓密的灌木或小针叶树下，或厚草丛中的苔藓洼地。巢由树枝、草、苔藓和地衣制成，内衬细草。每窝产3至5枚卵，颜色为绿或灰色，带有不同程度的小红棕色斑点。卵平均尺寸为22.2×16.5毫米，重约3.3克。孵化期约为13.5天。雏鸟出生时重约3.1克。幼鸟将在大约8至10天后离巢，时间在7月4日至7月13日之间。离巢后约3周，幼鸟独立于父母。如果首次筑巢被破坏，可能会产下第二窝，延长父母照顾期约3天。由于其孤立的繁殖区域，赫氏带鹀是研究最少的北美雀类之一。","identification":"赫氏带鹀在繁殖季节与其他种类的区别在于其独特的粉红色喙和黑色头部、面部、喉部及上胸的特征。非繁殖季节的成鸟与白喉带鹀和白冠带鹀在外观上有差异，但最明显的区别是赫氏带鹀的深色王冠、胸部斑点和粉红色喙。幼鸟与冬季成鸟相似，但喉部主要是白色，脸部和王冠上的黑色较少。冬季，可能与铁爪鹀混淆，但长嘴雀尾巴较短，尾羽边缘白色，翅膀上部覆盖着丰富的赤褐色，且严格在开阔地面活动。","protection":"IUCN：NT（近危）","distribution":"繁殖区域位于北美加拿大中北部和中部。非繁殖区域在美国中南部，从南达科他州南部延伸至德克萨斯州中部。","other":"赫氏带鹀的寿命可达11年零8个月。巢穴的天敌包括北极地松鼠（Spermophilus parryii）、黄鼠狼（Mustela erminea）。灰噪鸦、西方灰伯劳和灰背隼是巢穴（包括雏鸟和成鸟）的严重威胁。冬季，纹腹鹰和美洲雕鸮是已知的捕食者。赫氏带鹀受到全球气候变化的影响，导致其栖息地发生变化，包括森林火灾增加和土壤质量下降。"},{"name":"白冠带鹀","english_name":"White-crowned Sparrow","scientific_name":"Zonotrichia leucophrys","overview":"白冠带鹀（英文名：White-crowned Sparrow，学名：Zonotrichia leucophrys），是雀形目雀鹀科带鹀属的鸟类。中型的北美洲本地鸟类。其最显著的特征是灰色脸部配以黑白相间的头纹，分布广泛，从北方的针叶林到西部山脉和太平洋沿岸都有其踪迹。在北部地区繁殖的种群会迁徙至美国南部乃至墨西哥中部过冬。","appearance":"成年白冠带鹀拥有约15-16厘米的体长，头部饰有鲜明的黑白色条纹，上体棕色条纹，下体灰白色，尾羽较长。嘴部颜色从粉色到黄色不等，具有明显的个体差异。幼鸟的头部条纹呈棕色和灰色，与成鸟形成对比。","habits":"白冠带鹀偏好灌木丛生的环境，如海滨灌木带、农田边缘、荒地及草坪，较少出现在密林中。它们常在地面或低矮植被中觅食，冬季会与其他小型鸟类混群。食物主要包括种子、植物部分和昆虫。","breeding":"繁殖季节，白冠带鹀会在灌木下的低处或地面筑巢，产下3至5枚带有褐色斑点的灰色或蓝绿色蛋。北方的种群会向南迁徙至美国南部或墨西哥。","identification":"与白喉带鹀相比，白冠带鹀没有明显的白色喉咙标记，且头部的黑白条纹更为醒目。不同的亚种之间在嘴部颜色和头纹的清晰度上有细微差异。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要位于北美北部，包括加拿大北部、美国西部和太平洋沿岸。非繁殖期分布至美国南部直至墨西哥中部。"},{"name":"白喉带鹀","english_name":"White-throated Sparrow","scientific_name":"Zonotrichia albicollis","overview":"白喉带鹀（英文名：White-throated Sparrow，学名：Zonotrichia albicollis），是雀形目雀鹀科带鹀属的鸟类。冬季南迁至美国南部。其独特的头部图案和白色喉咙是其显著的外部特征。分布于加拿大西北部和西部至东南部，以及美国东北部和中北部。","appearance":"这种大型sparrow长度在15到19厘米之间，翼展约23厘米，体重介于22至32克，平均26克。它们具有长尾巴和相对较小的喙。头部有明显的黑白条纹或棕白条纹，黄色斑点位于眼睛和喙之间，以及白色的喉咙。上半身呈红褐色，下半身为灰色，有灰色的喙和明亮的眼睛。翅膀为红褐色，有两个明显的白色翼条。雌雄相似。","call":"白喉带鹀的鸣唱常被描述为'Oh-sweet-canada-canada'或'Old-Sam-Peabody-Peabody'的口哨声，声音清脆，通常在树梢或灌木丛顶上鸣叫。","habits":"白喉带鹀在繁殖季节居住在针叶林或混合森林中，靠近空旷地带。迁徙期间和冬季，它们出现在树林、森林边缘、灌木丛和多草的田野中。它们在地面上觅食，主要以种子、昆虫和浆果为食。它们会拜访喂食站。","breeding":"它们在中央加拿大和新英格兰地区繁殖，巢建在地面下的灌木下或低矮树木中，产三到五枚带有棕色标记的蓝或绿白色蛋。","identification":"白喉带鹀与白冠带鹀有明显区别，白喉带鹀的喉咙有白色标记和黄色眼斑。有两种成年羽毛变体，白色条纹型和棕条纹型，它们几乎总是与相反颜色的形态配对繁殖。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要在北美，覆盖加拿大西北部和西部至加拿大东南部，以及美国东北部和中北部。冬季迁徙至墨西哥北部。","other":"白喉带鹀是北美东部冬季最丰富的本土鸟类之一，偶尔作为罕见迷鸟出现在西欧。"},{"name":"金冠带鹀","english_name":"Golden-crowned Sparrow","scientific_name":"Zonotrichia atricapilla","overview":"金冠带鹀（英文名：Golden-crowned Sparrow，学名：Zonotrichia atricapilla），是雀形目雀鹀科带鹀属的鸟类。因其独特的鸣叫声而得名。这大型的带鹀，以黑色条纹环绕黄色冠羽为显著特征，尤其是在繁殖季节的成年个体上更为明显。金冠带鹀广泛分布于北美西部，从北美的阿拉斯加至加拿大西南部繁殖，冬季迁徙至美国西海岸乃至墨西哥西北部。","appearance":"金冠带鹀体型较大，尾长，嘴灰色，成年鸟背部呈灰褐色，布满宽大的棕色黑色条纹，臀部灰棕色，翅膀和尾巴为棕色，有两道白色翼纹。头部两侧、喉咙和胸部为灰色至淡灰色，有时带有微弱的锈色。繁殖季成鸟具黑色冠羽，中间被宽阔的黄色条纹分割，向后转为淡灰色。幼鸟更显棕色，但仍可见黄色冠羽中央。雌雄相似，但在繁殖季雄鸟的黄色冠羽更为鲜艳。","call":"其鸣唱为几声清晰的哨音，音调逐渐下降，形成一种忧郁的旋律，常被描述为\"oh-dear-me\"或\"I'm so weary\"。在春季迁徙前和秋季迁徙后，以及繁殖季节，这种鸣叫声尤为频繁。","habits":"金冠带鹀在繁殖季节栖息于低矮灌木丛生的苔原边缘或北方森林边缘。冬季则迁徙至灌木丛、灌木丛地带、公园、花园和其他开阔地带。它们在地面和低矮植被中寻找种子和昆虫为食，偶尔也会访问喂食器。金冠带鹀在迁徙和冬季时常常成群活动，与白冠带鹀混群。","breeding":"繁殖期从5月末持续到8月初。雄鸟会在繁殖地的显眼位置整天鸣唱。雌鸟建造一个厚重的杯状巢，通常位于地面或低矮树枝上，由干燥的植物材料构成，内衬毛发、细草和羽毛。一窝通常产卵5枚，卵呈淡绿色，有红褐色斑点，孵化期约为11至14天。幼鸟孵化后12天内离巢。双亲共同喂养幼鸟。","identification":"金冠带鹀在繁殖羽时容易识别，其黑色和黄色的头饰是显著特征。非繁殖期和幼鸟可能与白冠带鹀或白喉带鹀混淆，但可通过其暗色(而非浅粉色或黄色)的喙、较大的体型、无斑点的喉咙和缺乏淡色中央冠纹来区分。此外，金冠带鹀比家麻雀更大，羽毛颜色更深，尾巴更长，额头通常有暗黄色的羽毛。","protection":"IUCN：LC(无危)","distribution":"繁殖于美国阿拉斯加州西部至加拿大西南部，冬季迁徙至美国西海岸和墨西哥西北部。","other":"金冠带鹀是北美西部冬季最常见的鸟类之一，曾因群体聚集和食用花园和农田中的蔬菜和花卉而被视为破坏性物种。近年来，冬季个体数量似乎有所增加，但饮食习惯基本未变，已不再被列入害鸟名单。"},{"name":"黄眼灯草鹀","english_name":"Volcano Junco","scientific_name":"Junco vulcani","overview":"黄眼灯草鹀（英文名：Volcano Junco，学名：Junco vulcani），是雀形目雀鹀科灯草鹀属的鸟类。是北美特有种，以明亮的黄色虹膜而著称，头部和下体呈淡灰色，背部黑色条纹和棕色相间。分布于中美洲高海拔地区，主要在哥斯达黎加和巴拿马西部的火山地带。","appearance":"成鸟性状相似，头部、颈背灰橄榄色，眼周和面颊黑或石板黑色，形成明显的面具。背部、肩羽、臀部和上尾覆羽呈褐色，有黑色条纹。翅膀暗色，边缘呈淡褐色。下体淡灰色，喉部较胸部略淡，两胁带淡褐色。幼鸟上体条纹更重，下体污灰色，有暗色条纹。","call":"叫声包括细薄的'tseee'或更清脆的'wheew'。其鸣唱混合了尖叫声和嗡嗡声：'k’chew chu k’wee chip chip chueee'。","habits":"栖息于高海拔的开阔草地或灌木丛，通常在3000米以上，但在哥斯达黎加加勒比坡的孤立群体可低至2100米。活动于地面，常单独或小群出现，以种子、落地浆果、昆虫和蜘蛛为食。","breeding":"筑巢于地面，通常位于树根、灌木或岩石下，或植被覆盖的斜坡上的洞穴。巢为整洁的杯状，内部铺垫。雌鸟产下两个淡蓝色带有褐色斑点的蛋。","identification":"与其他灯草鹀属物种相比，其尾部几乎全黑，上体有黑色条纹，虹膜黄色，喙和腿粉色。与黄眼灯草鹀地理隔离的墨西哥灯草鹀和淡墨西哥灯草鹀也有黄色虹膜，但上体无条纹，尾部有白色外侧尾羽。","protection":"IUCN：LC（无危）","distribution":"繁殖区域：哥斯达黎加和巴拿马西部，主要分布在火山地区。非繁殖区域：无特别提及。","other":"黄眼灯草鹀的自然历史研究尚浅，其生态习性有待进一步探索。"},{"name":"暗眼灯草鹀","english_name":"Dark-eyed Junco","scientific_name":"Junco hyemalis","overview":"暗眼灯草鹀（英文名：Dark-eyed Junco，学名：Junco hyemalis），是雀形目雀鹀科灯草鹀属的鸟类。是北美洲极为常见的一种小型灰色新世界雀鸟。广泛分布于北美洲温带至北极地区，展现显著的地理变异。该物种以圆头、长尾和淡粉色喙为特征，腹部白色，尾羽外侧显白色。雌雄羽毛颜色存在差异，雄鸟颜色更深。繁殖季节栖息于北美针叶林或混交林，冬季分布于美国南部至墨西哥。","appearance":"暗眼灯草鹀成鸟体长13-17.5厘米，翼展18-25厘米，体重18-30克。头部、颈部和胸部一般呈灰色，背部和翅膀为灰色或棕色，腹部白色。喙通常为浅粉红色。幼鸟有浅色条纹，直至2-3个月后换为成鸟羽毛。雄鸟较雌鸟颜色更深，雌鸟可能带有红棕色的侧面。","call":"鸣叫为颤音，与棕顶雀鹀相似，但暗眼灯草鹀的歌声更为复杂。","habits":"暗眼灯草鹀繁殖于北美的针叶林或混交林区，冬季集群活动，主要以昆虫和种子为食。巢筑于地面或灌木丛中隐蔽处，非繁殖期常集群。喙边缘微向内弯，切合线中略有缝隙。","breeding":"每年繁殖季，暗眼灯草鹀会筑巢于地面或低矮的灌木丛中，巢为杯状，由细草和毛发衬里。每窝产四枚蛋，孵化期12-13天，幼鸟在11-14天后离巢。","identification":"与其他同属物种相比，暗眼灯草鹀的白色外尾羽和高音颤鸣是主要识别特征。雄鸟与雌鸟颜色深浅有别，幼鸟具浅色条纹。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北美北部和西部，非繁殖区分布在美国南部至墨西哥。部分群体为永久居民或高度迁移，冬季常见于城镇周边。","other":"暗眼灯草鹀的系统分类仍在研究中，已知至少15个亚种，其中一些曾被视为独立物种。"},{"name":"瓜岛灯草鹀","english_name":"Guadalupe Junco","scientific_name":"Junco insularis","appearance":"体长约14厘米，体重数据未公布。外观最接近暗眼灯草鹀的亚种mearnsi。相较于暗眼灯草鹀复合群中的成员，瓜岛灯草鹀体型较小，喙较长（雄鸟平均9.3毫米，而J. h. hyemalis为8.02毫米），脚更大，翅膀更短（雄鸟平均69.3毫米，而J. h. hyemalis为78.2毫米），尾巴也较短（雄鸟平均62.6毫米，而J. h. hyemalis为68.1毫米），尾羽外侧三枚羽片上的白色较少。头部灰暗至棕色，脸部深色，下巴和喉咙较浅的灰色；背部呈暗褐色；两胁宽幅带有粉红肉桂色标记。性别间外观相似。虹膜深棕色；喙蓝白色；腿和脚呈深棕色、灰肉色或深粉色。","call":"发出高音、尖锐的'sik'声，以及一系列持续的chip音，通常穿插着buzz和trill声。","habits":"广泛适应各种生境，前提是存在本土植被。栖息于瓜达卢佩岛北端的蒙特雷松林、海峡岛橡树林和瓜达卢佩柏树林，海拔可达1400米；在岛屿东北侧海平面附近的野烟草灌木丛中也能发现它们的身影。主要以昆虫和地面获取的种子为食。","breeding":"繁殖季节为1月至6月，可能一年两次繁殖。筑巢地点隐蔽，位于地面或岩石裂缝中，至少有一次记录显示在一棵松树的裂缝中，离地面约2米。每窝产卵3枚，卵长约为20毫米×15毫米，颜色为浅绿白色，带红褐色斑点。关于孵卵和雏鸟期的时长信息缺失。","identification":"与暗眼灯草鹀的近亲J. hyemalis mearnsi相比，瓜岛灯草鹀的冠部和胸部（通常）稍暗，腹部的白色较暗淡且面积较小。此外，其叫声和歌曲与暗眼灯草鹀有显著差异。","protection":"IUCN：EN（濒危）","distribution":"仅分布于墨西哥西北部的瓜达卢佩岛（Guadalupe Island）。","other":"历史上的数量因过度放牧和外来物种（如野山羊和野猫）的影响而大幅下降，但随着野山羊被清除，种群数量似乎正在恢复。"},{"name":"墨西哥灯草鹀","english_name":"Yellow-eyed Junco","scientific_name":"Junco phaeonotus","overview":"墨西哥灯草鹀（英文名：Yellow-eyed Junco，学名：Junco phaeonotus），是雀形目雀鹀科灯草鹀属的鸟类。主要分布在墨西哥，延伸至美国亚利桑那州和新墨西哥州南部山区。通常不迁徙，但在冬季会移至附近较低海拔处。雌鸟每年两到三次在干草筑成的开放巢中产下3至5枚淡灰色或蓝白色的蛋，孵化期约15天，雏鸟两周后即可离巢。其饮食以种子、浆果和昆虫为主。","appearance":"这是一种中等体型的雀类，总长14至16厘米，体重16至23克，雄鸟比雌鸟大5%，外观上两者相似。成年个体头部和尾羽上覆羽呈灰色，背部、翼上大覆羽和三级飞羽对比鲜明地呈现锈红色。黄色的眼睛与黑色的颊斑形成强烈对比。下巴和喉部为浅灰色，腹部和下尾覆羽白色，胁部略带橄榄色。尾巴深色，外侧尾羽白色。喙部双色，上颚黑色，下颚黄色；腿和脚淡黄褐色。幼鸟与成鸟相似，但眼睛暗色，头部有细微的暗色条纹。","call":"雄鸟会从高处的栖木发出2至3部分组成的颤音鸣唱。","habits":"栖息于山地松林和松栎混交林，海拔从4000至11000英尺。非繁殖季节会向低海拔迁移，与暗眼灯草鹀形成冬季群落。主要在地面觅食，通过翻找落叶层寻找种子和昆虫。","breeding":"每年繁殖期，雌鸟会在干燥的草丛中筑巢，产下3至5枚蛋，孵化期约15天，雏鸟两周后即可离巢。","identification":"与暗眼灯草鹀中的'灰头'亚种（J. h. dorsalis和J. h. caniceps）相似，但可通过黄色的眼睛、更广泛分布的锈色翼上覆羽和三级飞羽以及双色的喙部区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在墨西哥，向北延伸至美国西南部的亚利桑那州和新墨西哥州，南至危地马拉。在亚利桑那州南部和新墨西哥州西南部，它们维持着全年的繁殖领地。","other":"适应力强，容易在圈养环境中生存，是行为研究的理想物种。"},{"name":"淡墨西哥灯草鹀","english_name":"Baird's Junco","scientific_name":"Junco bairdi","overview":"淡墨西哥灯草鹀（英文名：Baird's Junco，学名：Junco bairdi），是雀形目雀鹀科灯草鹀属的鸟类。仅分布于墨西哥下加利福尼亚州南部的拉拉古纳山脉。其头部呈淡灰色，背部锈红色，翼部亦有锈色延伸，尾羽外侧白色显著，双眼金黄色，喙部一半黑一半黄。该物种体型中等，约15厘米长，雄鸟平均重量18克。栖息于海拔1200至1900米的半干旱橡树林和混合松橡木林中。","appearance":"淡墨西哥灯草鹀的头部为蓝灰色，眼周黑色，喉咙、胸部及上腹部灰白，下腹部及尾下覆羽变白，两胁淡肉桂紫红色，背部棕色肉桂色，臀部及尾上覆羽橄榄沙色。尾羽外侧白色，在飞行中尤为显眼。虹膜金黄色，喙肉色至黄色肉色，基部暗色，腿肉色。雌雄色彩相似，但雄鸟在翼、尾及跗跖长度上平均较大。幼鸟头部及上体棕色，具黑色条纹。","call":"其鸣唱为悦耳的颤音鸣唱，持续约1.5至2秒，与墨西哥灯草鹀明显不同。叫声为尖锐的“tsk”或“tsik”。","habits":"淡墨西哥灯草鹀为留鸟，尽管部分个体可能在冬季迁至较低海拔。它们主要在地面觅食，以昆虫、其他无脊椎动物和种子为食。","breeding":"巢为开放杯状，由干草和根须构成，置于地面浅凹处或低矮树木或灌木中。已知窝卵数为两个，蛋壳呈白色带红褐色斑点。孵化期和其他繁殖细节未知，预计与墨西哥灯草鹀相似。","identification":"与墨西哥灯草鹀相比，淡墨西哥灯草鹀体型较小，整体羽毛颜色更淡，脸颊和背部对比鲜明。","protection":"IUCN：NT（近危）","distribution":"分布于墨西哥下加利福尼亚州南部的拉拉古纳山脉，繁殖于海拔1500米以上的松橡木森林。","other":"原被归类为墨西哥灯草鹀的一个亚种，后经研究确认为独立物种。"},{"name":"稀树草鹀","english_name":"Savannah Sparrow","scientific_name":"Passerculus sandwichensis","overview":"稀树草鹀（英文名：Savannah Sparrow，学名：Passerculus sandwichensis），是雀形目雀鹀科稀树草鹀属的鸟类。广泛分布于北美的小型雀形目鸟类。在开放的草地环境中常见，其羽毛颜色变化大，但通常具有独特的黄色眼斑。栖息于北美各地，从加拿大至危地马拉，包括美国北部、墨西哥及中美洲。繁殖季节时，雄鸟会发出持续的虫鸣般的歌声，吸引伴侣。","appearance":"稀树草鹀为中等体型，尾部较短，羽毛颜色因地理位置而异，但总带有条纹。头部较小，体态丰满，冠羽有时竖起形成小尖顶。上体呈褐色，带黑色条纹；下体白色，胸部及侧腹有细密的褐色或黑色条纹。脸部图案明显，前眼处有黄色斑块，但某些个体可能不明显或缺失。喙短而锥形，腿色偏粉。雌雄羽毛相似，但雄鸟平均比雌鸟大5%左右。","call":"稀树草鹀在繁殖季节会发出持续的、类似昆虫的鸣唱声，用于吸引伴侣和领地标记。","habits":"稀树草鹀主要栖息于开阔地带，如牧场、草地、沼泽、海岸沙丘及冻土带。它们倾向于选择比歌鹀更为开放的栖息地，且体型更小，尾部更短。夏季以昆虫和其他节肢动物为主食，冬季和迁徙期间则转向地面的小种子。大部分种群迁徙，但西南地区的盐沼群落则主要为留鸟。","breeding":"稀树草鹀在繁殖季节表现出约50%的年死亡率，成鸟倾向于回到同一繁殖地，尤其在岛屿群体中，鸟类常返回出生地。这种强烈的地域性导致了生殖隔离和显著的地理变异，目前认可的亚种有17个，包括在诺瓦斯科舍省萨布尔岛繁殖的‘Ipswich’sparrow。繁殖期、求偶、筑巢、交配、产卵、孵化和育雏等行为在不同的亚种间存在差异。","identification":"稀树草鹀与其他同域分布的雀科鸟类通过其短而凹陷的尾巴、眼上方的黄色斑点以及头部和胸部缺乏浅色特征进行区分。在草原雀中，最相似的是贝氏草鹀，但后者头部整体泛橙，缺少明显的后眼线。稀树草鹀的头部和胸部图案与歌带鹀最为接近，但后者体型更大，尾部比例较长。","protection":"IUCN：LC（无危）","distribution":"稀树草鹀的分布广泛，覆盖了北美的大部分地区，从加拿大至危地马拉。太平洋沿岸和墨西哥的种群全年留驻，而其他种群则迁徙，越冬地从美国南部延伸至中美洲北部及南美洲北部。","other":"稀树草鹀因其广泛的地理分布、多种栖息地适应性、高繁殖密度、岛屿上的亲缘地域性以及种群间的进化分歧，成为生态和演化研究的理想对象。"},{"name":"海滨沙鹀","english_name":"Seaside Sparrow","scientific_name":"Ammospiza maritima","overview":"海滨沙鹀（英文名：Seaside Sparrow，学名：Ammospiza maritima），是雀形目雀鹀科 Ammospiza 属的鸟类。体型长约13至15厘米。其前额有深棕色斑点，上体棕色，带有较暗的褐色斑纹，眼先有很短的黄纹，下颏有白色条纹，腹部浅棕黄色。栖息于北美东岸和南岸的盐沼和潮间带，偏好密集的盐生草丛环境。","appearance":"海滨沙鹀是一种小型鸣禽，体长可达13至15厘米，翼展约18至20厘米。头部特征明显，前额有深棕色斑点，上体覆盖着棕色羽毛，饰以较暗的褐色斑纹。眼先处有一道短小的黄纹，沿着下颏延伸有一白色条纹。腹部呈浅棕黄色，整体外观与麻雀相似。这种鸟体型较小，头部扁平，尾部较短。喙部较细弱，上下喙边缘不完全贴合，略向内弯曲，形成微小的缝隙。","call":"海滨沙鹀的鸣声是一种沙哑的嗡嗡声，类似于远处红翅黑鹂的叫声。","habits":"海滨沙鹀通常栖息于半开放地带的灌木丛中，偏好盐沼和潮间带的环境。非繁殖季节，它们倾向于群居活动。繁殖季节，海滨沙鹀会在地面或灌丛内筑造碗状巢穴。它们主要在草地或沼泽地活动，食物以昆虫、无脊椎动物和种子为主。具体而言，它们会食用多种昆虫，如蝗虫、甲虫、毛虫，也会吃蜘蛛、小螃蟹、蜗牛、端足目动物和海洋蠕虫。在秋冬季节，海滨沙鹀的饮食中会加入大量的种子，如大米草和滨藜。","breeding":"海滨沙鹀的繁殖行为包括在盐沼或潮间带的适宜地点筑巢，巢穴通常建在盐生草丛中。雌性海滨沙鹀会产下2至5枚蛋。","identification":"海滨沙鹀与其他类似物种如尖尾沙鹀和纳氏沙鹀的区别在于体型更大、颜色更灰，头部和身体的标记更为模糊。幼鸟的羽毛比成鸟更偏淡黄色，具有明显的眉毛纹，缺乏翅膀上的红棕色斑块。","protection":"IUCN：LC（无危）","distribution":"海滨沙鹀分布于美国东海岸和墨西哥湾沿岸，从南部新罕布什尔州至德克萨斯州南部的盐沼和潮间带。部分北方种群冬季会迁徙至维吉尼亚至佛罗里达北部。","other":"海滨沙鹀共有七个亚种，其中最北端的亚种maritima繁殖于缅因州到北卡罗来纳州北部，迁徙至维吉尼亚至佛罗里达北部越冬；macgillivraii亚种则从北卡罗来纳州中部至乔治亚州南部，全年留驻；peninsulae亚种分布在佛罗里达州墨西哥湾沿岸，从坦帕至半岛地带；fisheri亚种居住于阿拉巴马至德州东部；sennetti亚种位于德克萨斯州南部沿海；mirabilis亚种，即Cape Sable海滨沙鹀，栖息于佛罗里达州埃弗格莱兹的淡水沼泽，已被列为濒危物种；而非常黑暗的nigrescens亚种，即Dusky海滨沙鹀，曾栖息于佛罗里达州大西洋沿岸的沼泽，于1987年灭绝。"},{"name":"纳氏沙鹀","english_name":"Nelson's Sparrow","scientific_name":"Ammospiza nelsoni","overview":"纳氏沙鹀（英文名：Nelson's Sparrow，学名：Ammospiza nelsoni），是雀形目雀鹀科 Ammospiza 属的鸟类。小型新世界sparrow。拥有多个分散的种群，内陆繁殖个体通常比沿海种群色彩更为鲜明。在歌唱时显眼，平时则非常隐蔽。其歌声像油锅中的水滴发出的嘶嘶声。在大西洋沿岸和墨西哥湾沿岸的沼泽地过冬。此鸟以美国自然学家爱德华·威廉·纳尔逊命名。1995年前，纳氏沙鹀与尖尾沙鹀被视为同一物种，现因羽色、鸣叫、大小、行为和基因差异而被分拆。","appearance":"纳氏沙鹀比尖尾沙鹀小，比莱氏沙鹀或黄胸草鹀大，具圆顶头部和尖喙。雌雄羽色相似，关键识别特征为明亮的黄橙色眉纹和偏褐色的眼后条纹。背部为深褐色至橄榄色，有四条明显灰色或白色侧向条纹。底面为白色至淡黄色，胸部和侧翼有淡或微弱的褐色条纹。幼鸟与成鸟相似，但具有黑色冠羽，宽阔的橙色中线和超眉纹，肩胸呈栗色或锈色，臀部和上尾覆羽略带条纹。","call":"其叫声为粗糙的颤音，几乎是一种机械声音，类似水滴落在热煎锅上的声音。此叫声可能在繁殖季节的飞行中发出。","habits":"栖息于北美加拿大和美国北部的沼泽地带，迁徙至美国东南部过冬。在地面或沼泽植被中觅食，有时在泥中探查，主要食物为昆虫、水生无脊椎动物和种子。","breeding":"雄鸟竞争雌鸟但不保卫领地，有时会帮助喂养幼鸟。交配多为双方滥交，一窝多父现象常见。巢为开放式杯状，附着于近地面的植被上，因接近地面而易受栖息地丧失影响，面临海平面上升的风险。","identification":"与尖尾沙鹀不易区分，尤其是大西洋种群，但内陆繁殖种群整体色彩更鲜艳。纳氏沙鹀喙稍短，有橙色眉和颊，缺乏条纹，与胸部和侧翼的色调一致。尖尾沙鹀一般有更强烈的橙色颊，与较暗橙色胸部和上颌形成对比，且后者通常在后部有弥漫性的条纹。","protection":"IUCN：LC（无危）","distribution":"繁殖区：加拿大，美国北部；非繁殖区：美国东南部。"},{"name":"尖尾沙鹀","english_name":"Saltmarsh Sparrow","scientific_name":"Ammospiza caudacuta","overview":"尖尾沙鹀（英文名：Saltmarsh Sparrow，学名：Ammospiza caudacuta），是雀形目雀鹀科 Ammospiza 属的鸟类。北美特有种，主要分布于美国东海岸的潮汐盐沼。曾与纳氏沙鹀视为同一物种。尖尾沙鹀体型小，具有独特的橙色眉纹和颊纹，以及淡黄色胸腹部带褐色条纹。该物种面临严重威胁，主要由于人类活动导致的栖息地丧失，全球数量自1990年代至2010年代初下降了约75%，预计在无管理干预下，可能于2050年前灭绝。","appearance":"尖尾沙鹀为小型鸟类，总长12-13厘米，翼展53-59毫米，体重14-17克。性状单一，雌雄相似，拥有锥形长喙和适度短尾，尾羽尖锐。成鸟头部主要呈棕色，面部三角区橙色明显，耳羽灰暗，冠部深棕，有时可见灰色中线。背部橄榄棕色，肩羽具白色条纹。喉部白色，胸部淡黄色至白色，具深色条纹，腹侧较浅。两翼及尾羽颜色随地理位置而异，北方个体条纹更褐，南方个体更黑。幼鸟与成鸟相似，但上部和下部斑纹更为强烈，呈土黄色调。","call":"鸣唱复杂，由低沉的嗡嗡声、颤音和咕噜声组成，声音微弱。叫声区别于尼尔森sparrow的响亮嘶嘶声加嘈杂鸣叫。","habits":"栖息于潮汐盐沼，偏好密集的高草丛生环境，如盐沼草和盐沼芦苇。繁殖季节在泥泞的开阔地带或草丛中觅食，偶尔攀爬至植被中较高处追逐昆虫。以盐沼植物种子为食，同时捕食飞蝇、端足类、蚱蜢和蛾子，尤其是兵蝇的幼虫、蛹和成虫。","breeding":"繁殖期始于春季高潮之后，允许雏鸟在下一个高潮前离巢。筑巢于盐沼草或盐沼芦苇中，巢呈开放杯状。每窝产卵3-5枚，雌鸟独力孵化，孵化期11-12天。雏鸟孵化后8-11天离巢，但仍依赖母鸟额外15-20天的喂养。","identification":"与尼尔森sparrow相比，尖尾沙鹀的胸腹条纹更为鲜明，面部三角区色彩更浓，下部条纹从胸至侧腹更强烈，后超眉纹有深色条纹，肩羽条纹较灰或更白，背底色更深，橄榄棕色，喙平均较长。","protection":"IUCN：EN（濒危）","distribution":"繁殖区域限于美国东海岸，从缅因州向南至切萨皮克湾和马里兰州的德尔马瓦半岛。冬季分布于美国东南部，北卡罗来纳州至佛罗里达州。","other":"尖尾沙鹀对海平面上升极为敏感，因洪水导致巢穴死亡率高。全球数量急剧下降，自1990年代至2010年代初，年下降率为5%-9%，总数量下降超过75%。"},{"name":"莱氏沙鹀","english_name":"LeConte's Sparrow","scientific_name":"Ammospiza leconteii","overview":"莱氏沙鹀（英文名：LeConte's Sparrow，学名：Ammospiza leconteii），是雀形目雀鹀科 Ammospiza 属的鸟类。亦称莱氏鹀或莱氏鵐，小型的北美新世界鹀。栖息在内陆北美的湿草地和沼泽地带，拥有亮丽的橙黄色脸庞，银色两颊，以及紫灰色带斑点的颈背。这种鸟因其隐蔽性而难以观察，除非雄鸟在高处唱歌，否则不易发现其踪迹。","appearance":"莱氏沙鹀体型小，尾短，头部较大，喙呈灰色，尾部尖。脸部呈现橙黄色，两颊为银色，顶冠暗棕色并有一条中央白纹。颈部为淡紫色，带有灰褐色条纹，背部有棕色和米色的条纹。腹部颜色偏白，胸部和两侧为橙黄色，带有深棕色条纹。脚和腿呈棕粉色。","call":"鸣唱时发出类似蚱蜢的嗡嗡声，伴有短暂的吱吱声开头和结尾的短促啁啾。","habits":"偏好湿润开阔的草地环境，常见于牧场、田野、作物残茬、浅水边、草原，偶尔在北方森林的沼泽和湖岸。冬季栖息于美国东南部，最西可达德克萨斯中部，最北至伊利诺伊和密苏里中部。","breeding":"繁殖季节从四月末开始，高峰期在五月中期。雄鸟在密集的草丛中唱歌吸引雌鸟。一窝产卵数量为2至6枚，以4枚最为常见。雌鸟单独孵化，孵化期大约为11至13天。幼鸟出生时为晚成鸟，覆盖着淡褐色绒毛。每年会育雏一次或两次。","identification":"与纳氏沙鹀相似，但莱氏沙鹀的颈背有淡紫色且条纹更细腻，冠部中央有白色条纹。此外，其鸣唱声与纳氏沙鹀有细微差别。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大中部至美国中北部，越冬于美国东南部，范围西至德克萨斯中部，北至伊利诺伊和密苏里中部。","other":"农业和湿地排水是对其最大的威胁。"},{"name":"贝氏草鹀","english_name":"Baird's Sparrow","scientific_name":"Centronyx bairdii","appearance":"贝氏草鹀体型较小，长约12厘米，体重约19克。成鸟头部显著的黄赭色，眉纹处最为明显。头型扁平，喙粗壮。头部特征还包括赭石色的中央冠纹，深色的喉侧条纹，耳覆羽边缘深色，以及淡黄色的颈环带有细密的黑色条纹。背部混杂着黑褐色和浅棕色的斑纹；翅膀整体呈棕褐色。尾巴略呈凹陷，长度超过同属其它种类。尾羽末端有窄的乳白色边线，在飞行和栖息时尤为明显。腹部白色，胸部和两侧有黑色条纹，但很少形成中央的胸斑。雌雄羽毛相似，但雌鸟的胸部条纹可能更为密集，头顶和脸部的颜色也不如雄鸟鲜明。全年羽色保持一致。幼鸟与成鸟类似，但腹部条纹更重，上体羽毛边缘的浅色形成鳞片状外观。","call":"贝氏草鹀的歌声由一系列快速而清晰的前奏音节构成，通常以颤音结尾，这是识别它们的重要特征。","habits":"贝氏草鹀在冬季和迁徙期间较为隐秘，但在春季和夏季时，雄鸟会在领地内唱歌，因此相对容易被观察到。它们从夏季繁殖地，即美国中北部和加拿大中南部的高草草原，迁徙至墨西哥北部和美国南部的德克萨斯州附近过冬。在迁徙季节，它们可能出现在美国中西部的多个地区，但在夏季主要分布在北达科他州、南达科他州、明尼苏达州、蒙大拿州以及加拿大境内。","breeding":"贝氏草鹀在地面上筑巢，通常选择在草地的凹陷处或草丛中。巢由草制成，通常包含两层，内层材质更细腻。它们倾向于形成松散的小群体进行繁殖。一窝产卵数通常为2至6枚，卵呈白灰色，带有棕色斑点。幼鸟为晚成鸟，依赖亲鸟喂养才能生存。繁殖种群数量随年份波动，这可能是对环境变化如野火、干旱和美洲野牛群迁移的适应。","identification":"贝氏草鹀与相似物种的区别在于头部丰富的赭石色调、耳后深色斑块、深色线条勾勒的浅色颊纹，以及尾部的缺口。与稀树草鹀相比，后者背部条纹更明显，腹部常有一个深色中心斑点，且眼后有一连续的深色线条；与黄胸草鹀相比，后者面部显得较为平淡，缺乏贝氏草鹀明显的深色喉侧条纹，且腹部几乎无斑点，即便是幼鸟也仅在胸部有条纹，面部的暗色标记也较少；与亨氏草鹀相比，后者头部有绿色调，总体颜色更深，翼羽和肩羽有栗色。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北美，涵盖加拿大中南部和美国中北部。非繁殖期则迁徙至墨西哥北部。","other":"贝氏草鹀曾被认为是只栖息于本土草地的物种，但近期研究显示它们也能接受之前耕作过的土地，只要这些土地结构类似于本土草原，如干草田或牧场，其中种植了非本土草种。然而，积极耕作的土地对它们而言并不适宜，很可能是导致种群数量下降的原因之一。"},{"name":"亨氏草鹀","english_name":"Henslow's Sparrow","scientific_name":"Centronyx henslowii","overview":"亨氏草鹀（英文名：Henslow's Sparrow，学名：Centronyx henslowii），是雀形目雀鹀科 Centronyx 属的鸟类。一种典型的草鹀科鸟类，以橄榄绿的颈部、红褐色的翅膀和清晰的黑色条纹著称。仅在稀疏灌木的杂草草地环境中生存，偏好高密度植被与厚实的落叶层。雄鸟在繁殖季节会显眼地在低矮植物上唱歌，但平时极为隐秘，尤其是在迁徙和冬季。种群数量在过去半个世纪显著减少，可能与农药使用和草原生境的丧失有关。","appearance":"亨氏草鹀体长约13厘米，体重介于10至15克之间，拥有短而尖的尾巴。头部宽大，顶着扁平的顶部，喙厚重且略带粉色，尾部短小而尖锐。全身色调偏暗，头部带有橄榄绿到黄绿色的渐变，深黄色的眼上斑点，以及深栗色的上体，尤其是三级飞羽和上翼覆羽。胸部和两胁有黑褐色条纹，其余下体白色。近距离观察时，其头部特征鲜明，包括橄榄绿色调、两条暗线（\"胡须\"线和侧喉线）、黑色条纹的冠顶（除中线外）、三角形的后眼斑以及中断的白色眼环。喙呈灰色，有时下颚边缘泛粉红色。雌雄相似，全年羽色变化不大，除了幼鸟的羽毛较为淡薄，头部标记较弱，下体条纹较少，背部和肩羽有淡色边缘，形成鳞片状效果。","call":"亨氏草鹀的叫声短促而微弱，难以察觉，但一旦听到，其简单的类似昆虫的\"tsi-lick\"声便成为识别特征，有时会在夜间发出。","habits":"亨氏草鹀栖息于北美的中东部和中部的湿草地和高草丛中，偏好高密度植被环境。它们在繁殖季节活跃，雄鸟会从隐蔽处的低矮植物上鸣唱。迁徙期间和冬季，它们变得极为隐蔽，更倾向于在草丛或杂草覆盖下奔跑，而非飞行。食物主要包括昆虫（如蚱蜢和甲虫）、浆果和种子。","breeding":"亨氏草鹀在加拿大南部、美国东北部和中西部的灌木草地繁殖，倾向于在潮湿环境中筑巢。它们的巢为隐蔽的开放杯状，位于或接近地面的草丛中，有时以小型群体的形式筑巢。繁殖所需的确切栖息地面积仍在研究中，最近的研究表明，小于预期的草地面积也能支持繁殖成功。","identification":"与莱氏沙鹀最为相似，但后者喙较小，头部色彩偏亮，背羽和肩羽的条纹更为明显。此外，莱氏沙鹀的耳羽银灰，眼周浅色。在手握比较时，莱氏沙鹀的跗跖较长。也可能与贝氏草鹀混淆，但两者一般不会在同一生境中出现；贝氏草鹀体型较大，头部橙色偏重，尾部较长且呈凹形，背部外观呈鳞片状。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要位于北美中东部和中部，非繁殖期则迁移至美国东南部的沼泽和开阔松林。","other":"亨氏草鹀的种群数量在过去几十年里急剧下降，部分原因可能是栖息地丧失和农药使用。然而，自1990年代初以来，通过美国农业部的保护储备计划创建的草地栖息地导致部分地区种群数量增加，有助于稳定其总体趋势。"},{"name":"黄胸草鹀","english_name":"Grasshopper Sparrow","scientific_name":"Ammodramus savannarum","overview":"黄胸草鹀（英文名：Grasshopper Sparrow，学名：Ammodramus savannarum），是雀形目雀鹀科沙鹀属的鸟类。小型、短尾，常见于北美和中美洲的草甸地带。其名字源于它类似蚱蜢的鸣声和对草蜢的喜爱。该物种拥有温暖的淡褐色体色和干净的无条纹胸部，以及独特的橙黄色眼上方斑块和细白眼环。","appearance":"黄胸草鹀体长约10.8至11.5厘米，体重介于14.5至20克之间。头部扁平，喙部深色，胸部呈无条纹的奶油色至淡褐色，腹部白色。头顶暗色，带有狭窄的淡色条纹，背部和翅膀上灰、锈色交错，翼缘黄色。尾羽短小，末端尖锐。雄雌羽毛相似，幼鸟则具有胸部条纹，背部呈现棕色、黑色和淡褐色的混合。成年鸟具有明亮的黄色翼弯羽毛和橙黄色眼上方斑块。","call":"黄胸草鹀的鸣声由一到四个简短音符引出，随后是一连串高音颤音，类似‘tup zeeee’或‘tip tup zeee’，因与蚱蜢的声音相似而得名。此外，还有另一种较音乐性的交替鸣声，用于建立和维持配偶关系。","habits":"黄胸草鹀偏好中等草丛生境，特别是在干燥、稀疏的高草草原和东部草地上。它们倾向于避开树木和灌木丛，在开阔地带觅食昆虫，如蚱蜢、蜘蛛和种子。该物种在春季迁徙时，雄鸟会比雌鸟提前一周或两周到达繁殖地。","breeding":"繁殖季节，黄胸草鹀选择在裸露的地面筑巢，巢呈圆顶状，隐藏在草丛中。每窝产卵4至5枚，由雌鸟孵化，孵化期为10至12天。幼鸟出生后6至9天即可离巢。父母双方共同喂养幼鸟，直到它们能够独立。","identification":"黄胸草鹀与同属其他物种的区别在于其橙黄色的眼上方斑块和干净的无条纹胸部。与其他草鹀如亨氏草鹀、莱氏沙鹀和纳氏沙鹀的区别在于体色、生境偏好和鸣声。","protection":"IUCN：LC（无危）","distribution":"黄胸草鹀广泛分布于北美洲南部加拿大、美国、墨西哥、中美洲以及哥伦比亚的部分地区。在美国中部，该物种迅速占据新出现的适宜生境，通过播放同类鸣声吸引至特定地点。在南美，仅在哥伦比亚有小规模濒危种群。","other":"黄胸草鹀的佛罗里达亚种（floridanus）被列为极度濒危物种，2017年记录的繁殖对数低至15对，至2022年报告的数量为120只。"},{"name":"草地蝇鹀","english_name":"Grassland Sparrow","scientific_name":"Ammodramus humeralis","overview":"草地蝇鹀（英文名：Grassland Sparrow，学名：Ammodramus humeralis），是雀形目雀鹀科沙鹀属的小型鸟类。体型短小，头部较大，尾巴较短，主要栖息于各种草甸环境，包括农业区边缘的草地。其最显著的外部特征包括淡黄色的眼眉，不延伸至眼后。","appearance":"草地蝇鹀体长约13厘米，重量在13-19克之间。拥有短尾和大头，嘴部中等大小，腿较长，脚宽大，翅膀短，初级飞羽被三级飞羽完全覆盖。成鸟的冠部呈棕色，有清晰的白色中央冠纹，脸部灰褐色，眼周淡色，上眼睑区域有明显的黄色斑块，继续延伸为淡灰色眉线；眼后有宽阔的暗棕色条纹，颈侧亦可见。背部为灰暖棕色，有深色条纹，臀部无条纹，呈暖棕色；尾巴棕色；翅膀上覆羽有宽黑边和淡色尖端，形成两个不明显翼斑，内覆羽边缘肉桂色，外覆羽灰色或灰棕色，三级飞羽黑色，边缘白色；翼弯处有明亮的黄色区域。喉部白色，胸部和两胁暖黄褐色，有时两侧有模糊的条纹，其余下体部分偏白。虹膜深色；喙蓝灰色到粉红色，鼻孔暗色；腿淡粉色。雄雌外观相似。幼鸟与成鸟类似，但羽毛颜色更浅更暗淡，面部图案不那么鲜明，眼睑区域缺乏黄色，胸部有细窄的条纹带。各地种群在大小和羽毛色泽上有细微差异。","call":"通常会从围栏柱子或灌木丛中发出一系列柔和的嗡嗡声鸣唱。","habits":"栖息于多种草甸环境，包括高草甸、巴西的campos和cerrado、湿润的草原以及帕姆帕斯湿润足以生长莎草（Cyperus articulatus）的地带。也出现在牧场和其他农业区的草边。不喜欢过度放牧导致草过短的地方。海拔可达1300米。可能是阿根廷中部的短距离迁徙鸟。食物主要是种子和昆虫，后者尤其在繁殖季节较多。仅在地上觅食，成鸟专门吃草籽，会用脚拉下较高的草，以便在地面上进食。","breeding":"繁殖季在北部为4月至8月，在南部为9月至2月。杯状巢建于地面，有跑道通往巢穴，有时草会长过跑道，形成松散的遮盖隧道。每窝产3-4枚蛋，蛋壳淡白色。无其他信息。","identification":"与黄眉蝇鹀相比，草地蝇鹀的喙更短，面部中线为淡色，眼睑上方的黄色仅限于上眼睑区域，翅膀覆羽和三级飞羽上的图案更为大胆。","protection":"IUCN：LC（无危）","distribution":"南美洲广泛分布，包括阿根廷、玻利维亚、巴西、哥伦比亚、法属圭亚那、圭亚那、巴拉圭、秘鲁、苏里南、乌拉圭和委内瑞拉。在低地和高达1100米（可能在委内瑞拉南部更高）的海拔都有分布。"},{"name":"黄眉蝇鹀","english_name":"Yellow-browed Sparrow","scientific_name":"Ammodramus aurifrons","overview":"黄眉蝇鹀（英文名：Yellow-browed Sparrow，学名：Ammodramus aurifrons），是雀形目雀鹀科沙鹀属的小型鸟类。1825年由Johann Baptist von Spix首次描述。拥有明显的黄色眉纹，分布于南美洲亚马逊盆地的广阔地带，包括哥伦比亚至亚马孙雨林区域。","appearance":"体长约13厘米，重14.5-19克。短尾、长腿，喙相对长而粗壮，翼短，初级飞羽被三级飞羽完全遮盖。头顶灰色，有细密的深色纵纹，黄色眉纹显著，延伸至头部中部，脸部灰黄色，上体灰色伴以深色斑纹，臀部灰褐色无斑点；尾羽棕色；翅膀上的小覆羽暗褐色，边缘橄榄黄色，中覆羽类似但边缘淡黄色，形成较弱的翼斑，其余上翅羽毛暗褐色，边缘棕色至灰色，次级飞羽基部明亮黄色；喉部白色，狭窄的褐色髭纹；胸部和两胁灰色，其余下体灰白色；虹膜暗色；喙上部暗色，下部蓝灰色；腿肉灰色至暗粉色。幼鸟与成鸟相似，但色泽更淡，面部黄色较少，胸带由细窄条纹构成。不同亚种在羽色深浅和面部黄色程度上有差异。","call":"发出高音的嗡嗡声，'tic tic ZEEEE tic ZEEEE'，常从显眼的栖木上歌唱。","habits":"栖息于低地热带草原和开阔地带，适应性强，可生活在各种开放生境，包括短草丛、高草丛、牧场、村落周边的空旷地带、路旁草地以及城市中的空地等各种退化或开放生境。全年留居于其分布范围内。主要以种子和昆虫为食，尤其擅长于地面觅食草籽。活动范围广泛，不局限于草丛中。","breeding":"繁殖季节在委内瑞拉为5月至10月，在哥伦比亚为2月至9月。杯状巢由干草制成，内部铺垫柔软材料，置于地面；每窝产2-3枚白色蛋。","identification":"与草地蝇鹀相比较，黄眉蝇鹀具有更长的喙，脸部黄色更明显，无中冠纹，翼覆羽和三级飞羽图案不明显。通过其独特的鸣唱、较为开放的行为和广泛的栖息地偏好来识别。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊盆地，从哥伦比亚到巴西的亚马孙雨林区域，常见于低地至1000米高度，偶尔可达2500米高度，特别是在厄瓜多尔东部。"},{"name":"异雀鹀","english_name":"Sierra Madre Sparrow","scientific_name":"Xenospiza baileyi","overview":"异雀鹀（英文名：Sierra Madre Sparrow，学名：Xenospiza baileyi），是雀形目雀鹀科异雀鹀属的小型鸟类，特有种于墨西哥中部的高山区。其外观与常见的歌带鹀相似，但体型较小，翼部锈色更为明显，通常栖息于松林间的草丛中，濒危物种。","appearance":"异雀鹀是一种小型鸟类，长约12厘米。其上体呈锈红色，有黑色条纹，颈部逐渐变为灰色。头部两侧有黑褐色的冠纹，眼周有一圈灰色的眉线和耳羽。面部有黑色的眼纹和髭纹，喉部至腹部白色，密集地布满黑色条纹。尾巴相对较短且粗壮。成鸟和幼鸟在外表上相似，但幼鸟背部色泽较暗淡，有宽阔的中央黑色羽轴条纹，边缘橄榄棕色至橄榄色，肩羽和肩胛区颜色更丰富，颈后部颜色更灰，呈现出‘扇贝状’效果。下体被脏黄色覆盖，胸部条纹较弱且颜色为棕色而非黑色，集中形成脸颊条纹。","habits":"异雀鹀主要栖息于海拔2300-3050米的亚高山草甸地带，常在开阔的松树林中的草丛觅食，也会在邻近的耕地上活动。它们偏好在显眼的草茎上歌唱。","identification":"与歌带鹀相比，异雀鹀体型更小，翼部锈色更为显著，且歌带鹀生活在较为湿润的环境中。","protection":"IUCN：EN（濒危）","distribution":"异雀鹀分布于墨西哥中部，特别是在两个特定区域，属于该地区的特有种。"},{"name":"美洲树雀鹀","english_name":"American Tree Sparrow","scientific_name":"Spizelloides arborea","overview":"美洲树雀鹀（英文名：American Tree Sparrow，学名：Spizelloides arborea），是雀形目雀鹀科Spizelloides的鸟类。中等体型的新大陆雀科鸟类，分布于北美，以加拿大北部和美国阿拉斯加州的苔原和北方森林边缘为繁殖地。","appearance":"成年美洲树雀鹀具有丰满的体形，小嘴和长而细的尾巴。头部呈灰色，带有锈色的帽状斑纹和眼线，胸腹部灰白色，中央有一暗色污点。背部色彩丰富，条纹由淡褐色、黑色和棕色组成。喙部短而圆锥形，上颚深色至黑色，下颚黄色。腿脚呈淡棕色，足部黑色。雄雌相似，仅在平均羽色亮度上有细微差异。幼鸟与成鸟相似，但冠羽有条纹，胸部和侧面有烟灰色条纹。","call":"鸣叫声为柔和悦耳的啾啾声，当不在筑巢期间时，常成小群跳跃于地面，寻找草籽和杂草种子，彼此间以这种轻柔的音乐般的叫声交流。","habits":"在冬季，它们常见于杂草丛生的田野、灌木篱笆、森林边缘或沼泽附近。它们乐于访问人类居住区，尤其是在有鸟食供给的地方。繁殖季节，雄鸟持续鸣唱以宣示领地。它们主要在地面或低矮灌木中觅食，以种子为主食，偶尔也吃昆虫和浆果。","breeding":"繁殖期主要在夏季，雌鸟在地面或近地面处筑巢，独自孵化蛋。双亲共同抚养一窝通常包含3到5只幼鸟的雏鸟。","identification":"与其他雀科鸟类相比，美洲树雀鹀的特征在于其锈色的帽状斑纹和眼线，以及灰色脸庞上的暗色胸点。它们的小喙和长尾也是辨识的关键。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北美：加拿大北部和美国阿拉斯加州。非繁殖区广泛分布于美国南部地区。","other":"虽然适应人类居住环境，但自1970年至2014年间，其数量估计下降了53%，原因可能涉及土地使用变化，如农业集约化和森林成熟导致的栖息地丧失。"},{"name":"棕顶雀鹀","english_name":"Chipping Sparrow","scientific_name":"Spizella passerina","overview":"棕顶雀鹀（英文名：Chipping Sparrow，学名：Spizella passerina），是雀形目雀鹀科雀鹀属的鸟类。是北美广泛分布的小型鸣禽。这种鸟体长12-15厘米，翼展约21厘米，最显著的特征是其栗色的顶冠和黑色的贯眼纹。偏好半开放地区的灌木丛生境，主要以草籽、种子和果实为食，也会摄取昆虫。棕顶雀鹀在北美洲和中美洲均有分布。","appearance":"成年棕顶雀鹀在繁殖季节呈现鲜明的外观：具有橙红至锈色的上体，灰色头部和下体，以及醒目的红色帽状羽冠。非繁殖季节时，羽色变得较为暗淡，帽状羽冠变为棕色，面部标记也不再那么明显。幼鸟下体有明显的条纹，上体呈棕色，带有细暗条纹，腹部和颈部无条纹。冬季时，它们的羽色更偏向于淡褐色，带有深色的眼线和暖棕色的帽状羽冠。","call":"棕顶雀鹀的鸣唱是一种变化多端的颤音，区域内不同个体间存在差异。有两种主要的鸣唱类型：快颤音和慢颤音。快颤音元素连续速度约为慢颤音的两倍，快颤音听起来像嗡嗡声或打鼾声，而慢颤音则类似于快速的手指敲击声。它们的飞行叫声全年可闻，是一种尖锐的纯音调叫声，持续时间约50毫秒，频率从9千赫兹开始，降至7千赫兹，然后再次上升到9千赫兹。","habits":"棕顶雀鹀广泛分布于北美和中美洲的半开放生境，包括林地边缘、灌木草地和公园。它们倾向于形成松散的群体，尤其在迁徙季节和冬季更为明显。它们在地面上觅食，寻找种子和其他食物，有时也会攀爬植物和树木，寻找芽和小型节肢动物。在迁徙期间，它们主要在夜间飞行，其飞行叫声成为春季和秋季美国夜空中特有的声音。","breeding":"繁殖季始于3月至8月，雄鸟先于雌鸟到达繁殖地，随后通过鸣唱寻找配偶。筑巢由雌鸟完成，通常位于树或灌木丛中，距离地面不超过6米。巢由植物纤维和动物毛发构成，呈松散平台状。每窝产2至7枚蛋，颜色为浅蓝至白色，带有黑、棕或紫色斑点，由雌鸟孵化约10至15天。在繁殖季节，昆虫占其饮食的大部分。它们有时会受到褐头牛鹂的寄生，导致巢穴被遗弃。","identification":"与相似的褐雀鹀、美洲树雀鹀和布氏雀鹀相比，棕顶雀鹀的灰色臀部和黑色眼线是识别关键。此外，冬季时，其棕色帽状羽冠和清晰的眼线也是重要的辨识特征。在西部，不同亚种之间在羽色和行为上存在细微差异。","protection":"IUCN：LC（无危）","distribution":"棕顶雀鹀广泛分布于北美洲和中美洲，从加拿大南部至墨西哥中部。在北美，它们主要繁殖于北部地区，冬季南迁至墨西哥和美国南部。","other":"尽管棕顶雀鹀在北美洲广泛分布且数量众多，但关于其生活史的详细研究仍然不足，尤其是在繁殖行为、种群动态、迁徙模式和冬季生态学方面。"},{"name":"田雀鹀","english_name":"Field Sparrow","scientific_name":"Spizella pusilla","overview":"田雀鹀（英文名：Field Sparrow，学名：Spizella pusilla），是雀形目雀鹀科雀鹀属的鸟类。广泛分布于北美东部，自加拿大东南部至美国中部及东部。这种鸟约14厘米长，重约12.5克。头部呈灰色，具锈色冠羽，白色眼环，粉色喙。上体棕色，带有黑色和淡褐色条纹，胸部淡黄色，腹部白色，尾部叉状。存在两种色型，一型更灰，另一型更锈色。","appearance":"成年田雀鹀的上体为棕色，胸部为淡黄色，腹部为白色，有两道白色的翼带和深棕色的叉状尾。面部灰色，冠羽锈色，有白色眼环，眼后有锈色标记。喙和腿粉色，是其显著特征。幼鸟较成鸟色彩暗淡，胸部和侧面有狭窄的暗色条纹。雄鸟略大于雌鸟。","call":"田雀鹀的鸣唱是一系列清脆的哨音，加速如同一个落地的乒乓球，以颤音结束，持续约4秒，声音悠扬。","habits":"田雀鹀栖息于灌木丛生的草地，偏好有草本植物和低矮灌木的环境。在春季和夏季，它们会从高处的枝头或围栏发出响亮的鸣唱，宣告领地。冬季，它们会形成小群，在地面或低矮植被中觅食，主要以种子和昆虫为食。","breeding":"田雀鹀的巢为杯状，建于地面，通常隐藏于草丛或灌木丛中。它们可能在一个季节内多次筑巢，随着季节推进，巢的位置逐渐升高。每次繁殖期，它们都会建造新的巢穴。每窝产卵数枚，颜色为淡蓝白色，带有黄褐色和灰紫色斑点。","identification":"田雀鹀与黑顶山雀和卡罗山雀相比，体型较小且更为纤细。与歌带鹀相比，它更小且身形更苗条。在大平原地区的个体比东部的同类更大、更苍白、更灰色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖了加拿大东南部至美国中部和东部。非繁殖期，它们向南迁移至美国南部和墨西哥东北部。","other":"田雀鹀的数量在早期北美殖民时期因森林被清除而增加，但近几十年可能有所减少。尽管如此，由于其广泛分布和常见性，IUCN 将其保护状况评为无危。"},{"name":"沃氏雀鹀","english_name":"Worthen's Sparrow","scientific_name":"Spizella wortheni","overview":"沃氏雀鹀（英文名：Worthen's Sparrow，学名：Spizella wortheni），是雀形目雀鹀科雀鹀属的鸟类。仅见于墨西哥东北部的沙漠高原。其特征为锈色冠羽、灰色头部、粉色喙、白色眼圈和黑色腿脚。分布区域极小，数量稀少，属于极度濒危物种。","appearance":"体长11至14厘米，体重9.5至15克。雄鸟成鸟具有锈色冠羽，逐渐变为灰色靠近喙部，灰褐色颈背；脸侧灰色，耳羽灰褐，淡黄色眼圈，淡色暗细的髭纹和颊纹；背部沙棕色，披肩带深棕色斑纹，臀部灰白；尾羽深棕色，边缘窄灰；上翼深棕，多数羽毛边缘浅灰黄，中大覆羽尖端淡黄（形成两道弱翼纹，磨损羽毛时可能消失）；喉部白色，下体淡灰色；虹膜深色；喙粉红；腿脚黑或粉至浅橙色。雌鸟与雄鸟相似，但冠羽淡黄褐色，顶部模糊黑板岩色条纹，有时背部淡黄褐色，底色略带肉桂色，肩羽、次级飞羽和翼覆羽边缘淡黄褐色。幼鸟类似成鸟，但无锈色冠羽，具显著淡黄眼圈和枕纹，头部、胸部和侧腹有暗色条纹。","call":"鸣唱为高音‘pee churr’，首音滑降，通常音调较低，亦被描述为干裂的叽叽声，类似棕顶雀鹀的歌声。叫声为高而细的干‘tssip’或‘tsip’，有时快速重复。","habits":"栖息于干旱的灌木草甸，偏好介于喜盐碱草地和沙漠灌丛之间的生态过渡区。以种子为主食，辅以其他植物食物和昆虫（如蛾类）、蜘蛛。在地面觅食。非繁殖季节常结成小群，曾观察到多达50只的群体，偶尔可达120只；与和/或褐雀鹀形成混合群。","breeding":"繁殖高峰期在Zacatacas、Coahuila和Nuevo León的6月和7月，幼鸟8月可见。巢杯状，由干草编织，内衬细腻，置于tarbush或棘灌丛中，或接近地面（通常低于30厘米）的杂草中。每窝2至5枚卵，最常见3枚，颜色为淡蓝色，大端有棕色至栗色斑点，似褐雀鹀的卵。孵化和育雏期未知。繁殖成功率低，一处14%，另一处为0%；家畜干扰和捕食为主要因素。","protection":"IUCN：EN（濒危）","distribution":"分布于中美洲的墨西哥北部，具体在Coahuila东南部至Nuevo León西部。","other":"面临农业和放牧导致的栖息地破坏威胁，全球估计仅有100至120只成熟个体。"},{"name":"黑颏雀鹀","english_name":"Black-chinned Sparrow","scientific_name":"Spizella atrogularis","overview":"黑颏雀鹀（英文名：Black-chinned Sparrow，学名：Spizella atrogularis），是雀形目雀鹀科雀鹀属的小型鸟类。在北美西南部至墨西哥中部。显著特征为长尾、灰白的体羽，以及繁殖季节雄鸟所展现的黑色颏部和喉咙。分布于干燥的灌木丛生地带，偏好岩石斜坡与高灌木丛生的环境。","appearance":"体长约13至15厘米，翼展约19至20厘米，体重介于9至14.8克。雄鸟在繁殖季节具有明显的黑色颏部、喉咙和脸部前方，背部长有红棕色条纹。雌鸟和非繁殖期雄鸟的黑色特征较淡或缺失。头部、躯干和臀部呈灰色，腹部略显白色，背部和翅膀边缘呈深棕色。喙为粉红色，腿和脚为暗棕色。","call":"发出一系列高音清脆的哨声，加速形成快速颤音，通常音调升高，类似丢下的乒乓球声。","habits":"栖息于干旱和半干旱环境，如灌木丛、鼠尾草丛、松柏树林等。飞行时靠近地面，以摇摆式飞行。冬季，北部种群向南迁移，主要进入墨西哥，一些种群可能迁往较低海拔。","breeding":"繁殖期从四月末持续到六月，雄鸟会在领地内的显眼位置唱歌。巢由植物材料制成，呈浅开杯状，置于低矮灌木中。雌鸟为主筑巢者，每窝产2至5枚淡蓝色或蓝绿色蛋，孵化期约为13天。双亲共同喂养雏鸟。","identification":"与暗眼灯草鹀相比，黑颏雀鹀更瘦长，背部有条纹，翅膀边缘呈棕色，尾巴无白色。雄鸟在繁殖季节的黑色颏部是辨识关键。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要在美国西南部至墨西哥中部，包括加州北部至德克萨斯西部，以及犹他州南部和内华达州南部。非繁殖季节部分种群会迁往墨西哥。","other":"全球变暖可能对其数量造成负面影响，预计到2080年，其当前的繁殖范围将不再被使用。"},{"name":"褐雀鹀","english_name":"Clay-colored Sparrow","scientific_name":"Spizella pallida","overview":"褐雀鹀（英文名：Clay-colored Sparrow，学名：Spizella pallida），是雀形目雀鹀科雀鹀属的鸟类。广泛分布于北美的干燥草原灌木区域，主要繁殖于加拿大中部至美国中北部。是北美洲大平原低矮灌木社区中最常见的雀类之一，尤其在加拿大草原省份南部。随着适宜生境的扩展，如砍伐森林和农业活动创造的环境，其分布范围已向东和向北扩张。","appearance":"褐雀鹀体型小巧，拥有灰色和淡褐色相间的羽毛，背部带有深色条纹，腹部呈灰白色，头部特征明显，包括灰色或白色的顶冠条纹、棕色耳斑、暗色颊须、灰色颈背与其余体羽形成对比。喙部粉色，上部和尖端较暗。两性相似，但在颜色和大小上有轻微差异，雄鸟平均有更白的眉纹。幼鸟全身有条纹，尤其是在腹部、头部、颈背和背部，到夏末秋初时，幼鸟换羽成类似成鸟的羽毛，此时在野外几乎无法区分。","call":"鸣唱为一系列低沉、虫鸣般的嗡嗡声，Bzzzz bzzzz za za。","habits":"栖息于灌木开放地带，繁殖季节在加拿大中部和美国中北部的灌木丛和松树林中。非繁殖季节，它们会迁移到墨西哥西部。它们在地上觅食，主要以种子和昆虫为食。在非繁殖季节，它们常常以小群体的形式觅食。","breeding":"筑巢于地面或低矮灌木中，巢由草和其他细软材料构成，通常产三到五枚蓝绿色带斑点的蛋，孵化期约为11天。其巢可能被棕头牛鹂寄生，导致巢被弃置。","identification":"与栗腹鹀和布鲁尔氏鹀相似，但头部标记更为复杂，尤其是宽大的黑色条纹与苍白的眉纹和顶冠条纹形成鲜明对比。在非繁殖季节，常与其他种类的鹀鸟群居。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于北美，覆盖加拿大中部至美国中北部，非繁殖季节迁徙至墨西哥西部。","other":"自20世纪初以来，由于适宜生境的增加，如伐木和农业活动，其分布范围逐渐向东和向北扩张。"},{"name":"布氏雀鹀","english_name":"Brewer's Sparrow","scientific_name":"Spizella breweri","overview":"布氏雀鹀（英文名：Brewer's Sparrow，学名：Spizella breweri），是雀形目雀鹀科雀鹀属的鸟类。小型、低调，分布于北美中西部至墨西哥中部。其外观虽不起眼，却与环境中的灰褐色调完美融合，尤其在主要栖息地——西部的鼠尾草灌丛中最为突出。春季与夏季，布氏雀鹀在鼠尾草灌丛中最为常见，数量众多，尽管外表普通，但其鸣唱绝非如此，充满活力的颤音与升降旋律在清晨的鼠尾草灌木草原上回荡。","appearance":"布氏雀鹀体型小而修长，尾长。头部有淡灰色颈背，淡色眉纹，脸部图案简单，耳羽棕色，边缘黑色，下侧由灰色白色亚颊纹勾勒。下颌线黑色细薄，下部淡白。下体颜色偏白，两肋灰白。上体颜色为棕色，背部与臀部有黑色条纹，翼覆羽棕色，翼缘粉色，形成两个不明显的翼斑。喙色扁平暗黑至淡棕，尖端灰暗。虹膜色深榛或黑。脚色淡粉。","call":"布氏雀鹀的鸣唱是一系列混合颤音和长音的嗡嗡声，音调独特，持续时间较长，是其识别的重要特征。","habits":"栖息于鼠尾草灌丛，春季和夏季最为活跃。冬季则在南部大盆地、洛矶山脉和内华达山脉的山麓以及美国西南部和墨西哥北部的沙漠灌木丛中过冬，常与其他种类的雀类结群。以昆虫为主食，夏季尤为明显，种子在非繁殖季节成为主要食物来源。","breeding":"繁殖季节，通常在春季到达繁殖地不久后即形成配偶，于鼠尾草灌丛中筑巢，每次产卵3枚。若未遭天敌发现，约20至22天后孵化出3只雏鸟。若有足够时间，会尝试第二次繁殖。成鸟在秋季开始向南迁徙。","identification":"与褐雀鹀相似，但布氏雀鹀没有冠上的浅色条纹和灰色颈环。Timberline Sparrow（S. b. taverneri）亚种具有更粗更暗的背部条纹，灰色颈背，隐约可见的中央冠纹和显著的眉纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美中西部，非繁殖期分布至墨西哥中部，冬季分布在美国西南部和墨西哥北部。","other":"布氏雀鹀在某些地区的数量有所下降，原因尚不清楚，但可能与鼠尾草灌丛生境破坏有关。"},{"name":"栗肩雀鹀","english_name":"Vesper Sparrow","scientific_name":"Pooecetes gramineus","overview":"栗肩雀鹀（英文名：Vesper Sparrow，学名：Pooecetes gramineus），是雀形目雀鹀科栗肩雀鹀属的鸟类。仅存于其专属的Pooecetes属中。这种淡褐色条纹明显的雀鸟广泛分布于北美的草原地带，自加拿大至美国北部的广阔地带都能见到它们的身影。在繁殖季节以独特的白眼环、外侧白色尾羽和肩部的栗色斑块著称，尽管后者在野外观察中往往难以察觉。冬季，栗肩雀鹀迁徙至美国南部和墨西哥过冬。","appearance":"栗肩雀鹀体长约13-16厘米，翼展约24厘米，体重介于20-28克之间。成鸟的上体呈淡棕色，饰有深色条纹；下体偏灰，尾羽外侧白色明显。头部的耳羽呈浅灰色，眼周环绕着醒目的白色眼环。腿爪粉红色，虹膜黑色。雌雄两性的外观相似，幼鸟与成鸟类似，但翅膀上的红褐色色彩较淡。喙短且圆锥形，比一般雀科鸟类的喙更为纤细。","call":"栗肩雀鹀的鸣唱始于两组重复的哨音，随后是一连串的颤音，旋律优美，与歌带鹀的歌声有几分相似。它们的歌声中包含滑音哨声，先是低音后接高音，此外还会加入短促的下行颤音。","habits":"栗肩雀鹀栖息于开阔的草地、干草原、农田和灌木草原地带，偏好干燥而非湿润的环境。秋季，它们会迁往美国东南部和墨西哥等地度过冬季，春季则返回繁殖地。除了繁殖季节外，它们常常以小群形式在地面觅食，主要以昆虫和种子为食，也会加入混合雀鸟群。","breeding":"繁殖期间，栗肩雀鹀通常独自或成对活动，雄鸟会在较高的位置如灌木或围栏上鸣唱，以宣示领地。它们的巢呈杯状，位于地面，由雌鸟孵化3-5枚蛋，孵化期约为12-13天。双亲共同喂养雏鸟，雏鸟至少在巢中停留9天后离巢。每年可育成两窝。","identification":"与类似物种如歌带鹀和稀树草鹀相比，栗肩雀鹀体形更大，尾部更长，具有明显的白眼环和白色尾羽。它们的肩部有不易察觉的栗色斑块，这在野外观察中可能难以发现。此外，栗肩雀鹀的歌声独特，有助于与其他雀鸟区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于北美西部和北部。非繁殖季节，它们迁徙至美国东南部和墨西哥。","other":"栗肩雀鹀与农业土地的关系复杂，虽然农业地带为其提供了栖息地，但也因不当的耕作实践导致了巢穴和雏鸟的损失。"},{"name":"云雀鹀","english_name":"Lark Sparrow","scientific_name":"Chondestes grammacus","overview":"云雀鹀（英文名：Lark Sparrow，学名：Chondestes grammacus），是雀形目雀鹀科鹨雀鹀属的鸟类。体型较大，独属于鹨雀鹀属。在北美广泛繁殖，主要分布在西部和北部，但在东部较为罕见，且其分布范围正在收缩。繁殖季节时，雄鸟会站在高处歌唱，发出类似云雀的悦耳歌声。","appearance":"云雀鹀体长15至17厘米，体重约24.7至33.3克，雄鸟略大于雌鸟。其显著特征包括较长的圆形尾巴，边缘明显白色，尤其是尾角部分。头部有独特的黑色、白色和赤褐色条纹，成年个体的条纹更鲜艳，而幼鸟则较暗淡。上体有变化的黑色条纹，通常呈灰褐色至浅棕色，两翼有浅色翼带。喉部白色，逐渐融入灰白的胸部，中央有一黑色斑点。面部有赤褐色的耳斑和冠纹，以及交替的黑白面部条纹。尾部深棕色或黑色，尾角白色明亮，仿佛一条白色的终端带。侧身和腹部淡棕黄色。雄雌外观相似，但幼鸟的下体有粗大的棕黑色条纹，主要在胸部和腹部两侧，上体有更大胆的黑色标记。","call":"其歌声是一系列丰富音符、颤音和穿插的尖锐‘churr’声，通常以几个清晰下降的哨音开始，随后是颤音。典型的叫声是一个相当独特、金属般的‘sik’或‘tsip’声，常在飞行中发出，有时会快速连续。","habits":"云雀鹀偏好开阔地带，如灌木草原、松果-杜鹃树缘、草地、路旁、农田和牧场。它们在繁殖期间倾向于有零星树木的开阔地带，冬季则常群居于灌木丛地区。当受惊扰时，它们通常会在地面觅食，然后飞入树中。在繁殖季节，雄鸟会在领地内的高点唱歌。","breeding":"繁殖期在春季至夏季，筑巢于地面，通常利用废弃的其他鸟类巢穴。巢由草制成，藏于一簇草或其他植被中，每窝产卵三到六枚，卵为白色，带有黑色划痕。已知受到褐头牛鹂的巢寄生影响。","identification":"与其他雀科鸟类相比，云雀鹀的头部图案大胆而复杂，结合了深色、浅色和赤褐色的条纹。胸侧和颊部的赤褐色斑点，以及眼上方的浅色眉纹和贯穿喉咙两侧的黑色髭纹是其标志性特征。尾部外侧的尾羽尖端为白色，胸部中央有一个黑色斑点。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要位于北美的西部和北部。非繁殖区则扩展至美国东南部至危地马拉。","other":"尽管历史上曾在北部和中部大西洋州繁殖，但其分布范围正在向其原始的哥伦布前分布区收缩，可能是因为东部土地回归森林或被城市化所取代。"},{"name":"五纹猛雀鹀","english_name":"Five-striped Sparrow","scientific_name":"Amphispizopsis quinquestriata","overview":"五纹猛雀鹀（英文名：Five-striped Sparrow，学名：Amphispizopsis quinquestriata），是雀形目雀鹀科 Amphispizopsis 属的鸟类。主要分布在墨西哥西北部和西部地区，其繁殖范围延伸至美国亚利桑那州南部。这种独特标记的鸣禽在夏季雨季开始繁殖，筑巢于灌木丛或草丛低处。雄鸟拥有丰富的鸣唱曲目，个别个体可达200种不同的歌曲。在非繁殖季节，五纹猛雀鹀隐秘而难以发现。","appearance":"五纹猛雀鹀具有独特的外观特征，头部有五条白色条纹（眉纹、颊纹和颏纹），黑色斑点位于灰色胸部和白色腹部之间。头部顶部呈淡紫色灰棕色，背部巧克力色无条纹。尾巴和翅膀呈深褐色，翼弯白色，无翼斑。上喙黑色，下喙蓝灰色。雌雄相似。平均总长度（博物馆标本）：13.3–14.5厘米。","call":"五纹猛雀鹀的雄鸟拥有庞大的鸣唱曲库，每只个体可能有高达200种不同的歌曲，但具体鸣叫特征的细节未提供。","habits":"五纹猛雀鹀偏好峡谷地区的陡峭灌木丛山坡，主要在地面寻找小种子和昆虫为食。夏季饮食偏重于昆虫，如毛虫。在非繁殖季节，它们的行为隐秘，不易被发现。","breeding":"五纹猛雀鹀在夏季雨季开始繁殖，筑巢于灌木丛或靠近地面的草丛中。雄鸟有丰富的鸣唱曲目，用于吸引配偶和领地标记。具体的繁殖行为，如求偶、营巢、交配、产卵、孵化和育雏等细节未提供。","identification":"五纹猛雀鹀的紫调背部、翅膀和尾巴颜色是独一无二的，与任何其他鸣禽都不相同。这种上体色泽搭配明显的黑色颊纹和胸部黑斑，使其与黑喉漠鹀、艾草漠鹀等种类区分开来。幼鸟的下体黄色色调和缺乏苍白的眉纹，以及明显的颊纹，帮助区分于幼年的黑喉漠鹀、艾草漠鹀和贝氏漠鹀。","protection":"IUCN：LC（无危）","distribution":"五纹猛雀鹀主要分布在墨西哥西北部和西部，包括Sierra Madre Occidental山脉。北部种群从美国亚利桑那州东南部和墨西哥索诺拉州北部，向南至少至锡那罗亚州和杜兰戈州西部，南部种群从纳亚里特州、萨卡特卡斯州到哈利斯科州。在亚利桑那州南部，五纹猛雀鹀在孤立的峡谷中定期繁殖，尽管数量很小。","other":"五纹猛雀鹀在1950年代首次在美国亚利桑那州记录到繁殖，至今仍是一种罕见的繁殖鸟种。"},{"name":"黑喉漠鹀","english_name":"Black-throated Sparrow","scientific_name":"Amphispiza bilineata","overview":"黑喉漠鹀（英文名：Black-throated Sparrow，学名：Amphispiza bilineata），是雀形目雀鹀科漠鹀属的鸟类。小型新世界sparrow，主要栖息于北美西南部和墨西哥。Amphispiza属中的唯一成员，偏好干燥的沙漠山地和灌木丛生地带。","appearance":"体长约12-14厘米，体重约13.5克，雄鸟略大于雌鸟。成鸟上半身灰褐色，下半身白色，特征性的黑色三角形喉部斑块，白色眉纹和颊线；尾巴深色，外侧尾羽尖端和最外侧尾羽边缘白色。幼鸟类似成鸟脸部图案，但缺乏黑色胸部，下巴、喉咙和上胸白色，有暗淡的条纹和斑点。","call":"发出清脆的鸣叫声，歌曲包含短暂的颤音和啾啾声。","habits":"常在地面或附近活动，成对或小群体出现。以种子为主食，冬季尤其如此，但在繁殖季节会从灌木的叶子和茎上捕捉昆虫。一些位于较高纬度的种群会长距离迁徙，而南方繁殖的种群迁徙距离较短。","breeding":"繁殖期间，领域范围较大，筑巢期间缩小。雄鸟在高处唱歌，雌鸟在沙漠灌木或仙人掌低处筑巢。孵化和育雏期较短。夏季的季风雨可能会刺激重新筑巢，延长繁殖季节，有时允许第二次孵化。","identification":"与五纹猛雀鹀相比，体型较小，喙较轻，下体颜色较浅，有白色的下巴和喉咙中央条纹。与幼鸟时期的Sage Sparrow（Amphispiza belli）容易混淆，但黑喉漠鹀有连续的白色眉纹，尾巴上有更多白色，下方条纹较少。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括美国西部至墨西哥中部，非繁殖季节分布可能更广泛，包括北美的干旱高地环境。","other":"生理适应性研究揭示了该物种在沙漠环境下对水分压力的适应机制。"},{"name":"艾草漠鹀","english_name":"Sagebrush Sparrow","scientific_name":"Artemisiospiza nevadensis","overview":"艾草漠鹀（英文名：Sagebrush Sparrow，学名：Artemisiospiza nevadensis），是雀形目雀鹀科艾草漠鹀属的鸟类。广泛分布于北美西部和墨西哥西北部。曾被归入Amphispiza属，但2007年和2009年的研究证据将其独立为Artemisiospiza属。其外观淡色而花纹微妙，以灰头和白胸带暗斑点为显著特征。艾草漠鹀通常比贝氏漠鹀颜色更浅，对比度更低，背上有不明显的深色条纹。","appearance":"艾草漠鹀为中型sparrow，体长12.1至15厘米，体重15.3至21.9克，雄鸟较大。雌雄同形异色，上半身一般呈棕灰色，头部略灰，背部和翅膀更棕色。上体部分为深灰和灰棕色，其他部位比较苍白，有明显的深色条纹。眼前方有一白色斑点，细眼环，宽白须纹与白色下体和胸中央暗斑相配。喉侧有黑色颊纹，侧面和腹侧为淡灰褐色，带有暗色条纹。翼下缘有黄色斑块，尾巴对比鲜明的深黑棕色，有时露出较浅的外羽和尾羽尖端，有抬高尾巴的习惯。","call":"艾草漠鹀的鸣唱是一系列机械式的音乐音符，节奏较慢，不同于贝氏漠鹀。","habits":"艾草漠鹀栖息于北美西部的艾草灌木丛中，夏季雄鸟会在显眼的枝头唱歌。除唱歌外，它们大多时间在地面活动，藏匿于灌木丛中。它们在开阔干燥的环境中度过迁徙季节和冬季，包括由盐蒿和仙人掌主导的沙漠灌木丛。饮食习惯和食物来源尚待详细研究。","breeding":"艾草漠鹀的繁殖期在美国西部的春夏季节，雄鸟会从显眼的栖息处唱歌吸引雌鸟。关于筑巢、产卵和育雏的详细信息需要进一步观察。","identification":"艾草漠鹀与贝氏漠鹀非常相似，但通常更淡色，对比度较低，具有不那么明显的深色髭纹和背部的明确条纹。幼鸟下体有条纹，与黑喉漠鹀相似，但缺少白色的眉纹，下体条纹更重，尤其是侧面。","protection":"IUCN：LC（无危）","distribution":"艾草漠鹀的繁殖区域位于美国中西部，而非繁殖区域则延伸至美国西南部和墨西哥北部。","other":"2013年，美国鸟类学会将艾草sparrow分为两个不同的物种：一种成为艾草漠鹀，另一种被分类为贝氏漠鹀的四个亚种之一。"},{"name":"贝氏漠鹀","english_name":"Bell's Sparrow","scientific_name":"Artemisiospiza belli","overview":"贝氏漠鹀（英文名：Bell's Sparrow，学名：Artemisiospiza belli），是雀形目雀鹀科艾草漠鹀属的鸟类。广泛分布于美国西部和墨西哥西北部。曾归入Amphispiza属，现独立为Artemisiospiza属。有四种亚种，分布于加州南部、加州海岸山脉、Sierra Nevada山脉西部斜坡、San Clemente岛及Baja California西部。","appearance":"贝氏漠鹀整体呈棕色，头部略显灰色，胸部白色带暗色中央斑点。雌雄外观相似，体长约15厘米，体重约16.5克。上体灰褐色，背部和翅膀更偏褐色，头顶较灰。有明显的黑色颊纹和宽阔的白色亚颊纹，下体白色，胸带深色。幼鸟下体有条纹，与黑喉漠鹀幼鸟相似，但缺乏白眉纹，条纹更重，尤其是在侧翼。","call":"鸣唱由机械般音乐性的音符组成，比艾草漠鹀更快。","habits":"栖息于灌木丛生的广阔地带，主要以Sagebrush为生境，常见于加州和Baja California。会显眼地站在高处唱歌，其余时间保持低矮并隐藏。频繁地在地上奔跑，尾巴常翘起。食性、捕食者等信息未详述。","breeding":"繁殖季节、求偶、营巢、交配、产卵、孵化、育雏等细节未提供。","identification":"与艾草漠鹀非常相似，但贝氏漠鹀整体颜色更深，对比更明显，具有较宽的暗色颊纹和更朴素的背部，条纹不明显。亚种间有细微差异。","protection":"IUCN状态未提供。亚种A. b. clementeae自1977年被列为受威胁物种，数量因保育努力而增加，已提议从《濒危物种法案》中除名。","distribution":"分布于北美西南部至墨西哥下加利福尼亚州。具体繁殖区域包括南加州、加州海岸山脉、Sierra Nevada山脉西部、San Clemente岛及Baja California西部。","other":"贝氏漠鹀的命名源于John Graham Bell。"},{"name":"斯贝猛雀鹀","english_name":"Tumbes Sparrow","scientific_name":"Rhynchospiza stolzmanni","appearance":"通贝斯猛雀鹀拥有中等身材，喙部粗壮，尾部长。头部呈现浅灰色，冠侧有红褐色条纹，眼后有红褐色斑纹；背部棕色，饰有黑色条纹；下体浅灰或白色，无条纹。成年鸟的性别相似，颈部两侧灰白，冠侧条纹红褐色，背部和臀部灰褐，翼羽黑边，次级飞羽偏红，尾羽深棕，边缘较淡。幼鸟与成鸟相似，但冠中央和喉部有明显暗色条纹，冠侧颜色较暗，少红褐色。","call":"通贝斯猛雀鹀的鸣唱主要在繁殖季节听到，由一系列清晰的金属音组成，重复约五次“chew-chew-chew-chew”，其间穿插着一些颤音。","habits":"通贝斯猛雀鹀通常单独或成对出现，栖息于干燥灌木丛、开阔的干燥林地和半沙漠地带，偏好有仙人掌和灌木的环境。它的活动范围可达海拔约1,400米（4,600英尺）。以种子和昆虫为食，主要在地面觅食。","breeding":"繁殖与雨季同步，一般从1月持续到5月。筑巢于隐蔽位置，巢呈杯状，由草制成并铺以细软材料，位于地面的草丛中。","identification":"通贝斯猛雀鹀在分布范围内无类似物种。与阿根廷和巴拉圭的条冠雀鹀相比，通贝斯猛雀鹀喙更大，尾更短，头部相对更圆。幼鸟与成鸟的区别在于冠部和喉部的暗色条纹更明显。","protection":"IUCN：LC（无危）","distribution":"分布于南美的厄瓜多尔远南部和秘鲁西北部，具体范围从秘鲁的拉利伯塔德地区延伸至厄瓜多尔的洛哈省。"},{"name":"纹顶猛雀鹀","english_name":"Chaco Sparrow","scientific_name":"Rhynchospiza strigiceps","overview":"纹顶猛雀鹀（英文名：Chaco Sparrow，学名：Rhynchospiza strigiceps），是雀形目雀鹀科通贝斯雀鹀属的鸟类。曾称为Stripe-capped Sparrow，属于Passerellidae家族。主要分布在南美洲的阿根廷和巴拉圭，特别是在Gran Chaco地区，以半开放的林地为栖息地。其最显著的特征为头部的灰褐色条纹和黑色颊纹。纹顶猛雀鹀通常以成对或小群的形式活动，觅食于地面，同时在低树和灌木上鸣唱。","appearance":"纹顶猛雀鹀是一种小型雀鸟，体长约15-16厘米。它具有长尾和短翼，喙呈中等大小的锥形。成鸟头部中央有一条灰色冠纹，两侧为红褐色冠纹，脸部灰白色，具红褐色眼后纹，黑色眼先纹，上体淡棕色，有较暗的条纹，尾羽深棕色，边缘淡黄色。上翼棕色，肩部有温暖的棕色斑块，初级飞羽边缘白黄色，次级飞羽边缘红褐色，三级飞羽边缘锈色。下体淡黄色，喉部洁白，两侧有狭窄的黑色喉纹和淡黄色颊区，胸部有模糊的灰色带，两胁淡黄色。雌雄相似。幼鸟与成鸟相似，但色泽较为暗淡，头部无红褐色条纹，代之以暗棕色轴线，边缘呈肉桂色，整体暗棕色，略带肉桂色斑点。","call":"纹顶猛雀鹀的鸣唱是一系列快速而悦耳的口哨声，每几秒重复一次。","habits":"纹顶猛雀鹀栖息于开阔、草丛覆盖的生境，伴有散落的树木和低矮的灌木。它们在低海拔的地区活动，如Gran Chaco地区的半开放林地，偏好低至1000米的热带干林和灌木地。","breeding":"关于纹顶猛雀鹀的繁殖生态细节尚不明确。","identification":"纹顶猛雀鹀与云加斯猛雀鹀相似，但体型较小，眼睛和喙之间黑色较少，翅膀颜色更偏褐色，叫声不同。与通贝斯猛雀鹀也有相似之处，但分布区域不同。","protection":"IUCN：LC（无危）","distribution":"纹顶猛雀鹀主要分布于南美洲的Gran Chaco地区，从巴拉圭南部到阿根廷北部中部，包括玻利维亚东南部和阿根廷西北部。"},{"name":"央葛斯猛雀鹀","english_name":"Yungas Sparrow","scientific_name":"Rhynchospiza dabbenei","appearance":"云加斯猛雀鹀体长约15-16厘米，拥有灰色的中央冠纹和栗色的侧冠纹，脸部呈灰色，眼后有一栗色条纹，大而黑的眉纹，细窄的黑色髭纹有时混有肉桂棕色，以及黑色的颊纹。上体淡棕色，带有深色条纹；尾羽深棕色，边缘浅色；上翼呈棕色，肩部栗色；初级飞羽边缘白化，次级飞羽边缘肉桂色，三级飞羽边缘锈色；下方呈淡白色，喉部洁白，两侧有狭窄的黑色喉纹和白色颊区；胸部有模糊的灰色带，两肋呈淡黄色。雄雌相似，幼鸟色彩较暗淡，胸部有细小的条纹。","call":"云加斯猛雀鹀的鸣唱是一系列的啾啾声，与较为复杂的颤音的纹顶猛雀鹀形成对比。","habits":"云加斯猛雀鹀是南方安第斯云森林的常驻居民，栖息于亚热带高地气候下的常绿森林地带，活动于开阔的草地环境，散布着树木和低矮灌木丛中。","breeding":"相关信息尚未提供。","identification":"与纹顶猛雀鹀相似，但体型更大，面部黑色部分更广泛，翅膀颜色更红，鸣叫声不同。","protection":"IUCN：LC（无危）","distribution":"云加斯猛雀鹀是玻利维亚东南部至阿根廷西北部的常驻居民，分布于南方安第斯云森林，这一地区具有亚热带高地气候，以常绿森林为特征。","other":"无"},{"name":"纹头猛雀鹀","english_name":"Stripe-headed Sparrow","scientific_name":"Peucaea ruficauda","overview":"纹头猛雀鹀（英文名：Stripe-headed Sparrow，学名：Peucaea ruficauda），是雀形目雀鹀科珀卡雀鹀属的鸟类。在干燥的灌木林地和草丛中活动，通常以小群体出现。","appearance":"纹头猛雀鹀是一种体型较大、尾巴较长的雀类，体长可达15.5至18厘米，体重最高可达35克。成鸟头部黑色，有宽白条纹贯穿冠顶和眼上方，颈背灰窄，上身淡棕色，背部有黑色条纹，臀部和尾羽更显浅黄褐色。肩部呈锈红色，翼羽边缘为浅黄色。喉咙和腹部白色，两胁变为浅黄色，胸灰色。幼鸟头部图案较暗淡，具浅黄色条纹和棕色底色，胸部有斑纹。","call":"纹头猛雀鹀群体间通过吱吱的尖叫声保持联系。雄鸟的歌声从开阔的栖息地发出，由干燥而细弱的音符组成，具有地域变异性。","habits":"生活在低地至海拔1800米的北方和800米的哥斯达黎加的灌木草原、次生灌木丛和林缘，但不进入森林深处。它们主要在地面觅食，以草籽为主食，偶尔捕食小型昆虫和蜘蛛。","breeding":"雌鸟负责筑巢，巢为深杯状，由植物材料构成，内衬精细的草或马毛。巢建在离地面不到1.2米的孤立带刺灌木中。雌鸟产下2到4枚无斑点的浅蓝色蛋，孵化期为12至14天。整个群体协助喂养雏鸟，夜间集体紧挨着栖息。","identification":"纹头猛雀鹀的头部特征明显，具有大黑面具、显著的白色眉线和黑色冠顶，易于识别。南部种群胸部有变化不定的暗色斑点。","protection":"IUCN状态未提供。","distribution":"繁殖于太平洋沿岸从墨西哥西南部，包括横贯山脉、新火山山脉至哥斯达黎加北部的太平洋沿岸。","other":"纹头猛雀鹀存在四个亚种，从北向南逐渐增大且色彩更加鲜艳。"},{"name":"黑胸猛雀鹀","english_name":"Black-chested Sparrow","scientific_name":"Peucaea humeralis","overview":"黑胸猛雀鹀（英文名：Black-chested Sparrow，学名：Peucaea humeralis），是雀形目雀鹀科珀卡雀鹀属的鸟类。仅分布于墨西哥西南部内陆地区。其独特的黑色胸部、白色颊纹和锈色背部使其在外形上易于识别。","appearance":"黑胸猛雀鹀拥有鲜明的外观特征，最显著的是其黑色胸部，白色的颊纹如同细长的胡须，背部呈现锈红色。通常它们保持在低矮的灌木丛或地面上活动，但会在灌木顶部唱歌。","call":"这种鸟类通过高亢、有节奏的啾啾声保持群体间的联系，其鸣叫声具有一定的辨识度。","habits":"黑胸猛雀鹀栖息于干燥的热带山脚和内陆山谷的灌木林地边缘，偏好成对或小群活动，常在低处觅食。","breeding":"关于黑胸猛雀鹀的繁殖细节尚缺乏具体信息。","identification":"与其他本地鸟类相比，黑胸猛雀鹀的黑色胸部和锈色背部是明显的辨识特征。","protection":"IUCN：LC（无危）","distribution":"主要分布在墨西哥西部和中部南部地区，从南哈里斯科州和科利马州向东至莫雷洛斯州和普埃布拉州，向南至格雷罗州和瓦哈卡州西南部。"},{"name":"白须猛雀鹀","english_name":"Bridled Sparrow","scientific_name":"Peucaea mystacalis","overview":"白须猛雀鹀（英文名：Bridled Sparrow，学名：Peucaea mystacalis），是雀形目雀鹀科珀卡雀鹀属的特有种，仅分布于墨西哥南部的特定区域。这种中等体型的猛雀鹀以独特的黑白灰红羽色组合著称，其白色须纹尤为醒目。","appearance":"白须猛雀鹀是一种中等体型的雀类，拥有相对较长的喙和渐尖的尾巴。头部呈现淡灰色，脸部两侧有明显的白色须纹，喉咙为黑色，肩部锈色，两胁和尾下覆羽为丰富的淡褐色。背部棕色，带有黑色条纹，与锈色的肩胛和臀部形成鲜明对比。腹部白色，雌雄外观相似。","call":"这种鸟通常通过高亢、有节奏的啾啾声保持联系，尤其当它们成对或小群体出现时。","habits":"白须猛雀鹀栖息于半开放的干旱灌木丛、灌木丛和过度生长的草地边缘。它们倾向于低处活动，大部分时间在地面或附近的低矮植被中寻找种子、节肢动物，甚至观察到它们吸食开花树木的花蜜。它们的活动范围限制在特定的热带山脚和内陆山谷。","breeding":"关于白须猛雀鹀的繁殖生态知之甚少。它们的繁殖习性、筑巢、交配和育雏等细节尚待研究。","identification":"白须猛雀鹀在墨西哥南部特有的地理范围内非常独特。与之相近的黑胸猛雀鹀虽有相似之处，但黑胸猛雀鹀有白色的喉咙，下缘有一条宽阔的黑色带穿过胸部，上体更广泛地呈现锈色。","protection":"IUCN：LC（无危）","distribution":"白须猛雀鹀主要分布在中美洲的墨西哥中部，具体包括墨西哥的特定热带山脚和内陆山谷。","other":"尽管其分布范围有限，种群数量估计不足50,000只，但白须猛雀鹀尚未被列入任何受威胁物种名单。"},{"name":"红尾猛雀鹀","english_name":"Cinnamon-tailed Sparrow","scientific_name":"Peucaea sumichrasti","overview":"红尾猛雀鹀（英文名：Cinnamon-tailed Sparrow，学名：Peucaea sumichrasti），是雀形目雀鹀科珀卡雀鹀属的鸟类。最显著的特征是较长的肉桂色尾巴，以及独特的脸部条纹图案，包括双黑须纹和粉红色下喙。该物种主要分布于墨西哥西南部的伊斯特穆斯德特胡安特佩克地带，生存在热带低地的灌木林和边缘地带。","appearance":"红尾猛雀鹀是一种体型较大的雀鹀，总长度约16.5厘米。其头部呈栗褐色，背部和肩部为淡棕色或灰棕色，带有宽阔的黑色条纹。最显著的特征是其肉桂色的尾巴。脸部两侧呈灰色，具有较宽的灰色眉纹和白色眼眶下方的新月形斑块。喙为二色，上喙深灰色，下喙角质色。胸部中心为白色，两侧灰色，腹部灰白色。雄鸟和雌鸟相似，但幼鸟的羽毛颜色较为暗淡，胸部有条纹。","call":"红尾猛雀鹀通常通过高亢、有节奏的鸣叫保持联系，其叫声特点独特。","habits":"红尾猛雀鹀偏好生活在干燥的灌木丛生境，活动于地面或低矮的灌木丛中，常见于太平洋斜坡的热带低地。它们通常成对或小群体出现，活动范围有限，主要在低海拔地区活动，最高可达约900米。","breeding":"关于红尾猛雀鹀的繁殖习性的具体信息有限，但它们可能在灌木丛中筑巢，繁殖期可能与当地季节有关。","identification":"红尾猛雀鹀与同属其他物种在外形上有细微差异，尤其是其肉桂色的尾巴和脸部的条纹图案，这有助于与其他类似物种区分开来。","protection":"IUCN：NT（近危）","distribution":"红尾猛雀鹀主要分布在墨西哥西南部的伊斯特穆斯德特胡安特佩克地带，位于奥阿哈卡东部和恰帕斯西部交汇处，包括太平洋斜坡的热带低地。","other":"红尾猛雀鹀在过去曾因农业扩张导致的栖息地破坏而数量下降。"},{"name":"棕翅猛雀鹀","english_name":"Rufous-winged Sparrow","scientific_name":"Peucaea carpalis","overview":"棕翅猛雀鹀（英文名：Rufous-winged Sparrow，学名：Peucaea carpalis），是雀形目雀鹀科珀卡雀鹀属的鸟类。其最显著的外部特征是灰色头部和颈部，带有尖顶的锈色冠羽和锈色眼线，以及粉红色的厚喙。该物种主要分布于北美的索诺兰沙漠区域，从美国亚利桑那州南部至墨西哥锡那罗亚州北部。美国最后被发现和描述的鸟类之一。","appearance":"成年棕翅猛雀鹀体型小（约13-14厘米，重约15克），头部灰色，脸部有黑色颊纹和颊条，窄的锈色过眼纹，以及锈色的冠羽，上面带有灰色条纹。背部呈灰褐色，上面有深棕色的条纹；腹部淡灰色且无斑纹。翼部的暗褐色羽毛边缘呈锈色或锈褐色，形成两个不明显的淡黄色翼带，而较小的翼覆羽则为锈色。尾巴长而圆。喙部特征明显，下颚橙粉色，上颚暗色（除了切割边缘与下颚颜色相同）。雌雄相似，全年羽毛相似。幼鸟羽毛较成鸟更偏黄，尤其是在脸部、翼带、三级飞羽边缘和背部，胸部和侧腹有明显的斑点或条纹，头部条纹为棕色而非锈色，面部图案不那么明显，喙全黑。","call":"其哀怨的哨音歌曲具有独特性，全年均可听到，尤其在繁殖季节更为频繁。","habits":"棕翅猛雀鹀栖息于沙漠草原地带，偏好灌木丛生的草地环境，如分散的刺槐或仙人掌丛。它们也出现在有沙底的溪流、灌木丛生的灌溉沟渠以及被阔叶树、刺槐、草和野花包围的小溪边。它们主要以昆虫为食，特别是在繁殖季节，而其他时间则以种子为主食。这种鸟全年都保持领地，配偶关系持续终生。","breeding":"棕翅猛雀鹀通常在夏季雨季期间繁殖，筑巢于小型树木、灌木或仙人掌中，如美洲雪柳、绿檀、仙人掌和刺槐，巢位较低。平均一窝产卵四枚，一对鸟可能会每年繁殖两窝。","identification":"与之最为相似的物种是棕顶猛雀鹀，但成年棕顶猛雀鹀略大，喙为灰色，上下面部对比度不如棕翅猛雀鹀鲜明，背部有锈色条纹而非深棕色，只有一条颊纹而非两条，以及灰白色的较小翼覆羽。尽管与Aimophila和Peucaea属的雀鹀在外形上有相似之处，但棕翅猛雀鹀的整体外观让人联想到Spizella属的雀鹀，通过其独特的歌声和叫声可以将其区分开来。","protection":"IUCN：LC（无危）","distribution":"棕翅猛雀鹀是北美和中美洲的居民，主要分布在亚利桑那州南部至墨西哥西北部，包括美国西南部和墨西哥西北部。","other":"由于过度放牧和城市化导致的栖息地丧失被认为对该物种数量影响最大。"},{"name":"卡氏猛雀鹀","english_name":"Cassin's Sparrow","scientific_name":"Peucaea cassinii","overview":"卡氏猛雀鹀（英文名：Cassin's Sparrow，学名：Peucaea cassinii），是雀形目雀鹀科珀卡雀鹀属的鸟类。中型雀科鸟类，分布于北美中南部至墨西哥北部。其外观平实，以灰褐色为主调，缺乏显眼的花纹，但复杂的自然历史使其成为研究的焦点。卡氏猛雀鹀在繁殖季节中通过其独特的飞行表演和歌声来吸引配偶，这使得它在某些时期变得容易识别。此外，该物种对夏季降雨的反应强烈，影响其繁殖活动的密度。","appearance":"卡氏猛雀鹀具有典型的雀科身形，身长13-15厘米，体重约17-18克，喙长而直，体形修长，尾巴圆润。全身主要呈现灰褐色，脸部图案不明显，头顶灰色，翼弯处呈淡柠檬色，尾羽尖端有白色。存在较为罕见的红褐色形态，整体更亮，上体、翅膀边缘及尾羽覆羽带红褐色。雌雄羽毛相似，幼鸟与成鸟相似，但颜色较淡，腹部有明显的暗褐色条纹。","call":"卡氏猛雀鹀的歌声悦耳，由几个变化音符组成，随后是四个不同音高的哨音，\"see-soo, see-say\"，在繁殖季节，雄鸟会进行壮观的飞行歌唱表演。","habits":"卡氏猛雀鹀栖息于草甸与灌木丛交错的环境，偏好干旱的高平原草甸。其分布随夏季降雨量波动，影响其繁殖密度。迁徙模式独特，可能涉及区域性的游荡，寻找适宜的繁殖条件。饮食以昆虫和种子为主，尤其在夏季以昆虫为主要食物来源。","breeding":"繁殖期从春季持续到夏季，雄鸟会在空中进行飞行表演，同时发出歌声吸引雌鸟。巢穴建在草丛中，通常由雌鸟筑巢，产卵数3-5枚，孵化期和育雏过程依赖于昆虫喂养。","identification":"与伯氏猛雀鹀非常相似，但可以通过较小的喙、薄白眼圈和歌声来区分。卡氏猛雀鹀背部羽毛有灰色边缘，而伯氏猛雀鹀背部羽毛有棕色中心和黑色条纹。卡氏猛雀鹀尾羽覆羽末端有黑色新月形标记，尾羽有白色尖端，而伯氏猛雀鹀没有这些特征。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要位于美国中南部至西南部，包括墨西哥北部。非繁殖期间分布更为广泛，可能涉及游荡行为，覆盖更多区域。","other":"卡氏猛雀鹀的迁徙和栖息地选择受夏季降雨量影响显著，导致其数量和分布范围出现年度波动。"},{"name":"巴氏猛雀鹀","english_name":"Bachman's Sparrow","scientific_name":"Peucaea aestivalis","overview":"巴氏猛雀鹀（英文名：Bachman's Sparrow，学名：Peucaea aestivalis），是雀形目雀鹀科珀卡雀鹀属的小型鸟类。特有于美国东南部。此物种以纪念约翰·巴赫曼牧师而得名。历史上的常见栖息地为成熟的开阔松树林，现今由于大量原始森林被砍伐，巴氏猛雀鹀常出现在如砍伐区和输电线路走廊等开放地带，保留着其偏好的草地条件。该物种在过去一个世纪里分布区域和种群数量波动极大，目前在许多曾经普遍的地区变得罕见。政府机构关注的管理对象，尤其是在为濒危的红冠啄木鸟恢复的松林地区，同时保护了两种下降中的物种。","appearance":"巴氏猛雀鹀具有灰褐色上体，带红色条纹，下体呈淡黄色，腹部白色。头部有红褐色帽羽和眼线，脸部灰色。喙部上颚暗色，下颚较浅。翅膀弯曲处呈黄色。成年鸟总长度介于12.4至15.2厘米，体重约21克。雌雄相似，通过鸣唱比通过羽毛更容易识别。西部密西西比河以西的种群下方更明亮的黄褐色。","call":"巴氏猛雀鹀的鸣唱开始为清脆的哨音，随后是一段类似鹪鹩的音乐般的颤音。后续乐句通常在音高上有所不同。","habits":"巴氏猛雀鹀主要栖息在开阔的松树林，偏好有草丛或灌木丛的下层植被。它们通常单独出现，最易在鸣唱时被发现。巴氏猛雀鹀是非迁徙性的居民，但在某些地区可能从较北部的领地撤退。它们主要以种子为食，也会捕食昆虫。","breeding":"繁殖季节从四月持续到八月，巢穴通常是建在地面附近的一簇草或灌木旁的穹顶状结构。雌鸟产下3至5枚蛋。巴氏猛雀鹀通常每年抚育两窝幼鸟，失败后会重新筑巢。","identification":"与Cassin's和伯氏猛雀鹀相似，但后两者分布和生境不同。与田雀鹀的区别在于后者有较小的喙和尾巴，白色眼环，脸面更朴素，有两条白色翼斑。","protection":"IUCN：NT（近危）","distribution":"巴氏猛雀鹀主要分布在从佛罗里达半岛中部北至北卡罗来纳州东南部，西至俄克拉荷马州东部和德克萨斯州东部的美国东南部。历史上曾扩张至伊利诺伊州、印第安纳州等地，但后来随着森林恢复，种群在这些地区减少，北卡罗来纳州现在是其东部范围的最北端。","other":"巴氏猛雀鹀的睾丸大小与其体型相匹配，与近亲卡氏猛雀鹀形成对比，后者睾丸相对体重来说非常小。"},{"name":"伯氏猛雀鹀","english_name":"Botteri's Sparrow","scientific_name":"Peucaea botterii","overview":"伯氏猛雀鹀（英文名：Botteri's Sparrow，学名：Peucaea botterii），是雀形目雀鹀科珀卡雀鹀属的鸟类。主要分布在墨西哥，其分布范围延伸至美国亚利桑那州东南部和德克萨斯州南部的里奥格兰德河谷。该物种以意大利自然学家马特奥·波特里命名，曾因过度放牧导致亚利桑那州的种群消失，但随着植被恢复，现在在该地区局部常见。","appearance":"伯氏猛雀鹀拥有扁平头部和长喙，全身呈现暗淡的棕色，背部有深色条纹，头部图案微妙，带有略暗的冠羽和眼线。成年体重17-26克，全长146-171毫米。两性相似，上体颜色在不同亚种间有所不同，翼弯处黄色，下体白色至灰黄色，胸腹部有褐色条纹。","call":"伯氏猛雀鹀的叫声包括一系列尖锐多变的短促声和快速颤音，与卡氏猛雀鹀的甜美歌声截然不同。","habits":"偏好有灌木的草地，害羞但在鸣唱时会显眼地站立。与卡氏猛雀鹀在范围和栖息地上有重叠。栖息于半沙漠草甸，特别是在巨黍草和橡树树林中。在美国分布受限，但在健康未被过度放牧的草甸中较为丰富。","breeding":"在亚利桑那州和德克萨斯州南部繁殖，筑巢于地面。关于繁殖的详细信息未提及。","identification":"与卡氏猛雀鹀相似，但可通过更长的喙、扁平的头部、暗色背部条纹、灰色翼板和缺乏白色眼环来区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在墨西哥，繁殖区域扩展至美国亚利桑那州东南部和德克萨斯州南部的里奥格兰德河谷。","other":"在亚利桑那州和德克萨斯州的分布受农业压力影响，种群密度与植被状况紧密相关。"},{"name":"棕顶猛雀鹀","english_name":"Rufous-crowned Sparrow","scientific_name":"Aimophila ruficeps","overview":"棕顶猛雀鹀（英文名：Rufous-crowned Sparrow，学名：Aimophila ruficeps），是雀形目雀鹀科猛雀鹀属的鸟类。主要分布在美国中南部和西南部以及墨西哥大部分内陆地区，南至横山山脉，沿太平洋海岸向西南延伸至横山山脉以南。该鸟种有棕色背部，暗色条纹，灰色腹部，最显著的特征是其红褐色的冠羽，灰色的脸颊和眉纹，以及一条粗黑的颊纹。","appearance":"棕顶猛雀鹀体长13至15厘米，体重15至23克。雄鸟和雌鸟的颜色相似，但雄鸟略大。成鸟头部顶部呈锈色，其余上体为灰褐色，常带有锈色条纹；眼上纹灰色；耳羽深色；明显的黑色颊纹；突出的眼环；下体无斑点，灰色或淡黄灰色。幼鸟的冠羽呈暗褐色，有较淡的褐色条纹；上体有狭窄的暗褐色条纹；下体浅黄褐色，胸侧有暗褐色细条纹；颊纹不明显。","call":"鸣唱为短促、快速的、带气泡感的chip音序列，有时接近结尾加速；叫声包括鼻音的chur和尖细的tsi。当受威胁或与配偶分离时，会发出dear-dear-dear的叫声。","habits":"棕顶猛雀鹀通常在干燥的山坡或灌木丛中生活，尤其在干燥斜坡上散落着灌木的地方。它们主要在地面附近活动，特别是在干燥的斜坡上有零星灌木的地方。它们经常在隐蔽的灌木或草丛下寻找种子和昆虫。在冬季，它们主要以种子为食，而在春季和夏季，则以昆虫为主食。","breeding":"繁殖期在春季，雄鸟通过歌声吸引伴侣并维护领地。巢建在地面或低矮的灌木丛中，由干草和根须构成，有时会加入树皮条、小树枝和杂草茎。每窝产2到5枚蛋，仅由雌鸟孵化。孵化期持续11到13天。幼鸟出生时裸露无毛，直到第三天才开始长出绒羽。幼鸟在8或9天后离开巢穴，此时还不会飞，但已能穿过灌木丛，父母仍会继续喂养一段时间。","identification":"与锈红猛雀鹀、瓦哈猛雀鹀、棕翅猛雀鹀、棕顶雀鹀、美洲树雀鹀或幼年白冠带鹀相比，棕顶猛雀鹀的红褐色冠羽、灰色中线上的条纹、黑色颊纹、白色眼环、无胸部斑点或条纹、灰到淡黄灰褐色的胸腹以及灰褐色的背部，使其易于识别。","protection":"IUCN：LC（无危）","distribution":"该物种广泛分布于美国西南部和墨西哥内陆，南至横山山脉，沿太平洋海岸向西南延伸至横山山脉以南。具体分布于加州、亚利桑那州南部、新墨西哥州南部、得克萨斯州、俄克拉荷马州中部，南至下加利福尼亚半岛和墨西哥西部，直至墨西哥普埃布拉州南部和瓦哈卡州。","other":"尽管该物种总体上被列为无灭绝威胁，但一些亚种受到栖息地破坏的威胁，其中一个亚种可能已经灭绝。"},{"name":"锈红猛雀鹀","english_name":"Rusty Sparrow","scientific_name":"Aimophila rufescens","overview":"锈红猛雀鹀（英文名：Rusty Sparrow，学名：Aimophila rufescens），是雀形目雀鹀科猛雀鹀属的中型鸟类。广泛分布在中美洲，从墨西哥西北部至哥斯达黎加西北部的多样植被类型中，包括农业边缘的灌木丛、橡树和松橡木林地、湿润的高山常绿森林和草原。其分布海拔范围从近海平面到约2700米。锈红猛雀鹀体型较大（长约20厘米），具有显著的特征，如栗色的冠羽和长而渐尖的尾巴。","appearance":"锈红猛雀鹀是一种中等体型的猛雀鹀，全身覆盖着锈色的冠羽和长而逐渐变细的尾巴。成鸟的头部以灰色为主，带有黑色的耳羽，眼睛周围有一圈白色的眼环，下颚为蓝灰色，上喙为黑色。背部呈锈褐色，翅膀和尾羽边缘有明显的锈色。腹部为灰黄色，两胁带有淡黄色的斑点。雄雌外观相似，但幼鸟色彩较为暗淡，体羽上有更重的条纹，包括胸部。","habits":"锈红猛雀鹀栖息于多种生境，包括灌木边缘、森林边缘和过密的开阔地带，特别是在橡树林和松橡木林中。它们通常较为隐蔽，活动于地面附近，但在繁殖季节会从灌木和树木的显眼位置鸣唱。","identification":"锈红猛雀鹀与瓦哈猛雀鹀最为相似，但前者体型更大，嘴部相对较大，翼羽和尾羽边缘有明显的锈色。与棕顶猛雀鹀相比，锈红猛雀鹀的嘴部比例更大，下颌为蓝灰色而非黑色，翼羽边缘和尾羽呈锈褐色。","protection":"IUCN：LC（无危）","distribution":"锈红猛雀鹀主要分布在中美洲，从墨西哥西北部至哥斯达黎加西北部，包括了从近海平面到约2700米的海拔范围内。"},{"name":"瓦哈猛雀鹀","english_name":"Oaxaca Sparrow","scientific_name":"Aimophila notosticta","overview":"瓦哈猛雀鹀（英文名：Oaxaca Sparrow，学名：Aimophila notosticta），是雀形目雀鹀科猛雀鹀属的鸟类。仅分布于墨西哥南部的瓦哈卡州。在干燥的森林和荆棘灌丛中生活，由于栖息地丧失，其数量正在缓慢减少。","appearance":"瓦哈猛雀鹀具有典型的猛雀鹀属特征，头部栗色，头顶有一条狭窄的灰色中线，侧面主要是灰白色，具有一条从眼窝延伸到眼睛下方的黑色细线，以及一条白色的眉纹。上体棕色，背部有黑色条纹，翅膀边缘呈锈褐色，下体灰白色，喉部有黑色侧纹。喙全黑，有时下颚淡灰色。","habits":"瓦哈猛雀鹀偏好在灌木林地和边缘地带，以及橡树丛生的环境中生活，通常在地面附近活动，但在一天的早晚时段会到边缘觅食。繁殖季节期间，雄鸟会从较为显眼的灌木和树木上唱歌。","identification":"与锈红猛雀鹀相比，瓦哈猛雀鹀体型较小，喙较小，没有锈色尾巴，翼部的锈色较少，脸部图案更为明显。与棕顶猛雀鹀的区别在于更大的体型，黑色的喙，对比更鲜明的脸部图案和上体的黑色条纹更清晰。","protection":"IUCN：LC（无危）","distribution":"瓦哈猛雀鹀仅分布于墨西哥南部的瓦哈卡州，生活在干燥森林和荆棘灌丛中。"},{"name":"萨帕塔鹀","english_name":"Zapata Sparrow","scientific_name":"Torreornis inexpectata","overview":"萨帕塔鹀（英文名：Zapata Sparrow，学名：Torreornis inexpectata），是雀形目雀鹀科萨帕塔鹀属的唯一物种，古巴的特有种。全球濒危的萨帕塔鹀分布在三个彼此相隔甚远的地区，每个种群都有其独特的亚种身份。分别位于扎帕塔沼泽的锯草草原，萨瓦纳-卡马圭群岛的两个小岛，以及古巴东南部干旱的荆棘灌木丛。该物种主要在地上觅食，以昆虫、种子和小型果实为主食，夏季湿润季节也会食用小型蜥蜴和水蜗牛蛋。","appearance":"萨帕塔鹀拥有黄色腹部，逐渐过渡到橄榄色的两侧，灰色的脸庞上顶着锈红色的冠羽，下颚处有一条黑色边缘的白色喉纹。成年鸟的头部两侧为灰色，带有暗色眼后纹，冠羽主要为锈红色，脸部和耳羽为灰色。背部大多为灰橄榄色，翅膀较暗，边缘较淡，翼弯呈淡黄色。尾巴黑色，边缘略淡。下体主要为淡黄色，胸部有灰色斑点或带状，侧面和胁部橄榄色。雄雌相似，幼鸟的下体更偏橄榄色，冠羽和上体更均匀的灰橄榄色。","call":"萨帕塔鹀的鸣唱包括金属质感的高音颤音，间歇性的“tziii-tzziii-tzziii...”，以及轻柔的“tic-tic-tic”声。","habits":"萨帕塔鹀栖息于古巴特有的环境，如锯草草原、沿海灌木和低矮森林以及干旱的荆棘灌木丛。它们主要在地面活动，寻找昆虫、种子和小型果实。在潮湿季节，饮食中还包括小型蜥蜴和水蜗牛的蛋。","breeding":"繁殖期可能在三月至六月之间，具体细节尚待进一步研究。","identification":"萨帕塔鹀在古巴的范围内没有类似物种，其独特的外观和声音使其易于识别。不同亚种之间的差异主要体现在羽毛色彩和所处生境的不同。","protection":"IUCN：NT（近危）","distribution":"萨帕塔鹀分布在古巴的三个特定地区：扎帕塔沼泽的锯草草原，萨瓦纳-卡马圭群岛的两个小岛，以及古巴东南部的干旱荆棘灌木丛。","other":"萨帕塔鹀的发现归功于西班牙动物学家Fermín Zanón Cervera，于1927年首次被描述。"},{"name":"纹雀鹀","english_name":"Striped Sparrow","scientific_name":"Oriturus superciliosus","overview":"纹雀鹀（英文名：Striped Sparrow，学名：Oriturus superciliosus），是雀形目雀鹀科纹雀鹀属的鸟类。为墨西哥特有种。体型较大，头部扁平，以高海拔地区的开放松林和丛生草甸为栖息地。","appearance":"纹雀鹀具有鲜明的外观特征，雄雌相似。头部宽大，喙尖黑色。其最显著的特点是大胆的白色眉纹，锈褐色的顶冠，黑色的面罩，以及淡灰色的腹部。幼鸟颜色较成鸟更淡，头部图案较为暗淡，上部羽毛标记不那么明显，两胁带有斑点。","call":"其鸣唱由一系列金属质感的清脆声和哔哔声组成，随后是一串类似敲击的颤音，某些人认为这与雌性褐头牛鹂的叫声相仿。","habits":"纹雀鹀常群居，偏好开阔地带，如树桩或岩石上。它们主要在地面觅食，但也常在松树上栖息。以种子为主要食物。","breeding":"繁殖季节、筑巢和育雏等具体细节未详述。","identification":"与纹头猛雀鹀外观相似，但通过全黑的喙和棕色顶冠上的不明显中线可轻易区分。与锈红猛雀鹀、棕顶猛雀鹀和瓦哈猛雀鹀的区别在于其完整的白色眉纹、黑色面罩和更淡的腹部。","protection":"IUCN：LC（无危）","distribution":"主要分布在墨西哥西部和中部，特别是在高海拔的松树林和草地。"},{"name":"绿尾唧鹀","english_name":"Green-tailed Towhee","scientific_name":"Pipilo chlorurus","overview":"绿尾唧鹀（英文名：Green-tailed Towhee，学名：Pipilo chlorurus），是雀形目雀鹀科唧鹀属的鸟类。拥有独特的色彩模式：橄榄绿色的上体，灰白色的胸部，鲜亮的绿色翅膀和尾巴，以及醒目的红褐色冠羽和白色的喉部。广泛分布于美国西部，偏好在山地森林的受干扰地带和开阔斜坡繁殖，冬季则常见于沙漠冲沟的密丛中。","appearance":"绿尾唧鹀是一种体型较大、尾部长的鸣禽，长约18厘米，重约29克。两性相似，但雌鸟的羽毛可能略显暗淡，尤其是冠羽。成鸟具有明显的橄榄绿色上体，灰色胸部，长而绿色的尾巴，以及突出的红褐色帽状头部。白色的眼上斑点、髭纹、下巴、喉咙和腹部与头部和胸部的灰色形成强烈对比。幼鸟缺乏成鸟鲜明的特征，主要是浅褐色的上体，白色下体，全身布满黑色条纹，带有两个橄榄色的翼带。","call":"绿尾唧鹀的鸣唱是一系列杂乱的清晰哨音和颤音，持续约2.5秒，其叫声独特，为鼻音的猫叫声。","habits":"绿尾唧鹀常在地面或浓密的灌木丛中觅食，主要以种子和昆虫为食。它们很少访问喂鸟器。它们在繁殖季节偏好物种丰富的灌木群落，以及山地森林中的受干扰和开放区域，通常由森林火灾造成。冬季，它们在沙漠冲沟的浓密刺槐灌木丛中较为常见，与其它种类的鸟类一起组成群体，经常使用它们特有的双边抓挠技巧觅食。","breeding":"绿尾唧鹀在繁殖季会筑建隐藏在灌木中的庞大巢穴，这些巢穴容易受到捕食者的威胁。一对鸟儿在一个季节内可能多次筑巢，直到成功孵化，有时甚至到7月中旬才开始筑巢。在繁殖区内，这种鸟似乎在科罗拉多州西北部、犹他州东北部、中央塞拉内华达山脉以及加利福尼亚州山区最为常见。","identification":"绿尾唧鹀与较小的棕顶猛雀鹀的头部图案相似，后者在其冬季分布区内普遍存在，但棕顶猛雀鹀上体主要为棕色，而非橄榄绿色。与褐纹头雀也有相似之处，但褐纹头雀的头部图案更为暗淡。幼鸟与幼年褐纹头雀相似，但在得克萨斯州南部和墨西哥东北部的冬季共存，此时绿尾唧鹀已完成预成型换羽，故所有冬季绿尾唧鹀都应处于成鸟般的羽毛状态。","protection":"IUCN：LC（无危）","distribution":"绿尾唧鹀的繁殖区主要位于美国西部，包括科罗拉多州西北部、犹他州东北部、中央塞拉内华达山脉以及加利福尼亚州山区。冬季则迁徙至墨西哥中部。","other":"尽管绿尾唧鹀在部分繁殖范围内相对常见，但由于其隐蔽的生活习性和偏好地面活动，使得人们对它的了解相对有限。"},{"name":"领唧鹀","english_name":"Collared Towhee","scientific_name":"Pipilo ocai","overview":"领唧鹀（英文名：Collared Towhee，学名：Pipilo ocai），是雀形目雀鹀科唧鹀属的鸟类。大型、色彩鲜明的雀科鸟类，为墨西哥南部山区特有种。其自然栖息地主要为亚热带湿润的松栎混交林和重度退化的森林边缘地带，活动于海拔约1,500至3,500米之间。","appearance":"体长19.5至23厘米，体重54.5至68克，具有长长的尾巴。成年个体的下体无条纹，头部有明显的条纹，额头黑色带有窄白中线，头顶锈色，白色眉纹从喙基延伸至颈侧，脸颊和耳羽黑色；颈侧、上体包括翅膀和尾巴橄榄绿色，翼折部鲜黄色；喉部和颊须区白色，胸部灰色，中央有一黑色胸带，两侧和尾下覆羽褐色，腹部颜色较淡；虹膜红棕色，喙黑色，腿色浅角质至粉红色。雌雄羽色相似。幼鸟头至上体棕色，面颊黑色，眉纹暗黄，喉部和下体淡黄色，胸带由深棕色条纹组成，腹中部有模糊的暗色条纹，两胁和尾下覆羽单一的暗肉桂色，虹膜棕色。","call":"鸣唱为连续的颤音，穿插着尖锐的叫声，与栗顶薮雀的高音嘶鸣明显不同。","habits":"常在灌木丛底层、花丛和杂草丛生的田地活动，尤其在清晨和傍晚沿田野边缘或安静的路边觅食。会从灌木和低树上唱歌，但往往藏得很隐秘。","breeding":"关于其繁殖习性的具体信息资料不足。","identification":"与栗顶薮雀相比，领唧鹀的胸带更宽，眉纹更明亮，但栗顶薮雀的胸带更细，眉纹更金黄而非白色。叫声和鸣唱风格亦有显著差异。","protection":"IUCN：LC（无危）","distribution":"中美洲：墨西哥。主要分布于墨西哥中部山区。"},{"name":"斑唧鹀","english_name":"Spotted Towhee","scientific_name":"Pipilo maculatus","overview":"斑唧鹀（英文名：Spotted Towhee，学名：Pipilo maculatus），是雀形目雀鹀科唧鹀属的鸟类。大型新世界雀科鸟类。上体黑色，翼具白色点斑和翼带，腹白，两胁栗色，虹膜红色。分布于北美西部至危地马拉西部。","appearance":"斑唧鹀为大型新世界雀科鸟类，身长约17.5至21.3厘米，体重33至49克。雄鸟上体及喉部黑色，翼和背部有白色斑点，腹部白色，侧身呈温暖的栗色。雌鸟头部、喉部及上体为灰褐色，翼和背具白色斑点。两性均具有厚实的喙和长而圆的尾巴，尾端有白色角状斑块。幼鸟呈黄褐色，有明显的暗褐色条纹。","call":"斑唧鹀的叫声可能比棕胁唧鹀更尖锐且多变，具体描述未提供。","habits":"斑唧鹀栖息于干燥的上坡森林、开阔林地、灌木丛生地带及灌木丛。它们在北美的西北部繁殖，全年可见于加利福尼亚、内华达等地，但在沙漠气候中少见。它们偏好未受火灾影响的灌木丛，避免烧毁的区域。在恢复期（少于15年）的区域，由于良好的地面覆盖和丰富的地下食物，它们会较为常见。","breeding":"斑唧鹀在低矮的灌木丛或地面筑巢，巢由叶子、树皮条、枝条、草茎和松针等材料构成，通常建在离地约40厘米处。每季至少产两窝，每窝含3至5枚蛋，蛋壳呈灰色或奶油色，带有红棕色斑点。雌鸟单独孵化12至14天，幼鸟在10至12天后离巢。","identification":"与棕胁唧鹀相比，斑唧鹀翼上的白色标记更为广泛，但不会出现棕胁唧鹀折叠翅膀时可见的单一大胆白色斑块。在墨西哥，与领唧鹀杂交的个体展现出介于两者之间的特征。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于北美西北部，包括加拿大西南部至美国西北部，非繁殖季节分布延伸至美国中部平原。在加州、内华达、亚利桑那等地全年可见，但避免极端干旱的环境。","other":"在某些墨西哥地区的种群中，背部呈现橄榄绿色。"},{"name":"棕胁唧鹀","english_name":"Eastern Towhee","scientific_name":"Pipilo erythrophthalmus","overview":"棕胁唧鹀（英文名：Eastern Towhee，学名：Pipilo erythrophthalmus），是雀形目雀鹀科唧鹀属的鸟类。分布于北美东部和加拿大南部，历史上曾与西部的斑唧鹀共同被视为单一物种。体长可达20厘米，具有显著的黑冠、白尾角和栗色胁部，不同于斑唧鹀的翅膀白色斑点。雌雄羽色差异明显，雄鸟头部、上身和尾巴呈黑色，两胁为暖褐色，腹部为白色；雌鸟则以棕色替代黑色。幼鸟整体呈褐色，有明显的条纹。","appearance":"雄性棕胁唧鹀拥有醒目的黑色头颈、上体和尾部，两胁橙褐色，腹部洁白，眼周颜色随地理位置而异，北方及中部海湾地区的个体为红色，东南部个体则为淡黄色。雌鸟外观相似，但以枯叶般的棕色取代黑色。成年个体全身无斑纹，喙锥形，尾较长且圆润，展开时可见尾角的白色边缘。幼鸟则呈现典型的sparrow样貌，上体为肉桂色，下体偏黄，全身布满深色条纹。","call":"鸣唱为短暂的“drink your teeeeea”，开始于尖锐的叫声，以短促的颤音结束。常见叫声为升调的两声，有时被称为“chewink”。","habits":"栖息于灌木丛生地带，森林边缘，偏好密集的灌木丛。主要活动于地面，通过双足刮除落叶层寻找食物。北方种群迁徙至美国南部过冬，南方种群则为留鸟。食物主要包括昆虫、果实和种子，冬季依赖地面觅食。访问喂食器。","breeding":"繁殖期从春季持续到夏末，筑巢由雌鸟完成，位于低矮灌木或地面。每窝产卵2至6枚，平均3.6枚，孵化期12至13天，幼鸟约10至12天离巢，之后依赖亲鸟照料约一个月。","identification":"与斑唧鹀最为相似，但东方种上体几乎全黑，仅翼折处有一块白色斑点。雌雄羽色差异明显，雌鸟比雄鸟更接近褐色。亚种间辨识要点主要在于眼色，佛罗里达亚种具有淡黄色眼睛。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖加拿大南部和美国东部，非繁殖季节迁徙至墨西哥北部。具体分布包括从加拿大南部至美国中部和东部，南至佛罗里达州，西至德克萨斯东部。","other":"在1585-1586年间，画家John White在北卡罗来纳州罗阿诺克岛废弃的定居点首次描绘了棕胁唧鹀。"},{"name":"百慕大唧鹀","english_name":"Bermuda Towhee","scientific_name":"Pipilo naufragus","overview":"百慕大唧鹀（英文名：Bermuda Towhee，学名：Pipilo naufragus），是雀形目雀鹀科唧鹀属的鸟类。已经灭绝的鸟类，原生地仅限于百慕大群岛。与东部的同类相比，体型较大，与棕胁唧鹀有着紧密的亲缘关系。基于冰河时代晚期至全新世的洞穴沉积物中发现的遗骸，科学家于2012年对其进行了科学描述。一份1625年的旅行报告暗示了它的存在，描述其为体型肥大如红胸鸲的麻雀。","appearance":"关于百慕大唧鹀的外形特征细节已无从考证，但从其被描述为‘胖而丰满如红胸鸲’的麻雀，我们可以推测其体型较为圆润，比常见的麻雀更为庞大。具体羽毛颜色和图案因缺乏详细记载而无法精确描述。","habits":"百慕大唧鹀的生活习性细节已无法确知，由于它属于雀形目，我们可推测其可能栖息于岛屿的灌木丛中，以种子和昆虫为食。然而，具体的栖息地偏好、活动模式和迁徙行为均无从得知。","identification":"由于该物种已灭绝，与其他鸟类的辨识要点无从得知，但在其生存时期，可能通过体型、叫声或特定的行为特征与其他类似物种区分开来。","protection":"IUCN：EX（已灭绝）","distribution":"百慕大唧鹀仅分布于北大西洋中的百慕大群岛，这里是其唯一的自然栖息地。"},{"name":"白喉唧鹀","english_name":"White-throated Towhee","scientific_name":"Melozone albicollis","overview":"白喉唧鹀（英文名：White-throated Towhee，学名：Melozone albicollis），是雀形目雀鹀科地雀属的鸟类。仅在墨西哥的干内陆山麓和高地发现，主要集中在奥阿哈卡州。该物种在适宜的生境中相当常见且显眼。","appearance":"体型较大，尾长，全身呈淡褐色，具有一条白色的喉部斑纹，锈色的喉咙带和锈色的腹下部。头部两侧呈棕色，眼上有一条白色的眉纹，眼下方有少量白色，特别是在嘴角处，向下变为肉桂色，黑色的颊纹与白色的下巴和前颈形成鲜明对比。两翼棕色，有两条狭窄的淡色翼带，中覆羽的翼带更白，对比明显。性别在羽毛上相似，幼鸟与成鸟类似，但胸部有棕色斑点，翼带呈淡肉桂色。","habits":"栖息于破碎的半干旱山地灌木丛，也出现在松树-橡树森林中，海拔高度在1000至2800米之间。通常在地面或植被低层觅食，有时会在地面刮土寻食。以种子为主食，辅以昆虫和果实。全年留居于其栖息地。","breeding":"繁殖季节在2月至5月。筑巢材料为干燥的草，内部衬以细草、根须和毛发，巢置于地面或接近地面的位置，有时位于浓密灌木下。一窝产4枚卵，卵色从浅蓝到蓝白色，带有深棕色或红褐色斑点。","identification":"与其它同属物种相比，白喉唧鹀具有独特的白色喉部斑纹和锈色的喉咙带，是辨识的关键特征。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的墨西哥，主要在奥阿哈卡州的Balsas地区和内陆。"},{"name":"棕喉唧鹀","english_name":"Canyon Towhee","scientific_name":"Melozone fusca","overview":"棕喉唧鹀（英文名：Canyon Towhee，学名：Melozone fusca），是雀形目雀鹀科地雀属的鸟类。体型健壮，尾部长。其特征为全身呈土褐色，喉咙部分为淡黄色，尾巴下方覆盖着橙色羽毛。头部顶部呈红棕色，上胸有杂乱的暗色条纹，通常中央有一个暗色斑点。广泛分布于北美西南部的索诺兰地带，从美国的亚利桑那州、南部科罗拉多州、新墨西哥州和西部德克萨斯州，南至墨西哥的奥阿哈卡北部，主要避开沿海地区。适应多种生境，从干旱的水道灌木丛到高海拔的松栎林。","appearance":"成年棕喉唧鹀体长约19至25厘米，尾长明显，可达8.2至11厘米。体重介于36.5至67克之间，平均约45克。翅膀长度为8.2至10.1厘米，喙长1.4至1.7厘米，跗蹠长2.3至2.7厘米。全身土褐色，腹部颜色略浅，头部较深，头顶红棕色（墨西哥中部的个体头顶与背部颜色一致）。尾部下方有一片略带红色的区域。性别间差异不大。","call":"鸣叫声粗糙，与加州唧鹀的尖锐‘chip’声相比，更像是一系列节奏均匀的音符或短语，类似山雀或主红雀的声音。","habits":"栖息于低地的灌木丛或灌木草原，偏好干燥的环境，如沙漠和干草原中的密集灌木。以种子为主食，常在地上奔跑跳跃觅食。在人类居住区附近，常见于停车场，以车辆散热器上的昆虫为食，受惊时会躲藏在车下。","breeding":"繁殖季节未详，但已知会在矮灌木上筑巢，雄鸟在繁殖季会在矮灌木和仙人掌上鸣唱。","identification":"与加州唧鹀相比，棕喉唧鹀体型略小，整体颜色更淡，喉咙和尾部下方的羽毛为淡黄色而非肉桂色，腹部更白。南部加州唧鹀的沙漠亚种颜色接近棕喉唧鹀，但缺乏明显的胸部暗斑。与红腹唧鹀的区别在于后者有深色面罩，缺乏棕喉唧鹀的淡黄色喉咙和胸部暗斑。","protection":"IUCN：LC（无危）","distribution":"分布于北美西南部，包括美国的亚利桑那州、南部科罗拉多州、新墨西哥州和西部德克萨斯州，以及墨西哥北部至奥阿哈卡北部，主要避开沿海地区。","other":"曾与加州唧鹀被归为同一物种，称为棕唧鹀，直到分子遗传学证据支持它们应被视为独立的物种。"},{"name":"加州唧鹀","english_name":"California Towhee","scientific_name":"Melozone crissalis","overview":"加州唧鹀（英文名：California Towhee，学名：Melozone crissalis），是雀形目雀鹀科地雀属的鸟类。体型较大、色彩朴素的地面雀类，无性别色差。广泛分布于低矮植被环境中，主要在地面觅食，栖息于从美国西海岸半干旱高地到湿润河岸生境。加州唧鹀是加州最常见且知名度高的鸟类之一，能够适应乡村发展和城市化环境，是南至加州热带下加利福尼亚半岛的永久居民。","appearance":"加州唧鹀体长21-25厘米，体重37-67克，拥有长尾和棕色外观，翅膀略显暗色，尾巴、头冠带有深色，脸部和尾下覆羽带橙色。眼睛呈橙棕色，腿灰粉色，喙暗色，下颌基部较浅。雄鸟和雌鸟羽毛相似，雄鸟稍大。幼鸟颜色更淡，更均匀，缺乏成年鸟的橙色调，下体斑纹模糊。","call":"发出独特的尖锐金属声“chink”，还有兴奋时的尖叫和咕噜声。两只或以上的鸟会发出这种声音。歌声是由一系列加速的“chink”音符组成，中间部分节奏变化。","habits":"加州唧鹀主要在地面觅食，常在叶堆中刨食。它们在灌木丛、屋顶或树枝上长时间鸣叫。栖息在灌木丛生、干燥的生境，如灌木林和沿海鼠尾草丛。在城市郊区和住宅区也很常见，以种子和昆虫为主食。","breeding":"筑巢于低枝或灌木上，高度约0.5至4米。巢由雌鸟用树枝、茎、草和毛发构建。雌鸟独自孵卵，孵化期为11-14天，每年可能养育2-3窝，繁殖季节从4月初持续到8月初。","identification":"加州唧鹀与红腹唧鹀最为相似，但后者有黑色面罩，粉灰色腹部，更苍白的羽毛。与棕喉唧鹀相比，后者有对比明显的棕冠、白色腹部、中央深色胸点，羽毛更淡。加州唧鹀与棕喉唧鹀无分布重叠。","protection":"IUCN：LC（无危）","distribution":"分布于美国西部，包括南至加州热带下加利福尼亚半岛，北至俄勒冈南部，主要在低海拔的灌木丛生地带和城市郊区。","other":"加州唧鹀曾经与峡谷唧鹀被视为同一物种，现已确定为独立种类。其与阿伯特唧鹀的遗传关系更为密切。"},{"name":"红腹唧鹀","english_name":"Abert's Towhee","scientific_name":"Melozone aberti","overview":"红腹唧鹀（英文名：Abert's Towhee，学名：Melozone aberti），是雀形目雀鹀科地雀属的鸟类。是北美西南部特有种，主要分布在下科罗拉多河和吉拉河流域，几乎特有于亚利桑那州，但在加州、内华达州、犹他州、新墨西哥州和墨西哥索诺拉州也有少量分布。此鸟以美国鸟类学家James William Abert命名。","appearance":"红腹唧鹀体型较大，尾巴较长，全身呈灰褐色，具有明显的黑色面部特征和粉红色的喙。腹部为淡粉色至棕色，尾下覆羽橙色。雄鸟和雌鸟的羽毛颜色相同，平均体长21.2至23.1厘米，雄鸟平均体重47.1克，雌鸟平均体重44.8克。","call":"红腹唧鹀的鸣叫特征主要是由两性同时发出的尖叫声二重奏，这是它们重逢时的标志，用于加强和维持紧密的配偶关系。","habits":"红腹唧鹀栖息于下索诺兰沙漠区的灌木丛生的河流走廊，偏好隐藏在茂密的灌木下。它们主要在地面寻找种子和昆虫，偶尔也会在低矮的灌木或树枝上栖息。在郊区环境中，它们往往对人类的存在视而不见。","breeding":"红腹唧鹀的繁殖季节长，成对关系紧密，能够在环境条件改变时迅速开始筑巢。在高捕食率和寄生率的环境中，它们能够快速重建巢穴。在适宜的条件下，一对红腹唧鹀一年可以繁殖两次。","identification":"红腹唧鹀可以通过其黑色面部和淡色喙与其他棕色唧鹀相区别。在与加利福尼亚唧鹀的分布区域略有重叠的地方，红腹唧鹀的黑色面部更为明显。","protection":"IUCN：LC（无危）","distribution":"红腹唧鹀主要分布于美国西南部和墨西哥西北部，包括亚利桑那州、加州南部、内华达州东南部、犹他州南部、新墨西哥州西部以及墨西哥的索诺拉州。","other":"尽管红腹唧鹀的分布范围有限，但它已成功适应了亚利桑那州凤凰城都市区的郊区环境，并在亚利桑那州立大学校园内较为常见。"},{"name":"锈顶地雀","english_name":"Rusty-crowned Ground Sparrow","scientific_name":"Melozone kieneri","overview":"锈顶地雀（英文名：Rusty-crowned Ground Sparrow，学名：Melozone kieneri），是雀形目雀鹀科地雀属的鸟类。仅见于墨西哥西部山麓的体型较大的地栖雀类，常隐匿于热带林地灌丛、荫蔽咖啡园及农田灌木篱中，具锈红色冠羽、白色眼圈及中央具黑斑的白色胸兜，是墨西哥特有种。","appearance":"成鸟两性相似。冠部及头侧锈红，额及耳羽暗灰黑；上体为灰橄榄褐色，翼尾同色系；喉、胸、腹白色，胸中央具黑色圆斑；两胁褐色，尾下覆羽带锈色。幼鸟头至上体深褐并具暗色纵纹，喉及下体污乳黄并具褐色纵纹。全长15–17.5厘米，雄鸟翅长78.0毫米、尾72.4毫米、嘴峰13.2毫米、跗跖24.9毫米，体重约35–41克；雌鸟翅长70.1–76.2毫米，体重约36–40克。","call":"鸣唱为两声尖锐金属音接颤音，另一型为断续的“tzip tzip Chup Sweeet!”。另有高而薄的“dzzzzzzzziu”或“ssssssziu”、细“ti”及尖锐“tk”或“tsik”，可持续重复并转为干哑的喋喋不休声。","habits":"栖于海拔0–2000米的干旱至半湿润灌丛、荆棘林、次生林及橡树–杜松灌丛。通常在地面或近地面活动，以跳跃方式觅食，取食种子与昆虫；偶见于清晨沿静僻道路或小径边缘觅食，多成对或单独活动，受惊即隐匿密丛中。对哨音或鸮叫有趋近反应，常自显眼的枝头鸣唱。","breeding":"繁殖期资料稀少，仅知6–7月在墨西哥南部记录11巢，巢筑于灌丛或小树上，距地0.9–1.8米，为整洁杯状，外缘悬垂46厘米长枯草茎，内衬细草与牛毛。卵淡蓝白，通常无斑，偶具少量红点，大小22–23×16–16.5毫米。9巢被铜色牛鹂寄生，1巢同时被褐头牛鹂寄生。","identification":"在其分布区内不易与他种混淆。普氏地雀分布于特万特佩克地峡以南，具较大白色颊斑及耳羽黑色半环，胸无黑斑。棕喉唧鹀与白喉唧鹀体型更大，无锈红冠羽及白色面部对比纹，下体色暗。","protection":"IUCN: LC（无危）","distribution":"繁殖区：墨西哥西部，北自索诺拉州极南端，沿海及内陆向南经锡那罗亚、纳亚里特、杜兰戈西部、哈利斯科西部、科利马、瓜纳华托南部、米却肯、墨西哥州、莫雷洛斯、普埃布拉西南部、格雷罗至瓦哈卡西北部。非繁殖区：与繁殖区一致，留鸟。","other":"分子证据显示本种可能与棕色唧鹀群关系更近，而非传统归入的Melozone属。"},{"name":"普氏地雀","english_name":"Prevost's Ground Sparrow","scientific_name":"Melozone biarcuata","overview":"普氏地雀（英文名：Prevost's Ground Sparrow，学名：Melozone biarcuata），是雀形目雀鹀科地雀属的鸟类。纪念法国自然学家Florent Prévost而得名。体型中等偏大，长约15厘米，重约28克，头部具有独特的锈色帽状斑纹和白色脸部，黑眼珠突出，侧颊处有一块暗色斑。分布于中美洲，自墨西哥南部至洪都拉斯西部的山地地带。","appearance":"普氏地雀的成鸟拥有暗灰色短喙，橄榄褐色上体，无条纹的灰白色下体，锈色冠羽，以及明显的白色脸部，侧颈和喉部均为白色，耳部有一显著的黑色斑点。幼鸟颜色较深，下体呈黄色，头部图案较为暗淡模糊。两性相似，但雄鸟体型略大于雌鸟。","call":"鸣叫声包括细弱的‘tsit’声或更清脆的‘psee’声。雄鸟的鸣唱，通常在潮湿季节从隐蔽的枝头发出，是一种口哨般的‘pst’t’t peer peer peer whee whee whee’。","habits":"常以独行或成对出现，喜欢在半开敞的林下灌木丛、咖啡园、树篱和大型花园的低矮植被中活动。它们在清晨或黄昏时分较为活跃，有时会短暂地出现在开阔地带。","breeding":"巢由雌鸟建造，是一个精致的杯状巢，通常位于灌木或大草丛中不到2米高的位置。一窝产2到3枚带有红斑的白色蛋，由雌鸟孵化12至14天。雄鸟参与喂养雏鸟。偶尔会被青铜牛鹂寄生。","identification":"与近缘的锈顶地雀相比，普氏地雀的面部大部分为白色，仅限于眼区和眉纹部分为白色。两者地理分布上不重叠，前者分布于Isthmus of Tehuantepec以南。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥东南部至萨尔瓦多，主要栖息于海拔600至1600米的山地。"},{"name":"哥斯达黎加地雀","english_name":"Cabanis's Ground Sparrow","scientific_name":"Melozone cabanisi","overview":"哥斯达黎加地雀（英文名：Cabanis's Ground Sparrow，学名：Melozone cabanisi），是雀形目雀鹀科地雀属的鸟类。亦被称为Costa Rican Ground-Sparrow，中型雀形目地雀，分布于哥斯达黎加中部的山麓与高地。具有独特的头纹和黑色胸斑，是当地特有种。","appearance":"该雀长约15厘米，雄雌相似。头部以锈色为主，顶冠黑亮，面颊和前额呈黑色，包裹着白色眼圈和脸颊，形成鲜明对比。背部橄榄褐色，腹部主要为白色，胸前有一显著的黑色斑点。幼鸟颜色较暗淡，头部锈色变为锈褐色，有深色斑点。","habits":"哥斯达黎加地雀栖息于林缘、灌木丛和废弃空地，偏好在地面活动，常成对出现。它们主要生活在落叶林、森林边缘、湿润山地森林边缘及次生林中。","identification":"与普氏地雀相比，哥斯达黎加地雀有更多锈色头部，白脸侧面积较小，且具有黑色髭纹和胸斑。锈顶地雀脸部颜色更暗，仅限于眼环和眉纹为白色。","protection":"IUCN：NT（近危）","distribution":"中美洲：哥斯达黎加中部的Meseta Central。"},{"name":"白耳地雀","english_name":"White-eared Ground Sparrow","scientific_name":"Melozone leucotis","overview":"白耳地雀（英文名：White-eared Ground Sparrow，学名：Melozone leucotis），是雀形目雀鹀科地雀属的鸟类。中美洲山地特有的中型地栖雀，以黑白分明的头部、亮黄色颈侧及橄榄绿背尾为显著特征。独立成种的“白耳组”（含 leucotis 与 nigrior 两亚种）分布于尼加拉瓜北部高地至哥斯达黎加中央及图里亚尔瓦山谷，海拔500–2000米，全年留居，常见于荫蔽咖啡园及次生林缘。","appearance":"成鸟体长约15厘米。头黑色，具白色前额小斑、眼前后白斑及明显的白色耳斑；黄色眉纹自眼前延伸至耳后，颈侧呈亮黄色。喉及上胸黑色；胸后黑色斑块在 nigrior 亚种更扩展且常与黑色喉部相连。上体深灰至橄榄绿，翼、尾橄榄色；腹部灰白，尾下覆羽红褐。虹膜深褐，喙黑色，跗跖粉红。雄雌同色。幼鸟黑色部位暗淡，黄白斑纹模糊，胸斑不显，背羽具红褐色羽端。","call":"黎明后首小时最为活跃。雄鸟鸣唱为2–8种固定曲目，包含高频起始音、调频中段及短颤音尾段，用于求偶。雌雄合唱为独特非独唱型对唱，持续约5–6秒，用于领地防御。另有“chip”警戒联络声与“tseet”远距离联络声。","habits":"留鸟，全年成对活动，繁殖期家族群维持不足一月。栖息于海拔500–2000米的荫蔽咖啡园、次生林缘及河岸灌丛。觅食以地面双足同时扒落叶为主，偶在1–5米高处取果；食物包括草籽、榕果、昆虫及人类残食。遇行军蚁时会加入蚁队捕食节肢动物。领地直径50–80米，全年防御同种。","breeding":"繁殖期3–9月，高峰4–5月。巢为松散植物纤维杯状或地面叶柄平台，距地0–2米，置于咖啡、枯枝、天南星科叶或岩缝间。每窝2–3枚白色底、基端密布褐斑的卵，卵长23–27毫米、宽17–20毫米，仅雌鸟孵卵。双亲育雏，巢寄生率约50%，主要由铜色牛鹂寄生。","identification":"与灰冠地雀的区别：后者具灰色冠纹、黄色眉纹更宽更长、黑色胸斑缩减为不规则小点；与同属普氏地雀相比，后者具红褐冠、棕色上体及白色喉；与白颈薮雀相比，后者体型较大且具白色冠纹及黄色喉。","protection":"IUCN: LC（无危）。","distribution":"繁殖区：尼加拉瓜北部高地至哥斯达黎加中央山谷及图里亚尔瓦山谷。非繁殖区：全年留居，无迁徙。","other":"系统发育研究显示，白耳地雀与普氏地雀亲缘最近；灰冠地雀已分拆为独立种。"},{"name":"褐纹头雀","english_name":"Olive Sparrow","scientific_name":"Arremonops rufivirgatus","overview":"褐纹头雀（英文名：Olive Sparrow，学名：Arremonops rufivirgatus），是雀形目雀鹀科纹头雀属的小型鸟类。分布于北美和中美洲，包括墨西哥、中美诸国及美国德克萨斯州南部。体长14-15.5厘米，独有橄榄绿色背部，显著特征为棕色眼纹和条纹冠，以及淡色胸羽和白色腹部羽毛，喙部锥形。性别间外观相似，而幼鸟更偏土黄色，腹部有条纹。","appearance":"褐纹头雀体型中等，全长约13.5-15厘米，羽毛颜色灰暗。头部灰色，上身橄榄灰色，尾部更偏棕色。头部有明显的暗色条纹，通常呈棕色或更深色调，尤其是在墨西哥西部。雌雄外观相似，年轻个体颜色更暖，斑纹更多。喙部上颚棕色，下颚较浅。腿色淡，呈肉色。成年鸟和幼鸟的区别在于幼鸟有模糊的翼纹，上体颜色较暗淡，上下体皆有条纹或斑点。","call":"褐纹头雀发出一系列加速的芯片般的声音，类似于乒乓球弹跳声，音调逐渐加快。","habits":"褐纹头雀偏好密集的灌木丛生地，包括荆棘灌木、杂草丛生的田野、灌木区和森林下层植被丰富的环境。它们几乎总是在地面或靠近地面活动，主要在热带和亚热带地区栖息，从海平面到海拔6,000英尺（1,800米）。这种鸟不会迁徙，全年居住在选定的栖息地。","breeding":"筑巢高度通常在地面以上2-5英尺，巢由稻草、枝条、树皮、叶子和茎构成，较为庞大。每年3月至9月期间，每季产卵2-5枚，卵壳白色且无斑点。","identification":"褐纹头雀与绿背纹头雀相似，但后者背部更鲜亮的橄榄绿色，下尾覆羽柠檬黄色而非土黄色。与大黑纹头雀相比，后者更大，头部条纹黑色。","protection":"IUCN：LC（无危）","distribution":"褐纹头雀分布于北美南部至中美洲，具体包括美国德克萨斯州南部、墨西哥、中美诸国至哥斯达黎加。","other":"褐纹头雀在德克萨斯南部的半干旱亚热带区域常见，但因其隐蔽的生活习性，其繁殖生物学、行为和觅食习性的研究资料有限。"},{"name":"小黑纹头雀","english_name":"Tocuyo Sparrow","scientific_name":"Arremonops tocuyensis","overview":"小黑纹头雀（英文名：Tocuyo Sparrow，学名：Arremonops tocuyensis），是雀形目雀鹀科纹头雀属的鸟类。在哥伦比亚东北部和委内瑞拉西北部特有。栖息于非常干燥地区的灌木丛和森林边缘，常见于委内瑞拉的城市如Tocuyo和Lara。其自然生境包括亚热带或热带的干林和干灌木地带。","appearance":"这是一种体型较大的麻雀，约13至14厘米长，拥有橄榄褐色的背部和灰白色的腹部，腹部带有浅灰色调。头部呈灰色，有黑色条纹，最显著的是宽阔的黑色侧冠条纹在颈后融合。眉线白色，略淡于中冠条纹，眼线黑色，包括鼻孔区域。两性相似。幼鸟全身橄榄黄色，上下均有条纹，头部缺少成鸟的条纹图案，而是有淡黄色的眉线，头顶略暗且有条纹。","call":"其鸣唱从半隐蔽的高处发出，通常在黎明时分，声音变化多样，倾向于分成三个不同的部分，例如“tit, tit'ti'ti'ti'tsuee tsuee”或“sweeu sweeu eeee tu'tu'tu'tu”，比的歌声更柔和甜美。叫声为高音的“tiip”。","habits":"小黑纹头雀倾向于在地面或接近地面的地方觅食，通常单独或成对活动。它们非常隐蔽，很难被观察到。它们的饮食和觅食行为知之甚少。","identification":"与大黑纹头雀非常相似，但小黑纹头雀的眉线更灰，整体颜色稍暗，且通常栖息在较为湿润的环境中。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚东北部（瓜希拉半岛）和委内瑞拉西北部（包括Zulia北部、Falcón和Lara）。"},{"name":"绿背纹头雀","english_name":"Green-backed Sparrow","scientific_name":"Arremonops chloronotus","overview":"绿背纹头雀（英文名：Green-backed Sparrow，学名：Arremonops chloronotus），是雀形目雀鹀科纹头雀属的鸟类。分布于中美洲，自墨西哥东南部至洪都拉斯，常见于热带低地森林的林下层和邻近灌丛。曾被认为是大黑纹头雀的同种，现确认为独立物种。","appearance":"头部呈灰石板色，具宽阔的黑色或棕黑色侧冠条纹。背部、臀部、尾巴和翅膀为较明亮的橄榄绿色。翼缘为金黄色。头部两侧为灰石板色，眼前方有黑色或棕黑色斑点，后眼圈同样颜色。下巴和喉咙为暗白色。胸部和身体两侧为灰色，逐渐变为淡橄榄绿色于两侧。腹部为白色，尾下覆羽为黄橄榄色或橄榄黄。幼鸟上体较成鸟更暗淡的橄榄绿色，黑色条纹可能混有棕色。下体主要为灰色，略带橄榄黄色调。","call":"鸣唱和叫声与褐纹头雀相似，但绿背纹头雀的歌声通常节奏均匀，不同于褐纹头雀加速的音符。","habits":"栖息于热带湿润低地森林的林下层和邻近的灌木丛，偏好森林底层而非开阔地带。其分布区与褐纹头雀重叠，但生境选择不同。","identification":"与褐纹头雀地理分布重叠，但后者头部条纹为暗褐色，上体颜色较暗淡，尾下覆羽颜色偏米黄色。","protection":"IUCN状态未提供。","distribution":"分布于中美洲，包括墨西哥东南部、伯利兹、危地马拉北部、洪都拉斯西部。两个亚种分别占据不同区域，A. c. chloronotus分布在墨西哥东南部至尤卡坦南部和金塔纳罗奥，A. c. twomeyi位于洪都拉斯中部的奥兰乔和约罗部门。","other":"整个Arremonops属的分类学需要重新评估和修订。"},{"name":"大黑纹头雀","english_name":"Black-striped Sparrow","scientific_name":"Arremonops conirostris","overview":"大黑纹头雀（英文名：Black-striped Sparrow，学名：Arremonops conirostris），是雀形目雀鹀科纹头雀属的鸟类。体型壮实，灰身绿背，头部饰以醒目的黑色条纹，通过独特的头部图案与其它雀类和刷雀相区别。常见于中美至南美的低地和丘陵地带，海拔可达1,500米，偏好半开放生境，如灌木丛、次生林、废弃地、果园和花园。","appearance":"体长约16.5厘米，体重介于26至42克。头部灰色，两侧有宽大的黑色冠纹和较窄的黑眼纹。背部、翅膀和尾巴橄榄绿色，翼弯处呈黄色。喉部近白色，下体淡灰色，腹部白，后侧腹和尾下覆羽带有橄榄色。虹膜深红棕色，喙黑色，腿色偏粉至棕灰。雄雌羽毛相似，幼鸟头部黄橄榄色带暗褐色条纹，上体棕橄榄色，下体黄橄榄色，侧腹有暗褐色条纹，喙基部黄色。成年羽毛约在4个月龄时获得。不同亚种在大小和羽毛色调上略有差异。","call":"发出响亮悦耳的叫声和加速的歌声，具有金属质感的churk叫声。雄鸟的鸣唱由哨音和滑音组成，tsweet-tsweet tsweet-tswee ti-ti-ti，随后是一串颤音，但随地理位置而异。","habits":"主要栖息于地面，偶尔在低矮灌木中觅食，以昆虫、蜘蛛和种子为主食，也会从低矮的灌木上挑选浆果和无脊椎动物。通常单独或成对出现，性格羞涩。","breeding":"雌鸟独自筑造大型穹顶巢，材料粗犷，入口宽大，通常位于密生处离地不足1米，最高可达1.8米。每次产卵2枚，有时3枚，纯白色无斑点，仅雌鸟孵卵，孵化期为12至14天。","identification":"与褐纹头雀相似，但体型更大，两者分布区不重叠。头部的黑色条纹是识别的关键特征。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的洪都拉斯至南美洲北部巴西，包括委内瑞拉西部。在繁殖区域内广泛分布，非繁殖季节分布可能有所变化。","other":"本种共包含七个亚种，具体差异主要体现在体型大小和羽毛色彩上。"},{"name":"白眉金肩雀","english_name":"Pectoral Sparrow","scientific_name":"Arremon taciturnus","overview":"白眉金肩雀（英文名：Pectoral Sparrow，学名：Arremon taciturnus），是雀形目雀鹀科金肩雀属的鸟类。南美低地雨林中体型中等、羽色鲜明的地栖雀类。因雄鸟胸前常具黑色“胸带”（pectoral band）而得英文名。头顶黑白纵纹、翠绿背羽及白眉纹使其在林下幽暗环境中仍显醒目。本种广泛分布于安第斯山以东的低地至海拔约1000米的潮湿常绿林及成熟次生林，自哥伦比亚东南延伸至巴西亚马孙地区，并沿海岸南达圣埃斯皮里图州。","appearance":"雄鸟：头黑，具显著白色眉纹及灰色中冠纹；背及翼覆羽亮草绿色，翼弯处金黄；喉白，胸具宽阔黑色横带，腹部白色，两胁淡灰；尾羽橄榄绿。雌鸟：羽色较暗，上体暗橄榄绿，翼上黄色范围小且暗淡；下体淡乳白或浅黄褐，胸带灰褐而窄。幼鸟：上体暗橄榄，下体淡黄，胸胁色深，无翼斑，眉纹仅隐约可见。西北亚种axillaris嘴双色，胸带仅残存两侧黑斑；西南亚种nigrirostris嘴全黑，胸带亦中断。体长约15厘米，雄鸟翼长76–80毫米、尾长64–67毫米，体重平均24.6克。","call":"鸣唱极为尖锐纤细，常被形容为“昆虫般的”高音连续嘶声：zitip, zeee zeee zeee 或 tik-tseeeeeeu tseeeeeu。叫声为短促清脆的“tzip”或“tik”。","habits":"栖息于低地及山麓潮湿常绿林的浓密下层植被、溪谷、沟壑及林隙，也见于成熟次生林和林缘咖啡园。通常单独或成对在地面或近地面活动，偶尔加入混合种类觅食群。以跳跃方式在落叶层中扒寻昆虫（甲虫、蚂蚁、直翅目、半翅目等）及少量种子、果实，觅食时隐蔽而快速。","breeding":"繁殖期在秘鲁东南记录为8月下旬至12月初。一夫一妻制。巢为具侧入口的球形穹顶杯状，筑于近地面的倒木或树根旁，外层竹叶、树叶、根及嫩蕨叶，内层细根与枯叶，高、宽约12厘米，入口高约7.6厘米。每巢2枚卵，卵色白或白底褐斑，平均重3.5克、长23.6毫米、宽17.4毫米。巢成功率极低，主要受负鼠等夜行性哺乳动物捕食。","identification":"在其分布区内，白眉金肩雀独特的黑白头纹与绿色上体使之不易与其他Arremon属种类混淆。与分布接近的金翅金肩雀相比，后者栖于较干燥森林，无白眉纹及中冠纹，翼上黄斑更大且嘴亮黄色；橙嘴金肩雀具橙色嘴；半领金肩雀胸带不完整且下嘴黄色。亚种间依嘴色及胸带完整度可区分。","protection":"IUCN: LC（无危）","distribution":"繁殖区：南美安第斯山以东广阔低地，自哥伦比亚东南、委内瑞拉南部及西部，经圭亚那、巴西亚马孙地区，延伸至巴西大西洋沿岸至圣埃斯皮里图州，并南达秘鲁东南及玻利维亚北部。非繁殖区：留鸟，无明显迁徙。海拔分布自海平面至约1500米（委内瑞拉南部），一般记录多低于1000米。","other":"过去曾将半领金肩雀作为本种亚种，现已提升为独立种。属内系统发育尚未完全解析。"},{"name":"半领金肩雀","english_name":"Half-collared Sparrow","scientific_name":"Arremon semitorquatus","overview":"半领金肩雀（英文名：Half-collared Sparrow，学名：Arremon semitorquatus），是雀形目雀鹀科金肩雀属的特有鸟类，仅分布于巴西东南部的亚热带或热带湿润低地森林中。","appearance":"具有鲜明图案的金肩雀，常栖息于潮湿森林的林下层和次生植被中，通常难以观察到。特征明显的双色喙，上部黑色，下部鲜黄色，两侧胸部分布有黑色斑块。头部黑色与窄白眉纹和灰色颈背形成对比。背部橄榄绿，腹部大部白色，两胁灰色。","call":"鸣声为高音调的“tzee–tzeuuu-tzeeuuu”和金属质感的“tic”。","habits":"栖息于巴西东南部的亚热带或热带湿润低地森林及严重退化的前森林地带。","distribution":"南美洲巴西东南部，包括埃斯皮里图圣多州南部至巴拉那州东北部和里奥格兰德州东北部。"},{"name":"巴西金肩雀","english_name":"Sao Francisco Sparrow","scientific_name":"Arremon franciscanus","overview":"巴西金肩雀（英文名：Sao Francisco Sparrow，学名：Arremon franciscanus），是雀形目雀鹀科金肩雀属的鸟类。仅在巴西中东部的巴伊亚州和米纳斯吉拉斯州发现。栖息于灌木丛生的Caatinga地带，以其亮丽的橄榄绿色背部和鲜明的黑白脸部图案而闻名。","appearance":"巴西金肩雀具有黑色的面部，明亮的白色眉纹，以及黑色的冠顶带有中央的白色条纹。上体为鲜艳的黄绿色，下体呈灰色，胸部侧面有一小块黑色的刺状斑点。喙部颜色为鲜亮的橙黄色，上部边缘为深色。雄鸟头部两侧和冠顶为黑色，颈背和颈部两侧为淡灰色，上体一般为橄榄绿，部分个体翼下覆羽更显黄色。雌鸟尚未有详细描述。","call":"其鸣唱是一系列高音的悦耳复杂声音，以颤音结束，听起来像是“twip-twip tsip-tsip-tsip-tsip”。","habits":"巴西金肩雀主要栖息在Caatinga的灌木丛中，通常在地面觅食。它们的分布范围有限，数量从稀少到局部常见不等。","breeding":"关于巴西金肩雀的繁殖信息尚未充分研究。","identification":"与半领金肩雀相似，但后者胸部侧面有更多的暗色，喙部黄色部分较少，下体颜色较暗。此外，黄嘴金肩雀和白眉金肩雀也有各自的明显差异，例如喙部颜色和胸部条纹。","protection":"IUCN：NT（近危）","distribution":"巴西金肩雀分布于巴西中东部，具体在巴伊亚州和北部的米纳斯吉拉斯州。","other":"这种雀类直到1997年才被科学界正式描述，目前对其生态和生活习性的了解仍然有限。"},{"name":"黄嘴金肩雀","english_name":"Saffron-billed Sparrow","scientific_name":"Arremon flavirostris","overview":"黄嘴金肩雀（英文名：Saffron-billed Sparrow，学名：Arremon flavirostris），是雀形目雀鹀科金肩雀属的鸟类。新世界雀科鸟类，分布于南美洲东南部至中南部，包括阿根廷、玻利维亚、巴西和巴拉圭。其显著特征为明亮的橙色喙，头部黑白相间，胸部有一条黑色带纹。","appearance":"成年黄嘴金肩雀具有黑色头部，白色眉纹延伸至颈背，颈部灰色，背部、翅膀和尾巴呈绿色。下体白色，侧翼灰，胸上有一窄黑带。雄鸟与雌鸟相似，但雌鸟色彩较暗淡，腹部呈黄褐色。雏鸟与成鸟相似，但颜色更为暗淡。全长15至16.5厘米，体重平均23.6至28.1克。","call":"鸣唱为一系列快速音符，描述为“tsit, tsee-tsi-tsi, tseép-seép-tseép”和“sidsidlidsidlsidli”。叫声为类似昆虫的‘tseet’声。","habits":"栖息于热带落叶林，包括原生林和次生林，常见于森林边缘、内部空地和水道附近。海拔高度从海平面到1400米。饮食包括水果、谷物和昆虫。","identification":"与白眉金肩雀的区别在于其橙色的喙，而白眉金肩雀喙为黑色。与巴西金肩雀和橙嘴金肩雀的区别在于其完整的胸带和白色的颏部。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲东南部和中南部，具体包括巴西中部和东部、玻利维亚东部、巴拉圭大部分地区和阿根廷东北部。"},{"name":"橙嘴金肩雀","english_name":"Orange-billed Sparrow","scientific_name":"Arremon aurantiirostris","overview":"橙嘴金肩雀（英文名：Orange-billed Sparrow，学名：Arremon aurantiirostris），是雀形目雀鹀科金肩雀属的鸟类。从墨西哥东南部至秘鲁东北部都有其踪迹。这种中型雀鸟以其醒目的橙色喙和黑白相间的头部图案而著称。","appearance":"橙嘴金肩雀拥有鲜明的黑色头部，与白色的眉纹和喉咙形成强烈对比，其宽阔的黑色胸带更为其增添特色。上体呈橄榄绿色，翼弯处显黄色，下体灰白色，两侧和尾下覆羽为褐色至橄榄绿。雄雌相似，幼鸟上体和胸部为烟灰色橄榄色，腹部污橄榄色，较暗和棕色在两侧和尾下覆羽。","call":"鸣声高亢，但在地理上有显著变化。","habits":"生活在湿润的热带森林和边缘地带，常见于林下植被和灌木丛中，偶尔出现在小径或空地边缘。以叶下层或低矮灌木为食，主要摄食种子和昆虫。","breeding":"一般成对或小家庭群出现，进行领地防御，繁殖季节在雨季期间，筑巢于灌木丛中，具体繁殖细节尚需更多研究。","identification":"橙嘴金肩雀的橙色喙是其最显著的识别特征，与刷雀属的某些物种相似，但橙喙使其容易区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的墨西哥东南部至南美洲的哥伦比亚、厄瓜多尔和北秘鲁，栖息于低海拔至约1200米的热带湿润森林。","other":"已知存在八个亚种，主要基于羽毛颜色和体型的细微差异。"},{"name":"金翅金肩雀","english_name":"Golden-winged Sparrow","scientific_name":"Arremon schlegeli","overview":"金翅金肩雀（英文名：Golden-winged Sparrow，学名：Arremon schlegeli），是雀形目雀鹀科金肩雀属的鸟类。黑头黄喙的美丽雀类，分布于哥伦比亚和委内瑞拉的森林地带。其显著特征包括黑色头部、明亮黄色喙、白色喉部与体腹、淡灰色背羽、橄榄绿背部及金色肩部。体型中等，仅在南美北部地区可见。","appearance":"金翅金肩雀拥有鲜明的黑色头盔、长而鲜亮的黄色喙，白色的喉部与腹部，淡灰色的披肩，背部与臀部呈橄榄绿色，翅膀和尾巴为灰色，肩部则闪耀着金色光泽。雌鸟的喙色较暗，下体带有微弱的黄褐色调。成年雄鸟的头部、颊部和胸部延伸至耳羽下方的黑色斑块形成断续的胸带，环绕着白色的喉部。背部中央及肩部有一块明显的绿色区域。亚成鸟的冠羽、眉纹、耳羽和颊部为橄榄绿色，逐渐转变为黑色。","call":"其鸣唱为一连串高音的重复音节，通常被描述为\"Zeut, Zeut, Zeee\"或\"Soot Soot Soot See\"，尤其在清晨的四月至五月间常能听到。","habits":"金翅金肩雀栖息于干湿林地及灌木丛生的次生植被中，常见于开阔的落叶林或干燥的次生植被，海拔高度可达1400米。它们以种子、果实和昆虫为食，既独行也成对觅食。","breeding":"繁殖季节尚不明确，但据观察，歌唱活动的增加预示着雨季的到来，这可能是繁殖期。其歌曲是一系列高亢、细薄的重复音符。","identification":"金翅金肩雀在分布范围内是唯一具有全黑头部的雀类。与之最相似的是白眉金肩雀和橙嘴金肩雀，前者通过完整的黑胸带、白色眉纹和黑色喙区分，后者则有橙色喙、完整黑胸带和明显白色眉纹。","protection":"IUCN：LC（无危）","distribution":"金翅金肩雀主要分布在哥伦比亚北部和委内瑞拉北部的干旱地区。"},{"name":"黑顶金肩雀","english_name":"Black-capped Sparrow","scientific_name":"Arremon abeillei","overview":"黑顶金肩雀（英文名：Black-capped Sparrow，学名：Arremon abeillei），是雀形目雀鹀科金肩雀属的鸟类。南美西北部特有种，分布于厄瓜多尔西南太平洋沿岸至秘鲁西北部。通体呈黑、灰、白三色，无金肩雀属典型的绿色上体或黄色粗喙，具有黑色冠顶、面罩及胸带，白色眉纹自眼上延伸至颈侧，喙全黑。栖于海拔1,800米以下干燥及半湿润森林的下层灌丛，亦见于次生灌丛。","appearance":"成鸟头顶、面颊及喉侧均为黑色，一条宽阔的白色眉纹自眼上方起向后延伸至颈侧，形成鲜明的黑白对比。上体蓝灰色，翼覆羽同色，少数个体（雌鸟？）中覆羽及大覆羽具极窄的浅色端缘，形成隐约的白色翼斑；飞羽暗褐，外缘蓝灰。颏喉洁白，胸部具完整的黑色横带；胸侧及胁蓝灰，腹部中央近白。喙全黑，虹膜褐色，跗跖及趾黑色。全长约15厘米，雄鸟平均体重26.0克，雌鸟25.8克。幼鸟羽色未描述。","call":"鸣唱为短促而高亢的两段式短语，每数秒重复一次：首段含2–4个升降交替或同音的哨音，第二段为快速同音颤音，常被描述为“tseeét, tsi-tsi-tsi-tsi tseeét”或“tsew tsew tsi-tetetetete”，整体频率高于橙嘴金肩雀但带较低、较少咝声的质感。常见叫声包括极短促的“tsik”、下降的“tseew”及带金属感的“bzee”，多单独或组合出现。鸣唱主要出现在1–5月雨季清晨至上午，自距地面数米的灌丛或低枝发出。","habits":"留鸟，活动范围限于干燥热带落叶林、长廊林及常绿林的下层，亦见于浓密次生灌丛。通常在地面或近地面觅食，单独或成对活动，极少加入混群，但有时与地栖灶鸟科如红冠拾叶雀和黑头针尾雀同时出现。食物推测包括昆虫、种子及小果实，但尚未详细记录。","breeding":"繁殖资料缺乏。推测营巢于灌丛或低枝，巢为侧面入口的叶枝圆顶状，与同属其他物种相似。鸣唱集中1–5月雨季，可能与繁殖期同步。","identification":"在分布区内，黑顶金肩雀是唯一具黑白头纹的小体型林栖雀类。橙嘴金肩雀与之在厄瓜多尔极窄重叠，偏好更湿润生境，具绿色上体及橙黄粗喙。灰眉薮雀体型更大，上体绿色更广泛，头纹灰色而非白色，无黑色胸带。与领歌鹀雄鸟略似，但后者栖于较高处，具白色颧纹、灰色冠顶及尾端白色。曾被视为同属的马谷金肩雀背、腰及小覆羽橄榄绿色，眉纹前段白色，鸣唱第二段音调上升且频率范围更小，两者分布不重叠。","protection":"IUCN: LC（无危）","distribution":"繁殖与非繁殖区域相同，分布于南美西北部太平洋沿岸：厄瓜多尔中部马纳维省及北部洛斯里奥斯省以南，至秘鲁西南卡哈马卡省。海拔范围厄瓜多尔可达1,600米，秘鲁可达1,800米，但主要见于700米以下低地。","other":"系统分类上长期与马谷金肩雀被视为同一物种，现基于羽色及鸣唱差异分列为独立种。"},{"name":"栗顶薮雀","english_name":"Chestnut-capped Brushfinch","scientific_name":"Arremon brunneinucha","overview":"栗顶薮雀（英文名：Chestnut-capped Brushfinch，学名：Arremon brunneinucha），是雀形目雀鹀科金肩雀属的鸟类。体型较为健壮、主要栖息于中美洲至南美洲山地森林下。拥有独特的头部特征，包括黄色边缘的栗色冠羽和颈背，黑色额部与侧头，以及醒目的白色喉部。分布于墨西哥至厄瓜多尔的高海拔地区。","appearance":"成年栗顶薮雀长约19厘米，重约45克，具有长而细的喙与较大的脚。其头部特征鲜明，包括黄色边缘的栗色冠羽和颈背，黑色的额部与两侧头部，中间和两侧额部有白色斑点，白色喉部在兴奋时会鼓起。上体呈深橄榄色，翅膀颜色更深。白色胸部中央与白色喉部由黑色带纹隔开，胸侧灰白，两胁和下腹橄榄绿色。幼鸟具烟灰色帽状羽、烟灰色面和橄榄棕色上体、喉咙与胸部。","call":"发出薄而尖锐的叫声和非常高的嘶嘶声。雄鸟的歌声混合了哨音和尖锐的音符。","habits":"栖息于海拔900米至2500米的湿润山地森林下层，常见于茂密的次生林和峡谷。主要以昆虫和蜘蛛为食，从叶床中用喙提取，也会从低矮灌木中挑选浆果和其他无脊椎动物。通常成对或家庭群活动。","breeding":"繁殖季节在墨西哥为5月中旬至6月，8月在格雷罗，4月初在奥哈卡州；在哥斯达黎加，筑巢时间为4月中旬至8月，大多数从4月开始；在巴拿马，观察到幼鸟在3月中旬。巢为大型杯状，由雌鸟构建，放置于离地面不到2.5米的灌木或小树中，内部铺垫更细腻的材料。每窝产卵2枚，有时仅1枚，卵为白色或淡蓝色，无斑点，仅由雌鸟孵化，孵化期14天，雏鸟期13天。","identification":"与领唧鹀的区别在于体型较小，色彩较暗淡，具有黑色领圈和白色的眉纹。不同亚种之间在羽毛标记和色彩上有差异。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲的高海拔地区，自墨西哥至厄瓜多尔。在哥斯达黎加发现于苔藓覆盖的亚热带森林，偏好最密集的下层植被；在危地马拉发现于温带森林、橡树林（Quercus）、其他阔叶树混杂松树（Pinus）的地带，以及一些较高山坡上的‘柏树’丛，可达3050米高度。"},{"name":"绿纹薮雀","english_name":"Green-striped Brushfinch","scientific_name":"Arremon virenticeps","overview":"绿纹薮雀（英文名：Green-striped Brushfinch，学名：Arremon virenticeps），是雀形目雀鹀科金肩雀属的鸟类。主要栖息于太平洋斜坡和中央火山带的高地森林中，海拔高度介于1800至3500米之间。其分布范围不与较为相似的栗顶薮雀重叠。","appearance":"绿纹薮雀是一种体形较健壮、类似麻雀的鸟类。成鸟拥有橄榄绿色的上体，头部两侧有宽黑条纹和黑色面罩，头顶中间有一条宽阔的黄橄榄绿色条纹。喉咙纯白，胸部和两肋灰白色，腹部白色。雌雄羽毛相似。幼鸟呈褐色，头纹较暗淡，喉咙和下体橄榄棕色，喉咙处有白色斑点，腹部有淡黄色条纹。","habits":"绿纹薮雀通常成对活动，以地面或近地面为食。它们偏好在茂密的灌木花丛和阴凉峡谷的林下层生活，往往隐匿不易观察。其栖息环境主要为冷杉和湿润的松栎树林下层。","identification":"绿纹薮雀与栗顶薮雀在外观上有明显区别，后者具有栗色的头顶和白色喉部边缘的黑色边界。此外，绿纹薮雀的绿色眉纹与栗顶薮雀的缺失形成对比。在中央墨西哥，两种物种的分布范围几乎相邻，但没有地理重叠。","protection":"IUCN：LC（无危）","distribution":"绿纹薮雀分布于中美洲的墨西哥西部和中部，具体而言是在太平洋斜坡和中央火山带的高海拔地区。"},{"name":"黑头薮雀","english_name":"Black-headed Brushfinch","scientific_name":"Arremon atricapillus","overview":"黑头薮雀（英文名：Black-headed Brushfinch，学名：Arremon atricapillus），是雀形目雀鹀科金肩雀属的小型鸟类。其显著特征为全黑色头部，与明亮的白色喉咙和橄榄色背部形成鲜明对比。该物种分布于中美洲巴拿马东部及南美洲哥伦比亚安第斯山脉的山脚地带。","appearance":"黑头薮雀的头部全黑，与白色的喉咙和橄榄绿色的背部形成鲜明对比。雌雄外观相似，通常单独或成对出现。它们的体型适中，活跃于地面附近。","habits":"黑头薮雀栖息于潮湿森林的灌木层，尤其偏好森林边缘，海拔高度在300至1200米之间。它们的生活习性包括在地面附近寻找食物。","identification":"黑头薮雀与条纹头薮雀的分布区域接近，但两者间没有明显的混种迹象。在哥伦比亚，它们的分布有重叠，但可通过头部颜色明显区分。","distribution":"黑头薮雀的分布范围主要集中在巴拿马东部和哥伦比亚的安第斯山脉。"},{"name":"哥斯达黎加薮雀","english_name":"Costa Rican Brushfinch","scientific_name":"Arremon costaricensis","overview":"哥斯达黎加薮雀（英文名：Costa Rican Brushfinch，学名：Arremon costaricensis），是雀形目雀鹀科金肩雀属的中型鸟类。拥有绿色背部，灰色眉纹，黑色脸颊和白色喉部。最相似于大黑纹头雀，但其整个脸颊呈黑色而非仅限眼线部分；与栗顶薮雀相比，缺乏锈色的冠羽。常成对出现，通常在落叶层中搜寻或低处灌丛中活动。","appearance":"哥斯达黎加薮雀体长约17.4至20厘米，体重40至49.5克。头部全黑，具有宽广的灰色中冠条纹和从上眶区延伸至颈侧和颈背的灰色条纹；上体、翼和尾橄榄绿色；喉、胸和腹部白色，侧身和胁部逐渐变为灰色，后胁、腹下部和尾下覆羽橄榄色；虹膜暗红色；喙深灰色；腿深粉色。雌雄同形同色。幼鸟头部暗区为烟黑色，比成鸟暗淡，上体橄榄绿色，下体灰色，腹部渐变为暗黄褐色。","call":"鸣声高亢而尖细，由相对简单的1至3个交替的、独特的高音节短语组成，其间穿插着沉默期。叫声尖锐且具金属质感。","habits":"栖息于中美洲哥斯达黎加西南部山脉及相邻的巴拿马西部地区的林地。常在地面或低矮植被中活动，以搜寻食物。","identification":"与大黑纹头雀和栗顶薮雀区别在于其脸颊全黑，缺乏锈色冠羽，通过这些特征可以有效区分。","distribution":"分布于中美洲的哥斯达黎加西南部和巴拿马西部（奇里基省）。"},{"name":"纹头薮雀","english_name":"White-browed Brushfinch","scientific_name":"Arremon torquatus","overview":"纹头薮雀（英文名：White-browed Brushfinch，学名：Arremon torquatus），是雀形目雀鹀科金肩雀属的鸟类。体型较大的雀类，主要分布在南美洲的秘鲁南部、玻利维亚和阿根廷西北部。其显著特征为橄榄色背部，黑色面罩，条纹头部和白色喉部，部分地区的个体还带有黑色胸带。此物种是南美洲安第斯山脉中较为常见的鸟类。","appearance":"纹头薮雀拥有橄榄绿色的背部，头部具有明显的条纹图案，包括一条宽大的黑色冠纹和侧头黑面具，上方覆盖着宽阔的白色眉纹。喉部纯白，大多数个体胸部有黑色新月形边框，但在南部玻利维亚和阿根廷的亚种中缺失。胸部中心和腹部为白色，两肋呈灰色，翼和尾部颜色与背部相似。雌雄外观相似。","call":"其典型鸣唱为一系列三到四个高音的哨声，呈现出升降调的模式。","habits":"生活在湿润森林的灌木丛中，偏好安第斯山脉东坡的环境，海拔主要在2000至3000米之间，但也有记录显示它们能在更低的海拔生存。纹头薮雀在森林下层的密丛中活动，以种子和小型昆虫为食。","breeding":"关于纹头薮雀的繁殖习性的具体信息较少，但基于同属其它物种的观察，它们可能在春季繁殖，营巢于灌木丛中，由雌鸟孵化卵。","identification":"与灰眉薮雀的区别在于纹头薮雀的眉纹为白色而非灰色。此外，纹头薮雀的分布区域有助于区分两者。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于南美洲的秘鲁南部、玻利维亚和阿根廷西北部。","other":"纹头薮雀曾被认为是纹头薮雀复合群的一部分，现已确认为独立物种之一，该复合群包含至少八种独立的薮雀物种。"},{"name":"北纹头薮雀","english_name":"Sierra Nevada Brushfinch","scientific_name":"Arremon basilicus","overview":"北纹头薮雀（英文名：Sierra Nevada Brushfinch，学名：Arremon basilicus），是雀形目雀鹀科金肩雀属的鸟类。脸部与胸部呈黑色，喉部白色，头部有条纹，体型较小范围内独特。","appearance":"这种鸟长19厘米，体态丰满，头部显得较大，喙较长。头部顶部和面部黑色，冠部中央有灰色条纹，眼上有一灰色眉纹；颊部下方和耳羽处黑色分明，与白色喉部形成强烈对比；背部、翅膀和尾巴橄榄绿色，在光照良好时更显草绿色；白喉部分与白色下体由黑色胸带分隔，侧胸灰，两胁至腹橄榄棕色；眼睛深栗色，喙和腿均为黑色。雌雄色彩相同，幼鸟比成鸟上部颜色更棕，头部暗淡无条纹，下体淡棕色带有深棕色斑纹。","call":"鸣唱是一系列高音的嘶嘶声和颤音，速度极快，声音略带紧张感，有时夹杂着一些颤抖的高音哨声。叫声为尖锐的单音。","habits":"栖息于湿润的山地森林低层植被中，尤其靠近边缘地带，海拔高度在600至2800米之间。通常在地面觅食，倾向于在植被遮盖下活动，会用喙扒开枯叶。成对或单独活动。","breeding":"观察到的雏鸟出现时间在3月至7月间，关于繁殖的其他信息尚不清楚。","identification":"与其他近缘物种相比，北纹头薮雀的脸部和胸部黑色，不会延伸至颈部侧面，与白色喉部形成鲜明对比。在叫声和鸣唱上有独特之处。","protection":"IUCN：NT（近危）。该物种全球分布范围非常小，但可能人口数量稳定。考虑到其分布范围狭窄，需识别任何潜在威胁。","distribution":"分布于南美哥伦比亚圣玛尔塔山脉，主要在哥伦比亚北部的Sierra Nevada de Santa Marta。"},{"name":"东纹头薮雀","english_name":"Perija Brushfinch","scientific_name":"Arremon perijanus","overview":"东纹头薮雀（英文名：Perija Brushfinch，学名：Arremon perijanus），是雀形目雀鹀科金肩雀属的独特鸟类。仅见于南美洲佩里哈山脉，位于哥伦比亚东北部与委内瑞拉西北部边境地带，北临安第斯山脉主脉。其黑色面罩和胸带、白色喉部、条纹头部以及橄榄绿色背部使其在有限的分布区内易于识别。","appearance":"东纹头薮雀拥有醒目的外观，包括黑色的面罩和胸带，白色的喉部，头部有明显的条纹，背部呈橄榄绿色。体型适中，性别之间在外表上可能有细微差别。生活在云雾森林的下层，由于害羞和隐秘的行为，观察时较难发现。","call":"东纹头薮雀的鸣叫声高亢，类似蜂鸟的哼鸣声，由三音符组成：“seeuw.. see.. teechew”，重复不断，持续约2秒，首音节最为响亮，随后音调下降。","habits":"栖息于云雾森林的下层植被，偏好湿润森林边缘地带，活动于海拔300至1200米之间。以地面觅食为主，利用喙部在落叶层中搜寻食物，通常单独或成对出现，有时在次生林的下层活动。","identification":"与其他同属物种相比，东纹头薮雀的独特面罩、胸带、条纹头部以及特定的鸣叫声使其容易区分。","protection":"IUCN：LC（无危）","distribution":"分布局限于南美的佩里哈山脉，包括哥伦比亚东北部和委内瑞拉西北部的Serranía del Perijá区域。","other":"历史上的访问限制导致对该物种的生活习性了解有限，加之分类学不确定性，使得其状况评估复杂化。"},{"name":"灰眉薮雀","english_name":"Grey-browed Brushfinch","scientific_name":"Arremon assimilis","overview":"灰眉薮雀（英文名：Grey-browed Brushfinch，学名：Arremon assimilis），是雀形目雀鹀科金肩雀属的鸟类。分布于南美洲安第斯山脉，自委内瑞拉至秘鲁。上半身呈橄榄色，下半身为白色，两侧带有灰色，头部有鲜明的黑灰色条纹。雌雄外观相似，常在山地森林的底层、边缘和次生林中觅食，接近地面活动。一般活动高度在1500至3000米之间，局部地区可低至约500米。","appearance":"灰眉薮雀体长19-20厘米，头部显得较大，喙较长。具有黑色的冠和脸部，灰色的冠状条纹和眉纹几乎延伸至喙基，条纹在靠近喙处变得更白，在眼后加宽并与颈部的灰色相连，一直延伸至胸部侧面。脸颊和耳覆羽下缘的黑色与白色喉部形成强烈对比。上体、翅膀和尾巴为橄榄绿色，下体白色，胸部灰色延伸至侧翼，胁部灰褐色。虹膜深栗棕色，喙黑色，腿肉粉色到灰色。幼鸟橄榄色，脸颊灰暗，喙黄色。亚种nigrifrons冠纹不广泛，眉纹在眼后几乎消失；亚种larensis有宽阔的灰色眉纹，上喙区变白，具黑色胸带；亚种poliophrys类似，有黑色胸带，但眉纹更广泛。","habits":"灰眉薮雀在山地森林的底层、边缘和次生林中活动，偏好湿润环境，活动高度在300至1200米之间，以植物种子、果实和昆虫为食，常单独或成对觅食，近地面或地面活动。","identification":"灰眉薮雀与条纹头薮雀的区别在于其独特的叫声、羽毛颜色和遗传特征，使其被认定为独立物种。","protection":"IUCN：LC（无危）","distribution":"分布于南美的安第斯山脉，包括委内瑞拉、哥伦比亚、厄瓜多尔和秘鲁大部分地区。"},{"name":"加拉加斯薮雀","english_name":"Caracas Brushfinch","scientific_name":"Arremon phaeopleurus","overview":"加拉加斯薮雀（英文名：Caracas Brushfinch，学名：Arremon phaeopleurus），是雀形目雀鹀科金肩雀属的鸟类。活跃于委内瑞拉北部海岸山脉的潮湿森林地带，常在海拔300至1200米处的林缘地带活动。","appearance":"加拉加斯薮雀体型健壮，头部相对较大，喙较长。其头顶和面部呈黑色，具有一条灰色的中冠纹和一条几乎延伸至喙基部的灰白色眉纹，近喙处的眉纹颜色更显白色，眼后部位加宽并与颈部的灰色相接。脸颊下方和耳羽的黑色边缘与白色喉部形成鲜明对比。上体、翅膀和尾巴橄榄绿色，强光下呈现草绿色。胸部有黑色胸带，两侧的胸部为灰色，腹侧至臀部橄榄色。虹膜为栗褐色，喙黑色，腿肉色至黑灰色。两性相似，幼鸟特征未详述。","call":"加拉加斯薮雀的鸣唱极为高音，类似蜂鸟般的音调。其歌曲通常由三到五个音符组成的短语连续重复，一句约持续5秒，音调先升高后降下，略带粗糙。","habits":"这种鸟常单独或成对活动，偶尔以家庭群形式出现。它们在地面觅食，会用喙刨开落叶层寻找食物。加拉加斯薮雀偏好在密集的次生植被、森林边缘以及咖啡种植园等地活动。","breeding":"关于繁殖行为的具体信息缺失。","identification":"在分布范围内无相似物种，独特的黑色头部和白色眉纹使其易于辨认。","protection":"IUCN：LC（无危）。此物种虽全球分布有限，但在多个保护区内稳定存在，如San Esteban、Henri Pittier、Macarao、El Ávila和Guatopo国家公园，以及Pico Codazzi和Cerro Platillón自然保护区。","distribution":"加拉加斯薮雀主要分布在委内瑞拉北部的阿腊瓜、米兰达和联邦区的山脉。","other":"曾被视为条纹头薮雀的亚种，基于叫声、羽毛和遗传差异，现已确认为独立物种。"},{"name":"委内瑞拉薮雀","english_name":"Paria Brushfinch","scientific_name":"Arremon phygas","overview":"委内瑞拉薮雀（英文名：Paria Brushfinch，学名：Arremon phygas），是雀形目雀鹀科金肩雀属的鸟类。这种引人注目的小鸟拥有黑色头部和灰色眉毛，背部及尾巴橄榄黄色，腹部灰白，胸前有一条明显的黑色横带。仅分布在委内瑞拉海岸山脉东部。","appearance":"委内瑞拉薮雀体型略大，长约19厘米，显得头大且喙较长。成鸟具有黑色的冠顶和脸部，残留的灰色中线痕迹，眼后有白色眉纹。颈侧及胸侧灰色，胸前有一黑色横带与白色喉部形成鲜明对比。上体橄榄绿色，在良好光线下更显草绿。下体白色，侧面及两胁灰色，带有绿色调。虹膜深栗褐色，喙及腿黑色。雌雄相似，幼鸟上体暗橄榄色，下体灰肉桂色，带暗色条纹。","call":"其鸣唱和叫声重复且音调极高。","habits":"在湿润的山地森林中独自或成对活动，有时靠近边缘地带，高度在920至1500米之间。以地面为活动区域，用喙扒开枯叶寻找食物。","breeding":"关于其繁殖习性的细节尚不清楚。","identification":"在其分布范围内没有类似物种。独特的黑色头部和胸部横带是辨识关键。","protection":"IUCN：VU（易危）。由于栖息地森林破坏严重，种群数量正在缩减，且分布区越来越碎片化。","distribution":"委内瑞拉东北部，包括安索阿特吉、苏克雷和莫纳加斯山区。","other":"曾被认为是纹头薮雀的一个亚种，但基于鸣声、羽毛和遗传差异被确定为独立物种。"},{"name":"乌脸雀","english_name":"Sooty-faced Finch","scientific_name":"Arremon crassirostris","overview":"乌脸雀（英文名：Sooty-faced Finch，学名：Arremon crassirostris），是雀形目雀鹀科金肩雀属的鸟类。以橄榄色为主调，腹部显黄色，面部深灰，顶冠红褐色，具有独特的白髭纹。分布于中美洲哥斯达黎加至巴拿马西部山区，主要栖息于热带湿润山林。","appearance":"乌脸雀体长约15.0-17.1厘米，体重37-40.5克。头部红褐色，侧脸及喉部呈黑灰色，有一条明显的白色髭纹。上体暗橄榄绿，翅膀和尾巴略带棕色；下体大部分为暗橄榄绿色，下胸至腹部广泛黄色。虹膜深棕色，上喙暗灰色，下喙淡黄或白色，腿脚深色。雌雄羽毛相似，幼鸟上体丰富橄榄棕色，腹部中心淡黄色，带有黑色污点。","habits":"乌脸雀通常成对或小家庭群活动，偏好在森林溪流周围的低矮灌丛中或叶床中觅食，性格较为害羞。其活动范围和栖息地局限于热带湿润山林。","identification":"乌脸雀的辨识特征包括其红褐色顶冠、黑灰色脸部、白色髭纹及腹部黄色，这些特征使其在分布范围内容易与其他类似鸟类区分开来。","protection":"IUCN：LC（无危）","distribution":"乌脸雀分布于中美洲的哥斯达黎加（阿瓜卡特山脉）南至巴拿马（博卡斯德尔托罗、奇里基、维拉瓜斯、科克莱和东部达连）及邻近哥伦比亚西部（塞罗塔卡尔努纳）。"},{"name":"栗头绿雀","english_name":"Olive Finch","scientific_name":"Arremon castaneiceps","overview":"栗头绿雀（英文名：Olive Finch，学名：Arremon castaneiceps），是雀形目雀鹀科金肩雀属的鸟类。体型较小、羽色以橄榄绿色为主，头顶及颈背呈栗色，脸部和喉部为深灰色的鸟种。分布于南美洲安第斯山脉的哥伦比亚至秘鲁一带，常见于云雾缭绕的森林地带，偏好湿润的山地森林环境，尤其是溪流边的密林中。","appearance":"栗头绿雀的成鸟无论性别，外观相似，头部的前冠、冠顶和颈背呈现暗淡的栗色，而脸庞和喉部则是烟灰色，其余体羽为无条纹的橄榄绿色。翅膀和尾巴的颜色比身体其他部位更深。幼鸟与成鸟相似，但头顶颜色较暗淡，喉咙和脸部为橄榄色，整体羽毛色泽不够均匀。喙部上颚为黑色或深灰色，下颚浅灰色，尖端黑色；虹膜为棕色或深棕色；跗跖和脚趾为黑色。","call":"其鸣声为高音调、尖锐的歌声，即使在湍急流水的轰鸣声中也能被听见。","habits":"栗头绿雀偏好生活在湿度较高的山地森林，尤其喜爱在溪谷和峡谷的密丛中活动，有时也会远离水源。它们通常成单个或成对出现，保持在低矮植被层活动，以地面跳跃的方式移动。食物可能包括种子和昆虫。","breeding":"繁殖季节在3月至6月间，巢穴为大型的穹顶状结构，侧向开口，常被苔藓、藤蔓、蕨类或根系覆盖，由编织的根茎、竹叶和新鲜蕨叶构成。巢址多位于溪流边的河岸或靠近流水的植被中。每次产卵2枚，蛋壳主要为白色，偶尔可见小红棕色斑点集中在较大的一端。","identification":"与近缘种如乌脸雀相比，栗头绿雀具有更暗且均匀的体羽，以及独特的暗色喉部。幼鸟可以通过其较暗的脚色和双色喙（上颚黑色或深灰色，下颚黄色）与同属其他物种的幼鸟区分开来。","protection":"IUCN：NT（近危）","distribution":"栗头绿雀分布于南美洲的安第斯山脉，具体范围包括哥伦比亚西部至厄瓜多尔，以及从哥伦比亚南部延伸至秘鲁的东部地区。","other":"栗头绿雀曾被归类于Lysurus属，后被重新分类至Arremon属。"},{"name":"苔背金肩雀","english_name":"Moss-backed Sparrow","scientific_name":"Arremon dorbignii","overview":"苔背金肩雀（英文名：Moss-backed Sparrow，学名：Arremon dorbignii），是雀形目雀鹀科金肩雀属的鸟类。分布于南美洲，自玻利维亚中部至阿根廷西北部，常见于热带半落叶森林中。","appearance":"成年雄性苔背金肩雀头部主要为黑色，眼上至头后有白色眉纹，颈部灰色，背部、翅膀和尾巴呈暗橄榄绿色。腹部白色，边缘灰白，胸部上方有一窄黑带。雌鸟相似但整体较暗淡，冠纹橄榄色，腹部偏黄褐色，两侧棕色。雏鸟类似成鸟，但色泽更淡。其显著特征为橙色喙，与之前认为的亲缘种黄嘴金肩雀共享这一特征。成鸟平均重量约为22.1克。","call":"鸣唱为一系列高音调的音符。","habits":"栖息于热带半落叶林，包括原始林和次生林，常在林缘、内部空地和水边活动。海拔分布从海平面至1400米。饮食包括水果、谷物和昆虫。","breeding":"繁殖期从10月至12月，筑封闭巢，高度可达1米，平均产卵数为2.8枚，由雌鸟孵卵，两性共同喂养雏鸟。","identification":"与黄嘴金肩雀极为相似，主要区别在于眉纹的位置和长度，以及喙的颜色。","protection":"IUCN：LC（无危）","distribution":"分布于玻利维亚中部至阿根廷西北部，具体包括La Paz、Cochabamba和Santa Cruz部门，向南延伸至Catamarca省。","other":"曾被认为是黄嘴金肩雀的亚种，2021年由SACC和IOC升格为独立物种。"},{"name":"大脚薮雀","english_name":"Large-footed Finch","scientific_name":"Pezopetes capitalis","overview":"大脚薮雀（英文名：Large-footed Finch，学名：Pezopetes capitalis），是雀形目雀鹀科大脚雀属的唯一物种，分布于中美洲的哥斯达黎加和巴拿马西部高地。体型较大，尾长，拥有非常大的脚和腿，喙显得相对纤细。主要栖息于海拔2150至3350米的森林底层、次生林和杂草丛生的牧场。","appearance":"大脚薮雀是一种大型的、尾长而结实的雀类，体长约20厘米，体重约56克。其上体为深橄榄色，翅膀和尾巴呈黑色边缘带有橄榄色，下体为亮橄榄色，两胁和下腹带棕色色调。头部为灰色，喉部和前额至冠两侧为黑色，喙黑色，足和趾强大，颜色为黑色或褐色。","call":"发出尖锐的seet叫声，雄鸟的歌声由哨音、颤音、叽叽喳喳声和模仿组成，通常从地面或低矮的栖木上发出。","habits":"大脚薮雀偏好密集植被区，如山地森林底层、次生林和杂草丛生的牧场，以昆虫、蜘蛛和种子为食，通过强力的双爪挖掘落叶层中的食物。","breeding":"巢由雌鸟单独建造，是一个放置在竹子或浓密灌木中不足2米高的松散杯状植物材料的巢。典型的一窝含有一到两个带有棕色斑点的白色或蓝白色的蛋，仅由雌鸟独自孵化大约12至14天。","identification":"大脚薮雀与乌脸雀相似，但体型更大，野外观察时呈现暗色，其叫声也与橙腹夜鸫相似，但更简单，缺乏夜鸫歌声的笛音特质。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加和巴拿马西部高地，主要栖息于海拔2150至3350米的环境。","other":"大脚薮雀是Pezopetes属的唯一成员，属于Passerellidae家族，与美国的雀类、雀鹀、juncos和towhees有亲缘关系。"},{"name":"棕顶薮雀","english_name":"Rufous-capped Brushfinch","scientific_name":"Atlapetes pileatus","overview":"棕顶薮雀（英文名：Rufous-capped Brushfinch，学名：Atlapetes pileatus），是雀形目雀鹀科薮雀属的鸟类。一种吸引人的小型雀类，仅见于墨西哥中部高地。其自然生境为亚热带或热带湿润山地森林和高海拔灌木丛。","appearance":"体长14.5至16.5厘米，体重21.5至27.5克。头顶呈锈红色，脸部侧面深灰，颈背及头部其余部分灰色，喉部黄色宽大。上体包括翅膀和尾巴为暗橄榄绿色，下体黄色，胸部两侧带有橄榄色调，两胁和臀下覆羽通常更偏肉桂色。眼睛棕色至深红棕色，喙黑色，腿脚灰粉色至棕色。雌雄色彩相同。幼鸟类似成鸟，但头顶无锈色，翼上有淡色条纹，下方颜色较浅。","habits":"偏好潮湿松栎林（Pinus-Quercus）带的浓密灌木丛和花丛。主要以昆虫和种子为食，常在地面附近觅食，也会在灌木顶部活动。跳跃于地面，翻动叶子寻找昆虫和其他食物。有时跟随行军蚁群。通常成对或小群体活动。","identification":"与其他鸟类区别的关键特征包括锈色的帽状头顶，灰色的脸部，以及明亮的黄色喉部。与同域的棕顶王森莺相比，后者眉纹白色，而棕顶薮雀没有。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的墨西哥，特别是在900至3500米的高海拔地区。"},{"name":"白须薮雀","english_name":"Moustached Brushfinch","scientific_name":"Atlapetes albofrenatus","overview":"白须薮雀（英文名：Moustached Brushfinch，学名：Atlapetes albofrenatus），是雀形目雀鹀科薮雀属的鸟类。仅分布于委内瑞拉西部及哥伦比亚东部安第斯山，常见于海拔1600–2500 m的潮湿山地林缘及林下层，亦见于道路切坡与次生灌丛，虽分布范围狭小，但数量尚称普遍。目前记录有两个亚种：指名亚种（A. a. albofrenatus）喉部白色，而委内瑞拉亚种（A. a. meridae）喉部鲜黄，部分研究曾将其视为独立种。","appearance":"体型硕大，头相对大，嘴长而略下弯。成鸟头顶为鲜明的栗红色，自额至后颈一致；黑色面罩横贯眼上下，与头顶栗红形成强烈对比；白色髭纹（submoustachial stripe）宽阔显眼，下方以黑色髭线（malar stripe）为界。指名亚种喉部纯白，与髭纹几乎融为一体，仅偶见一条暗色细线分隔；meridae亚种喉部亮黄色，髭纹与喉色分界明显。上体包括翼及尾橄榄绿；下体柠檬黄，中央最鲜亮，侧腹及胁部带橄榄晕染。两性同色。幼鸟羽色较为黯淡：头顶橄榄褐，无栗红；上体橄榄色，下体暗黄具模糊纵纹；髭纹仅呈淡黄，黑色髭线模糊；翼上覆羽端缘色浅，隐约成两道翼斑。指名亚种幼鸟整体更偏褐，meridae幼鸟则上体橄榄、下体金黄而带绿洗。","call":"鸣声因亚种而异。指名亚种歌声变化较大，一句持续1.2–4.1秒，含5–30个音符，句间间隔1–5秒；旋律以快速上滑或下滑音起始，中段为断续的chip或上下滑音，末尾接极快的颤音。meridae亚种歌声通常分两段：前段为清脆的“czeet czeet…”或“cheerp! cheerp!…”，后段转为快速连续的“tswit-tswit-tsu-tsu…”或“tuee-tu-tu-tu…”的咯咯颤音；另有二重唱型，音调更高、带颤抖音色。叫声包括尖细的“eeespe”、高音“ptiip”及鼻音“bzzzp”；还有级联式联系叫声，由一系列高频上滑音组成，末尾加速，meridae的级联声比指名亚种慢。晨昏为鸣唱高峰。","habits":"留鸟，无迁徙记录。栖息于潮湿亚热带、云雾林及栎林边缘、林下层及中层，偏好灌丛、蕨类与竹丛稠密的再生隙地、路边坡坎及林窗边缘，海拔多介于1600–2500 米，偶下探至1000 米。成对或家族小群活动，偶尔加入混合鸟群。觅食高度多在10 m以下，跳跃于覆苔树干、低枝及地面，探取节肢动物、小型果实与浆果。性不甚惧人，但仍喜隐匿于浓密植被中，偶登暴露枝头。","breeding":"繁殖生态资料极少。已知在哥伦比亚博亚卡省1月记录到亚成鸟，委内瑞拉佩里哈山区8月见幼鸟，梅里达州5–6月有刚离巢雏鸟，推测繁殖期至少涵盖1–8月，营巢及求偶细节尚缺。","identification":"与同域其他薮雀相比，白须薮雀以宽阔白色髭纹、栗红头顶及黄色下体为关键识别特征。与黄胸薮雀歌声相似，但后者无白色髭纹。亚种间差异：指名亚种喉白，髭纹与喉色几乎融合；meridae亚种喉黄，髭纹更宽，栗红冠羽前伸至喙基，前额无黑色。幼鸟缺乏成鸟鲜明栗红冠及黑白面纹，整体色调偏橄榄褐，需留意翼上隐约翼斑及淡黄髭区。","protection":"IUCN: LC（无危）。局限分布种，见于哥伦比亚东部安第斯及梅里达山脉EBA。种群尚称普遍，对林缘及次生环境具一定耐受性，目前无显著下降趋势。","distribution":"繁殖区：委内瑞拉梅里达州及塔奇拉州东部安第斯山；哥伦比亚东部安第斯山，自北桑坦德省向南至昆迪纳马卡省。非繁殖区：全年留居同一区域，无季节性迁移。","other":"系统发育研究显示，白须薮雀与赭胸薮雀及圣玛尔塔薮雀（哥伦比亚薮雀）亲缘关系最近，但该结论支持度不高。在哥伦比亚–委内瑞拉边界的佩里哈山可能存在与指名亚种渐变的未描述族群，有待进一步研究。"},{"name":"东白须薮雀","english_name":"Merida Brushfinch","scientific_name":"Atlapetes meridae","overview":"东白须薮雀（英文名：Merida Brushfinch，学名：Atlapetes meridae），是雀形目雀鹀科薮雀属的鸟类。仅分布于委内瑞拉西北部的安第斯山脉地区。","appearance":"成年东白须薮雀体重约30克，体长17.5至18厘米。其上体为橄榄色，下体渐变为柠檬黄色；翅膀和尾巴同样呈现橄榄色。头部特征明显，拥有栗色的冠羽、黑色的面罩、白色的亚嘴角纹和黄色的喉部。幼鸟色泽较为暗淡，上体为橄榄色，下体为深黄色，头部图案与成鸟相似但色调较淡。","habits":"东白须薮雀栖息于委内瑞拉西部安第斯山脉的湿润森林中，偏好橡树为主的森林环境，常见于茂密的林下植被中，包括蕨类和竹子。它们也能适应较干燥的林地，容忍受到干扰的生境，主要活动在海拔1,600至2,500米之间，偶尔下降至1,000米。它们以节肢动物、果实和浆果为主要食物，常在地面至10米高的灌木和树木间觅食。通常成对或家庭小群活动，偶尔加入混种群鸟群。","breeding":"关于东白须薮雀的繁殖生态知之甚少。目前尚未描述其求偶行为、巢穴和巢中活动。已观察到幼鸟，如在Perijá地区八月的幼鸟，以及五月和六月在Mérida地区的雏鸟。","identification":"东白须薮雀与其他薮雀属物种的区别在于其独特的头颈部颜色模式，包括黑色的面罩、白色的亚嘴角纹和黄色的喉部。","protection":"IUCN：LC（无危）","distribution":"东白须薮雀是委内瑞拉西北部的特有种，主要分布在Mérida和Táchira地区的安第斯山脉。","other":"现为白须薮雀亚种。"},{"name":"赭胸薮雀","english_name":"Ochre-breasted Brushfinch","scientific_name":"Atlapetes semirufus","overview":"赭胸薮雀（英文名：Ochre-breasted Brushfinch，学名：Atlapetes semirufus），是雀形目雀鹀科薮雀属的独特鸟类。其头部和胸部完全呈现锈橙色，背部橄榄绿色，腹部呈黄白色。分布于南美洲北部，自委内瑞拉至哥伦比亚北中部，主要栖息于海拔1,000至3,500米的山地森林底层及其边缘。","appearance":"赭胸薮雀拥有鲜明的外观，其头部和胸部覆盖着均匀的锈橙色羽毛，背部为橄榄绿色，腹部则是黄色。这种鸟的体型适中，雌雄羽色相似，幼鸟的羽色细节可能略有差异，但同样具有明显的锈橙色特征。","habits":"赭胸薮雀通常成对出现，偏好藏匿于茂密植被中，使其难以被观察到。它们生活在山地森林的底层，栖息地范围从1,000米到3,500米的高度，主要在南美洲的委内瑞拉和哥伦比亚北部地区。","identification":"赭胸薮雀最显著的识别特征是其头部和胸部的锈橙色羽毛，这在同属物种中独一无二。","distribution":"赭胸薮雀主要分布在南美洲的委内瑞拉和哥伦比亚北部，其栖息地包括山地森林的底层，偶尔也会出现在重度退化的前森林地带。"},{"name":"栗头薮雀","english_name":"Tepui Brushfinch","scientific_name":"Atlapetes personatus","overview":"栗头薮雀（英文名：Tepui Brushfinch，学名：Atlapetes personatus），是雀形目雀鹀科薮雀属的鸟类。分布于南美洲特普伊山脉的高海拔森林中。其显著特征为头部栗色，上体橄榄灰色，胸腹部黄色，这独特的组合使其在有限的分布区内非常容易识别。常见于潮湿森林的林下层，通常在海拔800米以上活动。","appearance":"体长约17至18厘米，拥有长尾。头部为鲜艳的栗色，上体橄榄灰色，下体黄色，两翼及尾部较深。亚种间差异主要体现在头部栗色的深浅及喉部颜色（锈色或黄色）。成鸟性状相似，幼鸟上体稍显棕色，头部非栗色而是棕灰色，随成长逐渐变为斑驳的栗色。","call":"鸣声包括干燥的吱吱声和各种模糊的接触音，歌声则是一系列短暂而引人注目的哨音。","habits":"生活在特普伊山脉的潮湿森林中，偏好海拔1000至2500米的地带，常在林下层或开阔地带活动。以种子和昆虫为食，有时加入混合物种群落。飞行特点不详，但活动范围广泛，会从隐蔽处出来觅食，最高可达几米高的苔藓枝条。","breeding":"关于繁殖习性的具体信息有限，但已知它在特普伊山脉的特定区域内繁殖。","identification":"在其分布范围内非常独特，没有其他类似物种。与赭胸薮雀外观相似，但两者地理分布不重叠，且赭胸薮雀的前部更为橙色。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲特普伊山脉的巴西、圭亚那和委内瑞拉，包括多个孤立的特普伊山峰。","other":"遗传分析显示，尽管与赭胸薮雀外表相似，但实则属于安第斯山脉秘鲁和厄瓜多尔地区的灰体薮雀群。"},{"name":"白颈薮雀","english_name":"White-naped Brushfinch","scientific_name":"Atlapetes albinucha","overview":"白颈薮雀（英文名：White-naped Brushfinch，学名：Atlapetes albinucha），是雀形目雀鹀科薮雀属的鸟类。上体暗灰色带橄榄色光泽，下体黄色，侧翼泛黄灰色。分布于墨西哥至厄瓜多尔远北部的云雾林、松栎混交林和热带森林边缘。","appearance":"体长17-21厘米，体重31-37.2克。成年鸟具有黑色头部，宽白中线冠纹，上体包括翅膀和尾巴呈深蓝灰色，略带橄榄色，喉咙和下体黄色，两胁泛黄灰色。虹膜红棕色到深棕色，喙黑色，腿肉色至暗灰棕色。雌雄相似。幼鸟外观类似成鸟，但上部暗煤灰色，头部更黑，下部黄色，喉咙最亮，与深色斑点的胸部形成对比，两胁微带棕肉桂色。不同亚种在体型、色彩和下体图案上有差异。","call":"发出一系列刻意的音符组成的歌曲，‘tsee tseea tseea tseea tseer’，有时被转译为‘o see, I’m weary, pity me’。","habits":"栖息于海拔1200-3150米的浓密灌木丛、云雾林开阔地带和热带森林边缘，常见于橡树林、松树和蕨类植物附近。通常在地面或接近地面的地方活动，跳跃寻找昆虫和其他食物，有时跟随行军蚁群。以各种昆虫和种子为食。","breeding":"繁殖记录显示，筑巢时间在墨西哥南部为4月末，在哥斯达黎加和巴拿马为4月至7月，在哥伦比亚为3月至9月。巢为开放的大杯状，由枝条、干草和叶子构成，内部铺有松针等细软材料，建于植被密集处0.6-3米高处，有时位于地面。每窝产卵2-3枚，罕见仅1枚，蛋白色无斑点。","identification":"与同属物种相比，白颈薮雀的黑色头部和鲜明的白色中线冠纹是其显著特征。在墨西哥，喉咙和下体主要是黄色。在中美洲和南美洲，黄色喉咙与淡灰色胸形成对比，这些鸟以前称为黄色喉刷雀。","protection":"IUCN：LC（无危）。在墨西哥、萨尔瓦多、哥斯达黎加和巴拿马西部和南部较为常见。自2012年起在厄瓜多尔东北部出现，似乎正在扩散。没有已知威胁。","distribution":"分布于中美洲至南美洲北部，具体包括墨西哥、哥斯达黎加、萨尔瓦多、危地马拉、洪都拉斯、尼加拉瓜、巴拿马、哥伦比亚。在墨西哥至厄瓜多尔远北部的云雾林、松栎混交林和热带森林边缘均有发现。","other":"历史系统学上，白颈薮雀的分类经历了一些变化，涉及不同亚种的命名和识别。"},{"name":"哥伦比亚薮雀","english_name":"Santa Marta Brushfinch","scientific_name":"Atlapetes melanocephalus","overview":"哥伦比亚薮雀（英文名：Santa Marta Brushfinch，学名：Atlapetes melanocephalus），是雀形目雀鹀科薮雀属的鸟类。仅见于哥伦比亚圣玛尔塔山脉，是该孤立山脉的特有种之一。拥有黑色头部、银灰色颊部、黄色下体和橄榄色背部的独特羽色模式。常见于云雾森林及林间空地，是鸟类爱好者访问该地区时最可能首先遇到的特有种。","appearance":"平均大小的薮雀，具有典型的厚实喙基。头部全黑，耳部有银灰色斑块，上体橄榄色，下体柠檬黄色。成鸟无性别二态性，幼鸟颜色较暗淡，上体偏褐色，下体淡黄带暗色细纹。","habits":"栖息于潮湿亚热带森林的灌木边缘和次生林，常在视线以下觅食，偶尔也会在中层林冠活动。以昆虫和其他小型无脊椎动物为食。","identification":"其银灰色颊部与全黑头部形成鲜明对比，是区别于其他薮雀属物种的显著特征。与黑额薮雀相似，但后者具栗色顶冠且颊部斑点不明显，且分布不重叠。","protection":"IUCN：LC（无危）","distribution":"局限于南美洲哥伦比亚的圣玛尔塔山脉。"},{"name":"黄枕薮雀","english_name":"Pale-naped Brushfinch","scientific_name":"Atlapetes pallidinucha","overview":"黄枕薮雀（英文名：Pale-naped Brushfinch，学名：Atlapetes pallidinucha），是雀形目雀鹀科薮雀属的鸟类。其特征为下半身黄色，上半身灰色，前冠呈灰褐色，至枕部渐变为白色。广泛分布于南美洲，包括哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉，栖息于海拔2700-3700米的高山森林边缘和灌木丛。","appearance":"此薮雀拥有一个相对较大的头部，高而圆的冠，喙厚实但短小且尖锐。指名亚种具有宽大的淡肉桂色中央条纹，从前额至中冠逐渐过渡为白色，与头部两侧的黑色形成鲜明对比。背部为深板岩灰色，上翼和尾羽近乎黑色。喉部呈现亮黄色，此色彩延展至胸部与腹部，侧面、侧翼及尾下覆羽则带有橄榄色至灰色。虹膜深栗色，喙黑色，腿部为粉红色的黄褐色。雌雄外观相似，幼鸟色泽较暗，顶部偏褐色，冠部有细窄的条纹，胸侧有灰暗的条纹。亚种papallactae额部呈极淡的肉桂色或黄色，下半身的橄榄色至灰色延伸至胸部，与黄色的喉部分离，幼鸟相比指名亚种更偏棕色，下半身色泽更深。","call":"领土性的歌声在北秘鲁被描述为旋律优美且吹哨般的“wheet-tew-tew-tew”。一种快速连续的叫声混合了甜美、尖锐、嗡嗡声和高音，单个个体发出略慢的歌曲，因频繁重复音符而类似金翅雀(Carduelis)，其叫声复杂难以描述，包含多种类型的音符快速交替。叫声包括高音柔和的“tip”以及重复几次的鼻音“pffe”。","habits":"偏好在地面或接近地面的密集灌木丛和树篱边缘觅食，常与混种鸟群一同活动。以浆果如Miconia或杜鹃花科植物为主食，同时食用昆虫、种子和其他植物材料。成对或家庭群体活动，经常加入混种觅食群。","breeding":"关于生长繁殖的信息未提及。","identification":"与其他薮雀区别在于下半身黄色与枕部的白色，没有其他薮雀具备这一特征。亚种间的辨识主要依赖于额部和下半身颜色的变化。","protection":"IUCN状态未提及。","distribution":"分布于南美洲，自委内瑞拉至秘鲁，主要栖息于海拔2700-3700米的高山森林边缘和灌木丛。","other":"系统学历史未提及。"},{"name":"绿头薮雀","english_name":"Yellow-headed Brushfinch","scientific_name":"Atlapetes flaviceps","overview":"绿头薮雀（英文名：Yellow-headed Brushfinch，学名：Atlapetes flaviceps），是雀形目雀鹀科薮雀属的鸟类。是哥伦比亚的特有种，以黄色头部而得名。分布于哥伦比亚中部和西部安第斯山脉的特定区域，生活于云雾森林中。","appearance":"绿头薮雀具有独特的色彩搭配，头部大多呈黄色，与灰橄榄色的背部、翅膀和尾巴形成鲜明对比。部分个体头部有暗斑。雄雌相似，幼鸟头部橄榄色更浓，胸部和侧翼也有橄榄色的洗染。体长约17厘米，头部较大，尾羽逐渐变细，冠羽常竖起，喙曲线均匀，显得相对钝圆。","call":"鸣唱包括一系列甜美的短音节，后跟一段更长的颤音和咔哒声的下降序列。叫声为高音的“tsiip”，间隔均匀重复；还有更响亮、更刺耳的“szeeet”。","habits":"栖息于云雾森林边缘的灌木丛，以及潮湿的山地森林下层。海拔高度在1300至2440米之间，偏好次生林、种植园边界和果园。食物包括小果实、昆虫和种子，经常成对或小群活动，有时加入多种裸鼻雀科和金额鸲莺组成的混种觅食群。","breeding":"繁殖活动记录在五月，巢穴活跃。六月观察到幼鸟与父母在一起，十一月收集筑巢材料。具体繁殖细节未知。","identification":"绿头薮雀以其独特的黄色头部和灰橄榄色背部容易识别，与其它薮雀种类明显不同。幼鸟头部的橄榄色较重，有助于区分。","protection":"IUCN：NT（近危）","distribution":"分布于哥伦比亚中部和西部安第斯山脉两侧，包括Caldas、Tolima、Cauca、Risaralda和Valle del Cauca地区。","other":"在四个国家公园内有记录：Las Hermosas、Los Nevados、Nevado del Huila和Puracé。"},{"name":"乌头薮雀","english_name":"Dusky-headed Brushfinch","scientific_name":"Atlapetes fuscoolivaceus","overview":"乌头薮雀（英文名：Dusky-headed Brushfinch，学名：Atlapetes fuscoolivaceus），是雀形目雀鹀科薮雀属的鸟类。主要分布在南美洲哥伦比亚的安第斯山脉南部地区，包括上马格达莱纳谷（Huila）在内的西南部地带。","appearance":"成年乌头薮雀具有深色的背部，黄色的腹部，以及一条独特的黑色髭纹。头部颜色较暗，年轻个体的头部颜色较为淡雅，下方可能带有模糊的条纹。成鸟缺乏明显的冠纹或冠斑，这有助于将其与其它种类的薮雀幼鸟区分开来。","call":"其鸣叫特征包括一系列短促的啾啾声和清晰的哨音，以及快速下降的叽叽喳喳声。","habits":"乌头薮雀偏好生活在云雾森林边缘的缠结植被中，通常避开森林内部。它们在清理地和云雾森林边缘的杂草丛中活动。","breeding":"关于乌头薮雀的繁殖生态信息有限，目前尚未详细记录。","identification":"乌头薮雀通过其深色的上体、黄色的下体和独特的黑色髭纹与其它薮雀种类相区分。缺乏冠纹或冠斑是识别成鸟的关键特征。","protection":"IUCN：NT（近危）","distribution":"乌头薮雀主要分布于哥伦比亚的西南部，特别是在安第斯山脉的东部和中部山脊，包括上马格达莱纳谷地区。","other":"乌头薮雀由于栖息地丧失，其种群数量正在减少，成为受关注的物种。"},{"name":"乔科薮雀","english_name":"Choco Brushfinch","scientific_name":"Atlapetes crassus","overview":"乔科薮雀（英文名：Choco Brushfinch，学名：Atlapetes crassus），是雀形目雀鹀科薮雀属的小型鸟类。广泛分布在哥伦比亚中西部和西南部至厄瓜多尔西南部的地区，以其橄榄色至黑色的上体和黄色的腹部为显著特征。","appearance":"成年乔科薮雀体重介于29.5至40克，体长16至18厘米。其上体颜色从橄榄绿到黑色不等，下体呈黄色，两侧的体色则带有橄榄色的浸染。头部两侧为黑色，头顶有一条醒目的黄色条纹，喉咙也是黄色的。幼鸟上体颜色较暗，为深棕色，下体较浅，呈浅棕色，头顶则为赤褐色。","habits":"乔科薮雀全年居住于哥伦比亚西部安第斯山脉和厄瓜多尔西部的开放云雾林中，偏好在湿润森林的边缘和次生林地的灌木层活动。其活动高度可达10米以上，与其它刷雀类主要在地面附近觅食的习惯形成对比。它们通常单独、成对或加入混合物种群落进行觅食。","breeding":"关于乔科薮雀的繁殖生态知之甚少。据报道，筑巢活动在哥伦比亚的11月、2月和5月被观察到，产卵记录出现在4月，而幼鸟离巢发生在6月和7月。已知的一个巢是一个放置在接近地面的厚实杯状结构，里面有一个带有暗色斑点的白色蛋。","identification":"乔科薮雀与三色薮雀在外形上有相似之处，但可通过其独特的颜色模式和分布区域加以区分。","protection":"IUCN：LC（无危）","distribution":"乔科薮雀的分布集中在南美洲的哥伦比亚中西部、西南部至厄瓜多尔西南部，主要栖息于海拔600至2,300米的区域，虽然也有零星记录显示其在更低和更高海拔处出现。"},{"name":"三色薮雀","english_name":"Tricolored Brushfinch","scientific_name":"Atlapetes tricolor","overview":"三色薮雀（英文名：Tricolored Brushfinch，学名：Atlapetes tricolor），是雀形目雀鹀科薮雀属的小型鸟类。主要分布于南美的安第斯山脉地区，包括秘鲁和厄瓜多尔的中部地带。其自然栖息地为亚热带或热带湿润山地森林及重度退化旧森林。","appearance":"三色薮雀具有独特的三色羽毛特征，但具体细节需参考更详细的资料以获取精确描述，包括雌雄幼鸟的羽毛颜色、大小及变化。","habits":"三色薮雀栖息于海拔较高的山地森林。","identification":"三色薮雀与同属的其他物种如乔科薮雀存在差异，具体辨识特征需参照专业文献。","distribution":"三色薮雀主要分布于南美的秘鲁，特别是在安第斯山脉的中部地区。"},{"name":"白翅缘薮雀","english_name":"White-rimmed Brushfinch","scientific_name":"Atlapetes leucopis","appearance":"长约18厘米，是一种深色的薮雀，具有醒目的白色眼环，喙基部较厚，鼻脊均匀弯曲。头顶至后颈呈暗锈色，脸部延伸至颊区，与白色眼环形成鲜明对比，后有短的白色耳后纹；上体，包括翅膀和尾巴，为灰黑色，臀部和上尾覆羽略带橄榄色；喉咙暗灰色，下体暗橄榄色，胸部有轻微的暗色斑点（形成斑驳外观），两胁和下尾覆羽比腹部中部和胸部稍暗的橄榄色；虹膜深棕色；喙黑色；腿肉色至灰褐色。性别相似，幼鸟头部有橄榄色，喉咙和胸部条纹更明显，腹部有模糊的条纹。","call":"三月时的歌声由4到15个尖锐的音符组成，或是上升或下降的哨声，从“swee twuu twuu twuu”到更长的“swee swee chewit chewit chewit tweew tweew chu chu”。还有复杂的二重奏，包含许多甜美的哨声、颤音和更复杂的音符。联系叫声是一个高音的“zeee”。","habits":"生活在湿热带山地森林的密集灌木丛和森林边缘，海拔2000至3100米之间。居民种，以浆果为食，尤其是蓝莓属的果实。在地面或低矮的下层林中觅食，觅食高度可达地面以上5米。单独、成对或最多三只个体一组出现，某些地区可能加入混合物种的觅食群，但在某些观察中并未如此。","breeding":"繁殖记录在哥伦比亚和厄瓜多尔的10月至12月，幼鸟与成鸟在哥伦比亚南部（纳里尼奥）12月被观察到。已知两个巢穴，其中一个正在建造中，是一个大的苔藓球，有一侧大入口，位于树叉8米高的地方；另一个是一个粗大的杯子，直径20×15厘米，由树枝和草制成，放置在大约1.5米高的地面洞穴中，洞穴长35厘米，入口25×18厘米，含有一枚淡奶油色带有绿色洗色和集中在宽端的栗色斑点的蛋，正在孵化中。","identification":"与其他薮雀的区别在于其深色的外观、白色的“眼镜”以及独特的歌声。","protection":"IUCN：LC（无危）；虽然以前被认为是近危，但最近发现其分布范围似乎更广泛，种群数量比之前认为的更大。","distribution":"分布于哥伦比亚南部，从马格达莱纳河谷南端至普图马约西部和纳里尼奥东南部，以及厄瓜多尔的西部斜坡（伊姆巴巴拉）和东部斜坡（至少在苏昆比奥斯省），科迪勒拉德瓜卡马约斯，在纳波省，还有阿苏艾省东部和莫罗纳-圣地亚哥省西北部，以及洛哈省南部。","other":"尽管罕见至不常见，但这种薮雀在所占地区的频繁发生的山体滑坡可能创造了其偏好的栖息地马赛克。"},{"name":"黄胸薮雀","english_name":"Yellow-breasted Brushfinch","scientific_name":"Atlapetes latinuchus","overview":"黄胸薮雀（英文名：Yellow-breasted Brushfinch，学名：Atlapetes latinuchus），是雀形目雀鹀科薮雀属的小型鸟类。又被称为云林薮雀。在北秘鲁到哥伦比亚北部的安第斯山脉高地上广泛分布。","appearance":"黄胸薮雀具有显著的黄色胸部羽毛，这是其最明显的外部特征之一。雄鸟和雌鸟在羽毛颜色上可能有所差异，但具体细节需进一步观察确认。","habits":"它们栖息于森林和林地环境，偏好安第斯山脉的高海拔地区。黄胸薮雀通常在哥伦比亚北部至秘鲁中部的南美洲地区活动，迁徙模式和飞行特点尚不明确。","breeding":"关于黄胸薮雀的繁殖习性的详细信息目前有限，包括繁殖期、求偶行为、营巢方式等，需要更多的研究来揭示。","identification":"与其他同属物种相比，黄胸薮雀可通过其黄色胸部羽毛进行辨识。不同亚种之间可能存在细微的外观差异。","protection":"IUCN：LC（无危）","distribution":"黄胸薮雀的分布范围从南美洲北部哥伦比亚到秘鲁中部，特别是在安第斯山脉的高海拔森林和林地环境中。","other":"2006年，新发现的亚种A. l. yariguierum在哥伦比亚Serranía de los Yariguíes被描述，表明黄胸薮雀的分类学研究仍在进行中。"},{"name":"黑额薮雀","english_name":"Black-fronted Brushfinch","scientific_name":"Atlapetes nigrifrons","overview":"黑额薮雀（英文名：Black-fronted Brushfinch，学名：Atlapetes nigrifrons），是雀形目雀鹀科薮雀属的小型鸟类。主要分布于南美的佩里哈山脉，包括哥伦比亚极北部和委内瑞拉西北部的特定区域。","appearance":"成年黑额薮雀长约17厘米，背部呈深灰色，腹部黄色，翅膀和尾巴颜色较暗。额头、脸颊两侧黑色，头顶至颈背呈现独特的红橙色。幼鸟色彩相似，但不具备成年鸟的红橙色头顶。","habits":"栖息于海拔1100至2850米的湿润山地森林，偏好灌木边缘和次生林地带，能适应受扰动的生境。通常成对或小群体活动，偶尔加入混种群。","breeding":"关于繁殖行为的信息有限。已知成鸟在1月至6月间处于繁殖状态，幼鸟在8月被观察到。","identification":"其独特之处在于黑色的额头和脸颊，以及红橙色的头顶，与同属的黄胸薮雀有明显的区别。","protection":"IUCN：LC（无危）","distribution":"分布局限于南美洲的佩里哈山脉，包括哥伦比亚极北部和委内瑞拉西北部。"},{"name":"安蒂薮雀","english_name":"Antioquia Brushfinch","scientific_name":"Atlapetes blancae","overview":"安蒂薮雀（英文名：Antioquia Brushfinch，学名：Atlapetes blancae），是雀形目雀鹀科薮雀属的鸟类。自20世纪70年代以来一直被认为可能已灭绝，直到2018年在哥伦比亚安第斯山脉北部城市麦德林附近的几个地点被重新发现。其特征与广泛分布的灰蓝薮雀相似，但色泽较淡，翼部无白色斑点，面部少有或无深色胡须纹。","appearance":"安蒂薮雀的外观与灰蓝薮雀极为相似，但整体色调更淡，缺少后者翼上的白色斑点，脸部图案上，胡须纹不明显或不存在。具体体型、羽毛颜色及变化细节尚需更多观察研究。","habits":"该物种栖息于残存的本地森林地带和灌木丛，同时也在邻近的耕作区活动。其具体生活习性、食物来源和活动模式仍待进一步研究。","identification":"与灰蓝薮雀相比，安蒂薮雀的羽色更为柔和，翼部无白色标记，胡须纹不显著，这些是识别两种物种的关键特征。","protection":"IUCN：CR（极危）","distribution":"仅在南美洲哥伦比亚中北部的特定区域有分布，包括圣佩德罗德洛斯米拉格罗斯（San Pedro de los Milagros）一带。"},{"name":"棕耳薮雀","english_name":"Rufous-eared Brushfinch","scientific_name":"Atlapetes rufigenis","overview":"棕耳薮雀（英文名：Rufous-eared Brushfinch，学名：Atlapetes rufigenis），是雀形目雀鹀科薮雀属的鸟类。主要特征为灰色身躯，头戴栗色冠帽，眼前方有一白色斑点，脸颊条纹黑白相间。该鸟种分布于秘鲁北部安第斯山脉的高海拔地区，尤其是上马腊翁河谷两侧。","appearance":"成年棕耳薮雀主要为灰色，头顶、颈侧及颈部呈锈褐色，脸部有白色斑块，上体（背部、翅膀、尾巴）为深烟灰色，具有明显的白色颊纹，喉部纯白，胸及两肋灰白，腹部及尾下覆羽近白色。幼鸟色调较暗淡，头部为暗灰棕色，非锈色，但仍有白色脸斑和白色喉部，上体灰色带棕色，胸腹暗棕色，腹部白色。","call":"发出丰富而下降的颤音，伴随高音的“sip”音符。","habits":"栖息于密林下层及灌木丛中，主要在Polylepis森林和树线灌木丛中活动，海拔高度在3200至4600米之间。觅食时靠近地面，常在视线以下的低矮植被中活动，也会在高山森林的厚苔藓覆盖的树枝上爬行。","breeding":"关于棕耳薮雀的繁殖习性信息极为有限。","identification":"成年棕耳薮雀与圣河薮雀及黑花脸薮雀相似，但两者分布于秘鲁南部山区，与棕耳薮雀完全不重叠。幼鸟与锈腹薮雀有表面相似之处，但后者缺乏棕耳薮雀明显的白色脸斑，且腹部为锈色而非白色。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁北部安第斯山脉，主要在上马腊翁河谷两侧，局部出现在太平洋斜坡区域。","other":"直到最近，圣河薮雀还被视作棕耳薮雀的一个分离亚种，但现在二者已被分类为独立物种。"},{"name":"圣河薮雀","english_name":"Apurimac Brushfinch","scientific_name":"Atlapetes forbesi","overview":"圣河薮雀（英文名：Apurimac Brushfinch，学名：Atlapetes forbesi），是雀形目雀鹀科薮雀属的鸟类。特有于南美秘鲁安第斯山脉的鸟类，这种红头小雀拥有灰烬般的体羽，头部呈锈红色，面部黑色，搭配白色的眼纹和髭纹，形成鲜明对比。其生活于高海拔的灌木丛和Polylepis森林中。","appearance":"成年圣河薮雀长约18厘米，背部暗色，腹部偏白，喙较长且基部中等深度。头部主要为赤褐色，包括颈背和侧面，额部黑色，眼上有一块明显的白色区域，与黑色的耳区和眼周形成对比。下颌有一条长的白色髭纹，黑色的颊纹明显。上体灰色，翼上部和尾巴略显黑褐色。翅膀折叠时可见白色的边缘（由突出的翼缘造成）。喉部白色，下体大部分灰色，腹部中央有白色斑点。虹膜棕色，喙黑色，腿深灰色。雌雄相似。幼鸟上体呈褐色，包括头部和脸部，眼周黑色，喉部白色，胸腹侧边呈斑驳的棕色，腹部白色；亚成体的下体似成鸟，但头部逐渐变成赤褐色，首先出现在颈背和后冠。","call":"其鸣唱包括一系列急促的高音金属哨声、嗡嗡的口哨声和尖锐的叫声。叫声为高音的‘pi’。","habits":"栖息于海拔2700至4600米的山地灌木和Polylepis森林中，通常在地面或接近地面处觅食。生活方式为定居。","breeding":"繁殖季节在3月，幼鸟在5月被观察到。具体繁殖行为信息较少。","identification":"区别于其他物种，圣河薮雀的特征在于其独特的红头黑面白髭纹组合，以及长喙和灰白相间的体色。","protection":"IUCN：LC（无危）。虽然全球分布范围有限，但该物种目前未受到直接威胁，其栖息地也未发现明显问题。","distribution":"分布于秘鲁南部安第斯山脉的阿普里马克（Apurímac）和相邻的库斯科（Cuzco）地区。"},{"name":"黑花脸薮雀","english_name":"Black-spectacled Brushfinch","scientific_name":"Atlapetes melanopsis","overview":"黑花脸薮雀（英文名：Black-spectacled Brushfinch，学名：Atlapetes melanopsis），是雀形目雀鹀科薮雀属的独特鸟类，仅分布于秘鲁中部安第斯山脉东部的狭窄地带。拥有醒目的头部图案，包括黑色面罩、栗色边缘、黑白相间的髭纹以及眼与喙之间的一个白色斑点。黑花脸薮雀与阿普里马克（Apurimac）和红耳（Rufous-eared）薮雀构成一个超物种群，这三种鸟类在秘鲁的隔离区域内有着相似的羽毛模式。","appearance":"黑花脸薮雀具有暗灰色上体和较淡的灰色下体，喉咙和腹部呈白色。它的头饰复杂，带有赭红色的冠羽、颈背和面侧环绕着黑色斑块，还有白色的眉纹、黑色的前额以及鲜明的白色颊纹和黑色喉侧条纹。除头部特征外，其整体呈现灰褐色调，腹部较为苍白。","call":"其鸣唱是一系列丰富而略带喘息的音符，富有特色。","habits":"栖息于季节性湿润的山地灌木丛和森林边缘，偏好海拔2500至3600米之间的干燥灌木区及邻近的湿润斜坡森林边界。在秘鲁的东坡地区并未发现其踪迹。","identification":"与圣河薮雀和棕耳薮雀相比，黑花脸薮雀的面罩更大，髭纹更粗厚。圣河薮雀分布在更东南部，面罩较小，髭纹更细。棕耳薮雀在北中部秘鲁的马兰翁山谷出现，与黑花脸薮雀完全无接触，且面部黑色较少。","protection":"IUCN：NT（近危）","distribution":"分布局限于秘鲁中部安第斯山脉的东部，特别是在季节性湿润的山地和高海拔的灌木丛与森林边缘。","other":"黑花脸薮雀被认为是与圣河薮雀和棕耳薮雀同属于一个超物种群体，它们在秘鲁的特定区域中各自形成独立的种群。"},{"name":"灰蓝薮雀","english_name":"Slaty Brushfinch","scientific_name":"Atlapetes schistaceus","overview":"灰蓝薮雀（英文名：Slaty Brushfinch，学名：Atlapetes schistaceus），是雀形目雀鹀科薮雀属的鸟类。典型的安第斯高山薮雀，通体以灰蓝色为主，具醒目的栗色冠羽、白色喉斑及黑色髭纹，主要分布于委内瑞拉至厄瓜多尔的安第斯山脉，栖息于海拔2500–3800米的灌丛与林缘地带，为留鸟。","appearance":"成鸟体长17–18厘米，体重22.6–43.9克。雌雄同色。头顶至后颈栗色；耳羽及颈侧近黑色，形成黑色面罩；白色髭纹显著，下缘以黑色颊纹为界；背部暗黑灰色；翅上覆羽与尾羽黑褐色，初级飞羽基部具明显白斑，折叠时呈小翼斑；喉部白色，微具暗点；胸、胁及尾下覆羽中灰色，腹中央近白。幼鸟似成鸟，但栗色冠羽被黑色掩盖，胸胁具黑色纵纹，翼斑较小。","call":"黎明雄鸟鸣唱为2–5个清脆哨音组成的舒缓短句，句间停顿约5秒，可重复或交替不同主题；常用音型“tsuu-tweet-tweet”或“tsew-wheet-tsew”。日间常见“Excitement Duet”：两性同时爆发高亢颤音与尖叫，结尾连发“chewy-chewy-chewy”。其他叫声包括金属质感的“spik!”、上扬的“tzeeee”及平直的“tzeet”，可连续重复。","habits":"留鸟，栖息于云雾林缘、潮湿山地次生林、高山灌丛及Polylepis林，海拔2500–3800米，局部可降至1800米。多单独或成对活动，常加入混合种觅食群，在0–5米的灌丛或次冠层内跳跃觅食，偶尔攀爬藤蔓。食物以昆虫等节肢动物为主，兼食小型果实；记录到的猎物包括蜘蛛、甲虫、双翅目、膜翅目、鳞翅目等，果实来自Gesneriaceae、Melastomataceae、Ericaceae等科。","breeding":"繁殖资料稀少。在哥伦比亚北部繁殖期见于4–9月，委内瑞拉记录到11月仍具繁殖状态；雏鸟离巢期在哥伦比亚为4–8月，委内瑞拉8月，厄瓜多尔12月底。曾见成鸟于12月末喂哺幼鸟，但巢址、巢形、卵数及孵化期尚无确切描述。","identification":"与同属灰系薮雀相比：锈腹薮雀腹及尾下覆羽具锈色且缺栗色冠斑；棕冠薮雀上体较淡且带橄榄色，尾下覆羽染皮黄色；白翅薮雀下体更淡，黑色颊纹较窄；安蒂薮雀整体色淡，背、胸及胁灰度低，冠部锈带更宽且淡，眉纹灰色而非白色，喉与胸缺乏对比。亚种间差异：指名亚种最淡且具白翼斑；castaneifrons及fumidus上体近黑，无白翼斑；tamae似castaneifrons但体型较大，下体更深，白翼斑亦缺。","protection":"IUCN: LC（无危）。","distribution":"繁殖区及全年活动范围：自哥伦比亚－委内瑞拉边界的佩里哈山脉，向西南经委内瑞拉塔奇拉州、哥伦比亚桑坦德省北部，延伸至委内瑞拉特鲁希略州、梅里达州，再向南贯穿哥伦比亚安第斯山脉至厄瓜多尔中部安第斯地区。","other":"分子系统学提示本种在属内关系复杂，曾因羽色相似而将形态差异较大的种群合并，实际存在多次黄色腹部的得失演化。曾被视为本种亚种的灰脸薮雀及暗灰薮雀已独立成种，后者与指名亚种地理隔离约700公里，亲缘关系更远。"},{"name":"白翅薮雀","english_name":"White-winged Brushfinch","scientific_name":"Atlapetes leucopterus","overview":"白翅薮雀（英文名：White-winged Brushfinch，学名：Atlapetes leucopterus），是雀形目雀鹀科薮雀属的鸟类。分布在南美洲的厄瓜多尔西北部至秘鲁西北部，中北部地区。其外观特征显著，拥有灰白相间的羽色和独特的黑色面部，部分地区的个体面部带有白色斑点。","appearance":"白翅薮雀的外观因地域而异，北方个体的面部为纯黑色，而在西南厄瓜多尔和北秘鲁的个体，面部则带有白色斑块。头顶通常为栗色，仅在特定局部群体中呈淡色。最显著的特征是其明显的白色翼斑，这有助于将其与棕冠薮雀区分开来。雌雄和幼鸟的具体差异未详述。","call":"鸣唱由高音细弱的两段式音符组成，缺乏与其他同域分布的Atlapetes物种所特有的颤音短语。其叫声为高降调的'tseeu'。","habits":"栖息于密集植被中，如山地灌木丛和路边杂草丛生地带。偏好亚热带或热带的干燥森林、湿润低地森林、湿润山地森林环境，也能在严重退化的前森林地区生存。","breeding":"具体繁殖细节未提及。","identification":"与棕冠薮雀相比，白翅薮雀通过其醒目的白色翼斑进行区分。不同亚种之间存在面部标记的差异，如北方亚种的纯黑面部与南部亚种的带白斑面部。","protection":"IUCN：LC（无危）。在厄瓜多尔和秘鲁分布较为广泛且相对常见，没有迹象显示其数量有显著下降，反而在厄瓜多尔有证据表明，由于森林砍伐，其分布范围可能在局部有所增加。","distribution":"分布于南美洲，主要在厄瓜多尔的西北部至秘鲁的西北部，中北部地区。","other":"系统学历史和分布详情表明，白翅薮雀在南美的特定区域有稳定的分布。"},{"name":"白头薮雀","english_name":"White-headed Brushfinch","scientific_name":"Atlapetes albiceps","overview":"白头薮雀（英文名：White-headed Brushfinch，学名：Atlapetes albiceps），是雀形目雀鹀科薮雀属的鸟类。是南美洲特有种，分布于厄瓜多尔远西南部和秘鲁西北部的干森林和灌木丛地带。其最显著的特征是拥有白色的面部与黑色的冠羽环绕，形成鲜明对比。","appearance":"成年白头薮雀头部大部分为白色，与黑色的冠羽和颈背形成强烈反差；上身呈灰石板色，翅膀和尾巴略带黑褐色，初级飞羽基部有白色斑块，形成闭合翅膀上的白色斑点。喉咙处有一条非常窄的黑色侧喉纹，喉咙颜色为白色，逐渐过渡至胸部和侧翼的灰白色，腹部和臀部呈白色。雌雄两性相似。幼鸟尚未描述。","habits":"白头薮雀主要栖息于安第斯山下坡和沿海山脉的干燥山谷灌木丛中，通常不会进入低地。它们常以对的形式出现，有时会形成相对较大的群落，与同属其他薮雀混群。它们既在地上觅食，也会在低矮的灌木丛中活动，食物包括种子和昆虫。","identification":"白头薮雀与白翅薮雀地理分布重叠，白头薮雀体型更大，常见于较低海拔（最高1400米）。白翅薮雀的冠羽为赤褐色，而白头薮雀的后冠始终为黑色。","protection":"IUCN：LC（无危）","distribution":"分布于南美，具体为厄瓜多尔远西南部和秘鲁西北部。在繁殖区域内，主要栖息于安第斯山脉下坡和沿海山区。"}];
